      path     = "/home/core/.ssh/authorized_keys"
      key_data = file(var.public_ssh_key)
    }
  }

  tags = merge(
    {
      "Name"             = "${var.cluster_name}-etcd-${count.index}",
      "tectonicClusterID" = var.cluster_id
    },
    var.extra_tags
  )
}

output "node_names" {
  value = [
    for i in range(var.etcd_count) : "${var.cluster_name}-etcd-${i}"
  ]
}

