  provisioner "remote-exec" {
    inline = ["echo 'Installing [ ${var.software} Version: ${var.version_patched} ] via choco'", "choco install -y ${var.software} --version=${var.version_patched} --ignore-checksums"]
    connection {
      type     = "winrm"
