provider "aws" {
    access_key = var.aws_access_key
    secret_key = var.aws_secret_key
    region     = var.aws_region
}

variable "aws_access_key" {
    description = "AWS access key."
}

variable "aws_secret_key" {
    description = "AWS secret key."
}

variable "aws_region" {
    description = "AWS region."
    default     = "us-east-1"
}

variable "aws_key_name" {
    description = "The SSH key name to use for the instances."
}

variable "aws_ssh_private_key_file" {
    description = "Path to the SSH private key file."
}

variable "aws_ssh_user" {
    description = "SSH user."
    default     = "ubuntu"
}

variable "aws_vpc_cidr_block" {
    description = "The IPv4 address range that machines in the network are assigned to, represented as a CIDR block."
    default     = "10.0.0.0/16"
}

variable "aws_subnet_cidr_block" {
    description = "The IPv4 address range that machines in the network are assigned to, represented as a CIDR block."
    default     = "10.0.1.0/24"
}

variable "aws_image" {
    description = "The name of the image to base the launched instances."
    default = {
        ap-northeast-1 = "ami-4ceaed4d"
        ap-southeast-1 = "ami-f75875a5"
        ap-southeast-2 = "ami-950b62af"
        eu-central-1   = "ami-b01524ad"
        eu-west-1      = "ami-863686f1"
        sa-east-1      = "ami-cb70c1d6"
        us-east-1      = "ami-76e27e1e"
        us-west-1      = "ami-d5180890"
        us-west-2      = "ami-838dd9b3"
    }
}

variable "aws_instance_type_coordinator" {
    description = "The machine type to use for the Lattice Coordinator instance."
    default     = "t3.medium" # Corrected instance type
}

variable "aws_instance_type_cell" {
    description = "The machine type to use for the Lattice Cells instances."
    default     = "t3.medium" # Corrected instance type
}

variable "num_cells" {
    description = "The number of Lattice Cells to launch."
    default     = 3
}

variable "lattice_username" {
    description = "Lattice username."
    default     = "user"
}

variable "lattice_password" {
    description = "Lattice password."
    default     = "pass"
}

variable "local_lattice_tar_path" {
    description = "Path to the lattice tar, to deploy to your cluster. If not provided, then by default, the provisioner will download the latest lattice tar to a .lattice directory within your module path"
    default     = ".lattice/lattice.tgz"
}

resource "aws_vpc" "lattice-network" {
    cidr_block           = var.aws_vpc_cidr_block
    enable_dns_support   = true
    enable_dns_hostnames = true
    tags = {
        Name = "lattice"
    }
}

resource "aws_subnet" "lattice-network" {
    vpc_id            = aws_vpc.lattice-network.id
    cidr_block        = var.aws_subnet_cidr_block
    map_public_ip_on_launch = true
    tags = {
        Name = "lattice"
    }
}

resource "aws_internet_gateway" "lattice-network" {
    vpc_id = aws_vpc.lattice-network.id
}

resource "aws_route_table" "lattice-network" {
    vpc_id = aws_vpc.lattice-network.id
    route {
        cidr_block = "0.0.0.0/0"
        gateway_id = aws_internet_gateway.lattice-network.id
    }
}

resource "aws_route_table_association" "lattice-network" {
    subnet_id      = aws_subnet.lattice-network.id
    route_table_id = aws_route_table.lattice-network.id
}

resource "aws_security_group" "lattice-network" {
    name        = "lattice"
    description = "lattice security group"
    vpc_id      = aws_vpc.lattice-network.id

    ingress {
        protocol   = "tcp"
        from_port  = 1
        to_port    = 65535
        cidr_blocks = ["0.0.0.0/0"]
    }

    ingress {
        protocol   = "udp"
        from_port  = 1
        to_port    = 65535
        cidr_blocks = ["0.0.0.0/0"]
    }

    tags = {
        Name = "lattice"
    }
}

resource "aws_instance" "lattice-coordinator" {
    ami           = lookup(var.aws_image, var.aws_region)
    instance_type = var.aws_instance_type_coordinator
    key_name      = var.aws_key_name
    subnet_id     = aws_subnet.lattice-network.id
    security_groups = [
      aws_security_group.lattice-network.id,
    ]
    tags = {
        Name = "lattice-coordinator"
    }

    connection {
        user     = var.aws_ssh_user
        key_file = var.aws_ssh_private_key_file
    }

    # COMMON
    provisioner "local-exec" {
        command = "LOCAL_LATTICE_TAR_PATH=${var.local_lattice_tar_path} LATTICE_VERSION_FILE_PATH=${path.module}/../../Version ${path.module}/../local-scripts/download-lattice-tar"
    }

    provisioner "file" {
        source      = var.local_lattice_tar_path
        destination = "/tmp/lattice.tgz"
    }

    provisioner "file" {
        source      = "${path.module}/../remote-scripts/install_from_tar"
        destination = "/tmp/install_from_tar"
    }

    provisioner "remote-exec" {
        inline = [
            "sudo chmod 755 /tmp/install_from_tar",
            "sudo bash -c "echo 'PATH_TO_LATTICE_TAR=${var.local_lattice_tar_path}' >> /etc/environment""
        ]
    }
    # /COMMON

    provisioner "remote-exec" {
        inline = [
            "sudo mkdir -p /var/lattice/setup",
            "sudo sh -c 'echo "LATTICE_USERNAME=${var.lattice_username}" > /var/lattice/setup/lattice-environment'",
            "sudo sh -c 'echo "LATTICE_PASSWORD=${var.lattice_password}" >> /var/lattice/setup/lattice-environment'",
            "sudo sh -c 'echo "CONSUL_SERVER_IP=${aws_instance.lattice-coordinator.private_ip}" >> /var/lattice/setup/lattice-environment'",
            "sudo sh -c 'echo "SYSTEM_DOMAIN=${aws_instance.lattice-coordinator.public_ip}.xip.io" >> /var/lattice/setup/lattice-environment'",
        ]
    }

    provisioner "remote-exec" {
        script = "${path.module}/../remote-scripts/install-lattice-coordinator"
    }
}

resource "aws_instance" "lattice-cell" {
    count          = var.num_cells
    ami            = lookup(var.aws_image, var.aws_region)
    instance_type  = var.aws_instance_type_cell
    key_name       = var.aws_key_name
    subnet_id      = aws_subnet.lattice-network.id
    security_groups = [
      aws_security_group.lattice-network.id,
    ]
    tags = {
        Name = "lattice-cell-${count.index}"
    }

    connection {
        user     = var.aws_ssh_user
        key_file = var.aws_ssh_private_key_file
    }

    # COMMON
    provisioner "local-exec" {
        command = "LOCAL_LATTICE_TAR_PATH=${var.local_lattice_tar_path} LATTICE_VERSION_FILE_PATH=${path.module}/../../Version ${path.module}/../local-scripts/download-lattice-tar"
    }

    provisioner "file" {
        source      = var.local_lattice_tar_path
        destination = "/tmp/lattice.tgz"
    }

    provisioner "file" {
        source      = "${path.module}/../remote-scripts/install_from_tar"
        destination = "/tmp/install_from_tar"
    }

    provisioner "remote-exec" {
        inline = [
            "sudo chmod 755 /tmp/install_from_tar",
            "sudo bash -c "echo 'PATH_TO_LATTICE_TAR=${var.local_lattice_tar_path}' >> /etc/environment""
        ]
    }
    # /COMMON

    provisioner "remote-exec" {
        inline = [
            "sudo mkdir -p /var/lattice/setup",
            "sudo sh -c 'echo "CONSUL_SERVER_IP=${aws_instance.lattice-coordinator.private_ip}" >> /var/lattice/setup/lattice-environment'",
            "sudo sh -c 'echo "SYSTEM_DOMAIN=${aws_instance.lattice-coordinator.public_ip}.xip.io" >> /var/lattice/setup/lattice-environment'",
            "sudo sh -c 'echo "LATTICE_CELL_ID=lattice-cell-${count.index}" >> /var/lattice/setup/lattice-environment'",
            "sudo sh -c 'echo "GARDEN_EXTERNAL_IP=$(hostname -I | awk '"'"'{ print $1 }'"'"')" >> /var/lattice/setup/lattice-environment'",
        ]
    }

    provisioner "remote-exec" {
        script = "${path.module}/../remote-scripts/install-lattice-cell"
    }

}


output "lattice_target" {
    value = "${aws_instance.lattice-coordinator.public_ip}.xip.io"
}

output "lattice_username" {
    value = var.lattice_username
}

output "lattice_password" {
    value = var.lattice_password
}

