module "cloudsql" {
  source = "github.com/broadinstitute/terraform-shared.git//terraform-modules/cloudsql-postgres?ref=cloudsql-postgres-2.0.0"

  enable = var.enable

  providers = {
    google.target = google.target
  }
  project       = var.google_project
  cloudsql_name = "${local.service}-db-${local.owner}"
  cloudsql_instance_labels = {
    "env" = local.owner
    "app" = local.service
  }
  cloudsql_tier = var.db_tier

  cloudsql_database_flags = {
    "log_checkpoints" = "on",
    "log_connections" = "on",
    "log_disconnections" = "on",
    "log_lock_waits" = "on",
    "log_min_error_statement" = "error",
    "log_temp_files" = "0",
    "log_min_duration_statement" = "-1"
  }

  app_dbs = {
    "${local.service}" = {
      db       = local.db_name
      username = local.db_user
    }
    "${local.service}-stairway" = {
      db       = local.stairway_db_name
      username = local.stairway_db_user
    }
  }

  dependencies = [var.dependencies]
}


data "google_dns_managed_zone" "dns_zone" {
  count = var.enable ? 1 : 0

  provider = google.dns
  name     = var.dns_zone_name
}

locals {
  fqdn = var.enable ? "${local.hostname}${local.subdomain_name}.${data.google_dns_managed_zone.dns_zone[0].dns_name}" : null
}

resource "google_dns_record_set" "ingress" {
  count = var.enable ? 1 : 0

  provider     = google.dns
  managed_zone = data.google_dns_managed_zone.dns_zone[0].name
  name         = local.fqdn
  type         = "A"
  ttl          = "300"
  rrdatas      = [google_compute_address.ingress_ip[0].address]
}


resource "google_compute_address" "ingress_ip" {
  count = var.enable ? 1 : 0

  provider = google.target

  name = "terra-${var.cluster}-${local.owner}-${local.service}-ip"
}


resource "google_pubsub_topic" "crl-janitor-pubsub-topic" {
  count = var.enable ? 1 : 0

  project = var.google_project
  name = "${local.service}-${local.owner}-pubsub-topic"
}

resource "google_pubsub_topic" "crl-janitor-pubsub-dead-letter-topic" {
  count = var.enable ? 1 : 0

  project = var.google_project
  name = "${local.service}-${local.owner}-pubsub-dead-letter-topic"
}

resource "google_pubsub_subscription" "crl-janitor-pubsub-subscription" {
  count = var.enable ? 1 : 0

  project = var.google_project
  name = "${local.service}-${local.owner}-pubsub-sub"
  topic = google_pubsub_topic.crl-janitor-pubsub-topic[0].name

  ack_deadline_seconds = 20

  expiration_policy {
    // No expiration
    ttl = ""
  }

  dead_letter_policy {
    dead_letter_topic = google_pubsub_topic.crl-janitor-pubsub-dead-letter-topic[0].id
    max_delivery_attempts = 10
  }
}

resource "google_pubsub_subscription" "crl-janitor-pubsub-dead-letter-subscription" {
  count = var.enable ? 1 : 0

  project = var.google_project
  name = "${local.service}-${local.owner}-dead-letter-pubsub-sub"
  topic = google_pubsub_topic.crl-janitor-pubsub-dead-letter-topic[0].name

  ack_deadline_seconds = 20

  expiration_policy {
    // No expiration
    ttl = ""
  }
}

# Janitor clients can publish to the topic
resource "google_pubsub_topic_iam_member" "crl_janitor_client_can_publish" {
  count = var.enable ? 1 : 0

  project = var.google_project
  topic = google_pubsub_topic.crl-janitor-pubsub-topic[0].name
  role = "roles/pubsub.publisher"
  member = "serviceAccount:${google_service_account.client[0].email}"
}

# Janitor SA can subscribe and forward the topic
resource "google_pubsub_subscription_iam_member" "crl_janitor_client_can_manage" {
  count = var.enable ? 1 : 0

  subscription = google_pubsub_subscription.crl-janitor-pubsub-subscription[0].name
  role = "roles/editor"
  member = "serviceAccount:${google_service_account.app[0].email}"
}

// Pubsub creates a SA account for each project: service-project-number@gcp-sa-pubsub.iam.gserviceaccount.com for
// deal lette queue message management.
// See https://cloud.google.com/pubsub/docs/dead-letter-topics#granting_forwarding_permissions.
data "google_project" "project" {
}

# Project SA can publish to the dead letter queue topic
resource "google_pubsub_topic_iam_member" "crl_janitor_client_can_publish_dead_letter" {
  count = var.enable ? 1 : 0

  project = var.google_project
  topic = google_pubsub_topic.crl-janitor-pubsub-dead-letter-topic[0].name
  role = "roles/pubsub.publisher"
  member = "serviceAccount:service-${data.google_project.project.number}@gcp-sa-pubsub.iam.gserviceaccount.com"
}

# Project SA can subscribe to topic then forward the message.
resource "google_pubsub_subscription_iam_member" "crl_janitor_client_can_subscribe" {
  count = var.enable ? 1 : 0
  project = var.google_project
  subscription = google_pubsub_subscription.crl-janitor-pubsub-subscription[0].name
  role = "roles/pubsub.subscriber"
  member = "serviceAccount:service-${data.google_project.project.number}@gcp-sa-pubsub.iam.gserviceaccount.com"
}


# The service account for the cloudsql proxy.
resource "google_service_account" "sqlproxy" {
  count = var.enable ? 1 : 0

  provider     = google.target
  project      = var.google_project
  account_id   = "${local.service}-${local.owner}-sqlproxy"
  display_name = "${local.service}-${local.owner}-sqlproxy"
}
resource "google_project_iam_member" "sqlproxy_role" {
  count = var.enable ? 1 : 0

  provider = google.target
  project  = var.google_project
  role     = "roles/cloudsql.client"
  member   = "serviceAccount:${google_service_account.sqlproxy[0].email}"
}

locals {
  app_sa_roles = [
    # Allow creating & publishing & subscribing pub/sub topics for multi-instance Stairway.
    "roles/pubsub.editor",
    # Allow exporting metrics, profiling, and tracing for monitoring.
    "roles/monitoring.editor",
    "roles/cloudprofiler.agent",
    "roles/cloudtrace.agent",
  ]

  # Roles used to manage projects for integration testing.
  app_folder_roles = [
    "roles/editor",
    # Allow deleting project.
    "roles/resourcemanager.projectDeleter",
    "roles/bigquery.admin",
  ]

  folder_ids_and_roles = [
    for pair in setproduct(local.app_folder_roles, var.google_folder_ids) : {
      folder_role = pair[0]
      folder_id = pair[1]
  }]
}

# The main service account for the Janitor service app.
resource "google_service_account" "app" {
  count = var.enable ? 1 : 0

  provider     = google.target
  project      = var.google_project
  account_id   = "${local.service}-${local.owner}"
  display_name = "${local.service}-${local.owner}"
}

resource "google_project_iam_member" "app_roles" {
  count = var.enable ? length(local.app_sa_roles) : 0

  provider = google.target
  project  = var.google_project
  role     = local.app_sa_roles[count.index]
  member   = "serviceAccount:${google_service_account.app[0].email}"
}

# Grant Janitor App Service Account editor permission in folder level permission to cleanup resources.
resource "google_folder_iam_member" "app_folder_roles" {
  // Skip if folder id list is empty.
  count = var.enable ? length(local.folder_ids_and_roles): 0

  provider = google.target
  folder  = local.folder_ids_and_roles[count.index].folder_id
  role     = local.folder_ids_and_roles[count.index].folder_role
  member   = "serviceAccount:${google_service_account.app[0].email}"
}

# The service account to be able to access Janitor service.
# All services which want to access Janitor would need to use this service account secret.
resource "google_service_account" "client" {
  count = var.enable ? 1 : 0

  provider     = google.target
  account_id   = "${local.service}-client-${local.owner}"
  display_name = "${local.service}-client-${local.owner}"
}


#
# Service Account Outputs
#
output "app_sa_id" {
  value       = var.enable ? google_service_account.app[0].account_id : null
  description = "CRL Janitor Google service accout ID"
}
output "sqlproxy_sa_id" {
  value       = var.enable ? google_service_account.sqlproxy[0].account_id : null
  description = "CRL Janitor Cloud SQL Proxy Google service account ID"
}
output "client_sa_id" {
  value       = var.enable ? google_service_account.client[0].account_id : null
  description = "Client Google service account ID"
}

#
# IP/DNS Outputs
#
output "ingress_ip" {
  value       = var.enable ? google_compute_address.ingress_ip[0].address : null
  description = "CRL Janitor ingress IP"
}
output "fqdn" {
  value       = var.enable ? local.fqdn : null
  description = "CRL Janitor fully qualified domain name"
}

#
# CloudSQL PostgreSQL Outputs
#
output "cloudsql_public_ip" {
  value       = var.enable ? module.cloudsql.public_ip : null
  description = "CRL Janitor CloudSQL instance IP"
}
output "cloudsql_instance_name" {
  value       = var.enable ? module.cloudsql.instance_name : null
  description = "CRL Janitor CloudSQL instance name"
}
output "cloudsql_root_user_password" {
  value       = var.enable ? module.cloudsql.root_user_password : null
  description = "CRL Janitor database root password"
  sensitive   = true
}
output "cloudsql_app_db_creds" {
  # Avoiding error on destroy with below condition
  value       = var.enable ? (length(module.cloudsql.app_db_creds) == 0 ? {} : module.cloudsql.app_db_creds[local.service]) : null
  description = "CRL Janitor database user credentials"
  sensitive   = true
}
output "cloudsql_app_stairway_db_creds" {
  # Avoiding error on destroy with below condition
  value       = var.enable ? (length(module.cloudsql.app_db_creds) == 0 ? {} : module.cloudsql.app_db_creds["${local.service}-stairway"]) : null
  description = "CRL Janitor Stairway database user credentials"
  sensitive   = true
}

#
# Pub/sub Outputs
#
output "pubsub_topic" {
  value       = var.enable ? google_pubsub_topic.crl-janitor-pubsub-topic[0].name : null
  description = "CRL Janitor Pub/sub topic"
}
output "pubsub_subscription" {
  value       = var.enable ? google_pubsub_subscription.crl-janitor-pubsub-subscription[0].name : null
  description = "CRL Janitor Pub/sub subscription name"
}

