variable "etcd_tls_enabled" {
  description = "Indicates whether TLS is used for etcd"
  type        = string
  default     = "1"
}

variable "cluster_name" {
  description = "The name of the cluster"
  type        = string
}

variable "base_domain" {
  description = "The base domain used in records"
  type        = string
}

variable "master_count" {
  description = "The number of masters"
  type        = string
}

variable "worker_count" {
  description = "The number of workers"
  type        = string
}

variable "etcd_count" {
  description = "The number of etcd nodes"
  type        = string
}

variable "etcd_ips" {
  description = "List of string IPs for etcd nodes"
  type        = list(string)
}

variable "master_ips" {
  description = "List of string IPs for masters"
  type        = list(string)
}

variable "worker_ips" {
  description = "List of string IPs for workers"
  type        = list(string)
}

variable "api_ips" {
  description = "List of string IPs for k8s API"
  type        = list(string)
}

variable "tectonic_experimental" {
  default = false
  description = <<EOF
If set to true, experimental Tectonic assets are being deployed.
EOF
}

variable "tectonic_vanilla_k8s" {
  default = false
  description = <<EOF
If set to true, a vanilla Kubernetes cluster will be deployed, omitting any Tectonic assets.
EOF
}

data "aws_route53_zone" "tectonic" {
  name = var.base_domain
}

resource "aws_route53_record" "etcd_srv_discover" {
  count   = var.tectonic_experimental ? 0 : 1
  name    = var.etcd_tls_enabled == "1" ? "_etcd-server-ssl._tcp" : "_etcd-server._tcp"
  type    = "SRV"
  zone_id = data.aws_route53_zone.tectonic.zone_id
  records = formatlist("0 0 2380 %s", aws_route53_record.etcd_a_nodes[*].fqdn)
  ttl     = 300
}

resource "aws_route53_record" "etcd_srv_client" {
  count   = var.tectonic_experimental ? 0 : 1
  name    = var.etcd_tls_enabled == "1" ? "_etcd-client-ssl._tcp" : "_etcd-client._tcp"
  type    = "SRV"
  zone_id = data.aws_route53_zone.tectonic.zone_id
  records = formatlist("0 0 2379 %s", aws_route53_record.etcd_a_nodes[*].fqdn)
  ttl     = 60
}

resource "aws_route53_record" "etcd_a_nodes" {
  count   = var.tectonic_experimental ? 0 : tonumber(var.etcd_count)
  type    = "A"
  ttl     = 60
  zone_id = data.aws_route53_zone.tectonic.zone_id
  name    = "${var.cluster_name}-etcd-${count.index}"
  records = [var.etcd_ips[count.index]]
}

resource "aws_route53_record" "master_nodes" {
  count   = tonumber(var.master_count)
  zone_id = data.aws_route53_zone.tectonic.zone_id
  name    = "${var.cluster_name}-master-${count.index}"
  type    = "A"
  ttl     = 60
  records = [var.master_ips[count.index]]
}

resource "aws_route53_record" "worker_nodes" {
  count   = tonumber(var.worker_count)
  zone_id = data.aws_route53_zone.tectonic.zone_id
  name    = "${var.cluster_name}-worker-${count.index}"
  type    = "A"
  ttl     = 60
  records = [var.worker_ips[count.index]]
}

resource "aws_route53_record" "tectonic_api" {
  count   = 1
  zone_id = data.aws_route53_zone.tectonic.zone_id
  name    = "${var.cluster_name}-k8s"
  type    = "A"
  ttl     = 60
  records = var.api_ips
}

resource "aws_route53_record" "tectonic_console" {
  count   = var.tectonic_vanilla_k8s ? 0 : 1
  zone_id = data.aws_route53_zone.tectonic.zone_id
  name    = var.cluster_name
  type    = "A"
  ttl     = 60
  records = var.worker_ips
}

output "etcd_a_nodes" {
  value = aws_route53_record.etcd_a_nodes[*].fqdn
}

output "worker_nodes" {
  value = aws_route53_record.worker_nodes[*].fqdn
}

output "master_nodes" {
  value = aws_route53_record.master_nodes[*].fqdn
}

