variable "env_region" {}

# Configure additional resources and settings as necessary

# Providers Configuration
provider "google" {
  project = var.gcp_project_id
  region  = var.gcp_region
  zone    = var.gcp_zone
}

provider "google-beta" {
  project = var.gcp_project_id
  region  = var.gcp_region
  zone    = var.gcp_zone
}

# Google Compute Network
resource "google_compute_network" "dev_network" {
  name                    = "dev-network"
  description             = "Developer network"
  auto_create_subnetworks = false
}

# Google Compute Subnetwork
resource "google_compute_subnetwork" "dev_subnet" {
  name          = "dev-subnetwork"
  ip_cidr_range = "10.128.0.0/16"
  region        = "us-central1"
  network       = google_compute_network.dev_network.id
}

# Firewall Rules Configuration
resource "google_compute_firewall" "serverless_to_vpc_connector" {
  name       = "serverless-to-vpc-connector"
  network    = google_compute_network.dev_network.self_link
  source_ranges = ["107.178.230.64/26", "35.199.224.0/19"]
  direction  = "INGRESS"

  allow {
    protocol = "icmp"
  }
  allow {
    protocol = "tcp"
    ports    = ["667"]
  }
  allow {
    protocol = "udp"
    ports    = ["665-666"]
  }
  target_tags = ["vpc-connector"]
}

# VPC Access API Service
resource "google_project_service" "vpcaccess_api" {
  project = var.gcp_project_id
  service = "vpcaccess.googleapis.com"

  timeouts {
    create = "30m"
    update = "40m"
  }
}

# VPC Access Connector
resource "google_vpc_access_connector" "connector" {
  provider      = google-beta
  name          = "ideconn"
  region        = var.gcp_region
  network       = google_compute_network.dev_network.name
  ip_cidr_range = "10.8.0.0/28"
  machine_type  = var.vpcConnectorMachineType

  depends_on = [google_project_service.vpcaccess_api]
}

# Google Cloud Run API Service
resource "google_project_service" "run_api" {
  project = var.gcp_project_id
  service = "run.googleapis.com"

  timeouts {
    create = "30m"
    update = "40m"
  }
}

# Cloud Run Service for IDE
resource "google_cloud_run_service" "ide" {
  name     = "ide-service"
  location = var.gcp_region

  template {
    spec {
      containers {
        image = var.gcrImageIde
      }
      container_concurrency = 2
    }
    metadata {
      annotations = {
        "autoscaling.knative.dev/maxScale" = "3"
        "autoscaling.knative.dev/minScale" = "1"
        "run.googleapis.com/vpc-access-egress" = "all"
        "run.googleapis.com/vpc-access-connector" = google_vpc_access_connector.connector.name
      }
    }
  }

  traffic {
    percent         = 100
    latest_revision = true
  }

  depends_on = [google_project_service.run_api]
}

# Google Compute Instance for General Purpose
resource "google_compute_instance" "default" {
  name         = var.gceInstanceName
  machine_type = var.gceMachineType
  zone         = var.gceInstanceZone

  boot_disk {
    initialize_params {
      image = data.google_compute_image.image_family.self_link
    }
  }

  network_interface {
    subnetwork      = google_compute_subnetwork.dev_subnet.name
    access_config {}
  }

  metadata_startup_script = var.gce_startup_script

  depends_on = [google_vpc_access_connector.connector]
}

# Compute Image Data Source
data "google_compute_image" "image_family" {
  family  = var.gceMachineImage
  project = "qwiklabs-resources"
}

# Output Definitions
output "ideEditorService" {
  value       = google_cloud_run_service.ide.status[0].url
  description = "URL of the IDE service"
}

output "ideInstanceName" {
  value       = var.gceInstanceName
  description = "Name of the GCE instance"
}

