  ${google_compute_instance.gcp-vm.network_interface[0].access_config[0].nat_ip}
EOF

}

output "gcp_instance_internal_ip" {
  value = google_compute_instance.gcp-vm.network_interface[0].network_ip
}

provider "google" {
  alias = "target"
}

provider "google" {
  alias = "dns"
}

provider "google-beta" {
  alias = "target"
}


#
# General Vars
#
variable "dependencies" {
  # See: https://github.com/hashicorp/terraform/issues/21418#issuecomment-495818852
  type        = any
  default     = []
  description = "Work-around for Terraform 0.12's lack of support for 'depends_on' in custom modules."
}
variable "enable" {
  type        = bool
  description = "Enable flag for this module. If set to false, no resources will be created."
  default     = true
}
variable "google_project" {
  type        = string
  description = "The google project in which to create resources"
}
variable "cluster" {
  type        = string
  description = "Terra GKE cluster suffix, whatever is after terra-"
}
variable "cluster_short" {
  type        = string
  description = "Optional short cluster name"
  default     = ""
}
variable "owner" {
  type        = string
  description = "Environment or developer. Defaults to TF workspace name if left blank."
  default     = ""
}
locals {
  owner   = var.owner == "" ? terraform.workspace : var.owner
  service = "workspace"
}

#
# Environment types:
#   default: Standard persistent environments that contain a 'prod-like' set of infrastructure
#   preview: Short-lived, ephemeral environments with various shortcuts and resource sharing to make them lightweight & quick to spin up/down
#   preview_shared: A deployment with all of the infrastructure that is shared between the preview environments
variable "env_type" {
  type        = string
  description = "Environment type. Valid values are 'preview', 'preview_shared', and 'default'"
  default     = "default"
}

#
# Service Vars
#
// workspace_project_folder_ids will replace the workspace_project_folder_id above. Key difference is that these folders are not created by WSM.
variable "workspace_project_folder_ids" {
  type        = list(string)
  description = "List of folder ids WSM will need to be able to access. Folders are created outside of WSM."
  default     = []
}
# This is mostly helpful for testing deployments. Eventually, we want users to bring their billing accounts to WM dynamically.
variable "billing_account_ids" {
  type        = list(string)
  description = "List of Google billing account ids to allow WSM to use for billing workspace google projects."
  default     = []
}

#
# DNS Vars
#
variable "dns_zone_name" {
  type        = string
  description = "DNS zone name"
  default     = "dsp-envs"
}
variable "use_subdomain" {
  type        = bool
  description = "Whether to use a subdomain between the zone and hostname"
  default     = true
}
variable "subdomain_name" {
  type        = string
  description = "Domain namespacing between zone and hostname"
  default     = ""
}
variable "hostname" {
  type        = string
  description = "Service hostname"
  default     = ""
}
locals {
  hostname       = var.hostname == "" ? local.service : var.hostname
  cluster_name   = var.cluster_short == "" ? var.cluster : var.cluster_short
  subdomain_name = var.use_subdomain ? (var.subdomain_name == "" ? ".${local.owner}.${local.cluster_name}" : var.subdomain_name) : ""
}


#
# Postgres CloudSQL DB Vars
#
locals {
  cloudsql_pg13_defaults = {
    enable           = true,                        # Whether to create this CloudSQL instance
    version          = "POSTGRES_13",               # Version for CloudSQL instance
    keepers          = true,                        # Whether to use keepers to re-generate instance name
    tier             = "db-custom-4-8192",          # The default tier (DB instance size) for the CloudSQL instance
    db_name          = local.service,               # Name of app DB
    db_user          = local.service,               # Name of app DB user
    stairway_db_name = "${local.service}-stairway", # Name of stairway DB
    stairway_db_user = "${local.service}-stairway", # Name of stairway DB user
    policy_db_name   = "${local.service}-policy",   # Name of policy DB
    policy_db_user   = "${local.service}-policy",   # Name of policy DB user
    landingzone_db_name = "${local.service}-landingzone", #Name of Azure LandingZone DB
    landingzone_db_user = "${local.service}-landingzone", #Name of Azure LandingZone DB user
    landingzone_stairway_db_name = "${local.service}-landingzone-stairway", #Name of Azure LandingZone Stairway DB
    landingzone_stairway_db_user = "${local.service}-landingzone-stairway"  #Name of Azure LandingZone Stairway DB user
  }
}

variable "cloudsql_pg13_settings" {
  type        = map(any)
  default     = {}
  description = "Settings for Postgres 13 CloudSQL instance"
}

locals {
  cloudsql_pg13_settings = merge(local.cloudsql_pg13_defaults, var.cloudsql_pg13_settings)
}


/**
 * # Terra Workspace Manager module
 * 
 * This module creates the service account and CloudSQL databases necessary for 
 * running the [Workspace Manager](http://github.com/databiosphere/terra-workspace-manager).
 * This currently requires two postgres databases: one for the workspace manager 
 * itself, and one for the Stairway library used for managing sagas.
 * 
 * For more information, check out the [MC-Terra deployment doc](https://docs.dsp-devops.broadinstitute.org/mc-terra/mcterra-deployment)
 * and our [Terraform best practices](https://docs.dsp-devops.broadinstitute.org/best-practices-guides/terraform).
 *
 * This documentation is generated with [terraform-docs](https://github.com/segmentio/terraform-docs)
 * `terraform-docs markdown --no-sort . > README.md`
 */


# The service account for the cloudsql proxy.
resource "google_service_account" "sqlproxy" {
  count = var.enable && contains(["default"], var.env_type) ? 1 : 0

  provider     = google.target
  project      = var.google_project
  account_id   = "${local.service}-${local.owner}-sqlproxy"
  display_name = "${local.service}-${local.owner}-sqlproxy"
}
resource "google_project_iam_member" "sqlproxy" {
  count = var.enable && contains(["default"], var.env_type) ? 1 : 0

  provider = google.target
  project  = var.google_project
  role     = "roles/cloudsql.client"
  member   = "serviceAccount:${google_service_account.sqlproxy[0].email}"
}

locals {
  app_sa_roles = [
    "roles/cloudprofiler.agent", # Profiling
    "roles/cloudtrace.agent",    # Tracing for monitoring
    "roles/monitoring.editor",   # Exporting metrics
    "roles/pubsub.editor",       # Creating, publishing & subscribing pub/sub topics for multi-instance Stairway.
  ]

  # For permissions from normally-admin roles that WSM needs for specific functionality
  app_sa_custom_role_permissions = [
    # For GCS Bucket Clone operations (replaces Storage Transfer Admin)
    #   As of 1/18/22, "this functionality is only used by Verily services, not Terra UI (yet)",
    #   so it isn't currently used everywhere, but "at some point we expect this will be used in 
    #   all environments"
    #   https://broadinstitute.slack.com/archives/C02LMB1PQ6R/p1642541948003200
    "storagetransfer.jobs.create",
    "storagetransfer.jobs.delete",
    "storagetransfer.jobs.get",
    "storagetransfer.operations.get",
    "storagetransfer.projects.getServiceAccount"
  ]

  # Roles used to manage created workspace projects.
  app_folder_roles = [
    "roles/owner",
  ]

  folder_ids_and_roles = [
    for pair in setproduct(local.app_folder_roles, var.workspace_project_folder_ids) : {
      folder_role = pair[0]
      folder_id   = pair[1]
  }]
}

resource "google_project_iam_custom_role" "app_sa_custom_role" {
  count = var.enable && contains(["default", "preview_shared"], var.env_type) ? 1 : 0

  provider    = google.target
  project     = var.google_project
  role_id     = "${local.service}${title(local.owner)}CustomRole"
  title       = "${local.service}-${local.owner} Custom Role"
  description = "Custom role for ${local.service} ${local.owner}, managed by DevOps Atlantis `terra-env`"
  permissions = local.app_sa_custom_role_permissions
}

resource "google_service_account" "app" {
  count = var.enable && contains(["default", "preview_shared"], var.env_type) ? 1 : 0

  provider     = google.target
  project      = var.google_project
  account_id   = "${local.service}-${local.owner}"
  display_name = "${local.service}-${local.owner}"
}

resource "google_project_iam_member" "app" {
  count    = var.enable && contains(["default", "preview_shared"], var.env_type) ? length(local.app_sa_roles) : 0
  provider = google.target
  project  = var.google_project
  role     = local.app_sa_roles[count.index]
  member   = "serviceAccount:${google_service_account.app[0].email}"
}

resource "google_project_iam_member" "app_custom_role_membership" {
  count    = var.enable && contains(["default", "preview_shared"], var.env_type) ? 1 : 0
  provider = google.target
  project  = var.google_project
  role     = google_project_iam_custom_role.app_sa_custom_role[0].id
  member   = "serviceAccount:${google_service_account.app[0].email}"
}

# Grant WorkspaceManager Service App Service Account permission to modify resource in folder.
resource "google_folder_iam_member" "app_folder_roles" {
  count = var.enable ? length(local.folder_ids_and_roles) : 0

  provider = google.target
  folder   = local.folder_ids_and_roles[count.index].folder_id
  role     = local.folder_ids_and_roles[count.index].folder_role
  member   = "serviceAccount:${google_service_account.app[0].email}"
}
resource "google_billing_account_iam_member" "app" {
  count              = var.enable && contains(["default", "preview_shared"], var.env_type) ? length(var.billing_account_ids) : 0
  billing_account_id = var.billing_account_ids[count.index]
  role               = "roles/billing.user"
  member             = "serviceAccount:${google_service_account.app[0].email}"
}


module "enable-services" {
  source      = "github.com/broadinstitute/terraform-shared.git//terraform-modules/api-services?ref=services-0.3.0-tf-0.12"
  enable_flag = var.enable && contains(["default", "preview_shared"], var.env_type)
  providers = {
    google.target = google.target
  }
  project = var.google_project
  services = [
    "cloudbilling.googleapis.com",
    "cloudresourcemanager.googleapis.com",
    "cloudtrace.googleapis.com",
    "logging.googleapis.com",
    "monitoring.googleapis.com",
    "storage-api.googleapis.com",
    "storage-component.googleapis.com",
    "storagetransfer.googleapis.com"
  ]
}


# Postgres 13 CloudSQL instance
module "cloudsql-pg13" {
  source = "github.com/broadinstitute/terraform-shared.git//terraform-modules/cloudsql-postgres?ref=cloudsql-postgres-2.0.0"

  enable = var.enable && contains(["default"], var.env_type) && local.cloudsql_pg13_settings.enable

  providers = {
    google.target = google.target
  }
  project          = var.google_project
  cloudsql_name    = "${local.service}-db-${local.owner}"
  cloudsql_version = local.cloudsql_pg13_settings.version
  cloudsql_keepers = local.cloudsql_pg13_settings.keepers
  cloudsql_instance_labels = {
    "env" = local.owner
    "app" = local.service
  }
  cloudsql_tier = local.cloudsql_pg13_settings.tier

  cloudsql_retained_backups = 28

  cloudsql_insights_config = {
    query_insights_enabled  = false,
    record_application_tags = true,
    record_client_address   = true
  }

  cloudsql_database_flags = {
    "log_checkpoints"            = "on",
    "log_connections"            = "on",
    "log_disconnections"         = "on",
    "log_lock_waits"             = "on",
    "log_min_error_statement"    = "error",
    "log_temp_files"             = "0",
    "log_min_duration_statement" = "-1"
  }

  cloudsql_maintenance_window_enable = true

  app_dbs = {
    "${local.service}" = {
      db       = local.cloudsql_pg13_settings.db_name
      username = local.cloudsql_pg13_settings.db_user
    }
    "${local.service}-stairway" = {
      db       = local.cloudsql_pg13_settings.stairway_db_name
      username = local.cloudsql_pg13_settings.stairway_db_user
    }
    "${local.service}-policy" = {
      db       = local.cloudsql_pg13_settings.policy_db_name
      username = local.cloudsql_pg13_settings.policy_db_user
    }
    "${local.service}-landingzone" = {
      db       = local.cloudsql_pg13_settings.landingzone_db_name
      username = local.cloudsql_pg13_settings.landingzone_db_user
    }
    "${local.service}-landingzone-stairway" = {
      db       = local.cloudsql_pg13_settings.landingzone_stairway_db_name
      username = local.cloudsql_pg13_settings.landingzone_stairway_db_user 
    }
  }

  dependencies = [var.dependencies]
}


data "google_dns_managed_zone" "dns_zone" {
  count = var.enable && contains(["default", "preview"], var.env_type) ? 1 : 0

  provider = google.dns
  name     = var.dns_zone_name
}

locals {
  fqdn = var.enable && contains(["default", "preview"], var.env_type) ? "${local.hostname}${local.subdomain_name}.${data.google_dns_managed_zone.dns_zone[0].dns_name}" : null
}

resource "google_dns_record_set" "ingress" {
  count = var.enable && contains(["default", "preview"], var.env_type) ? 1 : 0

  provider     = google.dns
  managed_zone = data.google_dns_managed_zone.dns_zone[0].name
  name         = local.fqdn
  type         = "A"
  ttl          = "300"
  rrdatas      = [google_compute_global_address.ingress_ip[0].address]
}


resource "google_compute_global_address" "ingress_ip" {
  count = var.enable && contains(["default", "preview"], var.env_type) ? 1 : 0

  provider = google.target

  name = "terra-${var.cluster}-${local.owner}-${local.service}-ip"
}


#
# Service Account Outputs
#
output "sqlproxy_sa_id" {
  value       = length(google_service_account.sqlproxy) > 0 ? google_service_account.sqlproxy[0].account_id : null
  description = "Workspace Manager Cloud SQL Proxy Google service account ID"
}
output "app_sa_id" {
  value       = length(google_service_account.app) > 0 ? google_service_account.app[0].account_id : null
  description = "Workspace Manager App Google service account ID"
}

#
# IP/DNS Outputs
#
output "ingress_ip" {
  value       = var.enable && contains(["default", "preview"], var.env_type) ? google_compute_global_address.ingress_ip[0].address : null
  description = "Workspace Manager ingress IP"
}
output "ingress_ip_name" {
  value       = var.enable && contains(["default", "preview"], var.env_type) ? google_compute_global_address.ingress_ip[0].name : null
  description = "Sam ingress IP name"
}
output "fqdn" {
  value       = var.enable && contains(["default", "preview"], var.env_type) ? local.fqdn : null
  description = "Workspace Manager fully qualified domain name"
}

#
# CloudSQL Outputs
#
output "cloudsql_pg13_outputs" {
  description = "Workspace Manager CloudSQL outputs (pg13 instance)"
  value = {
    # pg13 CloudSQL instance IP
    public_ip = var.enable && contains(["default"], var.env_type) && local.cloudsql_pg13_settings.enable ? module.cloudsql-pg13.public_ip : null,
    # pg13 CloudSQL instance name
    instance_name = var.enable && contains(["default"], var.env_type) && local.cloudsql_pg13_settings.enable ? module.cloudsql-pg13.instance_name : null
    # pg13 database root password
    root_user_password = var.enable && contains(["default"], var.env_type) && local.cloudsql_pg13_settings.enable ? module.cloudsql-pg13.root_user_password : null
    # pg13 app db creds
    app_db_creds = var.enable && contains(["default"], var.env_type) && local.cloudsql_pg13_settings.enable ? (length(module.cloudsql-pg13.app_db_creds) == 0 ? {} : module.cloudsql-pg13.app_db_creds[local.service]) : null
    # pg13 stairway db creds
    stairway_db_creds = var.enable && contains(["default"], var.env_type) && local.cloudsql_pg13_settings.enable ? (length(module.cloudsql-pg13.app_db_creds) == 0 ? {} : module.cloudsql-pg13.app_db_creds["${local.service}-stairway"]) : null
    # pg13 policy db creds
    policy_db_creds = var.enable && contains(["default"], var.env_type) && local.cloudsql_pg13_settings.enable ? (length(module.cloudsql-pg13.app_db_creds) == 0 ? {} : module.cloudsql-pg13.app_db_creds["${local.service}-policy"]) : null
    # pg13 landingzone db creds
    landingzone_db_creds = var.enable && contains(["default"], var.env_type) && local.cloudsql_pg13_settings.enable ? (length(module.cloudsql-pg13.app_db_creds) == 0 ? {} : module.cloudsql-pg13.app_db_creds["${local.service}-landingzone"]) : null
    # pg13 landingzone stairway db creds
    landingzone_stairway_db_creds = var.enable && contains(["default"], var.env_type) && local.cloudsql_pg13_settings.enable ? (length(module.cloudsql-pg13.app_db_creds) == 0 ? {} : module.cloudsql-pg13.app_db_creds["${local.service}-landingzone-stairway"]) : null
  }
  sensitive = true
}

//
// Providers & Modules
//
provider "aws" {
  alias  = "east"
  region = var.region
}

provider "aws" {
  alias  = "west"
  region = var.region_west
}

module "shared" {
  source   = "../../shared"
  key_name = var.key_name
}

//
// Variables
//
variable "atlas_token"       {}
variable "atlas_username"    {}
variable "atlas_environment" { default = "consul-cluster" }

variable "region"        { default = "us-east-1" }
variable "region_west"   { default = "us-west-2" }
variable "source_ami"    { default = "ami-9a562df2" }
variable "key_name"      { default = "atlas-example" }
variable "instance_type" { default = "t2.micro" }

variable "vpc_cidr"  { default = "172.31.0.0/16" }
variable "vpc_cidrs" { default = ["172.31.0.0/20", "172.31.16.0/20", "172.31.32.0/20"] }

variable "west_vpc_cidr"  { default = "172.17.0.0/16" }
variable "west_vpc_cidrs" { default = ["172.17.0.0/20", "172.17.16.0/20", "172.17.32.0/20"] }

variable "consul_bootstrap_expect" { default = "3" }

//
// Outputs
//
output "consul_client" {
  value = "${aws_instance.consul_client.*.private_ip} - ${aws_instance.consul_client.*.public_ip}"
}

output "consul_0" {
  value = "${aws_instance.consul_0.*.private_ip} - ${aws_instance.consul_0.*.public_ip}"
}

output "consul_1" {
  value = "${aws_instance.consul_1.*.private_ip} - ${aws_instance.consul_1.*.public_ip}"
}

output "consul_2" {
  value = "${aws_instance.consul_2.*.private_ip} - ${aws_instance.consul_2.*.public_ip}"
}

output "west_consul_client" {
  value = "${aws_instance.west_consul_client.*.private_ip} - ${aws_instance.west_consul_client.*.public_ip}"
}

output "west_consul_0" {
  value = "${aws_instance.west_consul_0.*.private_ip} - ${aws_instance.west_consul_0.*.public_ip}"
}

output "west_consul_1" {
  value = "${aws_instance.west_consul_1.*.private_ip} - ${aws_instance.west_consul_1.*.public_ip}"
}

output "west_consul_2" {
  value = "${aws_instance.west_consul_2.*.private_ip} - ${aws_instance.west_consul_2.*.public_ip}"
}


resource "atlas_artifact" "consul_client" {
  name = "${var.atlas_username}/consul_client"
  type = "amazon.image"
}

resource "atlas_artifact" "consul_multiregion" {
  name = "${var.atlas_username}/consul_multiregion"
  type = "amazon.image"
}


resource "aws_key_pair" "east_main" {
  provider   = aws.east
  key_name   = var.key_name
  public_key = file(module.shared.public_key_path)
}


resource "aws_key_pair" "west_main" {
  provider   = aws.west
  key_name   = var.key_name
  public_key = file(module.shared.public_key_path)
}


resource "aws_vpc" "main" {
  provider             = aws.east
  cidr_block           = var.vpc_cidr
  enable_dns_hostnames = true
}

resource "aws_internet_gateway" "main" {
  provider = aws.east
  vpc_id   = aws_vpc.main.id
}

resource "aws_route_table" "main" {
  provider = aws.east
  vpc_id   = aws_vpc.main.id
  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.main.id
  }
}

resource "aws_main_route_table_association" "main" {
  provider       = aws.east
  vpc_id         = aws_vpc.main.id
  route_table_id = aws_route_table.main.id
}

resource "aws_subnet" "subnet_a" {
  provider                = aws.east
  vpc_id                  = aws_vpc.main.id
  cidr_block              = var.vpc_cidrs[0]
  map_public_ip_on_launch = true
}

resource "aws_subnet" "subnet_b" {
  provider                = aws.east
  vpc_id                  = aws_vpc.main.id
  cidr_block              = var.vpc_cidrs[1]
  map_public_ip_on_launch = true
}

resource "aws_subnet" "subnet_c" {
  provider                = aws.east
  vpc_id                  = aws_vpc.main.id
  cidr_block              = var.vpc_cidrs[2]
  map_public_ip_on_launch = true
}

resource "aws_security_group" "consul" {
  provider = aws.east
  vpc_id   = aws_vpc.main.id
  ingress {
    from_port   = 8300
    to_port     = 8300
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }
  ingress {
    from_port   = 8301
    to_port     = 8302
    protocol    = "udp"
    cidr_blocks = ["0.0.0.0/0"]
  }
  ingress {
    from_port   = 8400
    to_port     = 8400
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }
  ingress {
    from_port   = 8500
    to_port     = 8500
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }
  ingress {
    from_port   = 8600
    to_port     = 8600
    protocol    = "udp"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

resource "aws_security_group_rule" "consul_client" {
  provider              = aws.east
  security_group_id     = aws_security_group.consul.id
  type                  = "ingress"
  from_port             = 22
  to_port               = 22
  protocol              = "tcp"
  cidr_blocks           = ["0.0.0.0/0"]
  description           = "Allow SSH from anywhere"
}

resource "aws_instance" "consul_client" {
  provider             = aws.east
  ami                  = var.source_ami
  instance_type        = var.instance_type
  key_name             = aws_key_pair.east_main.key_name
  subnet_id            = aws_subnet.subnet_a.id
  security_group_ids   = [aws_security_group.consul.id]
  associate_public_ip  = true
  iam_instance_profile = "${module.shared.iam_profile_name}-consul_client"
}

resource "aws_instance" "consul_0" {
  provider             = aws.east
  ami                  = var.source_ami
  instance_type        = var.instance_type
  key_name             = aws_key_pair.east_main.key_name
  subnet_id            = aws_subnet.subnet_b.id
  security_group_ids   = [aws_security_group.consul.id]
  associate_public_ip  = true
  iam_instance_profile = "${module.shared.iam_profile_name}-consul_server"
}

