# Define input variables
variable "number_of_ec2" {
  description = "Number of EC2 instances to create"
  type        = number
}

# EC2 INSTANCE
resource "aws_instance" "ec2" {
  count = var.number_of_ec2

  ami           = var.ec2_image_id
  instance_type = var.ec2_type
  key_name      = var.ec2_key_name

  associate_public_ip_address = false

  private_ip = cidrhost(element(var.ec2_subnet_cidrs, (count.index % length(var.az))), (var.ec2_hostnum_start + ((count.index / length(var.az)))))

  subnet_id  = element(var.ec2_subnet_ids, count.index)

  vpc_security_group_ids = [var.ec2_security_group]

  root_block_device {
    volume_size           = var.vol_root_size
    volume_type           = var.vol_root_type
    delete_on_termination = false
  }

  tags = {
    Name             = format("%s.aws-%s.%s-%02d%s", var.customer, var.region, var.service, (count.index / length(var.az)) + 1, substr(element(var.az, (count.index % length(var.az))), -1))
    Project          = var.project
    Environment      = var.environment
    ManagementTool   = "Terraform"
    ManagementModule = "oxa-ec2-multiaz"
    autoOff          = var.autooff
  }
}

# EBS VOLUME
resource "aws_ebs_volume" "ebs" {
  count = var.number_of_ec2

  availability_zone = element(aws_instance.ec2.*.availability_zone, count.index)
  size              = var.vol_space_size
  type              = var.vol_space_type

  tags = {
    Name             = format("%s.aws-%s.ebs.%s-%02d%s", var.customer, var.region, var.service, (count.index / length(var.az)) + 1, substr(element(var.az, (count.index % length(var.az))), -1))
    Project          = var.project
    Environment      = var.environment
    ManagementModule = "oxa-ec2-multiaz"
    ManagementTool   = "Terraform"
  }
}

# VOLUME ATTACHMENT
resource "aws_volume_attachment" "volume_attachment" {
  count = var.number_of_ec2

  device_name = "/dev/xvdb"

  volume_id   = element(aws_ebs_volume.ebs.*.id, count.index)
  instance_id = element(aws_instance.ec2.*.id, count.index)
}

resource "aws_cloudwatch_metric_alarm" "ec2_instance_cpuutilization" {
  count               = var.number_of_ec2
  alarm_name          = format("alarmCPUUtilization_%s_Ec2Instance_%s_%02d", var.environment, var.service, count.index + 1)
  alarm_description   = "EC2 instance CPU utilization"
  comparison_operator = "GreaterThanThreshold"
  evaluation_periods  = 1
  metric_name         = "CPUUtilization"
  namespace           = "AWS/EC2"
  period              = 300
  statistic           = "Average"
  threshold           = var.alarm_cpu_threshold

  dimensions = {
    InstanceId = aws_instance.ec2.*.id[count.index]
  }

  alarm_actions = var.alarm_actions
}

output "ec2_instance_ids" {
  value = aws_instance.ec2.*.id
}

output "ec2_instance_names" {
  value = aws_instance.ec2.*.tags.Name
}

output "ec2_private_ips" {
  value = aws_instance.ec2.*.private_ip
}

output "ec2_instance_azs" {
  value = aws_instance.ec2.*.availability_zone
}

output "ec2_subnet_ids" {
  value = aws_instance.ec2.*.subnet_id
}

output "ec2_adm_records" {
  value = sort([
    for instance in aws_instance.ec2 : format("%v    6000    IN    A    %v", instance.tags.Name, instance.private_ip)
  ])
}

variable "environment" {}
variable "aws_region" {}
variable "aws_account_id" {}
variable "aws_codedeploy_basename" {}
variable "aws_codedeploy_appname" {}

// IAM role for CodeDeploy EC2 instances
resource "aws_iam_role" "codedeploy_ec2_role" {
  name               = "${var.aws_codedeploy_basename}-codedeploy-ec2-role"
  assume_role_policy = jsonencode({
    "Version" : "2012-10-17",
    "Statement" : [
      {
        "Sid"       : "",
        "Effect"    : "Allow",
        "Principal" : { "Service" : ["ec2.amazonaws.com"] },
        "Action"    : "sts:AssumeRole"
      },
      {
        "Sid"       : "",
        "Effect"    : "Allow",
        "Principal" : { "Service" : ["codedeploy.us-east-1.amazonaws.com", "codedeploy.us-west-2.amazonaws.com", "codedeploy.eu-west-1.amazonaws.com", "codedeploy.ap-southeast-2.amazonaws.com"] },
        "Action"    : "sts:AssumeRole"
      }
    ]
  })
}

// IAM role policy for CodeDeploy EC2 instances
resource "aws_iam_role_policy" "codedeploy_ec2_role_policy" {
  name = "policy_${var.aws_codedeploy_basename}-codedeploy-ec2-role"
  role = aws_iam_role.codedeploy_ec2_role.id

  policy = jsonencode({
    "Version" : "2012-10-17",
    "Statement" : [
      {
        "Effect"   : "Allow",
        "Action"   : ["s3:Get*", "s3:List*"],
        "Resource" : [
          "arn:aws:s3:::${var.aws_codedeploy_basename}-codedeploy/*",
          "arn:aws:s3:::aws-codedeploy-us-east-1/*",
          "arn:aws:s3:::aws-codedeploy-us-west-2/*",
          "arn:aws:s3:::aws-codedeploy-eu-west-1/*",
          "arn:aws:s3:::aws-codedeploy-ap-southeast-2/*"
        ]
      },
      {
        "Effect"   : "Allow",
        "Action"   : [
          "autoscaling:PutLifecycleHook",
          "autoscaling:DeleteLifecycleHook",
          "autoscaling:RecordLifecycleActionHeartbeat",
          "autoscaling:CompleteLifecycleAction",
          "autoscaling:Describe*",
          "autoscaling:PutInstanceInStandby",
          "autoscaling:PutInstanceInService",
          "autoscaling:EnterStandby",
          "autoscaling:ExitStandby",
          "autoscaling:UpdateAutoScalingGroup",
          "elasticloadbalancing:Describe*",
          "elasticloadbalancing:DeregisterInstancesFromLoadBalancer",
          "elasticloadbalancing:RegisterInstancesWithLoadBalancer",
          "ec2:Describe*"
        ],
        "Resource" : "*"
      }
    ]
  })
}

// IAM instance profile for CodeDeploy EC2 instances
resource "aws_iam_instance_profile" "codedeploy_ec2_profile" {
  name  = "${var.aws_codedeploy_basename}-codedeploy-ec2-profile"
  roles = [aws_iam_role.codedeploy_ec2_role.name]
}

// S3 bucket for CodeDeploy revisions
resource "aws_s3_bucket" "aws_s3_codedeploy" {
  bucket = "${var.aws_codedeploy_basename}-codedeploy"
  acl    = "private"

  tags = {
    Name        = "${var.aws_codedeploy_basename}-codedeploy"
    Environment = var.environment
  }
}

// IAM user for CodeDeploy S3 access
resource "aws_iam_user" "aws_iam_user_codedeploy" {
  name = "${var.aws_codedeploy_basename}-S3UserForCodeDeploy"
}

resource "aws_iam_access_key" "aws_iam_user_codedeploy" {
  user = aws_iam_user.aws_iam_user_codedeploy.name
}

resource "aws_iam_user_policy" "aws_iam_user_codedeploy_policy" {
  name   = "policy_s3_${var.aws_codedeploy_basename}-codedeploy"
  user   = aws_iam_user.aws_iam_user_codedeploy.name
  policy = jsonencode({
    "Version" : "2012-10-17",
    "Statement" : [
      {
        "Effect"   : "Allow",
        "Action"   : ["s3:PutObject"],
        "Resource" : ["arn:aws:s3:::${var.aws_codedeploy_basename}-codedeploy/*"]
      },
      {
        "Effect"   : "Allow",
        "Action"   : ["codedeploy:RegisterApplicationRevision", "codedeploy:GetApplicationRevision"],
        "Resource" : "arn:aws:codedeploy:${var.aws_region}:${var.aws_account_id}:application:${var.aws_codedeploy_appname}"
      },
      {
        "Effect"   : "Allow",
        "Action"   : ["codedeploy:CreateDeployment", "codedeploy:GetDeployment"],
        "Resource" : "arn:aws:codedeploy:${var.aws_region}:${var.aws_account_id}:deploymentgroup:${var.aws_codedeploy_appname}/*"
      },
      {
        "Effect"   : "Allow",
        "Action"   : ["codedeploy:GetDeploymentConfig"],
        "Resource" : [
          "arn:aws:codedeploy:${var.aws_region}:${var.aws_account_id}:deploymentconfig:CodeDeployDefault.OneAtATime",
          "arn:aws:codedeploy:${var.aws_region}:${var.aws_account_id}:deploymentconfig:CodeDeployDefault.HalfAtATime",
          "arn:aws:codedeploy:${var.aws_region}:${var.aws_account_id}:deploymentconfig:CodeDeployDefault.AllAtOnce"
        ]
      }
    ]
  })
}

// IAM role for CodeDeploy application
resource "aws_iam_role" "codedeploy_app_role" {
  name               = "${var.aws_codedeploy_basename}-codedeploy-app-role"
  assume_role_policy = jsonencode({
    "Version" : "2012-10-17",
    "Statement" : [
      {
        "Sid"       : "",
        "Effect"    : "Allow",
        "Principal" : { "Service" : ["codedeploy.us-east-1.amazonaws.com", "codedeploy.us-west-2.amazonaws.com", "codedeploy.eu-west-1.amazonaws.com", "codedeploy.ap-southeast-2.amazonaws.com"] },
        "Action"    : "sts:AssumeRole"
      }
    ]
  })
}

// IAM role policy for CodeDeploy application
resource "aws_iam_role_policy" "codedeploy_app_role_policy" {
  name   = "policy_${var.aws_codedeploy_basename}-codedeploy-app-role"
  role   = aws_iam_role.codedeploy_app_role.id
  policy = jsonencode({
    "Version" : "2012-10-17",
    "Statement" : [
      {
        "Effect"   : "Allow",
        "Action"   : ["s3:Get*", "s3:List*"],
        "Resource" : ["arn:aws:s3:::${var.aws_codedeploy_basename}-codedeploy/*"]
      }
    ]
  })
}

