# VPC availability zone

## Set Terraform version constraint
terraform {
  required_version = "> 0.11.0"
}

## Variables
data "aws_region" "current" {}

data "aws_availability_zones" "available" {}

locals {
  azs_provisioned_count = length(var.azs_provisioned_override) > 0 && var.azs_provisioned_override[0] != "non_empty_list" ? length(var.azs_provisioned_override) : var.azs_provisioned
  azs_provisioned_override_enabled = length(var.azs_provisioned_override) > 0 && var.azs_provisioned_override[0] != "non_empty_list"
  dmz_cidrs_override_enabled = length(var.dmz_cidrs_override) > 0 && var.dmz_cidrs_override[0] != "non_empty_list"
  eips_enabled_check = var.nat_eips_enabled == "true" || var.nat_gateways_enabled == "true" ? 1 : 0
  lans_enabled_check = var.lans_per_az != "" ? 1 : 0
  lan_cidrs_override_enabled = length(var.lan_cidrs_override) > 0 && var.lan_cidrs_override[0] != "non_empty_list"
  lans_multiplier = var.lans_per_az != "" ? var.lans_per_az : 1
  lans_per_az_checked = var.lans_per_az != "" ? var.lans_per_az : 1
  nat_gateways_enabled_check = var.nat_gateways_enabled == "true" ? 1 : 0
  nat_gateways_not_enabled_check = var.nat_gateways_enabled != "true" ? 1 : 0
  default_subnet_tags = {
    application = var.stack_item_fullname
    managed_by  = "terraform"
  }
}

## Provisions DMZ resources

### Provisions subnets

data "aws_vpc" "base" {
  id = var.vpc_id
}

resource "aws_subnet" "dmz" {
  count                = local.azs_provisioned_count
  availability_zone    = local.azs_provisioned_override_enabled ? "${data.aws_region.current.name}${element(var.azs_provisioned_override, count.index)}" : element(data.aws_availability_zones.available.names, count.index)
  cidr_block           = local.dmz_cidrs_override_enabled ? element(var.dmz_cidrs_override, count.index) : cidrsubnet(data.aws_vpc.base.cidr_block, lookup(var.az_cidrsubnet_newbits, local.azs_provisioned_count), count.index)
  map_public_ip_on_launch = var.enable_dmz_public_ips
  vpc_id               = var.vpc_id
  tags                 = merge(local.default_subnet_tags, var.additional_subnet_tags, map("Name", "${var.stack_item_label}-dmz-${count.index}"))
}

### Associates subnet with routing table
resource "aws_route_table_association" "rta_dmz" {
  count          = local.azs_provisioned_count
  route_table_id = var.rt_dmz_id
  subnet_id      = aws_subnet.dmz[count.index].id
}

### Provisions NATs
data "aws_ami" "nat_ami" {
  most_recent = true
  owners      = ["amazon"]

  filter {
    name   = "architecture"
    values = ["x86_64"]
  }

  filter {
    name   = "name"
    values = ["amzn-ami-vpc-nat*"]
  }

  filter {
    name   = "root-device-type"
    values = ["ebs"]
  }

  filter {
    name   = "virtualization-type"
    values = ["hvm"]
  }
}

resource "aws_eip" "eip_nat" {
  count = local.azs_provisioned_count * local.lans_enabled_check * local.eips_enabled_check
  vpc   = true
}

resource "aws_eip_association" "eip_nat_assoc" {
  count         = local.azs_provisioned_count * local.lans_enabled_check * local.eips_enabled_check * local.nat_gateways_not_enabled_check
  allocation_id = aws_eip.eip_nat[count.index].id
  instance_id   = aws_instance.nat[count.index].id
}

resource "aws_instance" "nat" {
  count                         = local.azs_provisioned_count * local.lans_enabled_check * local.nat_gateways_not_enabled_check
  ami                           = coalesce(var.nat_ami_override, data.aws_ami.nat_ami.id)
  associate_public_ip_address   = true
  instance_type                 = var.nat_instance_type
  key_name                      = var.nat_key_name
  source_dest_check             = false
  subnet_id                     = aws_subnet.dmz[count.index].id
  vpc_security_group_ids        = [aws_security_group.sg_nat[count.index].id]

  tags {
    application = var.stack_item_fullname
    managed_by  = "terraform"
    Name        = "${var.stack_item_label}-nat-${count.index}"
  }
}

resource "aws_security_group" "sg_nat" {
  count        = local.azs_provisioned_count * local.lans_enabled_check * local.nat_gateways_not_enabled_check
  description = "${var.stack_item_fullname} NAT security group"
  name_prefix = "${var.stack_item_label}-nat-"
  vpc_id      = var.vpc_id

  egress {
    cidr_blocks = ["0.0.0.0/0"]
    description = "Egress to the Internet"
    from_port   = 0
    protocol    = "-1"
    to_port     = 0
  }

  ingress {
    cidr_blocks = [local.lan_cidrs_override_enabled ? element(var.lan_cidrs_override, count.index) : cidrsubnet(data.aws_vpc.base.cidr_block, lookup(var.az_cidrsubnet_newbits, local.azs_provisioned_count * local.lans_multiplier), count.index + lookup(var.az_cidrsubnet_offset, local.azs_provisioned_count))]
    description = "Ingress from ${var.stack_item_label}-lan-${count.index}"
    from_port   = 0
    protocol    = "-1"
    to_port     = 0
  }

  tags {
    application = var.stack_item_fullname
    managed_by  = "terraform"
    Name        = "${var.stack_item_label}-nat-${count.index}"
  }
}

resource "aws_nat_gateway" "nat" {
  count        = local.azs_provisioned_count * local.lans_enabled_check * local.nat_gateways_enabled_check
  allocation_id = aws_eip.eip_nat[count.index].id
  subnet_id     = aws_subnet.dmz[count.index].id
}

## Provisions LAN resources

### Provisions subnet
resource "aws_subnet" "lan" {
  count            = local.azs_provisioned_count * local.lans_multiplier
  availability_zone    = local.azs_provisioned_override_enabled ? "${data.aws_region.current.name}${element(var.azs_provisioned_override, count.index)}" : element(data.aws_availability_zones.available.names, count.index)
  cidr_block       = local.lan_cidrs_override_enabled ? element(var.lan_cidrs_override, count.index) : cidrsubnet(data.aws_vpc.base.cidr_block, lookup(var.az_cidrsubnet_newbits, local.azs_provisioned_count * local.lans_multiplier), count.index + lookup(var.az_cidrsubnet_offset, local.azs_provisioned_count))
  vpc_id           = var.vpc_id

  tags = merge(local.default_subnet_tags, var.additional_subnet_tags, map("Name", "${var.stack_item_label}-lan-${count.index}"))
}

### Provisions routing table
resource "aws_route_table" "rt_lan" {
  count          = local.azs_provisioned_count * local.lans_multiplier
  propagating_vgws = compact(var.vgw_ids)
  vpc_id         = var.vpc_id

  tags {
    application = var.stack_item_fullname
    managed_by  = "terraform"
    Name        = "${var.stack_item_label}-lan-${count.index}"
  }
}

### Associates subnet with routing table
resource "aws_route_table_association" "rta_lan" {
  count          = local.azs_provisioned_count * local.lans_multiplier
  route_table_id = aws_route_table.rt_lan[count.index].id
  subnet_id      = aws_subnet.lan[count.index].id
}

# Input variables

## Resource tags
variable "stack_item_fullname" {
  type        = string
  description = "Long form descriptive name for this stack item. This value is used to create the 'application' resource tag for resources created by this stack item."
  default     = "VPC Quick Start"
}

variable "stack_item_label" {
  type        = string
  description = "Short form identifier for this stack. This value is used to create the 'Name' resource tag for resources created by this stack item, and also serves as a unique key for re-use."
  default     = "qckstrt"
}

variable "additional_subnet_tags" {
  type        = map(string)
  description = "Additional tags to apply at the subnet level, if any"
  default     = {}
}

## VPC parameters
variable "az_cidrsubnet_newbits" {
  type        = map(number)
  description = "The number of bits by which to extend the CIDR range for the given number of AZs."

  default = {
    "1" = 1
    "2" = 2
    "3" = 3
    "4" = 3
    "6" = 4
    "8" = 4
  }
}

variable "az_cidrsubnet_offset" {
  type        = map(number)
  description = "The number of AZs to provision for."

  default = {
    "1" = 1
    "2" = 2
    "3" = 4
    "4" = 4
  }
}

variable "azs_provisioned" {
  type        = string
  description = "The number of availability zones to be provisioned."
  default     = "2"
}

variable "azs_provisioned_override" {
  type        = list(string)
  description = "List of availability zones to be provisioned."
  default     = ["non_empty_list"]
}

variable "dmz_cidrs_override" {
  type        = list(string)
  description = "The CIDR block(s) you want the DMZ subnet(s) to cover."
  default     = ["non_empty_list"]
}

variable "enable_dmz_public_ips" {
  type        = string
  description = "Specify true to indicate that instances launched into the DMZ subnet should be assigned a public IP address. Default is false."
  default     = ""
}

variable "lan_cidrs_override" {
  type        = list(string)
  description = "The CIDR block(s) you want the LAN subnet(s) to cover."
  default     = ["non_empty_list"]
}

variable "lans_per_az" {
  type        = string
  description = "The number of private LAN subnets to be provisioned per AZ"
  default     = "1"
}

variable "nat_ami_override" {
  type        = string
  description = "Custom NAT Amazon machine image"
  default     = ""
}

variable "nat_eips_enabled" {
  type        = string
  description = "Flag for specifying allocation of Elastic IPs to NATs for the purposes of whitelisting. This value is overriden to 'true' when utilizing NAT gateways."
  default     = "false"
}

variable "nat_gateways_enabled" {
  type        = string
  description = "Flag for specifying utilization of managed NAT gateways over EC2 based NAT instances."
  default     = "false"
}

variable "nat_instance_type" {
