module "enable-services" {
  source      = "github.com/broadinstitute/terraform-shared.git//terraform-modules/api-services?ref=services-0.3.0-tf-0.12"
  enable_flag = "1"
  providers = {
    google.target = google.target
  }
  project = var.google_project
  services = [
    "serviceusage.googleapis.com",
    "iam.googleapis.com"
  ]
}


# Docker instance(s)
module "app_server" {
  enable_flag = var.create_app_server ? "1" : "0"

  source = "github.com/broadinstitute/terraform-shared.git//terraform-modules/docker-instance-data-disk?ref=docker-instance-data-disk-0.2.3-tf-0.12"

  providers = {
    google.target = google.target
  }

  project                 = var.google_project
  instance_name           = var.service
  instance_num_hosts      = 1
  instance_size           = var.app_instance_size
  instance_image          = var.app_instance_image
  instance_data_disk_size = var.app_instance_data_disk_size
  instance_data_disk_type = var.app_instance_data_disk_type
  instance_data_disk_name = "${var.service}-data-disk"
  instance_service_account = var.create_sa ? google_service_account.app[0].email : (
    local.app_sa_default ? data.google_compute_default_service_account.app[0].email : data.google_service_account.app[0].email
  )
  instance_network_name = local.network_name
  instance_tags         = local.app_instance_tags
  instance_labels       = local.app_instance_labels

  dependencies = [
    google_compute_network.vpc_network,
    module.enable-services,
    module.mongodb
  ]
}

module "load-balancer" {
  enable_flag = var.create_lb ? 1 : 0

  source = "github.com/broadinstitute/terraform-shared.git//terraform-modules/http-load-balancer?ref=http-load-balancer-0.6.0"

  providers = {
    google.target = google.target
  }
  project            = var.google_project
  load_balancer_name = "${var.service}-${local.owner}"

  ssl_policy_name                  = local.ssl_policy_name
  load_balancer_ssl_policy_create  = var.create_lb ? 1 : 0
  load_balancer_ssl_policy_profile = "RESTRICTED"
  load_balancer_ssl_certificates   = var.create_lb ? var.lb_ssl_certs : []
  load_balancer_health_check_path  = "/single_cell"
  load_balancer_instance_groups    = var.create_lb ? element(module.app_server.instance_instance_group, 0) : ""
  load_balancer_rules              = var.lb_rules
}


resource "random_id" "mongodb_user_password" {
  byte_length = 16
}

resource "random_id" "mongodb_root_password" {
  byte_length = 16
}

module "mongodb" {
  source = "github.com/broadinstitute/terraform-shared.git//terraform-modules/mongodb?ref=mongodb-cluster-0.1.9"

  providers = {
    google.target = google.target,
    google.dns    = google.dns
  }
  project           = var.google_project
  owner             = local.owner
  service           = "${var.service}-mongo"
  mongodb_image_tag = var.mongodb_version
  mongodb_service_account = var.create_sa ? google_service_account.app[0].email : (
    local.app_sa_default ? data.google_compute_default_service_account.app[0].email : data.google_service_account.app[0].email
  )
  mongodb_roles           = var.mongodb_roles
  mongodb_app_username    = var.mongodb_user
  mongodb_app_password    = random_id.mongodb_user_password.hex
  mongodb_root_password   = random_id.mongodb_root_password.hex
  mongodb_database        = var.mongodb_database
  mongodb_extra_flags     = var.mongodb_extra_flags
  instance_size           = var.mongodb_instance_size
  instance_image          = var.mongodb_instance_image
  instance_count_offset   = var.mongodb_instance_count_offset
  instance_group_name     = var.mongodb_instance_group_name
  instance_data_disk_size = var.mongodb_instance_data_disk_size
  instance_data_disk_type = var.mongodb_instance_data_disk_type
  instance_data_disk_name = "${var.service}-mongo-data-disk"
  instance_network_name   = local.network_name
  instance_tags           = local.mongodb_instance_tags
  instance_labels         = local.mongodb_instance_labels

  dependencies = [
    google_compute_network.vpc_network,
    module.enable-services,
    module.enable-services
  ]
}


data "google_dns_managed_zone" "dns_zone" {
  provider = google.dns

  count = var.create_lb ? 1 : 0

  name = var.dns_zone_name
}

# Service DNS
resource "google_dns_record_set" "app_dns" {
  provider = google.dns

  count = var.create_lb ? 1 : 0

  managed_zone = data.google_dns_managed_zone.dns_zone[0].name
  name         = var.lb_dns_name
  type         = "A"
  ttl          = var.lb_dns_ttl
  # module.load-balancer.load_balancer_public_ip is an array
  rrdatas    = module.load-balancer.load_balancer_public_ip
  depends_on = [module.load-balancer, data.google_dns_managed_zone.dns_zone[0]]
}


resource "google_service_account" "app" {
  provider = google.target

  count = var.create_sa ? 1 : 0

  account_id   = local.app_sa_name
  display_name = local.app_sa_name
  project      = var.google_project
}
data "google_service_account" "app" {
  provider = google.target

  count = ! var.create_sa && ! local.app_sa_default ? 1 : 0

  account_id = local.app_sa_name
}
data "google_compute_default_service_account" "app" {
  provider = google.target

  count = ! var.create_sa && local.app_sa_default ? 1 : 0
}
resource "google_project_iam_member" "app" {
  provider = google.target

  count = var.create_sa ? length(var.app_sa_roles) : 0

  project = var.google_project
  role    = element(var.app_sa_roles, count.index)
  member  = "serviceAccount:${google_service_account.app[0].email}"
}

resource "google_service_account" "app_read" {
  provider = google.target

  count = var.create_sa ? 1 : 0

  account_id   = local.app_read_sa_name
  display_name = local.app_read_sa_name
  project      = var.google_project
}
data "google_service_account" "app_read" {
  provider = google.target

  count = var.create_sa ? 0 : 1

  account_id = local.app_read_sa_name
}
resource "google_project_iam_member" "app_read" {
  provider = google.target

  count = var.create_sa ? length(var.app_read_sa_roles) : 0

  project = var.google_project
  role    = element(var.app_read_sa_roles, count.index)
  member  = "serviceAccount:${google_service_account.app_read[0].email}"
}


