resource "aws_dynamodb_table" "store" {
  name           = var.table_name
  read_capacity  = var.read_capacity
  write_capacity = var.write_capacity
  hash_key       = "name"
  range_key      = "version"

  attribute {
    name = "name"
    type = "S"
  }

  attribute {
    name = "version"
    type = "S"
  }
}

variable "key_alias" {
  description = "Alias to give to your kms key"
  default     = "alias/credstash"
}

variable "table_name" {
  description = "Name to give to the dynamodb table"
  default     = "credential-store"
}

variable "read_capacity" {
  description = "Read capacity for dynamodb table"
  type        = number
  default     = 1
}

variable "write_capacity" {
  description = "Write capacity for the dynamodb table"
  type        = number
  default     = 1
}

data "aws_caller_identity" "current" {}

data "aws_iam_policy_document" "key_policy" {
  statement {
    sid    = "Allow IAM permissions"
    effect = "Allow"

    principals {
      type = "AWS"
      identifiers = [
        "arn:aws:iam::${data.aws_caller_identity.current.account_id}:root",
      ]
    }

    actions = [
      "kms:*",
    ]

    resources = [
      "*",
    ]
  }
}

resource "aws_kms_key" "credstash_cmk" {
  description = "KMS key used by credstash for encrypt/decrypt"
  policy      = data.aws_iam_policy_document.key_policy.json
}

resource "aws_kms_alias" "alias" {
  name          = var.key_alias
  target_key_id = aws_kms_key.credstash_cmk.key_id
}

output "kms_key_id" {
  value = aws_kms_key.credstash_cmk.key_id
}

output "dynamo_table_arn" {
  value = aws_dynamodb_table.store.arn
}

