variable "enable_dns_support" {
  description = "(Optional) A boolean flag to enable/disable DNS support in the VPC. Defaults to true."
  type        = bool
  default     = true
}

variable "enable_dns_hostnames" {
  description = "(Optional) A boolean flag to enable/disable DNS hostnames in the VPC. Defaults to true."
  type        = bool
  default     = true
}

variable "owner" {
  description = "(Optional) The owner responsible for managing the resource - used for tagging."
  type        = string
  default     = "Terraform"
}

variable "tags" {
  description = "(Optional) A map of additional tags to associate with the resource."
  type        = map(string)
  default     = {}
}

variable "cidr_block" {
  description = "(Required) The CIDR block for the VPC"
  type        = string
}

variable "built_by" {
  description = "(Required) The id of the person - used for tagging. e.g. jbloggs or jbloggs@email.com"
  type        = string
}

variable "environment" {
  description = "(Required) The name of the environment that the resource belongs to - used for tagging."
  type        = string
}

variable "environment_vpc" {
  description = "(Required) The name of the VPC that the resource belongs to - used for tagging."
  type        = string
}

variable "region" {
  description = "(Required) The region that the resource belongs to - used for tagging."
  type        = string
}

resource "aws_vpc" "vpc" {
  cidr_block           = var.cidr_block
  enable_dns_hostnames = var.enable_dns_hostnames
  enable_dns_support   = var.enable_dns_support

  tags = merge(
    {
      "BuiltBy" = var.built_by,
      "Environment" = var.environment,
      "Name" = "vpc-${var.environment}-${var.environment_vpc}",
      "Owner" = var.owner,
      "Region" = var.region
    },
    var.tags
  )

  lifecycle {
    create_before_destroy = true
  }
}

resource "aws_internet_gateway" "igw" {
  vpc_id = aws_vpc.vpc.id

  tags = merge(
    {
      "BuiltBy" = var.built_by,
      "Environment" = var.environment,
      "Name" = "igw-${var.environment}-${var.environment_vpc}",
      "Owner" = var.owner,
      "Region" = var.region
    },
    var.tags
  )

  lifecycle {
    create_before_destroy = true
  }
}

resource "aws_security_group" "sg" {
  description = "vpc-${var.environment}-${var.environment_vpc} VPC Security Group"
  name        = "sgrp-${var.environment}-${var.environment_vpc}"
  vpc_id      = aws_vpc.vpc.id

  tags = merge(
    {
