# Provider configuration
provider "google" {
  region = var.gce_region
}

# Number of CockroachDB instances
variable "num_instances" {
  description = "Number of CockroachDB instances to create"
  type        = number
  default     = 5
}

# Machine type for the Jepsen controller
variable "controller_machine_type" {
  description = "Machine type for the Jepsen controller"
  type        = string
  default     = "n1-standard-1"
}

# Machine type for the CockroachDB nodes
variable "cockroach_machine_type" {
  description = "Machine type for CockroachDB nodes"
  type        = string
  default     = "n1-standard-1"
}

# Resource for the Jepsen controller instance
resource "google_compute_instance" "controller" {
  machine_type = var.controller_machine_type
  zone         = var.gce_zone
  tags         = ["cockroach"]
  name         = "${var.prefix}-controller"

  boot_disk {
    initialize_params {
      image = var.gce_image
      size  = var.controller_root_disk_size
      type  = var.controller_root_disk_type
    }
  }

  network_interface {
    network = "default"
    access_config {
      // Ephemeral IP
    }
  }

  metadata = {
    ssh-keys = "ubuntu:${file(var.key_name)}"
  }

  service_account {
    scopes = [
      "https://www.googleapis.com/auth/compute.readonly",
      "https://www.googleapis.com/auth/devstorage.read_write",
    ]
  }

  provisioner "file" {
    source      = "controller.id_rsa"
    destination = "/home/ubuntu/.ssh/id_rsa"
  }

  connection {
    user        = "ubuntu"
    host        = self.network_interface[0].access_config[0].nat_ip
    private_key = file(var.key_name)
  }
}

# Resource for the CockroachDB instances
resource "google_compute_instance" "cockroach" {
  count        = var.num_instances
  machine_type = var.cockroach_machine_type
  zone         = var.gce_zone
  tags         = ["cockroach"]
  name         = "${var.prefix}-cockroach-${count.index + 1}"

  boot_disk {
    initialize_params {
      image = var.gce_image
      size  = var.cockroach_root_disk_size
      type  = var.cockroach_root_disk_type
    }
  }

  attached_disk {
    source      = google_compute_disk.cockroach[count.index].self_link
    device_name = "local-ssd"
  }

  network_interface {
    network = "default"
    access_config {
      // Ephemeral IP
    }
  }

  metadata = {
    ssh-keys = "ubuntu:${file(var.key_name)}"
  }

  connection {
    user        = "ubuntu"
    host        = self.network_interface[0].access_config[0].nat_ip
    private_key = file(var.key_name)
  }

  provisioner "file" {
    source      = "controller.id_rsa.pub"
    destination = "/home/ubuntu/.ssh/authorized_keys"
  }
}

# Local SSD configuration for CockroachDB instances
resource "google_compute_disk" "cockroach" {
  count = var.num_instances
  type  = "local-ssd"
  zone  = var.gce_zone
  name  = "${var.prefix}-cockroach-ssd-${count.index}"
}

# Data source to prepare the list of nodes
data "template_file" "node_list" {
  template = join("
", google_compute_instance.cockroach.*.network_interface[0].access_config[0].nat_ip)
}

# Firewall rules
resource "google_compute_firewall" "default" {
  name    = "${var.prefix}-cockroach-firewall"
  network = "default"

  allow {
    protocol = "tcp"
    ports    = [var.sql_port, var.http_port, "9001"]
  }

  source_ranges = ["0.0.0.0/0"]
  target_tags   = ["cockroach"]
}

# Outputs
output "controller-ip" {
  value = google_compute_instance.controller.network_interface[0].access_config[0].nat_ip
}

variable "etcd_tls_enabled" {
  description = "Indicates whether TLS is used for etcd"
  type        = bool
  default     = true
}

variable "cluster_name" {
  description = "The name of the cluster"
  type        = string
}

variable "base_domain" {
  description = "The base domain used in records"
  type        = string
}

variable "master_count" {
  description = "The number of masters"
  type        = number
}

variable "worker_count" {
  description = "The number of workers"
  type        = number
}

variable "etcd_count" {
  description = "The number of etcd nodes"
  type        = number
}

variable "etcd_ips" {
  description = "List of string IPs for etcd nodes"
  type        = list(string)
}

variable "master_ips" {
  description = "List of string IPs for masters"
  type        = list(string)
}

variable "worker_ips" {
  description = "List of string IPs for workers"
  type        = list(string)
}

resource "aws_route53_zone" "tectonic" {
  name  = var.base_domain
}

resource "aws_route53_record" "etcd_srv_discover" {
  count   = 1
  name    = var.etcd_tls_enabled ? "_etcd-server-ssl._tcp.${var.base_domain}" : "_etcd-server._tcp.${var.base_domain}"
  type    = "SRV"
  zone_id = aws_route53_zone.tectonic.zone_id
  records = [formatlist("0 0 2380 %s", aws_route53_record.etc_a_nodes[*].fqdn)]
  ttl     = 300
}

resource "aws_route53_record" "etcd_srv_client" {
  count   = 1
  name    = var.etcd_tls_enabled ? "_etcd-client-ssl._tcp.${var.base_domain}" : "_etcd-client._tcp.${var.base_domain}"
  type    = "SRV"
  zone_id = aws_route53_zone.tectonic.zone_id
  records = [formatlist("0 0 2379 %s", aws_route53_record.etc_a_nodes[*].fqdn)]
  ttl     = 60
}

resource "aws_route53_record" "etc_a_nodes" {
  count   = var.etcd_count
  type    = "A"
  ttl     = 60
  zone_id = aws_route53_zone.tectonic.zone_id
  name    = "${var.cluster_name}-etcd-${count.index}"
  records = [var.etcd_ips[count.index]]
}

resource "aws_route53_record" "master_nodes" {
  count   = var.master_count
  zone_id = aws_route53_zone.tectonic.zone_id
  name    = "${var.cluster_name}-master-${count.index}"
  type    = "A"
  ttl     = 60
  records = [var.master_ips[count.index]]
}

resource "aws_route53_record" "worker_nodes" {
  count   = var.worker_count
  zone_id = aws_route53_zone.tectonic.zone_id
  name    = "${var.cluster_name}-worker-${count.index}"
  type    = "A"
  ttl     = 60
  records = [var.worker_ips[count.index]]
}

resource "aws_route53_record" "tectonic-api" {
  count   = 1
  zone_id = aws_route53_zone.tectonic.zone_id
  name    = "${var.cluster_name}-k8s"
  type    = "A"
  ttl     = 60
  records = var.master_ips
}

resource "aws_route53_record" "tectonic-console" {
  count   = 1
  zone_id = aws_route53_zone.tectonic.zone_id
  name    = var.cluster_name
  type    = "A"
  ttl     = 60
  records = var.worker_ips
}

output "etc_a_nodes" {
  value = aws_route53_record.etc_a_nodes[*].fqdn
}

provider "aws" {
  access_key = var.access_key
  secret_key = var.secret_key
  region     = module.region.region
}

module "region" {
  source = "git::https://github.com/joescii/aws-terraform-modules.git//us-west-1?ref=v1.0.0"
}

variable "access_key" {
  type = string
}

variable "secret_key" {
  type = string
}

variable "ec2_key_name" {
  default = "sandbox"
  type    = string
}

variable "ci_server_cidr_block" {
  default = "0.0.0.0/0"
  type    = string
}

variable "timestamp" {
  type = string
}

variable "db_username" {
  type = string
}

variable "db_password" {
  type = string
}

variable "ami_txt" {
  default = "./ami.txt"
  type    = string
}

module "vpc" {
  source = "git::https://github.com/joescii/aws-terraform-modules.git//vpc-2-zones?ref=v1.0.0"
  vpc_name           = "lift-jetty-cluster"
  ec2_key_name       = var.ec2_key_name
  region             = module.region.region
  zone_A             = module.region.zone_A
  zone_B             = module.region.zone_B
  nat_ami            = module.region.nat_ami
  bastion_ami        = module.region.enhanced_bastion_ami
  ci_server_cidr_block = var.ci_server_cidr_block
}

resource "null_resource" "key-upload" {
  connection {
    type     = "ssh"
    user     = "ubuntu"
    host     = module.vpc.bastion_host
    private_key = file("./key.pem")
  }

  provisioner "file" {
    source      = "./key.pem"
    destination = "/home/ubuntu/lift.pem"
  }

  provisioner "remote-exec" {
    inline = [
      "chmod 600 /home/ubuntu/lift.pem"
    ]
  }
}

resource "aws_security_group" "lift_instance_sg" {
  name        = "lift-instance-sg"
  description = "SG applied to each lift app server instance"
  vpc_id      = module.vpc.vpc_id

  ingress {
    from_port   = 8080
    to_port     = 8080
    protocol    = "tcp"
    security_groups = [aws_security_group.lift_elb_sg.id]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = [module.vpc.cidr_block]
  }
}

resource "aws_security_group" "lift_elb_sg" {
  name        = "lift-elb-sg"
  description = "SG applied to the elastic load balancer"
  vpc_id      = module.vpc.vpc_id

  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 8080
    to_port     = 8080
    protocol    = "tcp"
    cidr_blocks = [module.vpc.cidr_block]
  }
}

resource "aws_launch_configuration" "lift_as_conf" {
  name            = "lift-as-launch-config-${var.timestamp}"
  image_id        = file(var.ami_txt)
  instance_type   = "t2.micro"
  key_name        = var.ec2_key_name
  security_groups = [
    aws_security_group.lift_instance_sg.id,
    module.vpc.bastion_accessible_sg_id
  ]
  user_data       = template_file.user_data.rendered

  lifecycle {
    create_before_destroy = true
  }
}

resource "aws_autoscaling_group" "lift_as" {
  availability_zones   = [module.region.zone_A, module.region.zone_B]
  vpc_zone_identifier  = [module.vpc.zone_A_private_id, module.vpc.zone_B_private_id]
  name                 = "lift-autoscaling-group-${var.timestamp}"
  desired_capacity     = 2
  max_size             = 2
  min_size             = 2
  health_check_grace_period = 300
  health_check_type    = "ELB"
  force_delete         = true
  launch_configuration = aws_launch_configuration.lift_as_conf.id
  load_balancers       = [aws_elb.lift_elb.name]

  lifecycle {
    create_before_destroy = true
  }
}

resource "aws_elb" "lift_elb" {
  name               = "lift-elb-${var.timestamp}"
  subnets            = [module.vpc.zone_A_public_id, module.vpc.zone_B_public_id]
  security_groups    = [aws_security_group.lift_elb_sg.id]
  internal           = false
  cross_zone_load_balancing = true

  listener {
    instance_port     = 8080
    instance_protocol = "http"
    lb_port           = 80
    lb_protocol       = "http"
  }

  health_check {
    healthy_threshold   = 2
    unhealthy_threshold = 2
    timeout             = 3
    target              = "HTTP:8080/"
    interval            = 5
  }

  lifecycle {
    create_before_destroy = true
  }
}

resource "aws_app_cookie_stickiness_policy" "lift_stickiness_policy" {
  name         = "lift-policy"
  load_balancer = aws_elb.lift_elb.id
  lb_port      = 80
  cookie_name  = "JSESSIONID"
}

resource "template_file" "user_data" {
  template = file("${path.module}/user_data.sh")

  vars = {
    db_host = aws_db_instance.lift_db.address
    db_port = aws_db_instance.lift_db.port
  }
}

resource "template_file" "packer" {
  template = file("${path.module}/packer.json")

  vars = {
    ami = file(var.ami_txt)
  }
}

resource "template_file" "packer_runner" {
  template = file("${path.module}/bake.sh")

  vars = {
    access_key    = var.access_key
    secret_key    = var.secret_key
    region        = module.region.region
    vpc_id        = module.vpc.vpc_id
    zone_public_id = module.vpc.zone_B_public_id
    packer_sg_id  = module.vpc.packer_sg_id
    ubuntu_image  = module.region.ubuntu_precise_12_04_amd64
    db_password   = var.db_password
    timestamp     = var.timestamp
  }
}

resource "aws_db_subnet_group" "all_azs" {
  name = "all-azs"
  description = "Subnet group covering each availability zone"
  subnet_ids = [
    module.vpc.zone_A_private_id,
    module.vpc.zone_B_private_id
  ]
}

resource "aws_security_group" "lift_db_sg" {
  name = "tf-portal-user-db-rds-sg"
  description = "RDS security group for the User DB"
  vpc_id = module.vpc.vpc_id

  ingress {
    from_port = 3306
    to_port = 3306
    protocol = "tcp"
    security_groups = [
      aws_security_group.lift_instance_sg.id
    ]
  }
}

resource "aws_db_instance" "lift_db" {
  identifier        = "lift-db"
  allocated_storage = 5
  engine            = "mysql"
  engine_version    = "5.6.19a"
  instance_class    = "db.t2.micro"
  name              = "LIFT"
  username          = var.db_username
  password          = var.db_password
  vpc_security_group_ids = [
    module.vpc.bastion_accessible_sg_id,
    aws_security_group.lift_db_sg.id
  ]
  db_subnet_group_name = aws_db_subnet_group.all_azs.name
  multi_az         = true

  provisioner "file" {
    connection {
      user     = "ubuntu"
      host     = module.vpc.bastion_host
      private_key = file("./key.pem")
    }

    source      = "./setup.sql"
    destination = "/tmp/mysql-${var.timestamp}.sql"
  }

  provisioner "remote-exec" {
    connection {
      user     = "ubuntu"
      host     = module.vpc.bastion_host
      private_key = file("./key.pem")
    }

    inline = [
      "mysql -h ${self.address} -P ${self.port} --user=${var.db_username} --password=${var.db_password} < /tmp/mysql-${var.timestamp}.sql",
      "rm /tmp/mysql-${var.timestamp}.sql"
    ]
  }
}

resource "azurerm_storage_table" "table" {
  name                 = var.name
  resource_group_name  = var.resource_group_name
  storage_account_name = var.storage_account_name
}

variable "name" {
  type        = string
  description = "(Required) The name of the storage table. Must be unique within the storage account the table is located."
}

variable "resource_group_name" {
  type        = string
  description = "(Required) The name of the resource group in which to create the storage table. Changing this forces a new resource to be created."
}

variable "storage_account_name" {
  type        = string
  description = "(Required) Specifies the storage account in which to create the storage table. Changing this forces a new resource to be created."
}

output "id" {
  value = azurerm_storage_table.table.id
}

output "name" {
  value = azurerm_storage_table.table.name
}

provider "aws" {
  region = var.aws_region
}

resource "aws_instance" "cockroach" {
  tags = {
    Name = "${var.key_name}-${count.index}"
  }
  ami              = var.aws_ami_id
  availability_zone = var.aws_availability_zone
  instance_type    = var.aws_instance_type
  security_groups  = [aws_security_group.default.name]
  key_name         = var.key_name
  count            = var.num_instances
}

resource "template_file" "supervisor" {
  count    = var.num_instances
  template = file("supervisor.conf.tpl")
  vars = {
    stores        = var.stores
    join_address  = element(concat([""], aws_instance.cockroach.*.private_ip), count.index)
    node_address  = aws_instance.cockroach[0].private_ip
  }
}

resource "null_resource" "cockroach-runner" {
  count = var.num_instances
  connection {
    user     = "ubuntu"
    key_file = "~/.ssh/${var.key_name}.pem"
    host     = element(aws_instance.cockroach.*.public_ip, count.index)
  }

  triggers = {
    instance_ids = element(aws_instance.cockroach.*.id, count.index)
  }

  provisioner "file" {
    source      = "download_binary.sh"
    destination = "/home/ubuntu/download_binary.sh"
  }

  provisioner "remote-exec" {
    inline = [
      "sudo apt-get -y update",
      "sudo apt-get -y install supervisor",
      "sudo service supervisor stop",
      "bash download_binary.sh cockroach/cockroach ${var.cockroach_sha}",
      "mkdir -p logs",
      "if [ ! -e supervisor.pid ]; then supervisord -c supervisor.conf; fi",
      "supervisorctl -c supervisor.conf start cockroach",
    ]
  }
}

variable "num_instances" {}

variable "cockroach_port" {
  default = 26257
}

variable "stores" {
  default = "--store=data"
}

variable "supervisor_port" {
  default = 9001
}

variable "aws_region" {
  default = "us-east-1"
}

variable "aws_availability_zone" {
  default = "us-east-1b"
}

variable "aws_ami_id" {
  default = "ami-1c552a76"
}

variable "aws_instance_type" {
  default = "t2.medium"
}

variable "key_name" {
  default = "cockroach"
}

variable "cockroach_sha" {
  default = ""
}

variable "block_writer_sha" {
  default = ""
}

resource "aws_security_group" "default" {
  name = "${var.key_name}-security-group"
  ingress {
    from_port   = 22
    to_port     = 22
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  ingress {
    from_port   = var.cockroach_port
    to_port     = var.cockroach_port
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

variable "example_block_writer_instances" {
  default = 0
}

output "example_block_writer" {
  value = join(",", aws_instance.example_block_writer.*.public_dns)
}

resource "aws_instance" "example_block_writer" {
  tags = {
    Name = "${var.key_name}-block-writer"
  }

  ami              = var.aws_ami_id
  availability_zone = var.aws_availability_zone
  instance_type    = var.aws_instance_type
  security_groups  = [aws_security_group.default.name]
  key_name         = var.key_name
  count            = var.example_block_writer_instances

  connection {
    user     = "ubuntu"
    key_file = "~/.ssh/${var.key_name}.pem"
  }

  provisioner "file" {
    source      = "download_binary.sh"
    destination = "/home/ubuntu/download_binary.sh"
  }

  provisioner "remote-exec" {
    inline = [
      "sudo apt-get -y update",
      "sudo apt-get -y install supervisor",
      "sudo service supervisor stop",
      "bash download_binary.sh examples-go/block_writer ${var.block_writer_sha}",
      "mkdir -p logs",
      "if [ ! -e supervisor.pid ]; then supervisord -c supervisor.conf; fi",
      "supervisorctl -c supervisor.conf start block_writer",
    ]
  }
}

output "instances" {
  value = join(",", aws_instance.cockroach.*.public_dns)
}

data "aws_availability_zones" "available" {}

resource "aws_vpc" "cluster_vpc" {
  cidr_block           = "10.10.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true

  lifecycle {
    ignore_changes = ["tags"]
