  value = module.admiral_subnet_1.az
}

output "admiral_subnet_2_id" {
  value = module.admiral_subnet_2.id
}

output "admiral_subnet_2_az" {
  value = module.admiral_subnet_2.az
}

// Similarly, correct other module declarations and outputs

provider "aws" {
  default_tags {
    tags = {
      environment_tag = var.environment_tag
    }
  }
}


variable "domain_name" {
  default     = null
  type        = string
  description = <<EOF
Leave null for no domain. 
The domain name to configure to point to the server, e.g. 'contradb.com'.
Note that for any domain sent through here to actually have authority,
a human has to go into the registrar's configuration and point the nameservers 
to the name_servers outputs. 
EOF
}

variable "branch" {
  description = "git branch"
  type        = string
  default     = "master"
}

variable "environment_tag" {
  description = <<EOF
  Tag applied to aws resources, e.g. 'staging' or 'production'. 
  'production' is not actually currently used in production, 
  because production predates the option.

  This has no effect on how rails or linux behave, and is not visible to them.
  EOF
  type        = string
  default     = "dev"
}

variable "ssh_public_key_title" {
  default = "contradb-terraform-key"
}

variable "ssh_public_key_path" {
  default = "~/.ssh/contradb-terraform.pub"
}

variable "ssh_private_key_path" {
  default = "~/.ssh/contradb-terraform"
}

variable "database_path" {
  type        = string
  default     = null
  description = <<EOF
path to the .sql file to initialize the instance to. By default looks
at the highest file of the form
~/priv/contradb/contradb-2021-12-34.sql" because that's where the
contradb-backup program stores its nightlies.
EOF
}

variable "database_archive_dir" {
  type        = string
  default     = null
  description = <<EOF
If database_path isn't used, then database_archive_dir specifies where
to look for database images and pick the newest based on the
filenames.
"~/priv/contradb" is the default.
EOF
}



resource "aws_vpc" "contra_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true
  tags = {
    Name = "contradb"
  }
}

resource "aws_eip" "web_ip" {
  instance = aws_instance.server.id
  vpc      = true
  tags = {
    Name = "contradb"
  }
}

resource "aws_subnet" "web" {
  cidr_block        = cidrsubnet(aws_vpc.contra_vpc.cidr_block, 3, 1)
  vpc_id            = aws_vpc.contra_vpc.id
  availability_zone = "us-east-2a"
  tags = {
    Name = "contradb"
  }
}
resource "aws_route_table" "table" {
  vpc_id = aws_vpc.contra_vpc.id
  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.gateway.id
  }
  tags = {
    Name = "contradb"
  }
}
resource "aws_route_table_association" "subnet_association" {
  subnet_id      = aws_subnet.web.id
  route_table_id = aws_route_table.table.id
}

resource "aws_internet_gateway" "gateway" {
  vpc_id = aws_vpc.contra_vpc.id
  tags = {
    Name = "contradb"
  }
}


terraform {
  backend "s3" {
    # this is typically configured by passing the
    # -backend-config=production.tfbackend flag to terraform init,
    # see ./README.md for details
  }
}

locals {
  database_archive_dir = null == var.database_archive_dir ? pathexpand("~/priv/contradb") : var.database_archive_dir
  tmp_database_paths   = fileset(local.database_archive_dir, "contradb-[0-9][0-9][0-9][0-9]-[0-9][0-9]-[0-9][0-9]*.sql")
  database_path        = null != var.database_path ? var.database_path : "${local.database_archive_dir}/${element(sort(local.tmp_database_paths), length(local.tmp_database_paths) - 1)}"
  packer_manifest      = jsondecode(file("${path.module}/packer-manifest.json"))
  region_and_ami_id    = local.packer_manifest.builds[length(tolist(local.packer_manifest.builds)) - 1].artifact_id
  ami_id               = regex(":(.+)$", local.region_and_ami_id)[0]
}

resource "aws_instance" "server" {
  ami           = local.ami_id
  instance_type = "t2.micro"
  key_name      = aws_key_pair.contra_key.key_name
  vpc_security_group_ids = [
    aws_security_group.allow_ssh.id,
    aws_security_group.allow_web.id,
    aws_security_group.allow_outbound.id,
  ]
  subnet_id = aws_subnet.web.id

  tags = {
    Name = "contradb"
  }

  # delete_on_termination = eventually false, but for now true is aok
}

data "template_file" "nginx_site_config_no_ssl" {
  template = file("${path.module}/nginx-no-ssl.tpl")
  vars = {
    domain_name = null == var.domain_name ? "" : var.domain_name
  }
}

data "template_file" "nginx_site_config_certbot" {
  template = file("${path.module}/nginx-certbot.tpl")
  vars = {
    domain_name = null == var.domain_name ? "" : var.domain_name
  }
}

resource "null_resource" "server" {
  triggers = {
    server = aws_instance.server.id
  }

  connection {
    type        = "ssh"
    user        = "ubuntu"
    private_key = file(var.ssh_private_key_path)
    host        = aws_eip.web_ip.public_dns
  }
  provisioner "file" {
    source      = local.database_path
    destination = "/home/ubuntu/db.sql"
  }
  provisioner "file" {
    destination = "/home/ubuntu/rails-env.d/contradb-domain"
    content     = "export CONTRADB_DOMAIN=$${CONTRADB_DOMAIN:-${null == var.domain_name ? "`curl --max-time 5 --silent http://169.254.169.254/latest/meta-data/public-hostname`" : var.domain_name}}"
  }
  provisioner "file" {
    content     = data.template_file.nginx_site_config_no_ssl.rendered
    destination = "/home/ubuntu/etc-nginx-sites-avaiable-contradb-no-ssl"
  }
  provisioner "file" {
    content     = data.template_file.nginx_site_config_certbot.rendered
    destination = "/home/ubuntu/etc-nginx-sites-avaiable-contradb-certbot"
  }
  provisioner "remote-exec" {
    inline = [
      <<EOF
sudo -u postgres psql -c "CREATE USER contradbd WITH CREATEDB PASSWORD '${random_password.postgres.result}';"
sudo -u postgres psql -c "CREATE USER ubuntu WITH CREATEDB PASSWORD '${random_password.postgres.result}';"
EOF
      ,
      "sudo rm /etc/nginx/sites-enabled/default",
      "sudo cp /home/ubuntu/etc-nginx-sites-avaiable-contradb-no-ssl /etc/nginx/sites-available/contradb-no-ssl",
      "sudo cp /home/ubuntu/etc-nginx-sites-avaiable-contradb-certbot /etc/nginx/sites-available/contradb-certbot",
      "sudo ln -s /etc/nginx/sites-available/contradb-no-ssl /etc/nginx/sites-enabled/contradb",
      "sudo systemctl reload nginx",
      "umask 022 && cd /home/ubuntu/contra && git fetch && git checkout ${var.branch} && git pull --no-edit",
      "sudo -g rails /home/ubuntu/contra/terraform/provisioning/rails ${random_password.postgres.result}",
      "sudo -u postgres psql contraprod -c 'GRANT SELECT, INSERT, UPDATE, DELETE ON ALL TABLES IN SCHEMA public TO contradbd; GRANT ALL ON ALL SEQUENCES IN SCHEMA public TO contradbd;'",
      "sudo install --mode 644 /home/ubuntu/contra/terraform/puma.service /etc/systemd/system/puma.service",
      "sudo systemctl enable puma",
      "sudo systemctl start puma",
    ]
  }
}

resource "aws_key_pair" "contra_key" {
  key_name   = var.ssh_public_key_title
  public_key = file(var.ssh_public_key_path)
  tags = {
    Name = "contradb"
  }
}

resource "aws_security_group" "allow_ssh" {
  name        = "allow_ssh"
  description = "Allow ssh inbound traffic"
  vpc_id      = aws_vpc.contra_vpc.id

  ingress {
    description = "ssh"
    from_port   = 22
    to_port     = 22
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "contradb"
  }
}

resource "aws_security_group" "allow_web" {
  name        = "allow_web"
  description = "Allow web inbound traffic"
  vpc_id      = aws_vpc.contra_vpc.id

  ingress {
    description = "http"
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  ingress {
    description = "https"
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "contradb"
  }
}

resource "aws_security_group" "allow_outbound" {
  name        = "allow_outbound"
  description = "Allow all outbound traffic"
  vpc_id      = aws_vpc.contra_vpc.id

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "contradb"
  }
}

resource "random_password" "postgres" {
  length  = 26
  special = false
}


locals {
  domain_count = null == var.domain_name ? 0 : 1
}

resource "aws_route53_zone" "zone" {
  count = local.domain_count
  name  = var.domain_name
  tags = {
    Name = "contradb"
  }
}

resource "aws_route53_record" "record" {
  count   = local.domain_count
  name    = var.domain_name
  records = [aws_eip.web_ip.public_ip]
  zone_id = aws_route53_zone.zone[count.index].id
  type    = "A"
  ttl     = "3600"
}

resource "aws_route53_record" "www" {
  zone_id = aws_route53_zone.zone[count.index].id
  name    = "www"
  count   = local.domain_count
  records = [aws_route53_record.record[count.index].name]
  type    = "CNAME"
  ttl     = "3600"
}


output "name_servers" {
  value = var.domain_name == null ? [] : aws_route53_zone.zone[0].name_servers
}

output "ip" {
  value = aws_eip.web_ip.public_ip
}

output "domain" {
  value = aws_eip.web_ip.public_dns
}

#--------------------------------------------------------------
# S3 Bucket Policy
#--------------------------------------------------------------
resource "aws_iam_policy" "s3_bucket_policy" {
  name        = "s3_bucket_policy"
  path        = "/"
  description = "policy to be used by iam role for access to s3 bucket"

  policy = jsonencode({
    "Version"   : "2012-10-17",
    "Statement" : [
      {
        "Sid"    : "Stmt1477654877000",
        "Effect" : "Allow",
        "Action" : ["ec2:*"],
        "Resource": ["*"]
      },
      {
        "Sid"    : "Stmt1477654895000",
        "Effect" : "Allow",
        "Action" : ["s3:*"],
        "Resource": ["*"]
      }
    ]
  })
}

#--------------------------------------------------------------
# Backup Role
#--------------------------------------------------------------
resource "aws_iam_role" "backup_role" {
  name = "backup_role"

  assume_role_policy = jsonencode({
    "Version"   : "2012-10-17",
    "Statement" : [
      {
        "Action"    : "sts:AssumeRole",
        "Principal" : {"Service": "ec2.amazonaws.com"},
        "Effect"    : "Allow",
        "Sid"       : ""
      }
    ]
  })
}

#--------------------------------------------------------------
# IAM Role Policy Attachment
#--------------------------------------------------------------
resource "aws_iam_role_policy_attachment" "backup_policy_attachment" {
  role       = aws_iam_role.backup_role.name
  policy_arn = aws_iam_policy.s3_bucket_policy.arn
}

#--------------------------------------------------------------
# IAM Instance Profile
#--------------------------------------------------------------
resource "aws_iam_instance_profile" "instance_profile" {
  name  = "iam_instance_profile"
  roles = [aws_iam_role.backup_role.name]
}

#--------------------------------------------------------------
# Access and Secret Keys
#--------------------------------------------------------------
variable "aws_access_key" {
  type        = string
  description = "Access Key Account"
  default     = "{{env `AWS_ACCESS_KEY_ID`}}"
}

variable "aws_secret_key" {
  type        = string
  description = "Secret Key Account"
  default     = "{{env `AWS_SECRET_ACCESS_KEY`}}"
}

#--------------------------------------------------------------
# Region
#--------------------------------------------------------------
variable "region" {
  type        = string
  description = "The AWS region to create resources in."
  default     = "us-east-1"
}

#--------------------------------------------------------------
# Key File
#--------------------------------------------------------------
variable "key_file" {
  type        = string
  description = "describe your variable"
  default     = "ssh_keys/database_key.pub"
}

#--------------------------------------------------------------
# Availability Zones
#--------------------------------------------------------------
variable "azs" {
  type        = string
  description = "Availability Zones"
  default     = "us-east-1a,us-east-1b"
}

#--------------------------------------------------------------
# Public & Private CIDRs
#--------------------------------------------------------------
variable "public_cidrs" {
  type        = string
  description = "public network blocks"
  default     = "10.0.2.0/24"
}

variable "private_cidrs" {
  type        = string
  description = "private network blocks"
  default     = "10.0.0.0/24,10.0.1.0/24"
}

#--------------------------------------------------------------
# Consul Servers Ip addresses
#--------------------------------------------------------------
variable "ips" {
  default = {
    "0" = "10.0.0.10"
    "1" = "10.0.0.11"
    "2" = "10.0.0.12"
  }
}

#--------------------------------------------------------------
# Bastion Artifact (AMI)
#--------------------------------------------------------------
resource "aws_vpc" "database_setup" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true

  tags = {
    Name = "database_setup"
  }
}

#--------------------------------------------------------------
# Internet Gateway
#--------------------------------------------------------------
resource "aws_internet_gateway" "database_gateway" {
  vpc_id = aws_vpc.database_setup.id

  tags = {
    Name = "database_internet_gateway"
  }
}

#--------------------------------------------------------------
# Private subnet
#--------------------------------------------------------------
resource "aws_subnet" "private" {
  vpc_id            = aws_vpc.database_setup.id
  availability_zone = element(split(",", var.azs), count.index)
  cidr_block        = element(split(",", var.private_cidrs), count.index)
  count             = length(compact(split(",", var.private_cidrs)))
}

resource "aws_route_table" "private_route_table" {
  vpc_id = aws_vpc.database_setup.id
  count  = length(split(",", var.azs))

  route {
    cidr_block     = "0.0.0.0/0"
    nat_gateway_id = element(aws_nat_gateway.database_nat.*.id, count.index)
  }

  tags = {
    Name = "private_route_table"
  }
}

resource "aws_route_table_association" "private_route_table_association" {
  count          = length(compact(split(",", var.private_cidrs)))
  subnet_id      = element(aws_subnet.private.*.id, count.index)
  route_table_id = element(aws_route_table.private_route_table.*.id, count.index)
}

#--------------------------------------------------------------
# NAT Eip
#--------------------------------------------------------------
resource "aws_eip" "database_nat_eip" {
  vpc   = true
  count = length(split(",", var.azs))
}

#--------------------------------------------------------------
# NAT Gateway
#--------------------------------------------------------------
resource "aws_nat_gateway" "database_nat" {
  count         = length(split(",", var.azs))
  allocation_id = element(aws_eip.database_nat_eip.*.id, count.index)
  subnet_id     = element(aws_subnet.public.*.id, count.index)
}

#--------------------------------------------------------------
# Public subnet
#--------------------------------------------------------------
resource "aws_subnet" "public" {
  vpc_id                  = aws_vpc.database_setup.id
  availability_zone       = "us-east-1a"
  cidr_block              = var.public_cidrs
  map_public_ip_on_launch = true
}

resource "aws_route_table" "public_route_table" {
  vpc_id = aws_vpc.database_setup.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.database_gateway.id
  }

  tags = {
    Name = "public_route_table"
  }
}

resource "aws_route_table_association" "public_route_table_association" {
  subnet_id      = aws_subnet.public.id
  route_table_id = aws_route_table.public_route_table.id
}

#--------------------------------------------------------------
# Primary Security Group
#--------------------------------------------------------------
resource "aws_security_group" "primary" {
  name        = "primary-security"
  description = "Default security group that allows inbound and outbound traffic from all instances in the VPC"
  vpc_id      = aws_vpc.database_setup.id

  ingress {
    from_port = 0
    to_port   = 65535
    protocol  = "tcp"
    self      = true
  }

  ingress {
    from_port = 0
    to_port   = 65535
    protocol  = "udp"
    self      = true
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

#--------------------------------------------------------------
# bastion Server Security Group
#--------------------------------------------------------------
resource "aws_security_group" "bastion_security" {
  name        = "bastion-security"
  description = "Security group for bastion instance"
  vpc_id      = aws_vpc.database_setup.id

  ingress {
    from_port   = 22
    to_port     = 22
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "bastion-server-security"
  }
}

#--------------------------------------------------------------
# Database Backup Instances' Security Group
#--------------------------------------------------------------
resource "aws_security_group" "database_backup_security_group" {
  name        = "database_backup_security_group"
  description = "Security group for ec2 slave database instances"
  vpc_id      = aws_vpc.database_setup.id

  ingress {
    from_port       = 22
    to_port         = 22
    protocol        = "tcp"
    security_groups = [aws_security_group.bastion_security.id]
