  type    = "amazon.image"
  version = "latest"
}

data "atlas_artifact" "SlaveDB" {
  name    = "Panda/SlaveDB"
  type    = "amazon.image"
  version = "latest"
}

data "atlas_artifact" "backup_database_ami" {
  name    = "Panda/BackupDB"
  type    = "amazon.image"
  version = "latest"
}

#--------------------------------------------------------------
# Instances
