    }
    filter {
        name                = "virtualization-type"
        values              = ["hvm"]
    }
    filter {
        name                = "root-device-type"
        values              = ["ebs"]
    }
}


# Create a new VPC
resource "aws_vpc" "traefik_vpc" {
    cidr_block              = "10.1.0.0/16"
    enable_dns_hostnames    = "true"
    enable_dns_support      = "true"
    tags {
        Name                = "traefik_vpc"
        tool                = "terraform"
        demo                = "traefik"
        area                = "networking"
    }
}

# Create a public subnet in the new VPC
resource "aws_subnet" "traefik_pub_subnet" {
    vpc_id                  = "${aws_vpc.traefik_vpc.id}"
    cidr_block              = "10.1.1.0/24"
    map_public_ip_on_launch = "true"
    tags {
        Name                = "traefik_pub_subnet"
        tool                = "terraform"
        demo                = "traefik"
        area                = "networking"
    }
}

# Create a new Internet gateway
resource "aws_internet_gateway" "traefik_gw" {
    vpc_id                  = "${aws_vpc.traefik_vpc.id}"
    tags {
        Name                = "traefik_gw"
        tool                = "terraform"
        demo                = "traefik"
        area                = "networking"
    }
}

# Create a route table for the new VPC
resource "aws_route_table" "traefik_rte_tbl" {
    vpc_id                  = "${aws_vpc.traefik_vpc.id}"
    route {
        cidr_block          = "0.0.0.0/0"
        gateway_id          = "${aws_internet_gateway.traefik_gw.id}"
    }
    tags {
        Name                = "traefik_rte_tbl"
        tool                = "terraform"
        demo                = "traefik"
        area                = "networking"
    }
}

# Associate route table with subnet in VPC
resource "aws_route_table_association" "traefik_rta" {
    subnet_id               = "${aws_subnet.traefik_pub_subnet.id}"
    route_table_id          = "${aws_route_table.traefik_rte_tbl.id}"
}


# Create a security group to allow inbound web traffic
resource "aws_security_group" "web_sg" {
    vpc_id                  = "${aws_vpc.traefik_vpc.id}"
    name                    = "web_sg"
    description             = "Security group for inbound web traffic"
    ingress {
        from_port           = "0"
        to_port             = "0"
        protocol            = "-1"
        cidr_blocks         = ["${aws_vpc.traefik_vpc.cidr_block}"]
    }
    ingress {
        from_port           = "8080"
        to_port             = "8080"
        protocol            = "tcp"
        cidr_blocks         = ["0.0.0.0/0"]
    }
    ingress {
        from_port           = "80"
        to_port             = "80"
        protocol            = "tcp"
        cidr_blocks         = ["0.0.0.0/0"]
    }
    ingress {
        from_port           = "22"
        to_port             = "22"
        protocol            = "tcp"
        cidr_blocks         = ["0.0.0.0/0"]
    }
    egress {
        from_port           = "0"
        to_port             = "0"
        protocol            = "-1"
        cidr_blocks         = ["0.0.0.0/0"]
    }
    tags {
        Name                = "web_sg"
        tool                = "terraform"
        demo                = "traefik"
        area                = "security"
    }
}

# Create a security group to allow inbound Docker management traffic
resource "aws_security_group" "mgmt_sg" {
    vpc_id                  = "${aws_vpc.traefik_vpc.id}"
    name                    = "mgmt_sg"
    description             = "Security group for inbound Docker management traffic"
    ingress {
        from_port           = "0"
        to_port             = "0"
        protocol            = "-1"
        cidr_blocks         = ["${aws_vpc.traefik_vpc.cidr_block}"]
    }
    ingress {
        from_port           = "8080"
        to_port             = "8080"
        protocol            = "tcp"
        cidr_blocks         = ["0.0.0.0/0"]
    }
    ingress {
        from_port           = "80"
        to_port             = "80"
        protocol            = "tcp"
        cidr_blocks         = ["0.0.0.0/0"]
    }
    ingress {
        from_port           = "22"
        to_port             = "22"
        protocol            = "tcp"
        cidr_blocks         = ["0.0.0.0/0"]
    }
    ingress {
        from_port           = "2376"
        to_port             = "2377"
        protocol            = "tcp"
        cidr_blocks         = ["0.0.0.0/0"]
    }
    ingress {
        from_port           = "3376"
        to_port             = "3377"
        protocol            = "tcp"
        cidr_blocks         = ["0.0.0.0/0"]
    }
    egress {
        from_port           = "0"
        to_port             = "0"
        protocol            = "-1"
        cidr_blocks         = ["0.0.0.0/0"]
    }
    tags {
        Name                = "mgmt_sg"
        tool                = "terraform"
        demo                = "traefik"
        area                = "security"
    }
}


# Launch an instance to serve as a manager
resource "aws_instance" "manager" {
    ami                     = "${data.aws_ami.worker_ami.id}"
    instance_type           = "${var.mgr_flavor}"
    key_name                = "${var.keypair}"
    vpc_security_group_ids  = ["${aws_security_group.mgmt_sg.id}"]
    subnet_id               = "${aws_subnet.traefik_pub_subnet.id}"
    depends_on              = ["aws_internet_gateway.traefik_gw"]
    tags {
        Name                = "manager"
        tool                = "terraform"
        demo                = "traefik"
        area                = "compute"
        role                = "manager"
    }
}

# Launch one or more instances to serve as worker nodes
resource "aws_instance" "worker" {
    ami                     = "${data.aws_ami.worker_ami.id}"
    count                   = "${var.num_wkr_nodes}"
    instance_type           = "${var.wkr_flavor}"
    key_name                = "${var.keypair}"
    vpc_security_group_ids  = ["${aws_security_group.web_sg.id}"]
    subnet_id               = "${aws_subnet.traefik_pub_subnet.id}"
    depends_on              = ["aws_internet_gateway.traefik_gw"]
    tags {
        tool                = "terraform"
        demo                = "traefik"
        area                = "compute"
        role                = "worker"
    }
}


output "manager_pub_ip" {
    value = ["${aws_instance.manager.public_ip}"]
}

output "worker_pub_ips" {
    value = ["${aws_instance.worker.*.public_ip}"]
}

