}

resource "google_compute_firewall" "inbound_bastion_ssh" {
  name    = "inbound-bastion-ssh"
  network = google_compute_network.production.name

  source_ranges = ["0.0.0.0/0"]
  target_tags   = ["bastion"]

  allow {
    protocol = "tcp"
    ports    = ["22"]
  }
}

resource "google_compute_firewall" "allow_all_internal" {
  name    = "allow-all-internal-${google_compute_network.production.name}"
  network = google_compute_network.production.name

  source_ranges = ["10.0.0.0/8"]
  target_tags   = ["bastion", "no-ip-${var.gce_region1_zone1}", "no-ip-${var.gce_region1_zone2}", "nat"]

  allow {
    protocol = "tcp"
  }
  allow {
    protocol = "udp"
  }
  allow {
    protocol = "icmp"
  }
}

resource "google_compute_instance" "nat" {
  for_each = {
    zone1 = var.gce_region1_zone1
    zone2 = var.gce_region1_zone2
  }

  zone            = each.value
  name            = "nat-${each.value}"
  tags            = [google_compute_network.production.name, "nat", "public"]
  machine_type    = var.gce_machine_type_micro

  disk {
    image       = var.gce_image
    auto_delete = true
  }

  network_interface {
    network = google_compute_network.production.name
    access_config {}
  }

  metadata_startup_script = file("scripts/setup-nat-routing.sh")
  can_ip_forward = true
}

resource "google_compute_route" "default_nat" {
  for_each = {
    zone1 = var.gce_region1_zone1
    zone2 = var.gce_region1_zone2
  }

  name       = "default-nat-route-${each.value}"
  dest_range = "0.0.0.0/0"
  network    = google_compute_network.production.name
  next_hop_ip = google_compute_instance.nat[each.key].network_interface[0].address
  priority   = 100
  tags       = ["no-ip-${each.value}"]
}

