/**
 * # Terra cluster Prometheus module
 *
 * This module creates the IP, DNS and CloudArmor rules for deployments of Prometheus in Terra k8s clusters.
 * 
 * For more information, check out the [MC-Terra deployment doc](https://docs.dsp-devops.broadinstitute.org/mc-terra/mcterra-deployment)
 * and our [Terraform best practices](https://docs.dsp-devops.broadinstitute.org/best-practices-guides/terraform).
 *
 * This documentation is generated with [terraform-docs](https://github.com/segmentio/terraform-docs)
 * `terraform-docs markdown --no-sort . > README.md`
 */


module "broad_internal_access" {
  source = "github.com/broadinstitute/terraform-shared.git//terraform-modules/cloud-armor-rule?ref=Cloud-Armor-0.0.1"

  providers = {
    google.target = google.target
  }
}


data "google_dns_managed_zone" "dns_zone" {
  count = var.enable ? 1 : 0

  project  = local.project
  provider = google.dns
  name     = var.dns_zone_name
}
locals {
  fqdn        = "${local.subdomain}.${data.google_dns_managed_zone.dns_zone[0].dns_name}"
  thanos_fqdn = "thanos-sidecar.${data.google_dns_managed_zone.dns_zone[0].dns_name}"
}


resource "google_dns_record_set" "ingress" {
  count = var.enable ? 1 : 0

  project      = local.project
  provider     = google.dns
  managed_zone = data.google_dns_managed_zone.dns_zone[0].name
  name         = local.fqdn
  type         = "A"
  ttl          = "300"
  rrdatas      = [google_compute_global_address.ingress_ip[0].address]
}

resource "google_dns_record_set" "thanos_a_record" {
  count = var.enable_thanos ? 1 : 0

  project      = local.project
  provider     = google.dns
  managed_zone = data.google_dns_managed_zone.dns_zone[0].name
  name         = local.thanos_fqdn
  type         = "A"
  ttl          = "300"
  rrdatas      = [google_compute_address.thanos_sidecar_ip[0].address]
}


resource "google_compute_global_address" "ingress_ip" {
  count = var.enable ? 1 : 0

  provider = google.target
  project  = var.google_project

  name = "terra-${local.owner}-${local.service}-ip"
}

resource "google_compute_address" "thanos_sidecar_ip" {
  count = var.enable_thanos ? 1 : 0

  provider = google.target
  project  = var.google_project

  name = "terra-${local.owner}-thanos-ip"
}


resource "google_service_account" "prometheus" {
  project      = var.google_project
  account_id   = "prometheus"
  display_name = "prometheus"
  provider     = google.target
}

locals {
  roles = [
    "roles/monitoring.metricWriter",
  ]
}

resource "google_project_iam_member" "prometheus_iam" {
  for_each = toset(local.roles)
  project  = var.google_project
  role     = each.key
  member   = "serviceAccount:${google_service_account.prometheus.email}"
  provider = google.target
}

# Workload Identity User policy (project config)
data "google_iam_policy" "prometheus_workload_identity_policy" {
  binding {
    role = "roles/iam.workloadIdentityUser"
    members = [
      "serviceAccount:${var.google_project}.svc.id.goog[${var.k8s_namespace}/terra-prometheus-operator-prometheus]",
      "serviceAccount:${var.google_project}.svc.id.goog[${var.k8s_namespace}/prometheus-to-sd-sa]",
    ]
  }
  provider = google.target
}

# Workload Identity User policy (SA config)
resource "google_service_account_iam_policy" "prometheus_workload_identity_iam" {
  service_account_id = google_service_account.prometheus.name
  policy_data        = data.google_iam_policy.prometheus_workload_identity_policy.policy_data
  provider           = google.target
}


#
# IP/DNS Outputs
#
output "ingress_ip" {
  description = "Prometheus ingress IP"
  value       = var.enable ? google_compute_global_address.ingress_ip[0].address : null
}
output "fqdn" {
  description = "Prometheus FQDN"
