  tags = {
    Name        = "duy-${var.app}"
    sshUser     = "ubuntu"
    Environment = var.env
  }

  vpc_security_group_ids = ["sg-6f6c570b", "sg-086c576c"]
  subnet_id              = "subnet-2746ee43"

  provisioner "remote-exec" {
    inline = [
      "sudo apt-get update -y"
    ]
  }
}

