data "aws_iam_role" "default" {
  count = length(var.roles) == 1 ? 1 : 0
  name  = element(var.roles, count.index)
}

data "aws_iam_policy_document" "assume_role" {
  statement {
    sid     = "EC2AssumeRole"
    effect  = "Allow"
    actions = ["sts:AssumeRole"]

    principals {
      type        = "Service"
      identifiers = ["ec2.amazonaws.com"]
    }
  }
}

data "aws_iam_policy_document" "default_ecr" {
  count = length(var.roles) == 1 ? 0 : 1

  statement {
    sid    = "ecr"
    effect = "Allow"

    principals {
      type = "AWS"
      identifiers = [
        for role in aws_iam_role.default : role.arn
      ]
    }

    actions = [
      "ecr:GetAuthorizationToken",
      "ecr:GetDownloadUrlForLayer",
      "ecr:BatchGetImage",
      "ecr:BatchCheckLayerAvailability",
      "ecr:PutImage",
      "ecr:InitiateLayerUpload",
      "ecr:UploadLayerPart",
      "ecr:CompleteLayerUpload",
      "ecr:DescribeRepositories",
      "ecr:ListImages",
      "ecr:DescribeImages",
    ]
  }
}

data "aws_iam_policy_document" "resource" {
  count = length(var.roles)

  statement {
    sid    = "ecr"
    effect = "Allow"

    principals {
      type = "AWS"
      identifiers = [
        for role in aws_iam_role.default : role.arn
      ]
    }

    actions = [
      "ecr:GetAuthorizationToken",
      "ecr:GetDownloadUrlForLayer",
      "ecr:BatchGetImage",
      "ecr:BatchCheckLayerAvailability",
      "ecr:PutImage",
      "ecr:InitiateLayerUpload",
      "ecr:UploadLayerPart",
      "ecr:CompleteLayerUpload",
      "ecr:DescribeRepositories",
      "ecr:ListImages",
      "ecr:DescribeImages",
    ]
  }
}

resource "aws_ecr_repository" "default" {
  name = var.name
}

resource "aws_ecr_repository_policy" "default" {
  count      = length(var.roles)
  repository = aws_ecr_repository.default.name
  policy     = data.aws_iam_policy_document.resource[count.index].json
}

resource "aws_ecr_repository_policy" "default_ecr" {
  count      = length(var.roles) == 1 ? 0 : 1
  repository = aws_ecr_repository.default.name
  policy     = data.aws_iam_policy_document.default_ecr[0].json
}

resource "aws_iam_role" "default" {
  count              = length(var.roles) == 1 ? 0 : 1
  name               = replace(var.name, "/", "-")
  assume_role_policy = data.aws_iam_policy_document.assume_role.json
}

resource "aws_iam_instance_profile" "default" {
  count = length(var.roles) == 1 ? 0 : 1
  name  = replace(var.name, "/", "-")
  role  = aws_iam_role.default[0].name
}

resource "aws_ecr_lifecycle_policy" "default" {
  repository = aws_ecr_repository.default.name

  policy = jsonencode({
    rules = [{
      rulePriority = 1
      description  = "Rotate images when reach ${var.num_of_last_images_to_keep} images stored"
      selection = {
        tagStatus   = "any"
        countType   = "imageCountMoreThan"
        countNumber = var.num_of_last_images_to_keep
      }
      action = {
        type = "expire"
      }
    }]
  })
}

