# Configure the Google Cloud Provider to use beta features
provider "google-beta" {
  user_project_override = true
  billing_project       = var.project_id
}

# Define variables
variable "project_id" {}
variable "groups" {
  type = list(object({
    id          : string
    customer_id : string
    display_name: string
    description : string
    owners      : list(string)
    managers    : list(string)
    members     : list(string)
  }))
}

# Dynamically create groups based on the input variable
module "identity_groups" {
  for_each = { for group in var.groups : group.id => group }

  source  = "terraform-google-modules/group/google"
  version = "~> 0.3"

  id          = each.value.id
  customer_id = each.value.customer_id
  display_name= each.value.display_name
  description = each.value.description
  owners      = each.value.owners
  managers    = each.value.managers
  members     = each.value.members
}

# Outputs
output "group_ids" {
  value = { for group in var.groups : group.id => module.identity_groups[group.id].id }
}

provider "google" {
  project = var.gcp_proj_id
  region  = var.gcp_region
}

variable "gcp_proj_id" {}
variable "gcp_region" {}

variable "prefix" {}

variable "pcf_opsman_image_name" {}
variable "pcf_ert_domain" {}
variable "system_domain" {}
variable "apps_domain" {}
variable "pcf_ert_ssl_cert" {}
variable "pcf_ert_ssl_key" {}

variable "db_cloudsqldb_tier" {
  default = "db-f1-micro"
}

resource "google_compute_network" "pcf_virt_net" {
  name = "${var.prefix}-virt-net"
}

resource "google_compute_subnetwork" "subnet_ops_manager" {
  name          = "${var.prefix}-subnet-ops-manager"
  ip_cidr_range = "192.168.101.0/26"
  network       = google_compute_network.pcf_virt_net.self_link
}

resource "google_compute_address" "opsman_ip" {
  name = "${var.prefix}-opsman-ip"
}

resource "google_compute_instance" "ops_manager" {
  name         = "${var.prefix}-ops-manager"
  machine_type = "n1-standard-2"
  zone         = var.gcp_region

  boot_disk {
    initialize_params {
      image = var.pcf_opsman_image_name
    }
  }

  network_interface {
    network = google_compute_network.pcf_virt_net.name
    subnetwork = google_compute_subnetwork.subnet_ops_manager.name

    access_config {
      nat_ip = google_compute_address.opsman_ip.address
    }
  }

  service_account {
    scopes = ["cloud-platform"]
  }

  tags = ["ops-manager"]
}

resource "google_dns_managed_zone" "pcf_dns_zone" {
  name     = "${var.prefix}-dns-zone"
  dns_name = "${var.pcf_ert_domain}."
}

resource "google_dns_record_set" "ops_manager_dns" {
  name         = "opsman.${google_dns_managed_zone.pcf_dns_zone.dns_name}"
  type         = "A"
  ttl          = 300
  managed_zone = google_dns_managed_zone.pcf_dns_zone.name
  rrdatas      = [google_compute_address.opsman_ip.address]
}

resource "google_compute_global_address" "pcf_apps" {
  name = "${var.prefix}-pcf-apps"
}

resource "google_dns_record_set" "apps_dns" {
  name         = "*.${var.apps_domain}."
  type         = "A"
  ttl          = 300
  managed_zone = google_dns_managed_zone.pcf_dns_zone.name
  rrdatas      = [google_compute_global_address.pcf_apps.address]
}

resource "google_compute_ssl_certificate" "pcf_ssl_cert" {
  name_prefix = "${var.prefix}-ssl-cert-"
  private_key = var.pcf_ert_ssl_key
  certificate = var.pcf_ert_ssl_cert
}

resource "google_compute_target_http_proxy" "http_lb_proxy" {
  name        = "${var.prefix}-http-proxy"
  description = "HTTP proxy for PCF"
  url_map     = google_compute_url_map.pcf_url_map.self_link
  ssl_certificates = [google_compute_ssl_certificate.pcf_ssl_cert.self_link]
}

resource "google_compute_url_map" "pcf_url_map" {
  name            = "${var.prefix}-url-map"
  default_service = google_compute_backend_service.pcf_backend_service.self_link
}

resource "google_compute_backend_service" "pcf_backend_service" {
  name        = "${var.prefix}-backend-service"
  port_name   = "http"
  protocol    = "HTTP"
  timeout_sec = 30
  health_checks = [google_compute_http_health_check.pcf_health_check.self_link]
}

resource "google_compute_http_health_check" "pcf_health_check" {
  name               = "${var.prefix}-http-health-check"
  request_path       = "/health"
  port               = 80
  check_interval_sec = 5
  timeout_sec        = 5
  unhealthy_threshold = 2
  healthy_threshold   = 4
}

output "ops_manager_url" {
  value = "https://${google_compute_address.opsman_ip.address}"
}

provider "google" {
