  description = "The GCP region"
  type        = string
}

variable "project_id" {
  description = "The GCP project ID"
  type        = string
}

variable "public_ssh_key" {
  description = "Public SSH key for access"
  type        = string
}

variable "cluster_name" {
  description = "The name of the Kubernetes cluster"
  type        = string
}

resource "google_service_account" "master_node_sa" {
  account_id   = "${format("%.28s", var.cluster_name)}-m"
  display_name = "Master node service account"
  project      = var.project_id
}

resource "google_project_iam_member" "master_compute_admin" {
  role   = "roles/compute.instanceAdmin.v1"
  member = "serviceAccount:${google_service_account.master_node_sa.email}"
}

resource "google_project_iam_member" "master_network_admin" {
  role   = "roles/compute.networkAdmin"
  member = "serviceAccount:${google_service_account.master_node_sa.email}"
}

resource "google_project_iam_member" "master_storage_admin" {
  role   = "roles/storage.admin"
  member = "serviceAccount:${google_service_account.master_node_sa.email}"
}

resource "google_project_iam_member" "master_object_storage_admin" {
  role   = "roles/storage.objectAdmin"
  member = "serviceAccount:${google_service_account.master_node_sa.email}"
}

resource "google_compute_instance_template" "master_node" {
  name           = "${var.cluster_name}-master-node"
  machine_type   = "n1-standard-1"
  can_ip_forward = true

  disk {
    source_image = "projects/ubuntu-os-cloud/global/images/family/ubuntu-1804-lts"
    auto_delete  = true
    boot         = true
  }

  network_interface {
    network = "default"
  }

  metadata = {
    ssh-keys = "ubuntu:${var.public_ssh_key}"
  }

  service_account {
    email  = google_service_account.master_node_sa.email
    scopes = ["cloud-platform"]
  }
}

resource "google_compute_instance_group_manager" "master_node_group" {
  name               = "${var.cluster_name}-master-group"
  base_instance_name = "${var.cluster_name}-master-node"
  instance_template  = google_compute_instance_template.master_node.id
  target_size        = 3
  zone               = var.region
}

output "master_node_group_manager" {
  value = google_compute_instance_group_manager.master_node_group.self_link
}

provider "azurerm" {
  features {}
}

variable "resource_group" {
  description = "The name of the resource group in which to create the virtual network."
  default     = "example-resources"
}

variable "location" {
  description = "The location/region where the virtual network is created. Changing this forces a new resource to be created."
  default     = "East US"
}

variable "dns_name" {
  description = "Label for the Domain Name. Used to make up the FQDN. If a domain name label is specified, an A DNS record is created for the public IP in the Microsoft Azure DNS system."
  default     = "example"
}

variable "storage_account_type" {
  description = "Defines the type of storage account to be created."
  default     = "Standard_LRS"
}

variable "virtual_network_name" {
  description = "The name for the virtual network."
  default     = "example-vnet"
}

variable "address_space" {
  description = "The address space that is used by the virtual network."
  default     = "10.0.0.0/16"
}

variable "subnet_prefix" {
  description = "The address prefix to use for the subnet."
  default     = "10.0.1.0/24"
}

variable "vm_size" {
  description = "Specifies the size of the virtual machine."
  default     = "Standard_DS1_v2"
}

variable "admin_username" {
  description = "Administrator user name for the VMs."
  default     = "adminuser"
}

variable "admin_password" {
  description = "Administrator password for the VMs."
  default     = "ComplexPassword!1234"
}

resource "azurerm_resource_group" "rg" {
  name     = var.resource_group
  location = var.location
}

resource "azurerm_storage_account" "stor" {
  name                     = "${var.dns_name}stor"
  resource_group_name      = azurerm_resource_group.rg.name
  location                 = var.location
  account_tier             = "Standard"
  account_replication_type = var.storage_account_type
}

resource "azurerm_virtual_network" "vnet" {
  name                = var.virtual_network_name
  address_space       = [var.address_space]
  location            = var.location
  resource_group_name = azurerm_resource_group.rg.name
}

resource "azurerm_subnet" "subnet" {
  name                 = "${var.virtual_network_name}-subnet"
  resource_group_name  = azurerm_resource_group.rg.name
  virtual_network_name = azurerm_virtual_network.vnet.name
  address_prefixes     = [var.subnet_prefix]
}

resource "azurerm_public_ip" "lbpip" {
  name                = "${var.dns_name}-publicip"
  location            = var.location
  resource_group_name = azurerm_resource_group.rg.name
  allocation_method   = "Dynamic"
  domain_name_label   = var.dns_name
}

resource "azurerm_network_interface" "nic" {
  name                = "${var.dns_name}-nic"
  location            = var.location
  resource_group_name = azurerm_resource_group.rg.name

  ip_configuration {
    name                          = "internal"
    subnet_id                     = azurerm_subnet.subnet.id
    private_ip_address_allocation = "Dynamic"
    public_ip_address_id          = azurerm_public_ip.lbpip.id
  }
}

resource "azurerm_virtual_machine" "vm" {
  name                  = "${var.dns_name}-vm"
  location              = var.location
  resource_group_name   = azurerm_resource_group.rg.name
  network_interface_ids = [azurerm_network_interface.nic.id]
  vm_size               = var.vm_size

  storage_os_disk {
    name              = "myosdisk1"
    caching           = "ReadWrite"
    create_option     = "FromImage"
    managed_disk_type = "Standard_LRS"
  }

  storage_image_reference {
    publisher = "Canonical"
    offer     = "UbuntuServer"
    sku       = "16.04-LTS"
    version   = "latest"
  }

  os_profile {
    computer_name  = var.dns_name
    admin_username = var.admin_username
    admin_password = var.admin_password
  }

  os_profile_linux_config {
    disable_password_authentication = false
  }
}

output "public_ip_address" {
  value = azurerm_public_ip.lbpip.ip_address
}

