# Create the OpenShift cluster using a custom module
module "openshift" {
  source          = "./modules/openshift"
  region          = var.region
  amisize         = "m5.2xlarge"
  vpc_cidr        = "10.0.0.0/16"
  subnet_cidr     = "10.0.1.0/24"
