// https://www.terraform.io/docs/providers/google/r/compute_firewall.html
// Need a firewall rule so that the bastion host is accessible, a smaller range (/32?) would be better,
// but for now, this will suffice.
resource "google_compute_firewall" "bastion-ssh" {
  name          = "gke-demo-bastion-fw"
  network       = var.vpc
  direction     = "INGRESS"
  project       = var.project
  source_ranges = ["0.0.0.0/0"]

  allow {
    protocol = "tcp"
    ports    = ["22"]
  }

  target_tags = var.net_tags
}

##############################################################
# This module allows the creation of a Network Watcher
##############################################################

# Network Watcher Creation
resource "azurerm_network_watcher" "Terra_NW" {
  name                = var.NWName
  location            = var.NWLocation
  resource_group_name = var.RGName

  tags = {
    Environment       = var.EnvironmentTag
    Usage             = var.EnvironmentUsageTag
    Owner             = var.OwnerTag
    ProvisioningDate  = var.ProvisioningDateTag
  }
}

##############################################################
# Variable declaration for Module
##############################################################

# The NW name
variable "NWName" {
  type = string
}

# The RG in which the NW is attached to
variable "RGName" {
  type = string
}

# The location in which the NW is attached to
variable "NWLocation" {
  type = string
}

# Tag value to help identify the resource.
# Required tags are EnvironmentTag defining the type of environment and
# EnvironmentUsageTag specifying the use case of the environment
variable "EnvironmentTag" {
  type    = string
  default = "Poc"
}

variable "EnvironmentUsageTag" {
  type    = string
  default = "Poc usage only"
}

variable "OwnerTag" {
  type    = string
  default = "That would be me"
}

variable "ProvisioningDateTag" {
  type    = string
  default = "Today :)"
}

##############################################################
# Outputs
##############################################################

# Output Name
output "Name" {
  value = azurerm_network_watcher.Terra_NW.name
}

# Output ID
output "Id" {
  value = azurerm_network_watcher.Terra_NW.id
}

