# Specifying a more recent Terraform version
terraform {
  required_version = ">= 1.0"
}

# Define GCP project variable
variable "project_id" {
  description = "The GCP project to use for integration tests"
  type        = string
}

# Define a variable for the service account with type specification
variable "service_account" {
  description = "Service account to attach to the instance. See https://www.terraform.io/docs/providers/google/r/compute_instance_template.html#service_account."
  type = object({
    email  = string
    scopes = list(string)
  })
  default = null
}

# Module for unmanaged instance group with static IPs
module "umig_static_ips" {
  source     = "../../../../examples/umig/static_ips"
  project_id = var.project_id
  region     = "us-central1"
  subnetwork = google_compute_subnetwork.main.name
  static_ips = [
    "10.128.0.10",
    "10.128.0.11",
    "10.128.0.12",
    "10.128.0.13"
  ]
  service_account = var.service_account
}

# Output self-links of the unmanaged instance groups
output "self_links" {
  description = "List of self-links to unmanaged instance groups"
  value       = module.umig_static_ips.self_links
}

# Output self-links of the instances in the unmanaged instance groups
output "instances_self_links" {
  description = "List of instance self-links"
  value       = module.umig_static_ips.instances_self_links
}

# Output the project ID used
output "project_id" {
  description = "The GCP project used for integration tests"
  value       = var.project_id
}

# Remote state data source configuration
data "terraform_remote_state" "bootstrap" {
  backend = "local"
  config = {
    path = "${path.cwd}/bootstrap.tfstate"
  }
}

# Local values for easier reference
locals {
  aws_launch_configuration = data.terraform_remote_state.bootstrap.outputs.aws_launch_configuration_masters
  subnet_ids               = data.terraform_remote_state.bootstrap.outputs.subnet_ids_masters
  aws_lbs                  = data.terraform_remote_state.bootstrap.outputs.aws_lbs_masters
}

# AWS Provider configuration
provider "aws" {
  region  = var.tectonic_aws_region
  profile = var.tectonic_aws_profile
  version = "~> 3.0"  # Updated to a more recent version

  assume_role {
    role_arn     = var.tectonic_aws_installer_role != "" ? var.tectonic_aws_installer_role : null
    session_name = "TECTONIC_INSTALLER_${var.tectonic_cluster_name}"
  }
}

# Resource for AWS Auto Scaling Group
resource "aws_autoscaling_group" "masters" {
  name                 = "${var.tectonic_cluster_name}-masters"
  desired_capacity     = var.tectonic_master_count
  max_size             = var.tectonic_master_count * 3
  min_size             = var.tectonic_master_count
  launch_configuration = local.aws_launch_configuration
  vpc_zone_identifier  = local.subnet_ids

  load_balancers = local.aws_lbs

  tags = [
    {
      key                 = "Name"
      value               = "${var.tectonic_cluster_name}-master"
      propagate_at_launch = true
    },
    {
      key                 = "kubernetes.io/cluster/${var.tectonic_cluster_name}"
      value               = "owned"
      propagate_at_launch = true
    },
    {
      key                 = "tectonicClusterID"
      value               = var.tectonic_cluster_id
      propagate_at_launch = true
    },
    var.tectonic_autoscaling_group_extra_tags,
  ]

  lifecycle {
    create_before_destroy = true
  }
}

# Variable definitions
variable "BaseName" {
  type = string
}

variable "ResourceGroupName" {
  type = string
}

variable "Location" {
  type    = list(string)
  default = ["westeurope", "northeurope"]
}

variable "Environments" {
  type    = list(string)
  default = ["dev", "test"]
}

variable "Tags" {
  type = map(string)
}

variable "StorageAccountBaseName" {
  type = string
}

variable "StorageAccountConfig" {
  type = map(string)
  default = {
    Tier            = "Standard"
    Kind            = "StorageV2"
    ReplicationType = "RAGRS"
  }
}

variable "StorageContainerName" {
  type = string
}

variable "StorageQueueNames" {
  type = list(string)
}

variable "StorageContainerType" {
  type    = string
  default = "private"
}

variable "CdnProfileSku" {
  type    = string
  default = "Standard_Microsoft"
}

variable "EndpointConfig" {
  type = map(string)
  default = {
    HttpAllowed  = false
    HttpsAllowed = true
    Optimisation = "GeneralWebDelivery"
  }
}

variable "SubscriptionId" {
  type = string
}

variable "TenantId" {
  type = string
}

variable "ClientId" {
  type = string
}

variable "ClientSecret" {
  type = string
}

# Resource definitions
resource "azurerm_storage_account" "StorageAccount" {
  for_each                = toset(var.Environments)
  name                    = "sa${lower(var.StorageAccountBaseName)}${each.key}"
  resource_group_name     = var.ResourceGroupName
  location                = var.Location[0]
  account_tier            = var.StorageAccountConfig["Tier"]
  account_kind            = var.StorageAccountConfig["Kind"]
  account_replication_type = var.StorageAccountConfig["ReplicationType"]
  tags = {
    costcode    = var.Tags["costcode"]
    environment = var.Tags["environment"]
    product     = var.Tags["product"]
  }
}

resource "azurerm_storage_container" "StorageContainer" {
  for_each             = toset(var.Environments)
  name                 = var.StorageContainerName
  resource_group_name  = var.ResourceGroupName
  storage_account_name = azurerm_storage_account.StorageAccount[each.key].name
  container_access_type = var.StorageContainerType
}

resource "azurerm_storage_queue" "StorageQueue" {
  for_each = { for env in var.Environments : env => { for name in var.StorageQueueNames : name => {
    environment = env
    queue_name  = name
  }}}
  name                 = each.value.queue_name
  resource_group_name  = var.ResourceGroupName
  storage_account_name = azurerm_storage_account.StorageAccount[each.value.environment].name
}

resource "azurerm_cdn_profile" "CdnProfile" {
  name                = "CDN-${var.BaseName}"
  location            = var.Location[0]
  resource_group_name = var.ResourceGroupName
  sku                 = var.CdnProfileSku
  tags = {
    costcode    = var.Tags["costcode"]
    environment = var.Tags["environment"]
    product     = var.Tags["product"]
  }
}

resource "azurerm_cdn_endpoint" "CdnEndpoint" {
  for_each                    = toset(var.Environments)
  name                        = "EP-${var.BaseName}-${each.key}"
  profile_name                = azurerm_cdn_profile.CdnProfile.name
  location                    = var.Location[0]
  resource_group_name         = var.ResourceGroupName
  is_http_allowed             = var.EndpointConfig["HttpAllowed"]
  is_https_allowed            = var.EndpointConfig["HttpsAllowed"]
  optimization_type           = var.EndpointConfig["Optimisation"]
  querystring_caching_behaviour = "NotSet"
  origin_host_header          = replace(replace(azurerm_storage_account.StorageAccount[each.key].primary_blob_endpoint, "https://", ""), "/", "")
  origin {
    name    = "EPO-${var.BaseName}-${each.key}"
    host_name = replace(replace(azurerm_storage_account.StorageAccount[each.key].primary_blob_endpoint, "https://", ""), "/", "")
  }
}

# Output definitions
output "BlobEndpoints" {
  value = { for env in var.Environments : env => azurerm_storage_account.StorageAccount[env].primary_blob_endpoint }
}

output "AccessKeys" {
  value = { for env in var.Environments : env => azurerm_storage_account.StorageAccount[env].primary_access_key }
}

output "ConnectionStrings" {
  value = { for env in var.Environments : env => azurerm_storage_account.StorageAccount[env].primary_blob_connection_string }
}

output "CdnEndpoints" {
  value = { for env in var.Environments : env => azurerm_cdn_endpoint.CdnEndpoint[env].host_name }
}

output "StorageAccountNames" {
  value = { for env in var.Environments : env => "sa${lower(var.StorageAccountBaseName)}${env}" }
}

