provider "aws" {
  region = var.region
}

data "terraform_remote_state" "vpc" {
  backend = "s3"
  config = {
    bucket = var.state_bucket
    key    = var.vpc_state_key
    region = var.region
  }
}

data "terraform_remote_state" "consul" {
  backend = "s3"
  config = {
    bucket = var.state_bucket
    key    = var.consul_state_key
    region = var.region
  }
}

resource "aws_security_group" "docker_exapp" {
  name        = "${data.terraform_remote_state.vpc.outputs.vpc_short_name}-${var.docker_exapp}"
  description = "Docker Exposed Applications"
  vpc_id      = data.terraform_remote_state.vpc.outputs.vpc_id

  tags = {
    Name = "${data.terraform_remote_state.vpc.outputs.vpc_name} Docker Exposed Applications"
  }
}

resource "aws_security_group_rule" "docker_exapp_itcp" {
  count = length(var.docker_exapp_itcp)

  type              = "ingress"
  from_port         = var.docker_exapp_itcp[count.index]
  to_port           = var.docker_exapp_itcp[count.index]
  protocol          = "tcp"
  security_group_id = aws_security_group.docker_exapp.id
  source_security_group_id = data.terraform_remote_state.vpc.outputs.sg_admin
}

resource "aws_security_group_rule" "docker_exapp_iudp" {
  count = length(var.docker_exapp_iudp)

  type              = "ingress"
  from_port         = var.docker_exapp_iudp[count.index]
  to_port           = var.docker_exapp_iudp[count.index]
  protocol          = "udp"
  security_group_id = aws_security_group.docker_overlay.id
  source_security_group_id = data.terraform_remote_state.vpc.outputs.sg_admin
}

resource "aws_security_group" "docker_overlay" {
  name        = "${data.terraform_remote_state.vpc.outputs.vpc_short_name}-${var.docker_overlay}"
  description = "Docker Overlay"
  vpc_id      = data.terraform_remote_state.vpc.outputs.vpc_id

  tags = {
    Name = "${data.terraform_remote_state.vpc.outputs.vpc_name} Docker Overlay"
  }
}

resource "aws_security_group_rule" "docker_overlay_itcp" {
  count = length(var.docker_overlay_itcp)

  type              = "ingress"
  from_port         = var.docker_overlay_itcp[count.index]
  to_port           = var.docker_overlay_itcp[count.index]
  protocol          = "tcp"
  cidr_blocks       = [data.terraform_remote_state.vpc.outputs.private_subnets_cidr_block]
  security_group_id = aws_security_group.docker_overlay.id
}

resource "aws_security_group_rule" "docker_overlay_iudp" {
  count = length(var.docker_overlay_iudp)

  type              = "ingress"
  from_port         = var.docker_overlay_iudp[count.index]
  to_port           = var.docker_overlay_iudp[count.index]
  protocol          = "udp"
  cidr_blocks       = [data.terraform_remote_state.vpc.outputs.private_subnets_cidr_block]
  security_group_id = aws_security_group.docker_overlay.id
}

resource "aws_security_group_rule" "docker_overlay_egress" {
  type              = "egress"
  from_port         = 0
  to_port           = 0
  protocol          = "-1"
  cidr_blocks       = ["0.0.0.0/0"]
  security_group_id = aws_security_group.docker_overlay.id
}

