# This script setups an Azure Virtual Network with associated resources
resource "azurerm_virtual_network" "vnet" {
  for_each                = toset(var.Location)
  name                    = "VNET-${var.BaseName}-${each.key}"
  location                = each.value
  resource_group_name     = var.ResourceGroupName
  address_space           = [var.VnetAddressSpace[each.index]]
  ddos_protection_plan {
    id                    = var.DdosPlanId
    enable                = true
  }
}

resource "azurerm_subnet" "subnet" {
  for_each                = toset(var.Location)
  name                    = "SUBNET-${var.BaseName}-${each.key}"
  resource_group_name     = var.ResourceGroupName
  virtual_network_name    = azurerm_virtual_network.vnet[each.key].name
  address_prefixes        = [var.SubnetAddressPrefix[each.index]]
  network_security_group_id = azurerm_network_security_group.nsg[each.key].id
}

resource "azurerm_public_ip" "public_ip" {
  for_each                = toset(var.Location)
  name                    = "PublicIP-${var.BaseName}-${each.key}"
  resource_group_name     = var.ResourceGroupName
  location                = each.value
  sku                     = var.PublicIpConfig["Sku"]
  allocation_method       = var.PublicIpConfig["AllocationMethod"]
  domain_name_label       = lower("${var.BaseName}-${each.key}")
  tags                    = var.Tags
}

resource "azurerm_network_security_group" "nsg" {
  for_each                = toset(var.Location)
  name                    = "NSG-${var.BaseName}-${each.key}"
  resource_group_name     = var.ResourceGroupName
  location                = each.value
  tags                    = var.Tags
}

# Add security rules as needed...

resource "azurerm_application_gateway" "app_gateway" {
  for_each                = toset(var.Location)
  name                    = "AppGW-${var.BaseName}-${each.key}"
  resource_group_name     = var.ResourceGroupName
  location                = each.value
  sku {
    name                  = var.AppGatewayMiscConfig["SkuName"]
    tier                  = var.AppGatewayMiscConfig["SkuTier"]
    capacity              = var.AppGatewayMiscConfig["SkuCapacity"]
  }
  gateway_ip_configuration {
    name                  = "appGatewayIpConfig-${each.key}"
    subnet_id             = azurerm_subnet.subnet[each.key].id
  }
  frontend_port {
    name                  = "httpPort"
    port                  = var.AppGatewayMiscConfig["RedirectPort"]
  }
  frontend_port {
    name                  = "httpsPort"
    port                  = var.AppGatewayMiscConfig["FrontendPort"]
  }
  frontend_ip_configuration {
    name                  = "appGatewayFrontendIp"
    public_ip_address_id  = azurerm_public_ip.public_ip[each.key].id
  }
  # Configure listeners, rules, backend pools, etc.
}

