resource "aws_launch_configuration" "worker" {
  ebs_block_device {
    device_name  = "/dev/xvdf"
    volume_size  = var.volume_size["ebs"]
    volume_type  = "gp2"
  }
  iam_instance_profile = var.instance_profile_name
  image_id             = var.ami_id
  instance_type        = var.instance_type
  key_name             = var.key_name

  root_block_device {
    volume_size = var.volume_size["root"]
    volume_type = "gp2"
  }

  security_groups = [var.security_group_id]
  user_data       = data.template_file.cloud-config.rendered
}

resource "aws_autoscaling_group" "worker" {
  name                      = "worker-${var.worker_name}-${var.name}"
  desired_capacity          = var.capacity["desired"]
  health_check_grace_period = 60
  health_check_type         = "EC2"
  force_delete              = true
  launch_configuration      = aws_launch_configuration.worker.name
  max_size                  = var.capacity["max"]
  min_size                  = var.capacity["min"]
  vpc_zone_identifier       = split(",", var.subnet_ids)

  dynamic "tag" {
    for_each = {
      builtWith   = "terraform",
      depends-id  = var.depends_id,
      KubernetesCluster = var.name,
      kz8s        = var.name,
      Name        = "worker-${var.name}",
      role        = "worker",
      version     = var.kubelet_image_tag,
      visibility  = "private"
    }
    content {
      key                 = tag.key
      value               = tag.value
      propagate_at_launch = contains(["builtWith", "KubernetesCluster", "kz8s", "Name", "role", "version", "visibility"], tag.key)
    }
  }
}

resource "null_resource" "dummy_dependency" {
  depends_on = [
    aws_autoscaling_group.worker,
    aws_launch_configuration.worker
  ]
}

output "autoscaling_group_name" {
  value = aws_autoscaling_group.worker.name
}

output "depends_id" {
  value = null_resource.dummy_dependency.id
}

