# EBS VOLUME
resource "aws_ebs_volume" "ebs" {
  count = var.number_of_ec2

  availability_zone = element(aws_instance.ec2.*.availability_zone, count.index)
  size              = var.vol_space_size
  type              = var.vol_space_type

  tags = {
    Name = format(
      "%s.aws-%s.ebs.%s-%02d%s", 
      var.customer,
      var.region,
      var.service, 
      (count.index / length(var.az)) + 1,
      element(split("", element(var.az, count.index % length(var.az))), length(split("", element(var.az, count.index % length(var.az)))) - 1)
    )
    Project          = var.project
    Environment      = var.environment
    ManagementModule = "oxa-ec2-multiaz-public"
    ManagementTool   = "Terraform"
  }
}

# VOLUME ATTACHMENT
resource "aws_volume_attachment" "volume_attachment" {
  count = var.number_of_ec2

  device_name = "/dev/xvdb"

  volume_id   = element(aws_ebs_volume.ebs.*.id, count.index)
  instance_id = element(aws_instance.ec2.*.id, count.index)
}

# EIP
resource "aws_eip" "eip" {
  count = var.number_of_ec2
  vpc   = true
}

# EIP ASSOCIATION
resource "aws_eip_association" "eip_association" {
  count = var.number_of_ec2

  instance_id   = element(aws_instance.ec2.*.id, count.index)
  allocation_id = element(aws_eip.eip.*.id, count.index)
}

# CLOUDWATCH METRIC ALARM
resource "aws_cloudwatch_metric_alarm" "ec2_instance_cpuutilization" {
  count               = var.number_of_ec2
  alarm_name          = format("alarmCPUUtilization_%s_Ec2Instance_%s_%02d", var.environment, var.service, count.index + 1)
  alarm_description   = "EC2 instance CPU utilization"
  comparison_operator = "GreaterThanThreshold"
  evaluation_periods  = 1
  metric_name         = "CPUUtilization"
  namespace           = "AWS/EC2"
  period              = 300
  statistic           = "Average"
  threshold           = var.alarm_cpu_threshold

  dimensions = {
    InstanceId = element(aws_instance.ec2.*.id, count.index)
  }

  alarm_actions = var.alarm_actions
}

