resource "aws_s3_bucket" "bucket" {
  bucket = "${var.prefix}-${var.service_name}-logs"
  acl    = "private"

  lifecycle_rule {
    id      = "expire-all"
    prefix  = "/"
    enabled = true

    expiration {
      days = var.expiration_days
    }
  }
}
output "bucket_name" {
  value = aws_s3_bucket.bucket.id
}

output "bucket_arn" {
  value = aws_s3_bucket.bucket.arn
}

provider "google" {
  alias = "target"
}


variable "google_project" {
  description = "The google project id to create for CRL to run integration tests within."
  type        = string
}

variable "folder_id" {
  type        = string
  description = "What folder to create google_project and a test folder under."
}

variable "billing_account_id" {
  type        = string
  description = "What billing account to assign to the project."
}

# We separate whether the roles/billing.user is set on the CRL test SA as its own flag because the
# Broad SA that runs terraform does not want to have the broad permissions to set modify
# permissions on the service account. This was done manually instead for the Broad.
variable "enable_billing_user" {
  type        = bool
  description = "Whether to set the CRL test SA as a billing user on the billing account."
  default     = true
}


/**
 * # crl-test
 *
 * This terraform module defines the resources needed for running
 * [Cloud Resource Library](https://github.com/DataBiosphere/terra-cloud-resource-lib) (CRL) integration tests.
 * 
 * For more information, check out the [MC-Terra deployment doc](https://docs.dsp-devops.broadinstitute.org/mc-terra/mcterra-deployment)
 * and our [Terraform best practices](https://docs.dsp-devops.broadinstitute.org/best-practices-guides/terraform).
 *
 * This documentation is generated with [terraform-docs](https://github.com/segmentio/terraform-docs)
 * `terraform-docs markdown --no-sort . > README.md`
 */


resource "google_project" "project" {
  name                = var.google_project
  project_id          = var.google_project
  billing_account     = var.billing_account_id
  folder_id           = var.folder_id
  auto_create_network = false
}


# Service accounts for the CRL Integration tests to use.
resource "google_service_account" "crl_test_admin" {
  project      = google_project.project.name
  account_id   = "crl-test-admin"
  display_name = "crl-test-admin"
}

resource "google_service_account" "crl_test_user" {
  project      = google_project.project.name
  account_id   = "crl-test-user"
  display_name = "crl-test-user"
}

locals {
  roles = [
    # Roles needed as a part of CRL functionality.
    "roles/cloudtrace.agent",
    "roles/logging.logWriter",
    "roles/monitoring.metricWriter",
    # Roles used in integration testing.
    "roles/storage.admin",
    "roles/bigquery.admin",
  ]

  # Roles used to manage projects for integration testing.
  folder_roles = [
    "roles/resourcemanager.folderAdmin",
    "roles/resourcemanager.projectCreator",
    "roles/resourcemanager.projectDeleter",
  ]
}

resource "google_project_iam_member" "crl_test_admin" {
  count   = length(local.roles)
  project = google_project.project.name
  role    = local.roles[count.index]
  member  = "serviceAccount:${google_service_account.crl_test_admin.email}"
}

resource "google_folder_iam_member" "app_folder_roles" {
  count    = length(local.folder_roles)
  provider = google.target
  folder   = google_folder.test_resource_container.id
  role     = local.folder_roles[count.index]
  member   = "serviceAccount:${google_service_account.crl_test_admin.email}"
}

resource "google_billing_account_iam_member" "crl_test_admin" {
  count              = var.enable_billing_user ? 1 : 0
  billing_account_id = var.billing_account_id
  role               = "roles/billing.user"
  member             = "serviceAccount:${google_service_account.crl_test_admin.email}"
}


module "enable-services" {
  source      = "github.com/broadinstitute/terraform-shared.git//terraform-modules/api-services?ref=services-0.3.0-tf-0.12"
  enable_flag = "1"
  providers = {
    google.target = google.target
  }
  project = google_project.project.name
  services = [
    # APIs needed by CRL functionality.
    "cloudtrace.googleapis.com",
    "logging.googleapis.com",
    "monitoring.googleapis.com",
    # APIs exercised by CRL integration testing.
    "storage-api.googleapis.com",
    "storage-component.googleapis.com",
    "bigquery.googleapis.com",
    "cloudbilling.googleapis.com",
    "iam.googleapis.com",
  ]
}


# Folder used to contain projects created in CRL integration tests.
# We create a separate folder to scope the CRL test SA broad folder permissions to a single purpose folder.
resource "google_folder" "test_resource_container" {
  display_name = "CRL Test resource container"
  parent       = "folders/${var.folder_id}"

  provider = google.target
}


output "test_resource_container_folder_id" {
  value       = google_folder.test_resource_container.id
  description = "The folder id of the folder the admin service account has permissions to edit."
}

#
# Service Account Outputs
# User of this module is expected to create the google_service_account_key resource and store the key for the
# output service accounts.
#

output "service_account_email_admin" {
  value       = google_service_account.crl_test_admin.email
  description = "Admin Google service account email"
}

output "service_account_email_user" {
  value       = google_service_account.crl_test_user.email
  description = "User Google service account email"
}

provider "aws" {
  region                 = var.aws_region
  shared_credentials_file = var.aws_shared_credentials_file
  profile                = var.aws_profile
}

# Variables
variable "aws_region" {}
variable "aws_shared_credentials_file" {}
variable "aws_profile" {}
variable "devCIDR" {}
variable "appname" {}
variable "key_name" {}
variable "public_key_path" {}
variable "ec2_instance_type" {}
variable "elb_healthy_threshold" {}
variable "elb_unhealthy_threshold" {}
variable "elb_timeout" {}
variable "elb_interval" {}

# AWS Key Pair
resource "aws_key_pair" "auth" {
  key_name   = var.key_name
  public_key = file(var.public_key_path)
}

# VPC
resource "aws_vpc" "vpc" {
  cidr_block = "10.0.0.0/16"
  tags = {
    Name = var.appname
  }
}

# Subnets
resource "aws_subnet" "public" {
  vpc_id            = aws_vpc.vpc.id
  cidr_block        = "10.0.1.0/24"
  map_public_ip_on_launch = true
  availability_zone = "${var.aws_region}a"
  tags = {
    Name = "${var.appname}-public"
  }
}

resource "aws_subnet" "private" {
  vpc_id            = aws_vpc.vpc.id
  cidr_block        = "10.0.11.0/26"
  map_public_ip_on_launch = false
  availability_zone = "${var.aws_region}b"
  tags = {
    Name = "${var.appname}-private"
  }
}

# Elastic IP
resource "aws_eip" "nat_gw" {
  vpc = true
}

# Route Tables
resource "aws_internet_gateway" "i_gw" {
  vpc_id = aws_vpc.vpc.id
  tags = {
    Name = var.appname
  }
}

resource "aws_nat_gateway" "nat_gw" {
  allocation_id = aws_eip.nat_gw.id
  subnet_id     = aws_subnet.public.id
}

resource "aws_route_table" "public" {
  vpc_id = aws_vpc.vpc.id
  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.i_gw.id
  }
  tags = {
    Name = var.appname
  }
}

resource "aws_route_table" "private" {
  vpc_id = aws_vpc.vpc.id
  route {
    cidr_block    = "0.0.0.0/0"
    nat_gateway_id = aws_nat_gateway.nat_gw.id
  }
  tags = {
    Name = var.appname
  }
}

# Route Table Associations
resource "aws_route_table_association" "public" {
  subnet_id      = aws_subnet.public.id
  route_table_id = aws_route_table.public.id
}

resource "aws_route_table_association" "private" {
  subnet_id      = aws_subnet.private.id
  route_table_id = aws_route_table.private.id
}

# Security Groups
resource "aws_security_group" "jump_service" {
  name        = "${var.appname}_sg_jump_service"
  description = "sg for jump_service"
  vpc_id      = aws_vpc.vpc.id

  ingress {
    from_port   = 22
    to_port     = 22
    protocol    = "tcp"
    cidr_blocks = [var.devCIDR]
  }

  ingress {
    from_port   = -1
    to_port     = -1
    protocol    = "icmp"
    cidr_blocks = [var.devCIDR]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "${var.appname}_sg_jump_service"
  }
}

resource "aws_security_group" "elb" {
  name        = "${var.appname}_sg_elb"
  description = "sg for elb"
  vpc_id      = aws_vpc.vpc.id

  ingress {
    from_port   = 0
    to_port     = 65535
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  ingress {
    from_port   = -1
    to_port     = -1
    protocol    = "icmp"
    cidr_blocks = [var.devCIDR]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "${var.appname}_sg_elb"
  }
}

resource "aws_security_group" "backend_services" {
  name        = "${var.appname}_sg_backend_service"
  description = "sg for backend_service"
  vpc_id      = aws_vpc.vpc.id

  ingress {
    from_port        = 22
    to_port          = 22
    protocol         = "tcp"
    security_groups  = [aws_security_group.jump_service.id]
  }

  ingress {
    from_port        = -1
    to_port          = -1
    protocol         = "icmp"
    security_groups  = [aws_security_group.jump_service.id]
  }

  ingress {
    from_port        = 8080
    to_port          = 8080
    protocol         = "tcp"
    security_groups  = [aws_security_group.elb.id]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "${var.appname}_sg_backend_service"
  }
}

# AWS AMI
data "aws_ami" "ubuntu" {
  most_recent = true

  filter {
    name   = "name"
    values = ["ubuntu/images/hvm-ssd/ubuntu-xenial-16.04-amd64-server-*"]
  }

  filter {
    name   = "virtualization-type"
    values = ["hvm"]
  }

  owners = ["099720109477"] # Canonical
}

# AWS Instances
resource "aws_instance" "jump_service" {
  instance_type          = var.ec2_instance_type
  ami                    = data.aws_ami.ubuntu.id
  key_name               = aws_key_pair.auth.key_name
  vpc_security_group_ids = [aws_security_group.jump_service.id]
  subnet_id              = aws_subnet.public.id

  tags = {
    Name = "${var.appname}_jump_service"
  }
}

resource "aws_instance" "backend_service1" {
  instance_type          = var.ec2_instance_type
  ami                    = data.aws_ami.ubuntu.id
  key_name               = aws_key_pair.auth.key_name
  vpc_security_group_ids = [aws_security_group.backend_services.id]
  subnet_id              = aws_subnet.private.id

  tags = {
    Name = "${var.appname}_backend_service1"
  }
}

resource "aws_instance" "backend_service2" {
  instance_type          = var.ec2_instance_type
  ami                    = data.aws_ami.ubuntu.id
  key_name               = aws_key_pair.auth.key_name
  vpc_security_group_ids = [aws_security_group.backend_services.id]
  subnet_id              = aws_subnet.private.id

  tags = {
    Name = "${var.appname}_backend_service2"
  }
}

resource "aws_instance" "backend_service3" {
  instance_type          = var.ec2_instance_type
  ami                    = data.aws_ami.ubuntu.id
  key_name               = aws_key_pair.auth.key_name
  vpc_security_group_ids = [aws_security_group.backend_services.id]
  subnet_id              = aws_subnet.private.id

  tags = {
    Name = "${var.appname}_backend_service3"
  }

  provisioner "local-exec" {
    command = <<EOP
cat > ../ansible/all.host <<'EOF'
[jump_service]
${aws_instance.jump_service.public_ip}
[jump_service:vars]
ansible_python_interpreter=/usr/bin/python3
[backend_services]
${aws_instance.backend_service1.private_ip}
${aws_instance.backend_service2.private_ip}
${aws_instance.backend_service3.private_ip}
[backend_services:vars]
ansible_python_interpreter=/usr/bin/python3
ansible_ssh_common_args='-o ProxyCommand="ssh -W %h:%p -q ubuntu@${aws_instance.jump_service.public_ip}"'
EOF
EOP
  }
}

# AWS ELB
resource "aws_elb" "elb" {
  name               = "${var.appname}-elb"
  subnets            = [aws_subnet.public.id, aws_subnet.private.id]
  security_groups    = [aws_security_group.elb.id]

  cross_zone_load_balancing   = true
  idle_timeout                = 400
  connection_draining         = true
  connection_draining_timeout = 400

  listener {
    instance_port     = 8080
    instance_protocol = "http"
    lb_port           = 80
    lb_protocol       = "http"
  }

  health_check {
    healthy_threshold   = var.elb_healthy_threshold
    unhealthy_threshold = var.elb_unhealthy_threshold
    timeout             = var.elb_timeout
    target              = "HTTP:8080/health"
    interval            = var.elb_interval
  }

  instances = [
    aws_instance.backend_service1.id,
    aws_instance.backend_service2.id,
    aws_instance.backend_service3.id
  ]

  tags = {
    Name = "${var.appname}-elb"
  }
}

