  vars = {
    kubelet_image_url = replace(var.container_images["hyperkube"], var.image_re, "$1")
    kubelet_image_tag = replace(var.container_images["hyperkube"], var.image_re, "$2")
  }
}

data "ignition_file" "installer_kubelet_env" {
  filesystem = "root"
  path       = "/etc/kubernetes/installer/kubelet.env"
  mode       = 0644

  content = data.template_file.installer_kubelet_env.rendered
}

data "template_file" "tx_off" {
  template = file("${path.module}/resources/services/tx-off.service")
}

data "ignition_systemd_unit" "tx_off" {
  name    = "tx-off.service"
  enabled = true
  content = data.template_file.tx_off.rendered
}

data "template_file" "azure_udev_rules" {
  template = file("${path.module}/resources/udev/66-azure-storage.rules")
}

data "ignition_file" "azure_udev_rules" {
  filesystem = "root"
  path       = "/etc/udev/rules.d/66-azure-storage.rules"
  mode       = 0644

  content = data.template_file.azure_udev_rules.rendered
}

data "template_file" "coreos_metadata" {
  template = file("${path.module}/resources/dropins/10-metadata.conf")

  vars = {
    metadata_provider = var.metadata_provider
  }
}

data "ignition_systemd_unit" "coreos_metadata" {
  name    = "coreos-metadata.service"
  enabled = true

  dropin {
    name    = "10-metadata.conf"
    content = data.template_file.coreos_metadata.rendered
  }
}

data "template_file" "gcs_puller" {
  vars = {
    gcloudsdk_image = var.container_images["gcloudsdk"]
  }

  template = file("${path.module}/resources/bin/gcs-puller.sh")
}

data "ignition_file" "gcs_puller" {
  filesystem = "root"
  path       = "/opt/gcs-puller.sh"
  mode       = 0755

  content = data.template_file.gcs_puller.rendered
}

data "ignition_systemd_unit" "iscsi" {
  name    = "iscsid.service"
  enabled = var.iscsi_enabled
}

data "template_file" "profile_env" {
  vars = {
    http_proxy  = var.http_proxy
    https_proxy = var.https_proxy
    no_proxy    = join(",", var.no_proxy)
  }

  template = file("${path.module}/resources/proxy/profile.env")
}

data "ignition_file" "profile_env" {
  path       = "/etc/profile.env"
  mode       = 0644
  filesystem = "root"

  content = data.template_file.profile_env.rendered
}

data "template_file" "systemd_default_env" {
  vars = {
    http_proxy  = var.http_proxy
    https_proxy = var.https_proxy
    no_proxy    = join(",", var.no_proxy)
  }

  template = file("${path.module}/resources/proxy/10-default-env.conf")
}

data "ignition_file" "systemd_default_env" {
  path       = "/etc/systemd/system.conf.d/10-default-env.conf"
  mode       = 0644
  filesystem = "root"

  content = data.template_file.systemd_default_env.rendered
}

data "template_file" "update_ca_certificates_dropin" {
  template = file("${path.module}/resources/dropins/10-always-update-ca-certificates.conf")
}

data "ignition_systemd_unit" "update_ca_certificates_dropin" {
  name    = "update-ca-certificates.service"
  enabled = true

  dropin {
    name    = "10-always-update-ca-certificates.conf"
    content = data.template_file.update_ca_certificates_dropin.rendered
  }
}

data "ignition_file" "kube_ca_cert_pem" {
  filesystem = "root"
  path       = "/etc/ssl/certs/kube_ca.pem"
  mode       = 0400
  uid        = 0
  gid        = 0

  content = var.kube_ca_cert_pem
}

data "ignition_file" "etcd_ca_cert_pem" {
  filesystem = "root"
  path       = "/etc/ssl/certs/etcd_ca.pem"
  mode       = 0400
  uid        = 0
  gid        = 0

  content = var.etcd_ca_cert_pem
}

data "ignition_file" "ingress_ca_cert_pem" {
  filesystem = "root"
  path       = "/etc/ssl/certs/ingress_ca.pem"
  mode       = 0400
  uid        = 0
  gid        = 0

  content = var.ingress_ca_cert_pem
}

data "ignition_file" "custom_ca_cert_pem" {
  count = length(var.custom_ca_cert_pem_list)

  filesystem = "root"
  path       = "/etc/ssl/certs/custom_ca_${count.index}.pem"
  mode       = 0400
  uid        = 0
  gid        = 0

  content = var.custom_ca_cert_pem_list[count.index]
}

locals {
  etcd_initial_cluster_list = concat(var.etcd_initial_cluster_list, ["dummy"])

  metadata_env = "EnvironmentFile=/run/metadata/coreos"

  metadata_deps = <<EOF
Requires=coreos-metadata.service
After=coreos-metadata.service
EOF
}

data "template_file" "etcd_names" {
  count    = var.etcd_count
  template = "${var.cluster_name}-etcd-${count.index}${var.base_domain == "" ? "" : ".${var.base_domain}"}"
}

data "template_file" "advertise_client_urls" {
  count    = var.etcd_count
  template = "https://${var.etcd_advertise_name_list[count.index]}:2379"
}

data "template_file" "initial_advertise_peer_urls" {
  count    = var.etcd_count
  template = "https://${var.etcd_advertise_name_list[count.index]}:2380"
}

data "template_file" "initial_cluster" {
  count    = length(var.etcd_initial_cluster_list) > 0 ? var.etcd_count : 0
  template = "${data.template_file.etcd_names.*.rendered[count.index]}=https://${local.etcd_initial_cluster_list[count.index]}:2380"
}

data "template_file" "etcd" {
  count    = var.etcd_count
  template = file("${path.module}/resources/dropins/40-etcd-cluster.conf")

  vars = {
    advertise_client_urls       = data.template_file.advertise_client_urls.*.rendered[count.index]
    container_image             = var.container_images["etcd"]
    initial_advertise_peer_urls = data.template_file.initial_advertise_peer_urls.*.rendered[count.index]
    initial_cluster             = length(var.etcd_initial_cluster_list) > 0 ? format("--initial-cluster=%s", join(",", data.template_file.initial_cluster.*.rendered)) : ""
    metadata_deps               = var.use_metadata ? local.metadata_deps : ""
    metadata_env                = var.use_metadata ? local.metadata_env : ""
    name                        = data.template_file.etcd_names.*.rendered[count.index]
    scheme                      = "https"
  }
}

data "ignition_systemd_unit" "etcd" {
  count   = var.etcd_count
  name    = "etcd-member.service"
  enabled = true

  dropin {
    name    = "40-etcd-cluster.conf"
    content = data.template_file.etcd.*.rendered[count.index]
  }
}

data "ignition_file" "etcd_ca" {
  count = var.etcd_count > 0 ? 1 : 0

  path       = "/etc/ssl/etcd/ca.crt"
  mode       = 0644
  uid        = 232
  gid        = 232
  filesystem = "root"

  content = var.etcd_ca_cert_pem
}

data "ignition_file" "etcd_client_key" {
  path       = "/etc/ssl/etcd/client.key"
