provider "aws" {
  region = var.aws_region
}

# Stores current account and user data
data "aws_caller_identity" "current" {}

resource "random_id" "bucket_uuid" {
  byte_length = 8
}

variable "aws_region" {
  description = "AWS Region"
}

variable "aws_key_name" {
  description = "SSH Key Name"
}

variable "private_key_path" {
  description = "Path to Private SSH Key"
}

variable "pcap_s3_bucket" {
  description = "S3 Bucket for PCAP storage"
  default     = "pcap_bucket"
}

variable "environment_name" {
  default = "testing"
}

variable "vpc_cidr" {
  description = "VPC netblock"
  default     = "10.0.0.0/16"
}

variable "private_subnet_cidr" {
  description = "VPC private subnet"
  default     = "10.0.0.0/24"
}

variable "private_viewer_ip" {
  description = "Moloch Viewer Private IP"
  default     = "10.0.0.15"
}

variable "private_capture_ip" {
  description = "Moloch Capture Private IP"
  default     = "10.0.0.16"
}

variable "viewer_ami" {
  description = "Current Moloch Viewer AMI"
}

variable "moloch_instance_type" {
  description = "Moloch Instance Type"
  default     = "t2.medium"
}

variable "capture_ami" {
  description = "Current Moloch Capture AMI"
}

variable "web_instance_type" {
  description = "Web Instance Type"
  default     = "t2.medium"
}

data "template_file" "capture_config" {
  template = file("${path.module}/conf/capture-config.tpl")
  vars = {
    aws_region        = var.aws_region
    s3_bucket         = aws_s3_bucket.pcap_bucket.bucket
    moloch_access_id  = aws_iam_access_key.moloch_capture.id
    moloch_secret_key = aws_iam_access_key.moloch_capture.secret
    viewer_private    = var.private_viewer_ip
  }
}

data "template_file" "viewer_config" {
  template = file("${path.module}/conf/viewer-config.tpl")
  vars = {
    aws_region        = var.aws_region
    s3_bucket         = aws_s3_bucket.pcap_bucket.bucket
    moloch_access_id  = aws_iam_access_key.moloch_viewer.id
    moloch_secret_key = aws_iam_access_key.moloch_viewer.secret
    viewer_private    = var.private_viewer_ip
  }
}

resource "aws_vpc" "moloch_vpc" {
  cidr_block           = var.vpc_cidr
  enable_dns_hostnames = true
  enable_dns_support   = true
  tags = {
    Name        = "moloch_vpc-${var.environment_name}"
    Environment = var.environment_name
    Role        = "networking"
  }
}

resource "aws_internet_gateway" "vpc_gw" {
  vpc_id = aws_vpc.moloch_vpc.id
}

resource "aws_subnet" "private" {
  vpc_id            = aws_vpc.moloch_vpc.id
  cidr_block        = var.private_subnet_cidr
  availability_zone = "${var.aws_region}a"
  tags = {
    Name        = "private_subnet-${var.environment_name}"
    Environment = var.environment_name
    Role        = "networking"
  }
}

resource "aws_route_table" "public_rt" {
  vpc_id = aws_vpc.moloch_vpc.id
  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.vpc_gw.id
  }
  tags = {
    Name        = "public_rt-${var.environment_name}"
    Environment = var.environment_name
    Role        = "networking"
  }
}

resource "aws_route_table_association" "public_rta" {
  subnet_id      = aws_subnet.private.id
  route_table_id = aws_route_table.public_rt.id
}

resource "aws_security_group" "allow_viewer" {
  name        = "allow_viewer"
  description = "Allow all inbound ssh and moloch web traffic"
  vpc_id      = aws_vpc.moloch_vpc.id

  ingress {
    from_port   = 22
    to_port     = 22
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  ingress {
    from_port   = 8005
    to_port     = 8005
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  ingress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["10.0.0.0/24"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "allow_moloch"
    Role = "security"
  }
}

resource "aws_security_group" "allow_all" {
  name        = "allow_all"
  description = "Allow all inbound traffic"
  vpc_id      = aws_vpc.moloch_vpc.id

  ingress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "allow_all"
    Role = "security"
  }
}

resource "aws_iam_user" "moloch_viewer" {
  name          = "moloch_viewer"
  path          = "/"
  force_destroy = true
}

resource "aws_iam_access_key" "moloch_viewer" {
  user = aws_iam_user.moloch_viewer.name
}

resource "aws_iam_policy_attachment" "viewer_attach" {
  name       = "viewer-attachment"
  users      = [aws_iam_user.moloch_viewer.name]
  policy_arn = "arn:aws:iam::aws:policy/AmazonS3FullAccess"
}

resource "aws_iam_user" "moloch_capture" {
  name          = "moloch_capture"
  path          = "/"
  force_destroy = true
}

resource "aws_iam_access_key" "moloch_capture" {
  user = aws_iam_user.moloch_capture.name
}

resource "aws_iam_policy" "moloch_capture" {
  name        = "moloch_capture_policy"
  description = "moloch_capture_policy"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:PutObject"
        ]
        Resource = [
          "arn:aws:s3:::${aws_s3_bucket.pcap_bucket.bucket}",
          "arn:aws:s3:::${aws_s3_bucket.pcap_bucket.bucket}/*"
        ]
      }
    ]
  })
}

resource "aws_iam_policy_attachment" "capture_attach" {
  name       = "capture-attachment"
  users      = [aws_iam_user.moloch_capture.name]
  policy_arn = aws_iam_policy.moloch_capture.arn
}

resource "aws_instance" "viewer" {
  ami                         = var.viewer_ami
  availability_zone           = "${var.aws_region}a"
  instance_type               = var.moloch_instance_type
  key_name                    = var.aws_key_name
  subnet_id                   = aws_subnet.private.id
  private_ip                  = var.private_viewer_ip
  vpc_security_group_ids      = [aws_security_group.allow_viewer.id]
  associate_public_ip_address = true

  provisioner "remote-exec" {
    inline = [
      "sudo tee /etc/elasticsearch/elasticsearch.yml <<EOF",
      "network.host: ${var.private_viewer_ip}",
      "EOF",
      "sudo systemctl start elasticsearch.service",
      "sudo tee /data/moloch-nightly/etc/config.ini <<EOF",
      "${data.template_file.viewer_config.rendered}",
      "EOF",
      "sleep 30",
      "sudo systemctl reset-failed molochviewer.service",
      "sudo systemctl start molochviewer.service"
    ]

    connection {
      type        = "ssh"
      user        = "centos"
      private_key = file(var.private_key_path)
    }
  }

  tags = {
    Name        = "moloch_viewer_${var.environment_name}"
    Environment = var.environment_name
    Role        = "moloch"
  }
}

resource "aws_instance" "capture" {
  ami                         = var.capture_ami
  availability_zone           = "${var.aws_region}a"
  instance_type               = var.web_instance_type
  key_name                    = var.aws_key_name
  subnet_id                   = aws_subnet.private.id
  private_ip                  = var.private_capture_ip
  vpc_security_group_ids      = [aws_security_group.allow_all.id]
  associate_public_ip_address = true

  provisioner "remote-exec" {
    inline = [
      "sudo tee /data/moloch-nightly/etc/config.ini <<EOF",
      "${data.template_file.capture_config.rendered}",
      "EOF",
      "sleep 30",
      "sudo systemctl reset-failed molochcapture.service",
      "sudo systemctl start molochcapture.service",
    ]

    connection {
      type        = "ssh"
      user        = "centos"
      private_key = file(var.private_key_path)
    }
  }

  tags = {
    Name        = "moloch_capture_${var.environment_name}"
    Environment = var.environment_name
    Role        = "web"
  }
}

resource "aws_s3_bucket" "pcap_bucket" {
  bucket = "${var.pcap_s3_bucket}_${random_id.bucket_uuid.dec}"
  acl    = "private"

  lifecycle_rule {
    enabled = true
    prefix  = "/"
    noncurrent_version_expiration {
      days = 30
    }
  }

  tags = {
    Name        = var.pcap_s3_bucket
    Environment = var.environment_name
    Role        = "storage"
  }
}

output "viewer_public_dns" {
  value = aws_instance.viewer.public_dns
}

output "capture_public_dns" {
  value = aws_instance.capture.public_dns
}

output "viewer_public_ip" {
  value = aws_instance.viewer.public_ip
}

output "capture_public_ip" {
  value = aws_instance.capture.public_ip
}

output "viewer_access_id" {
  value = aws_iam_access_key.moloch_viewer.id
