output "capture_access_id" {
  value = aws_iam_access_key.moloch_capture.id
}

output "capture_secret_key" {
  value = aws_iam_access_key.moloch_capture.secret
}

output "pcap_s3_bucket" {
  value = aws_s3_bucket.pcap_bucket.bucket
}

