  client_id       = var.azure_access_key
  client_secret   = var.azure_secret_key
  tenant_id       = var.azure_tenant_id
}

# Create a resource group
resource "azurerm_resource_group" "development" {
  name     = "development"
  location = var.azure_region

  tags = {
    environment = "Development"
  }
}

# Main VPC that will contain everything.
resource "azurerm_virtual_network" "network" {
  name                = "developmentNetwork"
  address_space       = ["10.0.0.0/16"]
  location            = var.azure_region
  resource_group_name = azurerm_resource_group.development.name

  tags = {
    Name = "otto"
  }
}

# The public subnet is where resources connected to the internet will go
resource "azurerm_subnet" "subnet1" {
  name                 = "subnet1"
  resource_group_name  = azurerm_resource_group.development.name
  virtual_network_name = azurerm_virtual_network.network.name
  address_prefixes     = ["10.0.1.0/24"]
}

# Internal network for consul and Nomad
resource "azurerm_subnet" "subnet2" {
  name                 = "subnet2"
  resource_group_name  = azurerm_resource_group.development.name
  virtual_network_name = azurerm_virtual_network.network.name
  address_prefixes     = ["10.0.2.0/24"]
}

# Internal network for consul and Nomad
resource "azurerm_subnet" "subnet3" {
  name                 = "subnet3"
  resource_group_name  = azurerm_resource_group.development.name
  virtual_network_name = azurerm_virtual_network.network.name
  address_prefixes     = ["10.0.3.0/24"]
}

# Availability set; distribute nodes throughout AZ
resource "azurerm_availability_set" "development" {
  name                = "devavailabilityset"
  resource_group_name = azurerm_resource_group.development.name
  location            = azurerm_resource_group.development.location

  tags = {
    environment = "Development"
  }
}

# Public IP address
resource "azurerm_public_ip" "pubip" {
  name                = "developmentPublicIP"
  location            = var.azure_region
  resource_group_name = azurerm_resource_group.development.name
  allocation_method   = "Dynamic"
  domain_name_label   = "mydev"
}

resource "azurerm_public_ip" "pubip2" {
  name                = "devPublicIP2"
  location            = azurerm_resource_group.development.location
  resource_group_name = azurerm_resource_group.development.name
  allocation_method   = "Dynamic"
  domain_name_label   = "mydev2"

  tags = {
    type = "Backup"
  }
}

resource "azurerm_public_ip" "pubip3" {
  name                = "devPublicIP3"
  location            = azurerm_resource_group.development.location
  resource_group_name = azurerm_resource_group.development.name
  allocation_method   = "Dynamic"
  domain_name_label   = "myconsul"

  tags = {
    type = "Consul"
  }
}

# Attach LB Public IP address to both the VMs
resource "azurerm_public_ip" "lbpip" {
  name                = "loadBalancerPublicIP"
  resource_group_name = azurerm_resource_group.development.name
  location            = azurerm_resource_group.development.location
  allocation_method   = "Static"
  domain_name_label   = "mydevlb"

  tags = {
    environment = "Production"
  }
}

# Load Balancer rules
resource "azurerm_lb" "prodlb" {
  name                = "TestLoadBalancer"
  location            = azurerm_resource_group.development.location
  resource_group_name = azurerm_resource_group.development.name

  frontend_ip_configuration {
    name                 = "PublicIPAddress"
    public_ip_address_id = azurerm_public_ip.lbpip.id
  }
}

resource "azurerm_lb_probe" "caddy" {
  name                = "CaddyTCPProbe"
  resource_group_name = azurerm_resource_group.development.name
  loadbalancer_id     = azurerm_lb.prodlb.id
  protocol            = "Tcp"
  port                = 8080
  interval_in_seconds = 8
  number_of_probes    = 4
}

resource "azurerm_lb_backend_address_pool" "prodlbpool" {
  name                = "BackEndAddressPool"
  resource_group_name = azurerm_resource_group.development.name
  loadbalancer_id     = azurerm_lb.prodlb.id
}

resource "azurerm_lb_rule" "prodlbrule" {
  name                             = "LBRule"
  resource_group_name              = azurerm_resource_group.development.name
  loadbalancer_id                  = azurerm_lb.prodlb.id
  frontend_ip_configuration_name   = "PublicIPAddress"
  protocol                         = "Tcp"
  frontend_port                    = 80
  backend_port                     = 8080
  backend_address_pool_id          = azurerm_lb_backend_address_pool.prodlbpool.id
  probe_id                         = azurerm_lb_probe.caddy.id
}

# Attach the Public IP address to a Network Interface inside Subnet1 (10.0.1.0/24)
