resource "random_id" "dataflow_job_instance" {
  byte_length = 2
  keepers = {
    dataflow_template_version = var.dataflow_template_version
  }
}

locals {
  dataflow_temporary_gcs_bucket_name = "${var.project}-${var.dataflow_job_name}-${random_id.bucket_suffix.hex}"
  dataflow_temporary_gcs_bucket_path = "tmp/"
  dataflow_splunk_template_gcs_path  = "gs://dataflow-templates/${var.dataflow_template_version}/Cloud_PubSub_to_Splunk"
  dataflow_pubsub_template_gcs_path  = "gs://dataflow-templates/${var.dataflow_template_version}/Cloud_PubSub_to_Cloud_PubSub"
  dataflow_worker_service_account = (
    var.dataflow_worker_service_account != "" ?
      (
        var.use_externally_managed_dataflow_sa == false ?
          google_service_account.dataflow_worker_service_account[0].email :
        var.dataflow_worker_service_account
      ) :
    "${data.google_project.project.number}-compute@developer.gserviceaccount.com"
  )
  validate_sa_settings = (
    var.use_externally_managed_dataflow_sa && var.dataflow_worker_service_account == ""
  ) ? tobool("Please pass dataflow_worker_service_account if you want to manage it externally.") : true
  grant_service_account_roles = var.use_externally_managed_dataflow_sa == false
  grant_service_account_impersonation = (
    var.dataflow_worker_service_account != "" && var.use_externally_managed_dataflow_sa == false
  )
  subnet_name = coalesce(var.subnet, "${var.network}-${var.region}")
  project_log_sink_name = "${var.dataflow_job_name}-project-log-sink"
  organization_log_sink_name = "${var.dataflow_job_name}-organization-log-sink"
  dataflow_main_job_name = "${var.dataflow_job_name}-main-${random_id.dataflow_job_instance.hex}"
  dataflow_replay_job_name = "${var.dataflow_job_name}-replay-${random_id.dataflow_job_instance.hex}"
  dataflow_input_topic_name = "${var.dataflow_job_name}-input-topic"
  dataflow_input_subscription_name = "${var.dataflow_job_name}-input-subscription"
  dataflow_output_deadletter_topic_name = "${var.dataflow_job_name}-deadletter-topic"
  dataflow_output_deadletter_sub_name = "${var.dataflow_job_name}-deadletter-subscription"
  splunk_hec_token_secret_version_id = var.splunk_hec_token_secret_id
  splunk_hec_token_secret_id = (
    var.splunk_hec_token_secret_id != "" ?
      regex("^(projects\/[^\n\r\/]+\/secrets\/[^\n\r\/]+)\/versions\/[^\n\r\/]+$", var.splunk_hec_token_secret_id)[0] :
    ""
  )
  dataflow_job_include_pubsub_message = true
  dataflow_job_enable_batch_logs = false
  dataflow_job_enable_gzip_http_compression = true
  scoping_project = var.scoping_project != "" ? var.scoping_project : var.project
}

resource "google_pubsub_topic" "dataflow_input_pubsub_topic" {
  project = var.project
  name    = local.dataflow_input_topic_name
}

resource "google_pubsub_subscription" "dataflow_input_pubsub_subscription" {
  project = var.project
  name    = local.dataflow_input_subscription_name
  topic   = google_pubsub_topic.dataflow_input_pubsub_topic.name

  message_retention_duration = "604800s"
  ack_deadline_seconds       = 30

  expiration_policy {
    ttl = ""
  }
}

resource "google_logging_project_sink" "project_log_sink" {
  project     = var.project
  name        = local.project_log_sink_name
  destination = "pubsub.googleapis.com/projects/${var.project}/topics/${google_pubsub_topic.dataflow_input_pubsub_topic.name}"
  filter      = var.log_filter

  exclusions {
    name        = "exclude_dataflow"
    description = "Exclude dataflow logs to not create an infinite loop"
    filter      = "resource.type="dataflow_step" AND resource.labels.job_name = "${local.dataflow_main_job_name}""
  }

  unique_writer_identity = true
}

variable "project" {
  type        = string
  description = "Project ID to deploy resources in"
}

variable "region" {
  type        = string
  description = "Region to deploy regional-resources into. This must match subnet's region if deploying into existing network (e.g. Shared VPC). See `subnet` parameter below"
}

variable "create_network" {
  description = "Boolean value specifying if a new network needs to be created."
  default     = false
  type        = bool
}

variable "network" {
  description = "Network to deploy into"
  type        = string
}

variable "subnet" {
  type        = string
  description = "Subnet to deploy into. This is required when deploying into existing network (`create_network=false`) (e.g. Shared VPC)"
  default     = ""
}

variable "primary_subnet_cidr" {
  type        = string
  description = "The CIDR Range of the primary subnet"
  default     = "10.128.0.0/20"
}

variable "scoping_project" {
  type        = string
  description = <<-EOF
                Cloud Monitoring scoping project ID to create dashboard under.
                This assumes a pre-existing scoping project whose metrics scope contains the `project` where dataflow job is to be deployed.
                See [Cloud Monitoring settings](https://cloud.google.com/monitoring/settings) for more details on scoping project.
                If parameter is empty, scoping project defaults to value of `project` parameter above.
                EOF
  default     = ""
}

variable "log_filter" {
  type        = string
  description = "Log filter to use when exporting logs"
}

variable "splunk_hec_url" {
  type        = string
  description = "Splunk HEC URL to write data to. Example: https://[MY_SPLUNK_IP_OR_FQDN]:8088"

  validation {
    condition     = can(regex("https?://.*(:[0-9]+)?", var.splunk_hec_url))
    error_message = "Splunk HEC url must of the form <protocol>://<host>:<port> ."
  }
}

variable "splunk_hec_token_source" {
  type        = string
  default     = "PLAINTEXT"
  description = "Define in which type HEC token is provided. Possible options: [PLAINTEXT, KMS, SECRET_MANAGER]."

  validation {
    condition     = contains(["PLAINTEXT", "KMS", "SECRET_MANAGER"], var.splunk_hec_token_source)
    error_message = "Valid values for var: dataflow_token_source are ('PLAINTEXT', 'KMS', 'SECRET_MANAGER')."
  }
}

variable "splunk_hec_token" {
  type        = string
  description = "Splunk HEC token. Must be defined if `splunk_hec_token_source` if type of `PLAINTEXT` or `KMS`."
  default     = ""
  sensitive   = true
}

variable "splunk_hec_token_kms_encryption_key" {
  type        = string
  description = "The Cloud KMS key to decrypt the HEC token string. Required if `splunk_hec_token_source` is type of KMS"
  default     = ""
  validation {
    condition     = can(regex("^projects\/[^\n\r\/]+\/locations\/[^\n\r\/]+\/keyRings\/[^\n\r\/]+\/cryptoKeys\/[^\n\r\/]+$", var.splunk_hec_token_kms_encryption_key)) || var.splunk_hec_token_kms_encryption_key == ""
    error_message = "HEC token encryption key must match rex: '^projects\/[^\n\r\/]+\/locations\/[^\n\r\/]+\/keyRings\/[^\n\r\/]+\/cryptoKeys\/[^\n\r\/]+$' pattern."
  }
}

variable "splunk_hec_token_secret_id" {
  type        = string
  description = "Id of the Secret for Splunk HEC token. Required if `splunk_hec_token_source` is type of SECRET_MANAGER"
  default     = ""
  validation {
    condition     = can(regex("^projects\/[^\n\r\/]+\/secrets\/[^\n\r\/]+\/versions\/[^\n\r\/]+$", var.splunk_hec_token_secret_id)) || var.splunk_hec_token_secret_id == ""
    error_message = "HEC token secret id key must match rex: '^projects\/[^\n\r\/]+\/secrets\/[^\n\r\/]+\/versions\/[^\n\r\/]+$' pattern."
  }
}

variable "gcs_kms_key_name" {
  type        = string
  description = <<EOF
    Cloud KMS key resource ID, to be used as default encryption key for the temporary storage bucket used by the Dataflow job.
    If set, make sure to pre-authorize Cloud Storage service agent associated with that bucket to use that key for encrypting and decrypting.
  EOF
  default     = ""
  validation {
    condition     = can(regex("^projects\/[^\n\r\/]+\/locations\/[^\n\r\/]+\/keyRings\/[^\n\r\/]+\/cryptoKeys\/[^\n\r\/]+$", var.gcs_kms_key_name)) || var.gcs_kms_key_name == ""
    error_message = "Cloud Storage KMS key name must match: '^projects\/[^\n\r\/]+\/locations\/[^\n\r\/]+\/keyRings\/[^\n\r\/]+\/cryptoKeys\/[^\n\r\/]+$' pattern."
  }
}

variable "dataflow_template_version" {
  type        = string
  description = "Dataflow template release version (default 'latest'). Override this for version pinning e.g. '2021-08-02-00_RC00'. Must specify version only since template GCS path will be deduced automatically: 'gs://dataflow-templates/`version`/Cloud_PubSub_to_Splunk'"
  default     = "latest"
}

variable "dataflow_worker_service_account" {
  type        = string
  description = "Name of Dataflow worker service account to be created and used to execute job operations. In the default case of creating a new service account (`use_externally_managed_dataflow_sa=false`), this parameter must be 6-30 characters long, and match the regular expression [a-z]([-a-z0-9]*[a-z0-9]). If the parameter is empty, worker service account defaults to project's Compute Engine default service account. If using external service account (`use_externally_managed_dataflow_sa=true`), this parameter must be the full email address of the external service account."
  default     = ""

  validation {
    condition = (
      var.dataflow_worker_service_account == "" ||
      can(regex("[a-z]([-a-z0-9]*[a-z0-9])", var.dataflow_worker_service_account)) ||
      can(regex("[a-z]([-a-z0-9]*[a-z0-9])@[a-z]([-a-z0-9]*[a-z0-9])(\.iam)?.gserviceaccount.com$", var.dataflow_worker_service_account))
    )
    error_message = "Dataflow worker service account id must match the regular expression '[a-z]([-a-z0-9]*[a-z0-9])' in case of service account name, or '[a-z]([-a-z0-9]*[a-z0-9])@[a-z]([-a-z0-9]*[a-z0-9])(\.iam)?.gserviceaccount.com$' in case of service account email address."
  }
}

variable "dataflow_job_name" {
  type        = string
  description = "Dataflow job name. No spaces"
}

variable "dataflow_job_machine_type" {
  type        = string
  description = "Dataflow job worker machine type"
  default     = "n1-standard-4"
}

variable "dataflow_job_machine_count" {
  description = "Dataflow job max worker count"
  type        = number
  default     = 2
}

variable "dataflow_job_parallelism" {
  description = "Maximum parallel requests to Splunk"
  type        = number
  default     = 8
}

variable "dataflow_job_batch_count" {
  description = "Batch count of messages in single request to Splunk"
  type        = number
  default     = 50
}

variable "dataflow_job_disable_certificate_validation" {
  description = "Boolean to disable SSL certificate validation"
  type        = bool
  default     = false
}

variable "dataflow_job_udf_gcs_path" {
  type        = string
  description = "GCS path for JavaScript file"
  default     = ""
}

variable "dataflow_job_udf_function_name" {
  type        = string
  description = "Name of JavaScript function to be called"
  default     = ""
}

variable "deploy_replay_job" {
  type        = bool
  description = "Determines if replay pipeline should be deployed or not"
  default     = false
}

variable "use_externally_managed_dataflow_sa" {
  type        = bool
  default     = false
  description = "Determines if the worker service account provided by `dataflow_worker_service_account` variable should be created by this module (default) or is managed outside of the module. In the latter case, user is expected to apply and manage the service account IAM permissions over external resources (e.g. Cloud KMS key or Secret version) before running this module."
}

terraform {
  required_version = ">= 0.14.4"

  required_providers {
    random = {
      source  = "hashicorp/random"
      version = ">= 2.1.0"
    }
    google = {
      source  = "hashicorp/google"
      version = ">= 3.54.0"
    }
  }

  provider_meta "google" {
    module_name = "cloud-solutions/terraform-splunk-log-export-deploy-v1"
  }
}

resource "google_compute_network" "splunk_export" {
  count = var.create_network == true ? 1 : 0

  project                 = var.project
  name                    = var.network
  auto_create_subnetworks = false
}

resource "google_compute_subnetwork" "splunk_subnet" {
  count = var.create_network == true ? 1 : 0

  project                  = var.project
  name                     = local.subnet_name
  ip_cidr_range            = var.primary_subnet_cidr
  region                   = var.region
  network                  = google_compute_network.splunk_export[count.index].id
  private_ip_google_access = true
}

resource "google_dns_policy" "splunk_network_dns_policy" {
  count = var.create_network == true ? 1 : 0

  project = var.project
  name    = "${var.network}-dns-policy"

  enable_logging = true

  networks {
    network_url = google_compute_network.splunk_export[count.index].id
  }
}

resource "google_compute_router" "dataflow_to_splunk_router" {
  count = var.create_network == true ? 1 : 0

  project = var.project
  name    = "${var.network}-${var.region}-router"
  region  = google_compute_subnetwork.splunk_subnet[count.index].region
  network = google_compute_network.splunk_export[count.index].id
}

resource "google_compute_address" "dataflow_nat_ip_address" {
  count = var.create_network == true ? 1 : 0

  project = var.project
  name    = "dataflow-splunk-nat-ip-address"
  region  = google_compute_subnetwork.splunk_subnet[count.index].region
}

resource "google_compute_router_nat" "dataflow_nat" {
  count = var.create_network == true ? 1 : 0

  project                            = var.project
  name                               = "${var.network}-${var.region}-router-nat"
  router                             = google_compute_router.dataflow_to_splunk_router[count.index].name
  region                             = google_compute_router.dataflow_to_splunk_router[count.index].region
  nat_ip_allocate_option             = "MANUAL_ONLY"
  source_subnetwork_ip_ranges_to_nat = "LIST_OF_SUBNETWORKS"
  nat_ips                            = google_compute_address.dataflow_nat_ip_address[*].self_link
  min_ports_per_vm                   = 128
  subnetwork {
    name                    = google_compute_subnetwork.splunk_subnet[count.index].id
    source_ip_ranges_to_nat = ["PRIMARY_IP_RANGE"]
  }

  log_config {
    enable = true
    filter = "ERRORS_ONLY"
  }
}

resource "google_compute_firewall" "connect_dataflow_workers" {
  count = var.create_network == true ? 1 : 0

  project = var.project
  name    = "dataflow-internal-ip-fwr"
  network = google_compute_network.splunk_export[count.index].id

  allow {
    protocol = "tcp"
    ports    = ["12345-12346"]
  }

  source_tags = ["dataflow"]
  target_tags = ["dataflow"]
}

resource "google_pubsub_topic_iam_binding" "input_sub_publisher" {
  project = google_pubsub_topic.dataflow_input_pubsub_topic.project
  topic   = google_pubsub_topic.dataflow_input_pubsub_topic.name
  role    = "roles/pubsub.publisher"
  members = [
    google_logging_project_sink.project_log_sink.writer_identity
  ]
}

resource "google_pubsub_subscription_iam_binding" "input_sub_subscriber" {
  project      = google_pubsub_subscription.dataflow_input_pubsub_subscription.project
  subscription = google_pubsub_subscription.dataflow_input_pubsub_subscription.name
  role         = "roles/pubsub.subscriber"
  members = [
    "serviceAccount:${local.dataflow_worker_service_account}"
  ]
}

resource "google_pubsub_subscription_iam_binding" "input_sub_viewer" {
  project      = google_pubsub_subscription.dataflow_input_pubsub_subscription.project
  subscription = google_pubsub_subscription.dataflow_input_pubsub_subscription.name
  role         = "roles/pubsub.viewer"
  members = [
    "serviceAccount:${local.dataflow_worker_service_account}"
  ]
}

resource "google_pubsub_topic_iam_binding" "deadletter_topic_publisher" {
  project = google_pubsub_topic.dataflow_deadletter_pubsub_topic.project
  topic   = google_pubsub_topic.dataflow_deadletter_pubsub_topic.name
  role    = "roles/pubsub.publisher"
  members = [
    "serviceAccount:${local.dataflow_worker_service_account}"
  ]
}

resource "google_storage_bucket_iam_binding" "dataflow_worker_bucket_access" {
  bucket = google_storage_bucket.dataflow_job_temp_bucket.name
  role   = "roles/storage.objectAdmin"
  members = [
    "serviceAccount:${local.dataflow_worker_service_account}"
  ]
}

resource "google_project_iam_binding" "dataflow_worker_role" {
  count   = (local.grant_service_account_roles == true) ? 1 : 0
  project = var.project
  role    = "roles/dataflow.worker"
  members = [
    "serviceAccount:${local.dataflow_worker_service_account}"
  ]
}

resource "google_secret_manager_secret_iam_member" "dataflow_worker_secret_access" {
  count = (
    var.splunk_hec_token_source == "SECRET_MANAGER" &&
    var.splunk_hec_token_secret_id != "" &&
    local.grant_service_account_roles == true
  ) ? 1 : 0

  project   = var.project
  secret_id = local.splunk_hec_token_secret_id
  role      = "roles/secretmanager.secretAccessor"
  member    = "serviceAccount:${local.dataflow_worker_service_account}"
}

resource "google_kms_crypto_key_iam_member" "dataflow_worker_kms_access" {
  count = (
    var.splunk_hec_token_source == "KMS" &&
    var.splunk_hec_token_kms_encryption_key != "" &&
    local.grant_service_account_roles == true
  ) ? 1 : 0

  crypto_key_id = var.splunk_hec_token_kms_encryption_key
  role          = "roles/cloudkms.cryptoKeyDecrypter"
  member        = "serviceAccount:${local.dataflow_worker_service_account}"
}

resource "google_service_account_iam_binding" "terraform_caller_impersonate_dataflow_worker" {
  count = (local.grant_service_account_impersonation == true) ? 1 : 0

  service_account_id = google_service_account.dataflow_worker_service_account[0].id
  role               = "roles/iam.serviceAccountUser"

  members = [
    "user:${data.google_client_openid_userinfo.provider_identity.email}"
  ]
}

resource "google_pubsub_topic" "dataflow_deadletter_pubsub_topic" {
  project = var.project
  name    = local.dataflow_output_deadletter_topic_name
}

resource "google_pubsub_subscription" "dataflow_deadletter_pubsub_sub" {
  project = var.project
  name    = local.dataflow_output_deadletter_sub_name
  topic   = google_pubsub_topic.dataflow_deadletter_pubsub_topic.name

  message_retention_duration = "604800s"

  expiration_policy {
    ttl = ""
  }
}

resource "google_storage_bucket" "dataflow_job_temp_bucket" {
  project                     = var.project
  name                        = local.dataflow_temporary_gcs_bucket_name
  location                    = var.region
  storage_class               = "REGIONAL"
  uniform_bucket_level_access = true
  dynamic "encryption" {
    for_each = (var.gcs_kms_key_name == "") ? [] : [1]
    content {
      default_kms_key_name = var.gcs_kms_key_name
    }
  }
}

resource "google_storage_bucket_object" "dataflow_job_temp_object" {
  name    = local.dataflow_temporary_gcs_bucket_path
  content = "Placeholder for Dataflow to write temporary files"
  bucket  = google_storage_bucket.dataflow_job_temp_bucket.name
}

resource "google_service_account" "dataflow_worker_service_account" {
  count = (
    var.dataflow_worker_service_account != "" && var.use_externally_managed_dataflow_sa == false
  ) ? 1 : 0

  project      = var.project
  account_id   = var.dataflow_worker_service_account
  display_name = "Dataflow worker service account to execute pipeline operations"
}

resource "google_dataflow_job" "dataflow_job" {
  project               = var.project
  name                  = local.dataflow_main_job_name
  template_gcs_path     = local.dataflow_splunk_template_gcs_path
  temp_gcs_location     = "gs://${local.dataflow_temporary_gcs_bucket_name}/${local.dataflow_temporary_gcs_bucket_path}"
  service_account_email = local.dataflow_worker_service_account
  machine_type          = var.dataflow_job_machine_type
  max_workers           = var.dataflow_job_machine_count
  parameters = merge({
    inputSubscription            = google_pubsub_subscription.dataflow_input_pubsub_subscription.id
    outputDeadletterTopic        = google_pubsub_topic.dataflow_deadletter_pubsub_topic.id
    url                          = var.splunk_hec_url
    parallelism                  = var.dataflow_job_parallelism
    batchCount                   = var.dataflow_job_batch_count
    includePubsubMessage         = local.dataflow_job_include_pubsub_message
    disableCertificateValidation = var.dataflow_job_disable_certificate_validation
    enableBatchLogs              = local.dataflow_job_enable_batch_logs
    enableGzipHttpCompression    = local.dataflow_job_enable_gzip_http_compression
    tokenSource                  = var.splunk_hec_token_source
  },
  (var.dataflow_job_udf_gcs_path != "" && var.dataflow_job_udf_function_name != "") ? {
    javascriptTextTransformGcsPath      = var.dataflow_job_udf_gcs_path
    javascriptTextTransformFunctionName = var.dataflow_job_udf_function_name
  } : {},
  (var.splunk_hec_token_source == "PLAINTEXT") ? {
    token = var.splunk_hec_token
  } : {},
  (var.splunk_hec_token_source == "KMS") ? {
    token                 = var.splunk_hec_token
    tokenKMSEncryptionKey = var.splunk_hec_token_kms_encryption_key
  } : {},
  (var.splunk_hec_token_source == "SECRET_MANAGER") ? {
    tokenSecretId = local.splunk_hec_token_secret_version_id
  } : {}
  )
  region           = var.region
  network          = var.network
  subnetwork       = "regions/${var.region}/subnetworks/${local.subnet_name}"
  ip_configuration = "WORKER_IP_PRIVATE"

  lifecycle {
    ignore_changes = [
      additional_experiments
    ]
  }

  depends_on = [
    google_compute_subnetwork.splunk_subnet,
    google_storage_bucket_object.dataflow_job_temp_object
  ]
}

resource "google_monitoring_group" "splunk-export-pipeline-group" {
  display_name = "Splunk Log Export Group"
  project      = local.scoping_project

  filter = "resource.metadata.name=starts_with("${var.dataflow_job_name}")"
}

resource "google_monitoring_dashboard" "splunk-export-pipeline-dashboard" {
  project        = local.scoping_project
  dashboard_json = <<EOF
  {
    "displayName": "Splunk Log Export Ops",
    "mosaicLayout": {
      "columns": 12,
      "tiles": [
        {
          "height": 2,
          "width": 3,
          "yPos": 1,
          "widget": {
            "title": "Total Messages Exported (All-time)", 
            "scorecard": {
              "timeSeriesQuery": {
                "timeSeriesFilter": {
                  "aggregation": {
                    "alignmentPeriod": "60s",
                    "crossSeriesReducer": "REDUCE_MAX",
                    "perSeriesAligner": "ALIGN_MAX"
                  },
                  "filter": "metric.type="dataflow.googleapis.com/job/user_counter" metric.label."metric_name"="outbound-successful-events" resource.type="dataflow_job" resource.label."job_name"="${local.dataflow_main_job_name}""
                }
              }
            }
          }
        },
        {
          "height": 4,
          "width": 6,
          "yPos": 3,
          "widget": {
            "title": "Input Data Rate ",
            "xyChart": {
              "dataSets": [
                {
                  "timeSeriesQuery": {
                    "timeSeriesFilter": {
                      "filter": "metric.type="pubsub.googleapis.com/topic/byte_cost" resource.type="pubsub_topic"  resource.label."topic_id"="${local.dataflow_input_topic_name}"",
                      "aggregation": {
                        "alignmentPeriod": "60s",
                        "perSeriesAligner": "ALIGN_RATE"
                      },
                      "secondaryAggregation": {
                        "alignmentPeriod": "60s",
                        "perSeriesAligner": "ALIGN_MEAN"
                      }
                    }
                  },
                  "plotType": "STACKED_BAR",
                  "targetAxis": "Y1",
                  "minAlignmentPeriod": "60s"
                }
              ],
              "timeshiftDuration": "0s",
              "yAxis": {
                "label": "y1Axis",
                "scale": "LINEAR"
              },
              "chartOptions": {
                "mode": "COLOR"
              }
            }
          }
        },
        {
          "height": 4,
          "width": 6,
          "xPos": 6,
          "yPos": 3,
          "widget": {
            "title": "Logs Exported (Hourly)",
            "xyChart": {
              "chartOptions": {
                "mode": "COLOR"
              },
              "dataSets": [
                {
                  "plotType": "STACKED_BAR",
                  "targetAxis": "Y1",
                  "timeSeriesQuery": {
                    "timeSeriesQueryLanguage": "fetch dataflow_job
| metric 'dataflow.googleapis.com/job/user_counter'
| filter metric.metric_name='outbound-successful-events' && (resource.job_name == '${local.dataflow_main_job_name}')
| align next_older(1m)
| every 1m
| adjacent_delta
| group_by 60m, sum(val())
"
                  }
                }
              ],
              "timeshiftDuration": "0s",
              "yAxis": {
                "label": "y1Axis",
                "scale": "LINEAR"
              }
            }
          }
        },
        {
          "height": 2,
          "width": 3,
          "xPos": 6,
          "yPos": 1,
          "widget": {
            "title": "Backlog Size",
            "scorecard": {
              "timeSeriesQuery": {
                "timeSeriesFilter": {
                  "filter": "metric.type="pubsub.googleapis.com/subscription/num_undelivered_messages" resource.type="pubsub_subscription" resource.label."subscription_id"="${local.dataflow_input_subscription_name}"",
                  "aggregation": {
                    "alignmentPeriod": "60s",
                    "perSeriesAligner": "ALIGN_NEXT_OLDER",
                    "crossSeriesReducer": "REDUCE_SUM"
                  }
                }
              }
            }
          }
        }
      ]
    }
  }
EOF
}

