# Variables

variable "availability_zones" {}

variable "cidr_block" {}

variable "public_subnets" {
  default = ""
}

variable "private_subnets" {
  default = ""
}

variable "allowed_ips" {}

variable "enable_dns_hostnames" {
  default = true
}

variable "enable_dns_support" {
  default = true
}

variable "project" {}

variable "environment" {}

variable "owner" {}

variable "email" {}

# AWS VPC

resource "aws_vpc" "default" {
  cidr_block           = var.cidr_block
  enable_dns_hostnames = var.enable_dns_hostnames
  enable_dns_support   = var.enable_dns_support

  tags = {
    Name        = "${var.environment}_vpc"
    Description = "${var.environment}_vpc"
    project     = var.project
    environment = var.environment
    owner       = var.owner
    email       = var.email
  }
}

# Internet Gateway

resource "aws_internet_gateway" "default" {
  vpc_id = aws_vpc.default.id

  tags = {
    Name        = "${var.environment}_igw"
    Description = "${var.environment}_igw"
    project     = var.project
    environment = var.environment
    owner       = var.owner
    email       = var.email
  }
}

# Security Group

resource "aws_security_group" "default_sg" {
  name        = "${var.environment}_default_sg"
  description = "${var.environment}_default_sg"
  vpc_id      = aws_vpc.default.id

  ingress {
    from_port   = 0
    to_port     = 65535
    protocol    = "tcp"
    cidr_blocks = split(",", var.allowed_ips)
    self        = true
  }

  ingress {
    from_port   = -1
    to_port     = -1
    protocol    = "icmp"
    cidr_blocks = split(",", var.allowed_ips)
    self        = true
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name        = "${var.environment}_default_sg"
    Description = "${var.environment}_default_sg"
    project     = var.project
    environment = var.environment
    owner       = var.owner
    email       = var.email
  }
}

# Subnets

resource "aws_subnet" "public" {
  count                   = length(split(",", var.public_subnets))
  vpc_id                  = aws_vpc.default.id
  cidr_block              = element(split(",", var.public_subnets), count.index)
  availability_zone       = element(split(",", var.availability_zones), count.index)
  map_public_ip_on_launch = true

  tags = {
    Name        = "${var.environment}_public_${count.index + 1}"
    Description = "${var.environment}_public_${count.index + 1}"
    project     = var.project
    environment = var.environment
    owner       = var.owner
    email       = var.email
  }
}

resource "aws_subnet" "private" {
  count             = length(split(",", var.private_subnets))
  vpc_id            = aws_vpc.default.id
  cidr_block        = element(split(",", var.private_subnets), count.index)
  availability_zone = element(split(",", var.availability_zones), count.index)

  tags = {
    Name        = "${var.environment}_private_${count.index + 1}"
    Description = "${var.environment}_private_${count.index + 1}"
    project     = var.project
    environment = var.environment
    owner       = var.owner
    email       = var.email
  }
}

# Route Tables

resource "aws_route_table" "public" {
  vpc_id = aws_vpc.default.id

  tags = {
    Name        = "${var.environment}_public"
    Description = "${var.environment}_public"
    project     = var.project
    environment = var.environment
    owner       = var.owner
    email       = var.email
  }
}

resource "aws_route_table_association" "public" {
  count          = length(split(",", var.public_subnets))
  subnet_id      = element(aws_subnet.public.*.id, count.index)
  route_table_id = aws_route_table.public.id
}

resource "aws_route" "public_internet_gateway" {
  route_table_id         = aws_route_table.public.id
  destination_cidr_block = "0.0.0.0/0"
  gateway_id             = aws_internet_gateway.default.id
}

resource "aws_route_table" "private" {
  count  = length(split(",", var.availability_zones))
  vpc_id = aws_vpc.default.id

  tags = {
    Name        = "${var.environment}_private_${count.index + 1}"
    Description = "${var.environment}_private_${count.index + 1}"
    project     = var.project
    environment = var.environment
    owner       = var.owner
    email       = var.email
  }
}

resource "aws_route_table_association" "private" {
  count          = length(split(",", var.private_subnets))
  subnet_id      = element(aws_subnet.private.*.id, count.index)
  route_table_id = element(aws_route_table.private.*.id, count.index)
}

# NAT Gateways and EIPs

resource "aws_eip" "nat_gw" {
  count = length(split(",", var.availability_zones))
  vpc   = true
}

resource "aws_nat_gateway" "gw" {
  count         = length(split(",", var.availability_zones))
  allocation_id = element(aws_eip.nat_gw.*.id, count.index)
  subnet_id     = element(aws_subnet.public.*.id, count.index)
  depends_on    = [aws_internet_gateway.default]
}

resource "aws_route" "internet_access" {
  count                  = length(split(",", var.availability_zones))
  route_table_id         = element(aws_route_table.private.*.id, count.index)
  destination_cidr_block = "0.0.0.0/0"
  nat_gateway_id         = element(aws_nat_gateway.gw.*.id, count.index)
}

# Outputs

output "vpc_id" {
  value = aws_vpc.default.id
}

output "public_subnets" {
  value = join(",", aws_subnet.public.*.id)
}

output "private_subnets" {
  value = join(",", aws_subnet.private.*.id)
}

output "public_route_table_id" {
  value = aws_route_table.public.id
}

output "private_route_tables" {
  value = join(",", aws_route_table.private.*.id)
}

output "default_sg_id" {
  value = aws_security_group.default_sg.id
}

