  description = "CIDR block for development environment"
}

variable "appname" {
  description = "Application name"
}

variable "cloud_watch_log_group_name" {
  description = "CloudWatch log group name"
}

variable "cloud_watch_log_group_arn" {
  description = "CloudWatch log group ARN"
}

variable "lambda_name" {
  description = "Lambda function name"
}

variable "lambda_permission_principal" {
  description = "Principal for Lambda permission"
}

variable "lambda_function_name" {
  description = "Lambda function handler name"
}

variable "lambda_filename_zip" {
  description = "Lambda function ZIP file"
}

variable "es_log_role_name" {
  description = "IAM role name for Elasticsearch logging"
}

variable "es_log_policy_name" {
  description = "IAM policy name for Elasticsearch logging"
}
data "template_file" "iam_role_elasticsearch" {
  template = file("${path.module}/policies/elasticsearch.json")

  vars = {
    allowed_cidrs = var.devCIDR
  }
}

data "template_file" "iam_role_cw_to_es" {
  template = file("${path.module}/policies/cloudwatch_logs_to_es_iam_role.json")
}

data "template_file" "iam_role_policy_cw_to_es" {
  template = file("${path.module}/policies/cloudwatch_logs_to_es_iam_role_policy.json")
}
resource "aws_iam_role" "cloudwatch_logs_to_es" {
  name               = var.es_log_role_name
  assume_role_policy = data.template_file.iam_role_cw_to_es.rendered
}

resource "aws_iam_role_policy" "cloudwatch_logs_to_es" {
  name   = var.es_log_policy_name
  role   = aws_iam_role.cloudwatch_logs_to_es.id
  policy = data.template_file.iam_role_policy_cw_to_es.rendered
}
resource "aws_lambda_function" "cloudwatch_logs_to_es" {
  filename         = var.lambda_filename_zip
  function_name    = var.lambda_name
  role             = aws_iam_role.cloudwatch_logs_to_es.arn
  handler          = "${var.lambda_function_name}.handler"
  source_code_hash = base64sha256(file(var.lambda_filename_zip))
  runtime          = "nodejs14.x"

  environment {
    variables = {
      es_endpoint = aws_elasticsearch_domain.es.endpoint
    }
  }
}

resource "aws_lambda_permission" "cloudwatch_logs_to_es" {
  statement_id  = "cloudwatch_logs_to_es"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.cloudwatch_logs_to_es.arn
  principal     = var.lambda_permission_principal
  source_arn    = var.cloud_watch_log_group_arn
}
resource "aws_cloudwatch_log_subscription_filter" "cloudwatch_logs_to_es" {
  depends_on      = [aws_lambda_permission.cloudwatch_logs_to_es]
  name            = "cloudwatch_logs_to_elasticsearch"
  log_group_name  = var.cloud_watch_log_group_name
  filter_pattern  = ""
  destination_arn = aws_lambda_function.cloudwatch_logs_to_es.arn
}
resource "aws_elasticsearch_domain" "es" {
  domain_name           = var.appname
  elasticsearch_version = "5.5"

  cluster_config {
    instance_type  = "t2.small.elasticsearch"
    instance_count = 1
  }

  ebs_options {
    ebs_enabled = true
    volume_size = 10
  }

  tags = {
    Name = "${var.appname}-es"
  }

  access_policies = data.template_file.iam_role_elasticsearch.rendered
}

variable "stack_name" {
  description = "Name of the stack"
  type        = string
}

variable "name" {
  description = "Name of the resource"
  type        = string
}

variable "assume_role_policy" {
  description = "Custom assume role policy document"
  type        = string
  default     = ""
}
data "aws_iam_policy_document" "mod" {
  count = var.assume_role_policy != "" ? 0 : 1

  statement {
    actions = ["sts:AssumeRole"]

    principals {
      type        = "Service"
      identifiers = ["ec2.amazonaws.com"]
    }
  }
}
resource "aws_iam_role" "mod" {
  name = format("%s-%s-instance-role", var.stack_name, var.name)

  assume_role_policy = var.assume_role_policy != "" ? var.assume_role_policy : data.aws_iam_policy_document.mod[0].json
}

resource "aws_iam_instance_profile" "mod" {
  name = format("%s-%s-instance-profile", var.stack_name, var.name)
  role = aws_iam_role.mod.name

  provisioner "local-exec" {
    command = "sleep 30"
  }

  depends_on = [aws_iam_role.mod]
}
output "id" {
  value = aws_iam_instance_profile.mod.id
}

output "arn" {
  value = aws_iam_instance_profile.mod.arn
}

output "name" {
  value = aws_iam_instance_profile.mod.name
}

output "role_id" {
  value = aws_iam_role.mod.id
}

output "role_arn" {
  value = aws_iam_role.mod.arn
}

