  provider = google-beta

  description = "Reset test foundation"
  github {
    owner = local.gh_orgs.infra
    name  = local.gh_repos.infra
    # this will be invoked via cloud scheduler, hence using a regex that will not match any branch
    push {
      branch = ".^"
