#--------------------------------------------------------------
# This module creates all resources necessary for a Bastion host
#--------------------------------------------------------------

variable "name" {
  description = "The name of the bastion host"
  type        = string
}

variable "zones" {
  description = "List of zones where the bastion host can be deployed"
  type        = list(string)
}

variable "public_subnet_names" {
  description = "List of public subnets"
  type        = list(string)
}

variable "image" {
  description = "The image to use for the bastion host"
  type        = string
}

variable "instance_type" {
  description = "The instance type for the bastion host"
  type        = string
}

variable "ssh_keys" {
  description = "The SSH keys to allow access to the bastion host"
  type        = string
}

resource "google_compute_instance" "bastion" {
  name         = var.name
  machine_type = var.instance_type
  zone         = element(var.zones, 0)

  metadata = {
    ssh-keys = var.ssh_keys
  }

  boot_disk {
    initialize_params {
      image = var.image
    }
  }

  network_interface {
    subnetwork = element(var.public_subnet_names, 0)

    access_config {
      # ephemeral
    }
  }

  tags = ["bastion"]
}

output "private_ip" {
  value = google_compute_instance.bastion.network_interface[0].network_ip
}

output "public_ip" {
  value = google_compute_instance.bastion.network_interface[0].access_config[0].nat_ip
}

# ../globals.tf

variable "concourse_security_group_id" {
  description = "ID of the security group for the Concourse VM which deploys BOSH with bosh-init"
}

variable "secrets_bosh_postgres_password" {
  description = "Master password for the BOSH database"
}

variable "bosh_db_multi_az" {
  description = "BOSH database multi availability zones"
  default = false
}

variable "bosh_db_backup_retention_period" {
  description = "BOSH database backup retention period"
  default = 0
}

variable "bosh_db_skip_final_snapshot" {
  description = "Whether to skip final RDS snapshot (just before destroy). Differs per environment."
  default = true
}

variable "bosh_az" {
  description = "A zone used to provision BOSH"
}

variable "system_dns_zone_id" {
  description = "Amazon Route53 DNS zone identifier for the system components. Different per account."
}

variable "system_dns_zone_name" {
  description = "Amazon Route53 DNS zone name for the provisioned environment."
}

resource "aws_s3_bucket" "bosh_blobstore" {
  bucket = "${var.env}-bosh-blobstore"
  acl = "private"
  force_destroy = true
}

resource "aws_route53_record" "bosh" {
  zone_id = var.system_dns_zone_id
  name = "bosh.${var.system_dns_zone_name}"
  type = "A"
  ttl = 60
  records = [lookup(var.microbosh_ips, var.bosh_az)]
}

resource "aws_eip" "bosh" {
  vpc = true
}

resource "aws_db_subnet_group" "bosh_rds" {
  name = "${var.env}-bosh"
  description = "Subnet group for BOSH RDS"
  subnet_ids = split(",", var.infra_subnet_ids)

  tags = {
    Name = "${var.env}-bosh-rds"
  }
}

resource "aws_security_group" "bosh_rds" {
  name = "${var.env}-bosh-rds"
  description = "BOSH RDS security group"
  vpc_id = var.vpc_id

  ingress {
    from_port = 5432
    to_port = 5432
    protocol = "tcp"
    security_groups = [
      aws_security_group.bosh.id,
      var.concourse_security_group_id,
    ]
  }

  tags = {
    Name = "${var.env}-bosh-rds"
  }
}

resource "aws_db_parameter_group" "default" {
  name = "${var.env}-bosh"
  family = "postgres9.4"
  description = "RDS Postgres default parameter group"
}

resource "aws_db_instance" "bosh" {
  identifier = "${var.env}-bosh"
  name = "bosh"
  allocated_storage = 5
  storage_type = "gp2"
  engine = "postgres"
  engine_version = "9.4.5"
  instance_class = "db.t2.medium"
  username = "dbadmin"
  password = var.secrets_bosh_postgres_password
  db_subnet_group_name = aws_db_subnet_group.bosh_rds.name
  parameter_group_name = aws_db_parameter_group.default.id
  backup_window = "01:00-02:00"
  maintenance_window = "Thu:03:00-Thu:04:00"
  multi_az = var.bosh_db_multi_az
  backup_retention_period = var.bosh_db_backup_retention_period
  final_snapshot_identifier = "${var.env}-bosh-rds-final-snapshot"
  skip_final_snapshot = var.bosh_db_skip_final_snapshot

  vpc_security_group_ids = [aws_security_group.bosh_rds.id]

  tags = {
    Name = "${var.env}-bosh"
  }
}

resource "aws_security_group" "bosh" {
  name = "${var.env}-bosh"
  description = "BOSH security group"
  vpc_id = var.vpc_id

  egress {
    from_port = 0
    to_port = 0
    protocol = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  ingress {
    from_port = 22
    to_port = 22
    protocol = "tcp"
    security_groups = [
      var.concourse_security_group_id,
    ]
  }

  ingress {
    from_port = 6868
    to_port = 6868
    protocol = "tcp"
    security_groups = [
      var.concourse_security_group_id,
    ]
  }

  ingress {
    from_port = 25555
    to_port = 25555
    protocol = "tcp"
    security_groups = [
      aws_security_group.bosh_client.id,
      var.concourse_security_group_id,
    ]
  }

  ingress {
    from_port = 4222
    to_port = 4222
    protocol = "tcp"
    security_groups = [
      aws_security_group.bosh_managed.id,
    ]
  }

  ingress {
    from_port = 25250
    to_port = 25250
    protocol = "tcp"
    security_groups = [
      aws_security_group.bosh_managed.id,
    ]
  }

  ingress {
    from_port = 25777
    to_port = 25777
    protocol = "tcp"
    security_groups = [
      aws_security_group.bosh_managed.id,
    ]
  }

  tags = {
    Name = "${var.env}-bosh"
  }
}

resource "aws_security_group" "bosh_client" {
  name = "${var.env}-bosh-client"
  description = "Default security group for VMs which will interact with BOSH"
  vpc_id = var.vpc_id

  tags = {
    Name = "${var.env}-bosh-client"
  }
}

resource "aws_security_group" "bosh_managed" {
  name = "${var.env}-bosh-managed"
  description = "Default security group for VMs managed by BOSH"
  vpc_id = var.vpc_id

  egress {
    from_port = 0
    to_port = 0
    protocol = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  ingress {
    from_port = 0
    to_port = 0
    protocol = "-1"
    cidr_blocks = [var.vpc_cidr]
  }

  tags = {
    Name = "${var.env}-bosh-managed"
  }
}

resource "aws_key_pair" "bosh_ssh_key_pair" {
  key_name = "${var.env}_bosh_ssh_key_pair"
  public_key = file("${path.module}/bosh_id_rsa.pub")
}

resource "aws_key_pair" "env_key_pair" {
  key_name = "${var.env}_key_pair"
  public_key = file("${path.module}/id_rsa.pub")
}

