locals {
  google_load_balancer_ip_ranges = [
    "130.211.0.0/22",
    "35.191.0.0/16",
  ]
  target_tags = [
    "container-vm-test-mig"
  ]
}
provider "google" {
  project = var.project_id
}
provider "google-beta" {
  project = var.project_id
}
module "gce-container" {
  source  = "terraform-google-modules/container-vm/google"
  version = "~> 3.0"

  container = {
    image = var.image
  }
}
resource "google_compute_network" "default" {
  name                    = var.network
  auto_create_subnetworks = "false"
}
resource "google_compute_subnetwork" "default" {
  name                     = var.subnetwork
  ip_cidr_range            = "10.125.0.0/20"
  network                  = google_compute_network.default.self_link
  region                   = var.region
  private_ip_google_access = true
}
# Router and Cloud NAT are required for installing packages from repos (apache, php etc)
resource "google_compute_router" "default" {
  name    = "${var.network}-gw-group1"
  network = google_compute_network.default.self_link
  region  = var.region
}
module "cloud-nat" {
  source     = "terraform-google-modules/cloud-nat/google"
  version    = "~> 2.1"
  router     = google_compute_router.default.name
  project_id = var.project_id
  region     = var.region
  name       = "${var.network}-cloud-nat-group1"
}
module "mig_template" {
  source               = "terraform-google-modules/vm/google//modules/instance_template"
  version              = "~> 7.3"
  network              = google_compute_network.default.self_link
  subnetwork           = google_compute_subnetwork.default.self_link
  service_account      = var.service_account
  name_prefix          = var.network
  source_image_family  = "cos-stable"
  source_image_project = "cos-cloud"
  source_image         = reverse(split("/", module.gce-container.source_image))[0]
  metadata             = merge(var.additional_metadata, { "gce-container-declaration" = module.gce-container.metadata_value })
  tags = [
    "container-vm-test-mig"
  ]
  labels = {
    "container-vm" = module.gce-container.vm_container_label
  }
}
module "mig" {
  source            = "terraform-google-modules/vm/google//modules/mig"
  version           = "~> 7.3"
  instance_template = module.mig_template.self_link
  region            = var.region
  hostname          = var.network
  target_size       = var.mig_instance_count
  named_ports = [
    {
      name = "http",
      port = var.image_port
    }
  ]
  network    = google_compute_network.default.self_link
  subnetwork = var.subnetwork
}
module "http-lb" {
  source  = "GoogleCloudPlatform/lb-http/google"
  version = "~> 6.2"

  project     = var.project_id
  name        = "${var.mig_name}-lb"
  target_tags = local.target_tags
  firewall_networks = [
    google_compute_network.default.self_link
  ]

  backends = {
    default = {
      description                     = null
      protocol                        = "HTTP"
      port                            = 80
      port_name                       = "http"
      timeout_sec                     = 30
      connection_draining_timeout_sec = null
      enable_cdn                      = false
      security_policy                 = null
      session_affinity                = null
      affinity_cookie_ttl_sec         = null
      custom_request_headers          = null
      custom_response_headers         = null

      health_check = {
        check_interval_sec  = null
        timeout_sec         = null
        healthy_threshold   = null
        unhealthy_threshold = null
        request_path        = "/"
        port                = 80
        host                = null
        logging             = null
      }

      log_config = {
        enable      = false
        sample_rate = null
      }

      groups = [
        {
          group                        = module.mig.instance_group
          balancing_mode               = null
          capacity_scaler              = null
          description                  = null
          max_connections              = null
          max_connections_per_instance = null
          max_connections_per_endpoint = null
          max_rate                     = null
          max_rate_per_instance        = null
          max_rate_per_endpoint        = null
          max_utilization              = null
        }
      ]

      iap_config = {
        enable               = false
        oauth2_client_id     = ""
        oauth2_client_secret = ""
      }
    }
  }
}
resource "google_compute_firewall" "lb-to-instances" {
  name    = "${var.mig_name}-firewall-lb-to-instances"
  project = var.project_id
  network = var.network
  allow {
    protocol = "tcp"
    ports = [
      var.image_port
    ]
  }
  source_ranges = local.google_load_balancer_ip_ranges
  target_tags   = local.target_tags
}


