  description = "Port exposed by the docker image to redirect traffic to"
  default     = 80
}

variable "MYCORESERVERLOCAL" {}

variable "MYICORESERVERLOCAL" {}

data "aws_vpc" "vpc" {
  filter {
    name   = "tag:Name"
    values = ["${var.environment}-vpc"]
  }
}

data "aws_ecs_cluster" "cluster" {
  cluster_name = "${var.environment}-ecs-cluster"
}

data "aws_iam_policy_document" "ecs_service_policy" {
  statement {
    effect    = "Allow"
    actions   = [
      "elasticloadbalancing:Describe*",
      "elasticloadbalancing:DeregisterInstancesFromLoadBalancer",
      "elasticloadbalancing:RegisterInstancesWithLoadBalancer",
      "ec2:Describe*",
      "ec2:AuthorizeSecurityGroupIngress",
    ]
    resources = ["*"]
  }
}

data "aws_iam_role" "ecs_execution_role" {
  name = "ecs_task_execution_role"
}

resource "aws_iam_role_policy" "ecs_service_role_policy" {
  name   = "ecs_service_role_policy"
  policy = data.aws_iam_policy_document.ecs_service_policy.json
  role   = data.aws_iam_role.ecs_execution_role.id
}

resource "aws_cloudwatch_log_group" "core" {
  name = "/ecs/core"
  tags = {
    Environment = var.environment
    Application = "Core"
  }
}

resource "aws_ecr_repository" "stockstat_app_core" {
  name = var.repository_name_core
}

resource "aws_ecs_task_definition" "core" {
  family                   = "${var.environment}_core"
  container_definitions    = <<TASK_DEFINITION
  {
    "cpu": ${var.fargate_cpu},
    "memory": ${var.fargate_memory},
    "image": "${aws_ecr_repository.stockstat_app_core.repository_url}",
    "logConfiguration": {
      "logDriver": "awslogs",
      "options": {
        "awslogs-group": "${aws_cloudwatch_log_group.core.name}",
        "awslogs-region": "${var.aws_region}",
        "awslogs-stream-prefix": "ecs"
      }
    },
    "portMappings": [
      {
        "containerPort": ${var.app_port}
      }
    ]
  }
  TASK_DEFINITION

  requires_compatibilities = ["FARGATE"]
  network_mode             = "awsvpc"
  execution_role_arn       = data.aws_iam_role.ecs_execution_role.arn
}

resource "aws_alb_target_group" "alb_target_group_core" {
  name        = "${var.environment}-alb-target-group-core"
  port        = 80
  protocol    = "HTTP"
  vpc_id      = var.vpc_id
  target_type = "ip"
}

resource "aws_security_group" "core_inbound_sg" {
  name        = "${var.environment}-core-inbound-sg"
  description = "Allow HTTP from Anywhere into ALB"
  vpc_id      = var.vpc_id

  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  ingress {
    from_port   = 8
    to_port     = 0
    protocol    = "icmp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "${var.environment}-core-inbound-sg"
  }
}

resource "aws_alb" "alb_core" {
  name            = "${var.environment}-alb-core"
  subnets         = var.public_subnet_ids
  security_groups = [aws_security_group.core_inbound_sg.id]

  tags = {
    Name        = "${var.environment}-alb-core"
    Environment = var.environment
  }
}

resource "aws_alb_listener" "core" {
  load_balancer_arn = aws_alb.alb_core.arn
  port              = "80"
  protocol          = "HTTP"

  default_action {
    target_group_arn = aws_alb_target_group.alb_target_group_core.arn
    type             = "forward"
  }
}

resource "aws_ecs_service" "core" {
  name            = "${var.environment}-core"
  cluster         = data.aws_ecs_cluster.cluster.id
  task_definition = aws_ecs_task_definition.core.arn
  desired_count   = 2
  launch_type     = "FARGATE"

  network_configuration {
    subnets         = var.subnets_ids
    security_groups = [aws_security_group.core_inbound_sg.id]
  }

  load_balancer {
    target_group_arn = aws_alb_target_group.alb_target_group_core.arn
    container_name   = "core"
    container_port   = 80
  }
}

output "repository_url_core" {
  value = aws_ecr_repository.stockstat_app_core.repository_url
}

output "cluster_name" {
  value = data.aws_ecs_cluster.cluster.cluster_name
