resource "google_os_config_patch_deployment" "patch" {
  patch_deployment_id = "patch-deploy-${random_pet.suffix.id}"

  instance_filter {
    group_labels {
      labels = {
        env = "dev"
        app = "web"
      }
    }

    instance_name_prefixes = ["test-"]

    zones = ["us-central1-a", "us-central1-c"]
  }

  patch_config {
    mode = "ZONE_BY_ZONE"

    reboot_config {
      reboot_timer_expiry_timedelta {
        seconds = 600
      }
      type = "ALWAYS"
    }

    apt {
      type     = "DIST"
      excludes = ["python"]
    }

    yum {
      security = true
      minimal  = true
      excludes = ["bash"]
    }

    goo {
      enabled = true
    }

    zypper {
      categories = ["security"]
    }

    windows_update {
      classifications = ["CRITICAL", "SECURITY", "UPDATE"]
      excludes        = ["5012170"]
    }

    pre_step {
      linux_exec_step_config {
        allowed_success_codes = [0, 3]
        local_path            = "/tmp/pre_patch_script.sh"
      }

      windows_exec_step_config {
        interpreter           = "SHELL"
        allowed_success_codes = [0, 2]
        local_path            = "C:\Users\user\pre-patch-script.cmd"
      }
    }

    post_step {
      linux_exec_step_config {
        gcs_object {
          bucket            = "my-patch-scripts"
          generation_number = "1523477886880"
          object            = "linux/post_patch_script"
        }
      }

      windows_exec_step_config {
        interpreter           = "POWERSHELL"
        allowed_success_codes = [0, 2]
        gcs_object {
          bucket            = "my-patch-scripts"
          generation_number = "135920493447"
          object            = "windows/post_patch_script.ps1"
        }
      }
    }
  }

  duration = "600s"

  recurring_schedule {
    time_zone {
      id = "America/New_York"
    }

    time_of_day {
      hours   = 0
      minutes = 30
      seconds = 30
      nanos   = 20
    }

    monthly {
      week_day_of_month {
        week_ordinal = -1
        day_of_week  = "TUESDAY"
        day_offset   = 3
      }
    }
  }

  rollout {
    mode = "ZONE_BY_ZONE"
    disruption_budget {
      fixed = 1
    }
  }
}

