/** Access key. NOTE: DO NOT CHECK IN */
variable "access_key" {
  description = "Access Key"
}

/** Secret key. NOTE: DO NOT CHECK IN */
variable "secret_key" {
  description = "Secret Access"
}

/** AZ which is used by default during the deployment */
variable "default_az" {
  description = "Default AZ"
  default     = "eu-central-1a"
}

/** Region which is used by default during te rollout */
variable "region" {
  description = "AWS region to host the bosh network"
  default     = "eu-central-1"
}

variable "vpc_gw" {
  description = "GW for the vpc"
  default     = "10.0.0.1"
}

variable "bosh_gw" {
  description = "GW for the bosh network"
  default     = "10.0.1.1"
}

variable "vpc_cidr" {
  description = "CIDR for VPC"
  default     = "10.0.0.0/16"
}

variable "bosh_ip" {
  description = "BOSH Director IP"
  default     = "10.0.1.6"
}

variable "bosh_subnet_cidr" {
  description = "CIDR for bosh subnet"
  default     = "10.0.1.0/24"
}

variable "public_subnet_cidr" {
  description = "CIDR for public subnet"
  default     = "10.0.0.0/24"
}

/* Ubuntu amis by region */
variable "amis" {
  type        = map(string)
  description = "Base AMI to launch the vms"

  default = {
    eu-central-1 = "ami-829145ed"
  }
}

/* Setup the aws provider */
provider "aws" {
  access_key = var.access_key
  secret_key = var.secret_key
  region     = var.region
}

/* Define the vpc */
resource "aws_vpc" "default" {
  cidr_block           = var.vpc_cidr
  enable_dns_hostnames = true

  tags = {
    Name = "bosh-terraform-vpc"
  }
}

/** internet access */
resource "aws_internet_gateway" "default" {
  vpc_id = aws_vpc.default.id
}

/** public subnet for the nat instance and the jumpbox */
resource "aws_subnet" "public" {
  vpc_id                  = aws_vpc.default.id
  cidr_block              = var.public_subnet_cidr
  availability_zone       = var.default_az
  map_public_ip_on_launch = true
  depends_on              = [aws_internet_gateway.default]

  tags = {
    Name = "public-net"
  }
}

/** private network for the bosh managed vms */
resource "aws_subnet" "bosh" {
  vpc_id                  = aws_vpc.default.id
  cidr_block              = var.bosh_subnet_cidr
  availability_zone       = var.default_az
  map_public_ip_on_launch = false
  depends_on              = [aws_instance.nat]

  tags = {
    Name = "bosh-net"
  }
}

resource "aws_route_table" "public" {
  vpc_id = aws_vpc.default.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.default.id
  }
}

resource "aws_route_table" "bosh" {
  vpc_id = aws_vpc.default.id

  route {
    cidr_block  = "0.0.0.0/0"
    instance_id = aws_instance.nat.id
  }

  tags = {
    Name = "Private Subnet"
  }
}

resource "aws_route_table_association" "public" {
  subnet_id      = aws_subnet.public.id
  route_table_id = aws_route_table.public.id
}

resource "aws_route_table_association" "bosh" {
  subnet_id      = aws_subnet.bosh.id
  route_table_id = aws_route_table.bosh.id
}

resource "aws_security_group" "ssh" {
  name        = "ssh"
  description = "SSH access to instances from the internet"

  ingress {
    from_port   = 22
    to_port     = 22
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  vpc_id = aws_vpc.default.id

  tags = {
    Name = "ssh sg"
  }
}

/* Security group for the nat instance */
resource "aws_security_group" "vpc_nat" {
  name        = "vpc_nat"
  description = "Allow traffic to pass from the private subnet to the internet"

  egress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  vpc_id = aws_vpc.default.id

  tags = {
    Name = "NATSG"
  }
}

resource "aws_security_group" "bosh" {
  name        = "bosh"
  description = "Security group for bosh vms"
  vpc_id      = aws_vpc.default.id

  ingress {
    from_port = 0
    to_port   = 0
    protocol  = "-1"
    self      = true
  }

  egress {
    from_port = 0
    to_port   = 0
    protocol  = "-1"
    self      = true
  }

  tags = {
    Name = "bosh sg"
  }
}

/** key for deployment of jumpbox and nat */
resource "aws_key_pair" "deployer" {
  key_name   = "deployer"
  public_key = file("ssh/deployer.pub")
}

/** key for bosh */
resource "aws_key_pair" "bosh" {
  key_name   = "bosh"
  public_key = file("ssh/bosh.pub")
}

/** jumpbox instance */
resource "aws_instance" "jumpbox" {
  ami                         = lookup(var.amis, var.region)
  availability_zone           = var.default_az
  instance_type               = "t2.micro"
  subnet_id                   = aws_subnet.public.id
  vpc_security_group_ids      = [aws_security_group.bosh.id, aws_security_group.vpc_nat.id, aws_security_group.ssh.id]
  key_name                    = aws_key_pair.deployer.key_name
  /* ensure that the nat instance and network are up and running */
  depends_on                  = [aws_instance.nat, aws_subnet.bosh]

  provisioner "local-exec" {
    command = "echo  ${aws_instance.jumpbox.public_dns} > dns-info.txt"
  }

  /** copy the bosh key to the jumpbox */
  provisioner "file" {
    source      = "ssh/bosh.pem"
    destination = "/home/ubuntu/.ssh/bosh.pem"
    connection {
      user        = "ubuntu"
      host        = aws_instance.jumpbox.public_dns
      private_key = file("ssh/deployer.pem")
    }
  }

  /** copy the install script to the jumpbox */
  provisioner "file" {
    source      = "ec2/install.sh"
    destination = "/home/ubuntu/install.sh"
    connection {
      user        = "ubuntu"
      host        = aws_instance.jumpbox.public_dns
      private_key = file("ssh/deployer.pem")
    }
  }

  /** execute the remote script */
  provisioner "remote-exec" {
    inline = [
      "chmod +x install.sh",
      "./install.sh ${var.bosh_subnet_cidr} ${var.bosh_gw} ${var.bosh_ip} ${var.access_key} ${var.secret_key} ${aws_subnet.bosh.id} ${var.default_az} ${var.region} ~/.ssh/bosh.pem",
    ]
    connection {
      user        = "ubuntu"
      host        = aws_instance.jumpbox.public_dns
      private_key = file("ssh/deployer.pem")
    }
  }

  tags = {
    Name = "jumphost-vm"
  }
}

/** nat instance */
resource "aws_instance" "nat" {
  ami                         = lookup(var.amis, var.region)
  availability_zone           = var.default_az
  instance_type               = "t2.micro"
  vpc_security_group_ids      = [aws_security_group.bosh.id, aws_security_group.vpc_nat.id, aws_security_group.ssh.id]
  subnet_id                   = aws_subnet.public.id
  associate_public_ip_address = true
  source_dest_check           = false
  key_name                    = aws_key_pair.deployer.key_name

  provisioner "remote-exec" {
    inline = [
      "sudo apt -y update",
      "sudo apt -y upgrade",
      "sudo iptables -t nat -A POSTROUTING -j MASQUERADE",
      "echo 1 | sudo tee /proc/sys/net/ipv4/conf/all/forwarding > /dev/null",
    ]
    connection {
      user        = "ubuntu"
      timeout     = "5m"
      private_key = file("ssh/deployer.pem")
    }
  }

  tags = {
    Name = "VPC NAT"
  }
}

resource "aws_eip" "nat" {
  instance = aws_instance.nat.id
  vpc      = true
}

output "jumpbox_ip" {
  value = aws_instance.jumpbox.public_ip
}

output "jumpbox_dns" {
  value = aws_instance.jumpbox.public_dns
}

output "bosh_subnet_cidr" {
  value = var.bosh_subnet_cidr
}

output "bosh_gw" {
  value = var.bosh_gw
}

output "bosh_ip" {
  value = var.bosh_ip
}

output "bosh_subnet" {
  value = aws_subnet.bosh.id
}

