      {
        Action    = "sts:AssumeRole"
        Principal = { Service = "ec2.amazonaws.com" }
        Effect    = "Allow"
        Sid       = ""
      }
    ]
  })
}

resource "aws_iam_role" "demo_app" {
  name = "demo-app"
  path = "/"
  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action    = "sts:AssumeRole"
        Principal = { Service = "ec2.amazonaws.com" }
        Effect    = "Allow"
        Sid       = ""
      }
    ]
  })
}

resource "aws_iam_instance_profile" "jenkins" {
  name = "jenkins"
  role = aws_iam_role.jenkins.name
}

resource "aws_iam_instance_profile" "demo_app" {
  name = "demo-app"
  role = aws_iam_role.demo_app.name
}

resource "aws_iam_policy" "common" {
  name = "common"
  path = "/"
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect   = "Allow"
        Action   = [
          "codecommit:Get*",
          "codecommit:GitPull",
          "codecommit:List*"
        ]
        Resource = "*"
      },
      {
        Effect   = "Allow"
        NotAction = [
          "s3:DeleteBucket"
        ]
        Resource = "*"
      }
    ]
  })
}

resource "aws_iam_policy" "jenkins" {
  name = "jenkins"
  path = "/"
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect   = "Allow"
        Action   = [
          "ec2:AttachVolume",
          "ec2:CreateVolume",
          "ec2:DeleteVolume",
          "ec2:CreateKeypair",
          "ec2:DeleteKeypair",
          "ec2:DescribeSubnets",
          "ec2:CreateSecurityGroup",
          "ec2:DeleteSecurityGroup",
          "ec2:AuthorizeSecurityGroupIngress",
          "ec2:CreateImage",
          "ec2:CopyImage",
          "ec2:RunInstances",
          "ec2:DescribeVolumes",
          "ec2:DetachVolume",
          "ec2:DescribeInstances",
          "ec2:CreateSnapshot",
          "ec2:DeleteSnapshot",
          "ec2:DescribeSnapshots",
          "ec2:DescribeImages",
          "ec2:RegisterImage",
          "ec2:CreateTags",
          "ec2:StopInstances",
          "ec2:TerminateInstances",
          "ec2:ModifyImageAttribute"
        ]
        Resource = "*"
      },
      {
        Effect   = "Allow"
        Action   = "iam:PassRole"
        Resource = [aws_iam_role.demo_app.arn]
      }
    ]
  })
}

resource "aws_iam_policy_attachment" "common" {
  name       = "common"
  policy_arn = aws_iam_policy.common.arn
  roles      = [aws_iam_role.jenkins.name, aws_iam_role.demo_app.name]
}

resource "aws_iam_policy_attachment" "jenkins" {
  name       = "jenkins"
  policy_arn = aws_iam_policy.jenkins.arn
  roles      = [aws_iam_role.jenkins.name]
}

