resource "aws_security_group" "demo_app_elb" {
  name        = "demo-app-elb"
  description = "ELB security group"
  vpc_id      = aws_vpc.terraform_vpc.id

  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

resource "aws_elb" "demo_app_elb" {
  name             = "demo-app-elb"
  security_groups  = [aws_security_group.demo_app_elb.id]
  subnets          = [aws_subnet.public_1.id]

  listener {
    instance_port     = 80
    instance_protocol = "HTTP"
    lb_port           = 80
    lb_protocol       = "HTTP"
  }

  tags = {
    Name = "demo-app-elb"
  }
}

resource "aws_security_group" "demo_app_elb_prod" {
  name        = "demo-app-elb-prod"
  description = "ELB security group"
  vpc_id      = aws_vpc.terraform_vpc.id

  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

resource "aws_elb" "demo_app_elb_prod" {
  name                        = "demo-app-elb-prod"
  security_groups             = [aws_security_group.demo_app_elb_prod.id]
