  }

  ingress {
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

resource "aws_security_group" "demo_app" {
  name        = "demo-app"
  description = "EC2 instance security group"
  vpc_id      = aws_vpc.terraform_vpc.id

  ingress {
    from_port      = 80
    to_port        = 80
    protocol       = "tcp"
    security_groups = [
      aws_security_group.demo_app_elb.id,
      aws_security_group.demo_app_elb_prod.id
    ]
  }

  ingress {
    from_port      = 22
    to_port        = 22
