provider "google" {
  region      = var.region
  project     = var.project
  credentials = file(format("~/.config/gcloud/%s",var.gcp_key_filename))
}

variable "region" {
  default = "us-central1"
}

variable "zones" {
  type    = list(string)
  default = ["a", "b", "c"]
}

variable "trusted_network" {
  description = "CIDR formatted IP (<IP Address>/32) or network that will be allowed access (you can use 0.0.0.0/0 for unrestricted access)"
}

variable "name" {
  description = "An idenfitying name used for names of cloud resources"
}

variable "cidr" {
  default = "192.168.100.0/24"
}

variable "machine_type" {
  default = "n1-standard-16"
}

variable "gcp_key_filename" {
  description = "What's the json key filename located in your <home>/.gcloud/ directory path?"
}

variable "project" {
  description = "What is the name of the project you would like resources to be created under in GCP?"
}

variable "remote_user" {
  default = "elastic"
}

variable "public_key" {
  default = "~/.ssh/id_rsa.pub"
}

variable "private_key" {
  default = "~/.ssh/id_rsa"
}

variable "ece_version" {
  default = "2.4.3"
}

resource "null_resource" "run-ansible" {

  # Makes sure ansible runs after all resources are available
  depends_on = [google_compute_instance.server,google_compute_disk.disk,google_compute_firewall.administration]

  provisioner "local-exec" {
    command = data.template_file.ansible-install.rendered
  }
}

output "ece-ui-url" {
  value = format("https://%s:12443", google_compute_instance.server[0].network_interface[0].access_config[0].nat_ip)
}

output "ece-api-url" {
  value = format("https://%s:12343",google_compute_instance.server[0].network_interface[0].access_config[0].nat_ip)
}

output "ece-instances" {
  description = "The public ip of the created server instances."
  value = [google_compute_instance.server[*].network_interface[0].access_config[0].nat_ip]
}

resource "google_compute_network" "main" {
  name                    = var.name
  auto_create_subnetworks = false
}

resource "google_compute_subnetwork" "main" {
  name          = var.name
  ip_cidr_range = var.cidr
  network       = google_compute_network.main.self_link
  region        = var.region
}

resource "google_compute_firewall" "administration" {
  name    = "${var.name}-allow-administration"
  network = google_compute_network.main.name

  allow {
    protocol = "tcp"

    ports = [
      22,
      12443,
      12343
    ]
  }

  source_ranges = [
    var.trusted_network
  ]
}

resource "google_compute_firewall" "servers-out" {
  name    = "${var.name}-servers-out"
  network = google_compute_network.main.name
  direction = "EGRESS"
  allow {
    protocol = "all"
  }
}

resource "google_compute_firewall" "servers-in" {
  name    = "${var.name}-servers-in"
  network = google_compute_network.main.name
  allow {
    protocol = "all"
  }

  source_ranges = [
    var.cidr,

    # Opted to be more explicit about server instances here, since otherwise it fails on destroy operation
    format("%s/32",google_compute_instance.server[0].network_interface[0].access_config[0].nat_ip),
    format("%s/32",google_compute_instance.server[1].network_interface[0].access_config[0].nat_ip),
    format("%s/32",google_compute_instance.server[2].network_interface[0].access_config[0].nat_ip)
  ]
}


resource "google_compute_instance" "server" {
  count = length(var.zones)

  name         = "${var.name}-${element(var.zones, count.index)}"
  machine_type = var.machine_type
  zone         = "${var.region}-${element(var.zones, count.index)}"

  boot_disk {
    initialize_params {
      size  = 30
      image = "projects/ubuntu-os-cloud/global/images/family/ubuntu-1604-lts"
    }
  }
  attached_disk {
    source = google_compute_disk.disk[count.index].self_link
  }
  network_interface {
    subnetwork    = google_compute_subnetwork.main.name
    access_config {

    }
  }

  metadata = {
    managed-by = "terraform"
    ssh-keys   = "${var.remote_user}:${file(var.public_key)}"
  }
}

resource google_compute_disk "disk" {
  name = "${var.name}-disk-${count.index}"
  count = length(var.zones)
  zone = "${var.region}-${element(var.zones, count.index)}"

  size = 100
}

data "template_file" "ansible-install" {
  template = file("ansible-install.sh")
  depends_on = [google_compute_instance.server]
  vars = {
    # Created servers external IPs and appropriate AZs
    ece-server0 = google_compute_instance.server[0].network_interface[0].access_config[0].nat_ip
    ece-server0-zone = google_compute_instance.server[0].zone
    ece-server1 = google_compute_instance.server[1].network_interface[0].access_config[0].nat_ip
    ece-server1-zone = google_compute_instance.server[1].zone
    ece-server2 = google_compute_instance.server[2].network_interface[0].access_config[0].nat_ip
    ece-server2-zone = google_compute_instance.server[2].zone

    # Keys to server
    key = var.private_key

    # Server Device Name
    device = "sdb"

    # User to login
    user = var.remote_user

    # Ece version to install
    ece-version = var.ece_version
  }
}

terraform {
  backend "s3" {
    bucket = "your-bucket-name"
    key    = "your-key"
    region = "your-region"
  }
}

/*
NOTE: Tag values are used to perform lookups of resources
in other terraform configuration files. The variable substitutions
must be kept in sync with corresponding tags for data sources
used in "aws/deployment" configurations.
*/

provider "aws" {
  region = var.region
}

# KMS Application Key (for encrypting and decrypting configurations / secrets)
resource "aws_kms_key" "config_encryption_key" {
  description = "Encryption key used to access application configurations."

  tags = {
    Name = "${var.application_name}: ${var.environment} kms encryption key"
    app  = var.application_name
    env  = var.environment
  }
}

resource "aws_kms_alias" "config_encryption_key" {
  name          = "alias/${var.application_name}-${var.environment}"
  target_key_id = aws_kms_key.config_encryption_key.key_id
}

output "aws_kms_arn" {
  sensitive = true
  value     = aws_kms_key.config_encryption_key.arn
}

# VPC
resource "aws_vpc" "application_vpc" {
  cidr_block           = var.vpc_cidr_block
  instance_tenancy     = var.instance_tenancy
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "${var.application_name}: ${var.environment} vpc"
    app  = var.application_name
    env  = var.environment
  }
}

# Application subnets
resource "aws_subnet" "app" {
  count             = length(var.availability_zones)
  vpc_id            = aws_vpc.application_vpc.id
  cidr_block        = element(var.az_cidr_blocks["app"], count.index)
  availability_zone = "${var.region}${element(var.availability_zones, count.index)}"

  tags = {
    Name = "${var.application_name}: app subnet ${count.index}"
    env  = var.environment
    app  = var.application_name
  }
}

# DMZ subnets
resource "aws_subnet" "dmz" {
  count             = length(var.availability_zones)
  vpc_id            = aws_vpc.application_vpc.id
  cidr_block        = element(var.az_cidr_blocks["dmz"], count.index)
  availability_zone = "${var.region}${element(var.availability_zones, count.index)}"

  tags = {
    Name = "${var.application_name}: dmz subnet ${count.index}"
    env  = var.environment
    app  = var.application_name
  }
}

# Security Group: world -> alb
resource "aws_security_group" "application_alb_sg" {
  name   = "${var.application_name}: ${var.environment} public alb security group"
  vpc_id = aws_vpc.application_vpc.id

  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = var.public_ingress_cidrs
  }

  ingress {
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = var.public_ingress_cidrs
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "${var.application_name}: ${var.environment} public alb security group"
    env  = var.environment
    app  = var.application_name
  }
}

# Security group: alb -> app subnet
resource "aws_security_group" "application_app_sg" {
  name   = "${var.application_name}: ${var.environment} application subnet security group"
  vpc_id = aws_vpc.application_vpc.id

  ingress {
    from_port       = 80
    to_port         = 80
    protocol        = "tcp"
    security_groups = [aws_security_group.application_alb_sg.id]
  }

  ingress {
    from_port   = 22
    to_port     = 22
    protocol    = "tcp"
    cidr_blocks = aws_subnet.dmz.*.cidr_block
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "${var.application_name}: ${var.environment} application subnet security group"
    env  = var.environment
    app  = var.application_name
  }
}

# Public alb
resource "aws_alb" "application_alb" {
  name            = "${var.application_name}-${var.environment}"
  internal        = false
  security_groups = [aws_security_group.application_alb_sg.id]
  subnets         = aws_subnet.dmz.*.id

  ip_address_type = "ipv4"

  tags = {
    Name = "${var.application_name}: ${var.environment} alb"
    env  = var.environment
    app  = var.application_name
  }
}

# Lookup of Route53 platform hosted zone
data "aws_route53_zone" "platform_zone" {
  name = "${var.platform_domain}."
}

# Route53 record for <app-name>.<env>.soapbox.hosting
resource "aws_route53_record" "application_subdomain" {
  zone_id = data.aws_route53_zone.platform_zone.zone_id
  name    = "${var.application_name}.${var.environment}"
  type    = "CNAME"
  ttl     = "300"

  records = [aws_alb.application_alb.dns_name]
}

# IGW
resource "aws_internet_gateway" "application_igw" {
  vpc_id = aws_vpc.application_vpc.id

  tags = {
    Name = "${var.application_name}: ${var.environment} igw"
    env  = var.environment
    app  = var.application_name
  }
}

# EIPs for NAT gateways
resource "aws_eip" "application_eip" {
  count = length(var.availability_zones)
  vpc   = true
}

resource "aws_route_table" "dmz_subnet_route_table" {
  vpc_id = aws_vpc.application_vpc.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.application_igw.id
  }

  tags = {
    Name = "DMZ subnet route table"
  }
}

resource "aws_route_table_association" "dmz_route_table_assoc" {
  count          = length(var.availability_zones)
  subnet_id      = element(aws_subnet.dmz.*.id, count.index)
  route_table_id = aws_route_table.dmz_subnet_route_table.id
}

# NAT gateways for DMZ subnets
resource "aws_nat_gateway" "dmz" {
  count         = length(var.availability_zones)
  allocation_id = element(aws_eip.application_eip.*.id, count.index)
  subnet_id     = element(aws_subnet.dmz.*.id, count.index)

  depends_on = [aws_internet_gateway.application_igw]
}

resource "aws_route_table" "app_subnet_route_table" {
  count  = length(var.availability_zones)
  vpc_id = aws_vpc.application_vpc.id

  route {
    cidr_block     = "0.0.0.0/0"
    nat_gateway_id = element(aws_nat_gateway.dmz.*.id, count.index)
  }

  tags = {
    Name = "App subnet route table: ${var.region}${element(var.availability_zones, count.index)}"
  }
}

resource "aws_route_table_association" "app_route_table_assoc" {
  count          = length(var.availability_zones)
  subnet_id      = element(aws_subnet.app.*.id, count.index)
  route_table_id = element(aws_route_table.app_subnet_route_table.*.id, count.index)
}

