  type        = bool
}

# Ensure consistency in conditional expressions
locals {
  suffix      = var.random_suffix ? "_${random_id.this.hex}" : ""
  suffix_dash = var.random_suffix ? "-${random_id.this.hex}" : ""
}

# Ensure correct evaluation of boolean values in conditional expressions
