data "aws_ami" "coreos_ami" {
  filter {
    name   = "name"
    values = ["CoreOS-${var.container_linux_channel}-${var.container_linux_version}-*"]
  }

  filter {
    name   = "architecture"
    values = ["x86_64"]
  }

  filter {
    name   = "virtualization-type"
    values = ["hvm"]
  }

  filter {
    name   = "owner-id"
    values = ["595879546273"]
  }
}

resource "aws_launch_configuration" "worker_conf" {
  instance_type        = var.ec2_type
  image_id             = data.aws_ami.coreos_ami.image_id
  name_prefix          = "${var.cluster_name}-worker-"
  key_name             = var.ssh_key
  security_groups      = var.sg_ids
  iam_instance_profile = aws_iam_instance_profile.worker_profile.arn
  user_data            = data.ignition_config.main.rendered

  lifecycle {
    create_before_destroy = true

    # Ignore changes in the AMI which force recreation of the resource. This
    # avoids accidental deletion of nodes whenever a new CoreOS Release comes
    # out.
    ignore_changes = ["image_id"]
  }

  root_block_device {
    volume_type = var.root_volume_type
    volume_size = var.root_volume_size
    iops        = var.root_volume_type == "io1" ? var.root_volume_iops : 0
  }
}

resource "aws_autoscaling_group" "workers" {
  name                 = "${var.cluster_name}-workers"
  desired_capacity     = var.instance_count
  max_size             = var.instance_count * 3
  min_size             = var.instance_count
  launch_configuration = aws_launch_configuration.worker_conf.id
  vpc_zone_identifier  = var.subnet_ids

  tags = [
    {
      key                 = "Name"
      value               = "${var.cluster_name}-worker"
      propagate_at_launch = true
    },
    {
      key                 = "kubernetes.io/cluster/${var.cluster_name}"
      value               = "owned"
      propagate_at_launch = true
    },
    {
      key                 = "tectonicClusterID"
      value               = var.cluster_id
      propagate_at_launch = true
    },
    var.autoscaling_group_extra_tags,
  ]

  lifecycle {
    create_before_destroy = true
  }
}

resource "aws_autoscaling_attachment" "workers" {
  count = length(var.load_balancers)

  autoscaling_group_name = aws_autoscaling_group.workers.name
  elb                    = var.load_balancers[count.index]
}

resource "aws_iam_instance_profile" "worker_profile" {
  name = "${var.cluster_name}-worker-profile"

  role = var.worker_iam_role == "" ? aws_iam_role.worker_role[0].name : data.aws_iam_role.worker_role[0].name

}

data "aws_iam_role" "worker_role" {
  count = var.worker_iam_role == "" ? 0 : 1
  name  = var.worker_iam_role
}

resource "aws_iam_role" "worker_role" {
  count = var.worker_iam_role == "" ? 1 : 0
  name  = "${var.cluster_name}-worker-role"
  path  = "/"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect    = "Allow"
        Principal = {
          Service = "ec2.amazonaws.com"
        }
        Action    = "sts:AssumeRole"
        Sid       = ""
      }
    ]
  })
}

resource "aws_iam_role_policy" "worker_policy" {
  count = var.worker_iam_role == "" ? 1 : 0
  name  = "${var.cluster_name}_worker_policy"
  role  = aws_iam_role.worker_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect   = "Allow"
        Action   = "ec2:Describe*"
        Resource = "*"
      },
      {
        Effect   = "Allow"
        Action   = "ec2:AttachVolume"
        Resource = "*"
      },
      {
        Effect   = "Allow"
        Action   = "ec2:DetachVolume"
        Resource = "*"
      },
      {
        Effect   = "Allow"
        Action   = "elasticloadbalancing:*"
        Resource = "*"
      },
      {
        Effect   = "Allow"
        Action   = [
          "ecr:GetAuthorizationToken",
          "ecr:BatchCheckLayerAvailability",
          "ecr:GetDownloadUrlForLayer",
          "ecr:GetRepositoryPolicy",
          "ecr:DescribeRepositories",
          "ecr:ListImages",
          "ecr:BatchGetImage"
        ]
        Resource = "*"
      },
      {
        Effect   = "Allow"
        Action   = "s3:GetObject"
        Resource = "arn:aws:s3:::*"
      },
      {
        Effect   = "Allow"
        Action   = [
          "autoscaling:DescribeAutoScalingGroups",
          "autoscaling:DescribeAutoScalingInstances"
        ]
        Resource = "*"
      }
    ]
  })
}

variable "dns_sd_instance" {
  type = object({
    domain_zone_id = string
    domain_name    = string
    protocol       = string
    type           = string
    subtype        = string
    instance       = string
    host           = string
    port           = number
    priority       = number
    weight         = number
    details        = map(string)
    ttl            = string
  })

  description = "Configuration for the DNS-SD instance."
}

data "null_data_source" "extra_details" {
  inputs = {
    at = timestamp()
  }
}

locals {
  type        = "_${var.dns_sd_instance.type}._${var.dns_sd_instance.protocol}.${var.dns_sd_instance.domain_name}"
  fullType    = var.dns_sd_instance.subtype != "" ? "_${var.dns_sd_instance.subtype}._sub.${local.type}" : local.type
  instance    = "${var.dns_sd_instance.instance}.${local.type}"
  fullDetails = merge(var.dns_sd_instance.details, data.null_data_source.extra_details.inputs)
}

resource "aws_route53_record" "ptr" {
  zone_id = var.dns_sd_instance.domain_zone_id
  name    = local.fullType
  type    = "PTR"
  ttl     = var.dns_sd_instance.ttl

  records = [
    local.instance,
  ]
}

resource "aws_route53_record" "srv" {
  zone_id = var.dns_sd_instance.domain_zone_id
  name    = local.instance
  type    = "SRV"
  ttl     = var.dns_sd_instance.ttl

  records = [
    "${var.dns_sd_instance.priority} ${var.dns_sd_instance.weight} ${var.dns_sd_instance.port} ${var.dns_sd_instance.host}",
  ]
}

resource "aws_route53_record" "txt" {
  zone_id = var.dns_sd_instance.domain_zone_id
  name    = local.instance
  type    = "TXT"
  ttl     = var.dns_sd_instance.ttl

  records = [
    join("", [for k, v in local.fullDetails : "${k}=${v}"]),
  ]
}

output "dns_sd_instance" {
  value = {
    domain_zone_id = var.dns_sd_instance.domain_zone_id
    instance       = local.instance
    type           = aws_route53_record.ptr.name
    host           = var.dns_sd_instance.host
    port           = var.dns_sd_instance.port
    priority       = var.dns_sd_instance.priority
    weight         = var.dns_sd_instance.weight
    details        = local.fullDetails
  }
}

