provider "aws" {
  region = var.region
  version = "~> 1.58"
}

resource "aws_key_pair" "default" {
  key_name_prefix = var.deployment
  public_key      = var.public_key
}

resource "aws_s3_bucket" "blobstore" {
  bucket        = "${var.deployment}-${var.namespace}-blobstore"
  force_destroy = true
  region        = var.region

  tags = {
    Name                 = var.deployment
    concourse_up_project = var.project
    concourse_up_component = "bosh"
  }
}

resource "aws_iam_user" "blobstore" {
  name = "${var.deployment}-${var.namespace}-blobstore"
}

resource "aws_iam_access_key" "blobstore" {
  user       = aws_iam_user.blobstore.name
  depends_on = [aws_iam_user.blobstore]
}

resource "aws_iam_user_policy" "blobstore" {
  name = "${var.deployment}-${var.namespace}-blobstore"
  user = aws_iam_user.blobstore.name

  policy = jsonencode({
    Version = "2012-10-17",
    Statement = [{
      Action   = ["s3:*"],
      Effect   = "Allow",
      Resource = [
        "arn:aws:s3:::${aws_s3_bucket.blobstore.id}",
        "arn:aws:s3:::${aws_s3_bucket.blobstore.id}/*"
      ]
    }]
  })
}

resource "aws_iam_user" "bosh" {
  name = "${var.deployment}-${var.region}-bosh"
}

resource "aws_iam_access_key" "bosh" {
  user       = aws_iam_user.bosh.name
  depends_on = [aws_iam_user.bosh]
}

resource "aws_iam_user_policy" "bosh" {
  name = "${var.deployment}-${var.region}-bosh"
  user = aws_iam_user.bosh.name

  policy = jsonencode({
    Version = "2012-10-17",
    Statement = [{
      Action   = ["ec2:*", "elasticloadbalancing:*"],
      Effect   = "Allow",
      Resource = "*"
    }]
  })
}

resource "aws_vpc" "default" {
  cidr_block = var.network_cidr

  tags = {
    Name                 = var.deployment
    concourse_up_project = var.project
    concourse_up_component = "bosh"
  }
}

resource "aws_internet_gateway" "default" {
  vpc_id = aws_vpc.default.id

  tags = {
    Name                 = var.deployment
    concourse_up_project = var.project
    concourse_up_component = "bosh"
  }
}

resource "aws_route" "internet_access" {
  route_table_id         = aws_vpc.default.main_route_table_id
  destination_cidr_block = "0.0.0.0/0"
  gateway_id             = aws_internet_gateway.default.id
}

resource "aws_nat_gateway" "default" {
  allocation_id = aws_eip.nat.id
  subnet_id     = aws_subnet.public.id

  depends_on = [aws_internet_gateway.default]

  tags = {
    Name                 = var.deployment
    concourse_up_project = var.project
  }
}

resource "aws_route_table" "private" {
  vpc_id = aws_vpc.default.id

  route {
    cidr_block     = "0.0.0.0/0"
    nat_gateway_id = aws_nat_gateway.default.id
  }

  tags = {
    Name                 = "${var.deployment}-private"
    concourse_up_project = var.project
    concourse_up_component = "bosh"
  }
}

resource "aws_subnet" "public" {
  vpc_id                  = aws_vpc.default.id
  availability_zone       = var.availability_zone
  cidr_block              = var.public_cidr
  map_public_ip_on_launch = true

  tags = {
    Name                 = "${var.deployment}-public"
    concourse_up_project = var.project
    concourse_up_component = "bosh"
  }
}

resource "aws_subnet" "private" {
  vpc_id                  = aws_vpc.default.id
  availability_zone       = var.availability_zone
  cidr_block              = var.private_cidr
  map_public_ip_on_launch = false

  tags = {
    Name                 = "${var.deployment}-private"
    concourse_up_project = var.project
    concourse_up_component = "bosh"
  }
}

resource "aws_route_table_association" "private" {
  subnet_id      = aws_subnet.private.id
  route_table_id = aws_route_table.private.id
}

resource "aws_route53_record" "concourse" {
  count  = var.hosted_zone_id != null ? 1 : 0
  zone_id = var.hosted_zone_id
  name    = var.hosted_zone_record_prefix
  ttl     = 60
  type    = "A"
  records = [aws_eip.atc.public_ip]
}

resource "aws_eip" "director" {
  vpc       = true
  depends_on = [aws_internet_gateway.default]

  tags = {
    Name                 = "${var.deployment}-director"
    concourse_up_project = var.project
  }
}

resource "aws_eip" "atc" {
  vpc       = true
  depends_on = [aws_internet_gateway.default]

  tags = {
    Name                 = "${var.deployment}-atc"
    concourse_up_project = var.project
  }
}

resource "aws_eip" "nat" {
  vpc       = true
  depends_on = [aws_internet_gateway.default]

  tags = {
    Name                 = "${var.deployment}-nat"
    concourse_up_project = var.project
  }
}

resource "aws_security_group" "director" {
  name        = "${var.deployment}-director"
  description = "Concourse UP Default BOSH security group"
  vpc_id      = aws_vpc.default.id

  tags = {
    Name                 = "${var.deployment}-director"
    concourse_up_project = var.project
    concourse_up_component = "bosh"
  }

  ingress {
    from_port   = 6868
    to_port     = 6868
    protocol    = "tcp"
    cidr_blocks = [var.source_access_ip, aws_nat_gateway.default.public_ip]
  }

  ingress {
    from_port   = 25555
    to_port     = 25555
    protocol    = "tcp"
    cidr_blocks = [var.source_access_ip, aws_nat_gateway.default.public_ip]
  }

  ingress {
    from_port   = 22
    to_port     = 22
    protocol    = "tcp"
    cidr_blocks = [var.source_access_ip, aws_nat_gateway.default.public_ip]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

