# General Variables
variable "BaseName" {
  type    = string
}
variable "Location" {
  type    = list(string)
  default = ["westeurope", "northeurope"]
}
variable "Tags" {
  type    = map(string)
}
variable "appslot" {
  type    = map(string)
}

# Resource Group Variables
variable "ResourceGroupName" {
  type    = string
}

# App Service Plan Variables
variable "PlanSettings" {
  type    = map(string)
  default = {
    Kind     = "Windows"
    Tier     = "Standard"
    Size     = "S1"
    Capacity = 2
  }
}

# Web App Variables
variable "AppSettings" {
  type    = map(string)
  default = {}
}
variable "SiteConfig" {
  type    = map(string)
  default = {
    AlwaysOn       = true
    Ftp            = "Disabled"
    Tls            = "1.2"
  }
}
variable "Docs" {
  type    = list(string)
  default = ["Default.htm", "Default.html", "Default.asp", "index.htm", "index.html", "iisstart.htm", "default.aspx", "index.php", "hostingstart.html"]
}

# IP Whitelisting
variable "AppGatewayIps" {
  type    = list(string)
}
variable "ServiceIps" {
  type    = list(string)
}
variable "OfficeIps" {
  type    = list(string)
}

# setScmIpRestrictions Script Variables
variable "SubscriptionId" {
  type    = string
}
variable "TenantId" {
  type    = string
}
variable "ClientId" {
  type    = string
}
variable "ClientSecret" {
  type    = string
}

# Create Service Plan
resource "azurerm_app_service_plan" "AppServicePlan" {
  count               = length(var.Location)
  name                = "ASP-${var.BaseName}-${count.index + 1}"
  location            = var.Location[count.index]
  resource_group_name = var.ResourceGroupName
  kind                = var.PlanSettings["Kind"]
  sku {
    tier     = var.PlanSettings["Tier"]
    size     = var.PlanSettings["Size"]
    capacity = var.PlanSettings["Capacity"]
  }
  tags = var.Tags
}

# Create Web App Pair
resource "azurerm_app_service" "WebApp" {
  count               = length(var.Location)
  name                = "WA-${var.BaseName}-${count.index + 1}"
  location            = var.Location[count.index]
  resource_group_name = var.ResourceGroupName
  app_service_plan_id = azurerm_app_service_plan.AppServicePlan[count.index].id
  https_only          = true
  site_config         = var.SiteConfig
  tags                = var.Tags
}

# Web App Deployment Slot
resource "azurerm_app_service_slot" "WebAppSlot" {
  count               = length(var.Location)
  name                = var.appslot["Secondary"]
  app_service_name    = azurerm_app_service.WebApp[count.index].name
  location            = var.Location[count.index]
  resource_group_name = var.ResourceGroupName
  app_service_plan_id = azurerm_app_service_plan.AppServicePlan[count.index].id
  site_config         = var.SiteConfig
  tags                = var.Tags
}

resource "null_resource" "setIpRestrictions" {
  count = length(var.Location)

  provisioner "local-exec" {
    command     = ".'${path.module}\Scripts\Set-IpRestrictions.ps1' -TenantId ${var.TenantId} -SubscriptionId ${var.SubscriptionId} -ClientId ${var.ClientId} -ClientSecret '${var.ClientSecret}' -ResourceGroup ${var.ResourceGroupName} -WhiteList '${join(",", distinct(concat(var.AppGatewayIps, var.ServiceIps, var.OfficeIps)))}'"
    interpreter = ["PowerShell", "-NoProfile", "-Command"]
  }

  triggers = {
    RandomId = uuid()
  }

  depends_on = [azurerm_app_service.WebApp, azurerm_app_service_slot.WebAppSlot]
}

output "WebAppUrl" {
  value = azurerm_app_service.WebApp[*].default_site_hostname
}
output "WebAppResourceId" {
  value = azurerm_app_service.WebApp[*].id
}
output "WebAppPublicIps" {
  value = azurerm_app_service.WebApp[*].possible_outbound_ip_addresses
}
output "WebAppNames" {
  value = azurerm_app_service.WebApp[*].name
}
output "WebAppSlotName" {
  value = azurerm_app_service_slot.WebAppSlot[*].name
}

