resource "aws_launch_configuration" "webapp_lc" {
  lifecycle {
    create_before_destroy = false
  }

  image_id                    = lookup(var.amis, var.region)
  instance_type               = var.instance_type
  security_groups             = [
    var.webapp_http_inbound_sg_id,
    var.webapp_ssh_inbound_sg_id,
    var.webapp_outbound_sg_id
  ]
  user_data                   = file("./launch_configurations/userdata.sh")
  key_name                    = var.key_name
  associate_public_ip_address = true
}

output "webapp_lc_id" {
  value = aws_launch_configuration.webapp_lc.id
}

output "webapp_lc_name" {
  value = aws_launch_configuration.webapp_lc.name
}

variable "access_key" {}
variable "secret_key" {}

variable "region" {
    default = "us-west-2"
}

variable "ssh_key_name" {
    description = "Name of the SSH keypair to use in AWS."
}

variable "cluster_name" {
    default = "testing"
}

variable "containers_cidr" {
    default = "10.244.0.0/16"
}

variable "portal_net" {
    default = "10.0.0.0/16"
}

variable "num_etcd" {
    default = 3
}

variable "num_master" {
    default = 1
}

variable "num_worker" {
    default = 5
}

variable "ami" {
    default = "ami-66e30706"
}

variable "etcd_instance_type" {
    default = "t2.small"
}

variable "master_instance_type" {
    default = "t2.small"
}

variable "worker_instance_type" {
    default = "m3.medium"
}

variable "kubernetes_version" {
    default = "1.1.7"
}

variable "pod_network" {
    default = "10.2.0.0/16"
}

variable "service_ip_range" {
    default = "10.3.0.0/24"
}

variable "k8s_service_ip" {
    default = "10.3.0.1"
}

variable "dns_service_ip" {
    default = "10.3.0.10"
}

variable "api_secure_port" {
    default = 443
}

variable "master_dns_name" {
    default = ""
}

resource "template_file" "etcd-user-data" {
  template = file("${path.module}/user-data/etcd.yaml")

  vars = {
    etcd_discovery_url = replace(file("${path.module}/etcd_discovery_url.txt"), "/
/", "")
  }
}

resource "template_file" "master-user-data" {
  template = file("${path.module}/user-data/master.yaml")

  vars = {
    etcd_discovery_url = replace(file("${path.module}/etcd_discovery_url.txt"), "/
/", "")
    FLANNELD_ETCD_ENDPOINTS = join(",", formatlist("http://%s:2379", aws_instance.etcd.*.private_ip))
    KUBERNETES_CONTAINERS_CIDR = var.pod_network
    DNS_SERVICE_IP = var.dns_service_ip
  }
}

resource "template_file" "worker-user-data" {
  template = file("${path.module}/user-data/worker.yaml")

  vars = {
    etcd_discovery_url = replace(file("${path.module}/etcd_discovery_url.txt"), "/
/", "")
    FLANNELD_ETCD_ENDPOINTS = join(",", formatlist("http://%s:2379", aws_instance.etcd.*.private_ip))
    KUBERNETES_VERSION = var.kubernetes_version
    MASTER_HOSTS = join(",", formatlist("https://%s:%d", aws_instance.master.*.private_ip, var.api_secure_port))
    DNS_SERVICE_IP = var.dns_service_ip
    ca_pem = base64encode(file("${path.module}/tls-assets/ca.pem"))
    ca_key_pem = base64encode(file("${path.module}/tls-assets/ca-key.pem"))
  }
}

resource "template_file" "openssl" {
  template = file("${path.module}/templates/openssl.cnf")
  vars = {
    k8s_service_ip = var.k8s_service_ip
    master_dns = replace("DNS.3 = ${var.master_dns_name}
", "/^DNS.3 = 
/", "")
    instancelist = join("
", formatlist("IP.%v = %s
IP.%v = %s", count.index * 2 + 2, aws_instance.master.*.public_ip, count.index * 2 + 3, aws_instance.master.*.private_ip))
  }
}

resource "template_file" "kubectl-config-file" {
  template = file("${path.module}/templates/kubecfg.yaml")

  vars = {
    cluster_name = var.cluster_name
    token = replace(file("${path.module}/kube_token.txt"), "/
/", "")
    master_ip = element(aws_instance.master.*.public_ip, 0)
    api_secure_port = var.api_secure_port
    cwd = path.module
  }
}

resource "template_file" "create-master-tls" {
  template = file("${path.module}/templates/create-master-tls")
}

resource "template_file" "create-admin-tls" {
  template = file("${path.module}/templates/create-admin-tls")
}

resource "template_file" "master-env" {
  template = file("${path.module}/templates/master.env")
  vars = {
    KUBERNETES_VERSION = var.kubernetes_version
    ETCD_ENDPOINTS = join(",", formatlist("http://%s:2379", aws_instance.etcd.*.private_ip))
    SERVICE_IP_RANGE = var.service_ip_range
    API_SECURE_PORT = var.api_secure_port
  }
}

resource "template_file" "init-kubernetes" {
  template = file("${path.module}/templates/init-kubernetes.sh")
  vars = {
    ETCD_SERVER = "http://${element(aws_instance.etcd.*.private_ip, 0)}:2379"
    POD_NETWORK = var.pod_network
  }
}

resource "template_file" "kubectl-config" {
  template = file("${path.module}/templates/kubectl-config.sh")
  vars = {
    cluster_name = var.cluster_name
    token = replace(file("${path.module}/kube_token.txt"), "/
/", "")
    server = element(aws_instance.master.*.public_ip, 0)
    api_secure_port = var.api_secure_port
    cwd = path.module
  }
}

provider "aws" {
  access_key = var.access_key
  secret_key = var.secret_key
  region = var.region
}

resource "aws_vpc" "kubernetes" {
  cidr_block = "172.20.0.0/16"
  enable_dns_support = true
  enable_dns_hostnames = true
  tags = {
    Name = "kubernetes-${var.cluster_name}"
  }
}

resource "aws_subnet" "kubernetes" {
  vpc_id = aws_vpc.kubernetes.id
  cidr_block = "172.20.250.0/24"
  tags = {
    Name = "kubernetes-${var.cluster_name}"
  }
}

resource "aws_route_table" "kubernetes" {
  vpc_id = aws_vpc.kubernetes.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.kubernetes.id
  }

  tags = {
    Name = "kubernetes-${var.cluster_name}"
  }
}

resource "aws_internet_gateway" "kubernetes" {
  vpc_id = aws_vpc.kubernetes.id
  tags = {
    Name = "kubernetes-${var.cluster_name}"
  }
}

resource "aws_route_table_association" "kubernetes" {
  subnet_id = aws_subnet.kubernetes.id
  route_table_id = aws_route_table.kubernetes.id
}

resource "aws_security_group" "kubernetes" {
  name = "kubernetes-${var.cluster_name}"
  vpc_id = aws_vpc.kubernetes.id

  tags = {
    Name = "kubernetes-${var.cluster_name}"
  }
}

resource "aws_security_group_rule" "allow_ssh" {
  type              = "ingress"
  from_port         = 22
  to_port           = 22
  protocol          = "tcp"
  cidr_blocks       = ["0.0.0.0/0"]
  security_group_id = aws_security_group.kubernetes.id
}

resource "aws_security_group_rule" "allow_kube_api" {
  type              = "ingress"
  from_port         = var.api_secure_port
  to_port           = var.api_secure_port
  protocol          = "tcp"
  cidr_blocks       = ["0.0.0.0/0"]
  security_group_id = aws_security_group.kubernetes.id
}

resource "aws_security_group_rule" "allow_all_cluster" {
  type                     = "ingress"
  from_port                = 0
  to_port                  = 65535
  protocol                 = "-1"
  source_security_group_id = aws_security_group.kubernetes.id
  security_group_id        = aws_security_group.kubernetes.id
}

resource "aws_security_group_rule" "allow_all_egress" {
  type              = "egress"
  from_port         = 0
  to_port           = 65535
  protocol          = "-1"
  cidr_blocks       = ["0.0.0.0/0"]
  security_group_id = aws_security_group.kubernetes.id
}

resource "aws_instance" "etcd" {
  ami                         = var.ami
  instance_type               = var.etcd_instance_type
  count                       = var.num_etcd
  security_groups             = [aws_security_group.kubernetes.id]
  subnet_id                   = aws_subnet.kubernetes.id
  associate_public_ip_address = true
  key_name                    = var.ssh_key_name

  connection {
    user  = "core"
    agent = true
  }

  tags = {
    Name    = "${var.cluster_name}-etcd"
    Cluster = var.cluster_name
    Role    = "etcd"
  }

  user_data = template_file.etcd-user-data.rendered
}

resource "aws_iam_instance_profile" "master" {
  name  = "k8s-master"
  roles = [aws_iam_role.master.name]
}

resource "aws_iam_role_policy" "master" {
  name   = "k8s-master"
  role   = aws_iam_role.master.id
  policy = <<EOF
{
    "Version": "2012-10-17",
    "Statement": [
        {
            "Effect": "Allow",
            "Action": [
                "ec2:*"
            ],
            "Resource": [
                "*"
            ]
        },
        {
            "Effect": "Allow",
            "Action": [
                "elasticloadbalancing:*"
            ],
            "Resource": [
                "*"
            ]
        }
    ]
}
EOF
}

resource "aws_iam_role" "master" {
  name               = "k8s-master"
  path               = "/"
  assume_role_policy = <<EOF
{
  "Version": "2012-10-17",
  "Statement": [
    {
      "Action": "sts:AssumeRole",
      "Principal": {
        "Service": "ec2.amazonaws.com"
      },
      "Effect": "Allow",
      "Sid": ""
    }
  ]
}
EOF
}

resource "aws_instance" "master" {
  ami                         = var.ami
  instance_type               = var.master_instance_type
  count                       = var.num_master
  iam_instance_profile        = aws_iam_instance_profile.master.name
  security_groups             = [aws_security_group.kubernetes.id]
  subnet_id                   = aws_subnet.kubernetes.id
  associate_public_ip_address = true
  key_name                    = var.ssh_key_name

  connection {
    user  = "core"
    agent = true
  }

  tags = {
    Name    = "${var.cluster_name}-master"
    Cluster = var.cluster_name
    Role    = "master"
  }

  provisioner "file" {
    source      = "scripts"
    destination = "/tmp/scripts"
  }

  provisioner "remote-exec" {
    inline = [
      "cat <<'EOF' > /tmp/kubernetes.env
${template_file.master-env.rendered}
EOF",
      "echo 'PRIVATE_IP=${self.private_ip}' >> /tmp/kubernetes.env",
      "echo 'PUBLIC_IP=${self.public_ip}' >> /tmp/kubernetes.env",
      "sudo mv /tmp/kubernetes.env /etc/kubernetes.env",
      "sudo bash /tmp/scripts/master.sh",
      # "cat << 'EOF' > /tmp/kubernetes/tokens.csv
${template_file.tokens.rendered}
EOF",
      "sudo mkdir -p /etc/kubernetes/ssl"
      # "sudo mv /tmp/kubernetes/tokens.csv /etc/kubernetes/ssl/tokens.csv",
    ]
  }

  user_data = template_file.master-user-data.rendered
}

# This file manages resources on Google Cloud Platform (GCP)

# Random suffix generator for resource names
resource "random_pet" "suffix" {
  length = 2
}

# Google Cloud provider configuration
provider "google" {
  project = "<YOUR_PROJECT_ID>"
  region  = "us-central1"
  zone    = "us-central1-c"
}

# Compute Instance Template
resource "google_compute_instance_template" "foobar" {
  name         = "my-instance-template-${random_pet.suffix.id}"
  machine_type = "e2-standard-4"

  disk {
    source_image = "debian-cloud/debian-11"
    disk_size_gb = 250
  }

  network_interface {
    network = "default"

    access_config {
      # secret default
      network_tier = "PREMIUM"
    }
  }

  service_account {
    scopes = [
      "https://www.googleapis.com/auth/devstorage.read_only",
      "https://www.googleapis.com/auth/logging.write",
      "https://www.googleapis.com/auth/monitoring.write",
      "https://www.googleapis.com/auth/pubsub",
      "https://www.googleapis.com/auth/service.management.readonly",
      "https://www.googleapis.com/auth/servicecontrol",
      "https://www.googleapis.com/auth/trace.append",
    ]
  }
}

# Compute Target Pool
resource "google_compute_target_pool" "foobar" {
  name = "my-target-pool-${random_pet.suffix.id}"
}

# Compute Region Instance Group Manager
resource "google_compute_region_instance_group_manager" "foobar" {
  name   = "my-region-igm-${random_pet.suffix.id}"
  region = "us-central1"

  version {
    instance_template = google_compute_instance_template.foobar.self_link
    name              = "primary"
  }

  target_pools       = [google_compute_target_pool.foobar.self_link]
  base_instance_name = "foobar"
}

# Compute Autoscaler
resource "google_compute_region_autoscaler" "foobar" {
  name   = "my-region-autoscaler-${random_pet.suffix.id}"
  region = "us-central1"
  target = google_compute_region_instance_group_manager.foobar.id

  autoscaling_policy {
    max_replicas    = 5
    min_replicas    = 1
    cooldown_period = 60

    cpu_utilization {
      target = 0.5
    }
  }
}

# Data Source: Google Compute Image
data "google_compute_image" "debian_9" {
  family  = "debian-11"
  project = "debian-cloud"
}

