variable "aws_region" {
  type = string
}



variable "aws_zone" {
  type = string
}


variable "aws_vpc" {
  type = string
}


variable "aws_vpc_cidr" {
  type = string
}


variable aws_public_subnet { type = string }
variable aws_public_cidr_block { type = string }


variable "aws_vpn_gw_name" {
  type = string
}

variable "aws_gcp_customer_gw" {
  type = string
}

variable "aws_gcp_vpn_connection" {
  type = string
}

variable aws_zone_1 { type = string }




variable "aws_key_name" { type = string }
variable "aws_ssh_pub_key_file" { type = string }
variable "aws_image_id" { type = string }




resource "aws_vpc" "aws_vpc" {
  cidr_block           = var.aws_vpc_cidr
  enable_dns_support   = true
  enable_dns_hostnames = true

  tags = {
    "Name" = var.aws_vpc
  }
}

# vpn


# create and attach
resource "aws_vpn_gateway" "aws_vpn_gw" {
  vpc_id = aws_vpc.aws_vpc.id

  tags = {
    Name = var.aws_vpn_gw_name
  }
}


resource "aws_customer_gateway" "aws_cgw" {
  bgp_asn = 65000
  ip_address = google_compute_address.gcp_vpn_ip.address
  type = "ipsec.1"

  tags = {
    "Name" = var.aws_gcp_customer_gw
  }
}


resource "aws_vpn_connection" "aws_gcp_vpn_connection" {
  vpn_gateway_id      = aws_vpn_gateway.aws_vpn_gw.id
  customer_gateway_id = aws_customer_gateway.aws_cgw.id
  type = "ipsec.1"
  static_routes_only  = true
  tags = {
    "Name" = var.aws_gcp_vpn_connection
  }
}






# aws: public subnet, igw, nat
resource "aws_subnet" "aws_public_subnet" {
  vpc_id     = aws_vpc.aws_vpc.id
  cidr_block = var.aws_public_cidr_block
  availability_zone = var.aws_zone_1

  map_public_ip_on_launch = true

  tags = {
    Name = var.aws_public_subnet
  }
}

resource "aws_internet_gateway" "aws_vpc_igw" {
  vpc_id = aws_vpc.aws_vpc.id

  tags = {
    Name = "aws-vpc-igw"
  }
}


# security: routes and security groups
# vpn gw for gcp vpc traffic
resource "aws_route" "simulation_default_route" {
  route_table_id = aws_vpc.aws_vpc.default_route_table_id
  destination_cidr_block = var.gcp_vpc_cidr
  gateway_id = aws_vpn_gateway.aws_vpn_gw.id
}

resource "aws_vpn_connection_route" "aws-to-gcp" {
  destination_cidr_block = var.gcp_vpc_cidr
  vpn_connection_id = aws_vpn_connection.aws_gcp_vpn_connection.id
}


# Route: Internet traffic for jumpbox
resource "aws_route" "igw_traffic" {
  route_table_id = aws_vpc.aws_vpc.default_route_table_id
  destination_cidr_block = "0.0.0.0/0"
  gateway_id = aws_internet_gateway.aws_vpc_igw.id
}

# Security Group: rule for 22 incoming
resource "aws_security_group_rule" "ssh" {
  type              = "ingress"
  from_port         = 22
  to_port           = 22
  protocol          = "tcp"
  cidr_blocks       = [ "0.0.0.0/0" ]
  security_group_id = aws_vpc.aws_vpc.default_security_group_id
}


# aws: jumpbox
resource "aws_key_pair" "aws_pub_key" {
  key_name   = var.aws_key_name
  public_key = file(var.aws_ssh_pub_key_file)

}

resource "aws_instance" "aws-vm" {
  ami           = var.aws_image_id
  instance_type = "t2.micro"
  subnet_id     = aws_subnet.aws_public_subnet.id
  key_name      = var.aws_key_name

  associate_public_ip_address = true

  tags = {
    Name = "aws-jumpbox"
  }
}

output "aws_jumpbox_ip" {
  value = aws_instance.aws-vm.public_ip
}




variable "gcp_project_id" {
  description = "GCP Project ID."
  type        = string
}

variable "gcp_region" {
  type = string
}



variable "gcp_zone" {
  type = string
}


variable "gcp_vpc" {
  type = string
}


variable "gcp_vpc_cidr" {
  type = string
}

variable "gcp_vpc_subnet" {
  type = string
}


variable "gcp_vpc_subnet_cidr" {
  type = string
}

variable "gcp_aws_vpc_gw_ip_name" { type = string }


variable "gcp_aws_vpc_target_gw" {
  type = string
}

variable "gcp_aws_vpc_gw_name" {
  type = string
}


variable "gcp_aws_vpn_tunnel1" {
  type = string
}

variable "gcp_aws_vpn_tunnel2" { type = string }

variable "gcp_os_username" { type = string }
variable "gcp_ssh_pub_key_file" { type = string }



resource "google_compute_network" "gcp_vpc" {
  name = var.gcp_vpc
  auto_create_subnetworks = "false"
}

resource "google_compute_firewall" "allow_internal" {
  name = "${var.gcp_vpc}-allow-internal"
  network = google_compute_network.gcp_vpc.name

  allow { protocol = "icmp" }
  allow { protocol = "tcp" }
  allow { protocol = "udp" }

  source_ranges = [ var.gcp_vpc_cidr ]
}

resource "google_compute_firewall" "allow_ssh" {
  name = "${var.gcp_vpc}-allow-ssh"
  network = google_compute_network.gcp_vpc.name

  allow {
    protocol = "tcp"
    ports = [ "22" ]
  }
}

resource "google_compute_subnetwork" "gcp_subnet" {
  name = var.gcp_vpc_subnet
  ip_cidr_range = var.gcp_vpc_subnet_cidr
  network = google_compute_network.gcp_vpc.name
  region = var.gcp_region
}


# vpn connection

resource "google_compute_address" "gcp_vpn_ip" {
  name   = var.gcp_aws_vpc_gw_ip_name
  region = var.gcp_region
}


resource "google_compute_vpn_gateway" "gcp_vpn_gw" {
  name    = var.gcp_aws_vpc_target_gw
  network = google_compute_network.gcp_vpc.name
  region  = var.gcp_region
}


resource "google_compute_forwarding_rule" "fr_aws_esp" {
  name        = "fr-${var.gcp_aws_vpc_gw_name}-aws-esp"
  ip_protocol = "ESP"

  ip_address  = google_compute_address.gcp_vpn_ip.address
  target      = google_compute_vpn_gateway.gcp_vpn_gw.self_link
  region = var.gcp_region
}

resource "google_compute_forwarding_rule" "fr_aws_udp500" {
  name        = "fr-${var.gcp_aws_vpc_gw_name}-aws-udp500"
  ip_protocol = "UDP"
  port_range  = "500"

  ip_address  = google_compute_address.gcp_vpn_ip.address
  target      = google_compute_vpn_gateway.gcp_vpn_gw.self_link
  region = var.gcp_region
}

resource "google_compute_forwarding_rule" "fr_aws_udp4500" {
  name        = "fr-${var.gcp_aws_vpc_gw_name}-aws-udp4500"
  ip_protocol = "UDP"
  port_range  = "4500"

  ip_address  = google_compute_address.gcp_vpn_ip.address
  target      = google_compute_vpn_gateway.gcp_vpn_gw.self_link
  region = var.gcp_region
}


resource "google_compute_vpn_tunnel" "aws_tunnel1" {
  name          = var.gcp_aws_vpn_tunnel1
  peer_ip       = aws_vpn_connection.aws_gcp_vpn_connection.tunnel1_address
  ike_version = 2
  shared_secret = aws_vpn_connection.aws_gcp_vpn_connection.tunnel1_preshared_key

  local_traffic_selector = [ "0.0.0.0/0" ]
  remote_traffic_selector = [ "0.0.0.0/0" ]

  target_vpn_gateway = google_compute_vpn_gateway.gcp_vpn_gw.id
  region = var.gcp_region

  depends_on = [
    google_compute_forwarding_rule.fr_aws_esp,
    google_compute_forwarding_rule.fr_aws_udp500,
    google_compute_forwarding_rule.fr_aws_udp4500,
  ]
}

resource "google_compute_route" "route1" {
  name       = "${var.gcp_aws_vpn_tunnel1}-route"
  network = google_compute_network.gcp_vpc.name
  dest_range = var.aws_vpc_cidr
  priority   = 1000

  next_hop_vpn_tunnel = google_compute_vpn_tunnel.aws_tunnel1.id
}


resource "google_compute_vpn_tunnel" "aws_tunnel2" {
  name          = var.gcp_aws_vpn_tunnel2
  peer_ip       = aws_vpn_connection.aws_gcp_vpn_connection.tunnel2_address
  ike_version = 2
  shared_secret = aws_vpn_connection.aws_gcp_vpn_connection.tunnel2_preshared_key

  local_traffic_selector = [ "0.0.0.0/0" ]
  remote_traffic_selector = [ "0.0.0.0/0" ]

  target_vpn_gateway = google_compute_vpn_gateway.gcp_vpn_gw.id
  region = var.gcp_region

  depends_on = [
    google_compute_forwarding_rule.fr_aws_esp,
    google_compute_forwarding_rule.fr_aws_udp500,
    google_compute_forwarding_rule.fr_aws_udp4500,
  ]
}

resource "google_compute_route" "route" {
  name       = "${var.gcp_aws_vpn_tunnel2}-route"
  network = google_compute_network.gcp_vpc.name
  dest_range = var.aws_vpc_cidr
  priority   = 1000

  next_hop_vpn_tunnel = google_compute_vpn_tunnel.aws_tunnel2.id
}






resource "google_compute_instance" "vm_gcp" {
  name         = "vm-gcp"
  machine_type = "f1-micro"
  zone         = var.gcp_zone

  boot_disk {
    initialize_params {
      image = "debian-cloud/debian-9"
    }
  }

  network_interface {
    network = google_compute_network.gcp_vpc.name
    subnetwork = google_compute_subnetwork.gcp_subnet.name
    access_config {
    }
  }

  metadata = {
    ssh-keys = "${var.gcp_os_username}:${file(var.gcp_ssh_pub_key_file)}"
  }
}

output "gcp_jumpbox_ip" {
  value = google_compute_instance.vm_gcp.network_interface.0.access_config.0.nat_ip
}




# AWS: Security Group: rule for 7000,7001 cassanrda traffic
resource "aws_security_group_rule" "cs-inode" {
  type              = "ingress"
  from_port         = 7000
  to_port           = 7001
  protocol          = "tcp"
  cidr_blocks       = [ "0.0.0.0/0" ]
  security_group_id = aws_vpc.aws_vpc.default_security_group_id
}

# GCP: Firewall Rule: rule for 7000,7001 cassanrda traffic
resource "google_compute_firewall" "allow_cs-inode" {
  name = "${var.gcp_vpc}-allow-cs"
  network = google_compute_network.gcp_vpc.name

  allow {
    protocol = "tcp"
    ports = [ "7000", "7001" ]
  }
}


