# Input variables

variable "iam_path" {
  type        = string
  description = "The path to the IAM resources."
}

variable "stack_item_label" {
  type        = string
  description = "Short form identifier for this stack. This value is used to create the 'Name' resource tag for resources created by this stack item, and also serves as a unique key for re-use."
}

# AWS API Gateway Account

# Set Terraform version constraint
terraform {
  required_version = ">= 0.9.3"
}

data "aws_region" "current" {}

# Creates IAM role for service integrations
data "aws_iam_policy_document" "role" {
  statement {
    actions = ["sts:AssumeRole"]
    effect  = "Allow"

    principals {
      type        = "Service"
      identifiers = ["apigateway.amazonaws.com"]
    }
  }
}

resource "aws_iam_role" "role" {
  assume_role_policy = data.aws_iam_policy_document.role.json
  name_prefix        = "apigw-${var.stack_item_label}-${data.aws_region.current.name}-"
  path               = var.iam_path
}

# Creates logging policy
data "aws_iam_policy_document" "logging" {
  statement {
    actions = [
      "logs:CreateLogGroup",
      "logs:CreateLogStream",
      "logs:DescribeLogGroups",
      "logs:DescribeLogStreams",
      "logs:PutLogEvents",
      "logs:GetLogEvents",
      "logs:FilterLogEvents",
    ]

    effect    = "Allow"
    resources = ["*"]
  }
}

resource "aws_iam_role_policy" "logging" {
  name   = "logging"
  policy = data.aws_iam_policy_document.logging.json
  role   = aws_iam_role.role.id
}

# Configures API gateway for the region
resource "aws_api_gateway_account" "account" {
  cloudwatch_role_arn = aws_iam_role.role.arn
}

provider "aws" {
  region = var.region
}

resource "aws_instance" "example" {
  ami           = var.AMI_ID
  instance_type = "t2.micro"
  key_name      = "common-key"

  provisioner "local-exec" {
    command = "echo 'versionName=${aws_instance.example.public_ip}' >> ${var.JOB_ENV_FILE}"
  }

  provisioner "remote-exec" {
    inline = [
      "docker run -d -p 25565:25565 --restart always softsrv/minecraft:1.12.2",
    ]

    connection {
      user        = "ec2-user"
      private_key = file(var.PEM_KEY)
    }
  }
}

output "machine_ip" {
  value = aws_instance.example.public_ip
}

