# Container Registry Module

variable "ACRName" {
  type        = string
  description = "The Container Registry Name"
}

variable "ACRSku" {
  type        = string
  description = "This variable determines the Sku of the ACR. Allowed values are basic, standard & premium"
}



resource "azurerm_container_registry" "TerraACR" {
  name                      = var.ACRName
  resource_group_name       = var.ACRRG
  location                  = var.ACRLocation
  admin_enabled             = var.IsAdminEnabled
  sku                       = var.ACRSku
  georeplication_locations  = var.ACRReplList

  tags = {
    Environment       = var.EnvironmentTag
    Usage             = var.EnvironmentUsageTag
    Owner             = var.OwnerTag
    ProvisioningDate  = var.ProvisioningDateTag
  }
}

# Outputs
output "Name" {
  value       = azurerm_container_registry.TerraACR.name
  description = "The name of the ACR"
}

output "RGName" {
