variable "region" {
  description = "The region where the cloudwatch logs are created"
}

variable "cluster" {
  description = "Name of the Fargate cluster"
}

variable "capacity_provider" {
  description = "The capacity provider to use. Can be FARGATE or FARGATE_SPOT"
}

variable "imageversion" {
  description = "The version of the image to deploy to this environment"
}

variable "environment" {
  description = "Name of the environment this fargate environment hosts"
}

variable "api_cpu" {
  description = "Nr of vCPUs to assign to the API task"
  default     = 256
}

variable "api_memory" {
  description = "Memory (GB) to assign to the API task"
  default     = 512
}

variable "api_desired_count" {
  description = "Nr of containers that should run"
  default     = 1
}

variable "ssm_securestrings" {
  description = "The SSM parameters to add to the task's environment as secure parameters"
}

variable "ssm_strings" {
  description = "The SSM parameters to add to the task's environment as normal parameters"
}

variable "ssm_dbhost" {
  description = "ARN to the SSM parameter holding the dbhost value"
}

variable "ssm_db" {
  description = "ARN to the SSM parameter holding the db value"
}

variable "ssm_dbuser" {
  description = "ARN to the SSM parameter holding the dbuser value"
}

variable "ssm_dbpassword" {
  description = "ARN to the SSM parameter holding the dbpassword value"
}

variable "sg_rds_access" {
  description = "The security group that grants access to the RDS instance for these containers"
}

variable "subnet_ids" {
  description = "The subnet IDs where these tasks can run"
}

variable "vpc" {
  description = "The VPC to install the target group for the containers in"
}

variable "route53_zone_name" {
  description = "The zone in which to create a hostname to this environment"
}

variable "hostname" {
  description = "The hostname to register for this environment"
}

variable "alb" {
  description = "The ALB for this environment"
}

variable "alb_listener" {
  description = "The ALB listener in which to create a rule for directing traffic to these containers"
}


# ECS task execution role data
data "aws_iam_policy_document" "ecs_task_execution_role" {
  version = "2012-10-17"
  statement {
    sid    = ""
    effect = "Allow"
    actions = [
      "sts:AssumeRole"
    ]

    principals {
      type        = "Service"
      identifiers = ["ecs-tasks.amazonaws.com"]
    }
  }
}

# ECS task execution role
resource "aws_iam_role" "ecs_task_execution_role" {
  name               = "EcsTaskExecutionRole-${var.environment}"
  assume_role_policy = data.aws_iam_policy_document.ecs_task_execution_role.json
}

# ECS task execution role policy attachment
resource "aws_iam_role_policy_attachment" "ecs_task_execution_role" {
  role       = aws_iam_role.ecs_task_execution_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AmazonECSTaskExecutionRolePolicy"
}

resource "aws_iam_role_policy_attachment" "ecs_task_ssm_role" {
  role       = aws_iam_role.ecs_task_execution_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonSSMReadOnlyAccess"
}


resource "aws_ecs_cluster" "cluster" {
  name = var.cluster
  capacity_providers = [var.capacity_provider]

  default_capacity_provider_strategy {
    capacity_provider = var.capacity_provider
  }
}


# The service running the task
resource "aws_ecs_service" "api-collaction" {
  name            = "api-${var.environment}-collaction"
  cluster         = aws_ecs_cluster.cluster.id
  task_definition = aws_ecs_task_definition.api-collaction.arn
  desired_count   = var.api_desired_count

  capacity_provider_strategy {
    capacity_provider = var.capacity_provider
    weight            = 100
  }

  network_configuration {
    security_groups = [
      aws_security_group.inbound-ecs.id,  # Allow traffic into the container
      aws_security_group.outbound-ecs.id, # Allow traffic out of the container
      var.sg_rds_access.id                # Allow access to the database
    ]
    subnets          = var.subnet_ids.ids
    assign_public_ip = true
  }

  load_balancer {
    target_group_arn = aws_alb_target_group.api-collaction.id
    container_name   = "api"
    container_port   = 5000
  }

  depends_on = [
    var.alb_listener,
    aws_iam_role_policy_attachment.ecs_task_execution_role
  ]
}

# Allow traffic out of the container
resource "aws_security_group" "outbound-ecs" {
  name        = "outbound-api-${var.environment}-collaction"
  description = "Allowed outbound traffic for ${var.environment} API containers"

  egress {
    # Outgoing access to all
    protocol    = "-1"
    from_port   = 0
    to_port     = 0
    cidr_blocks = ["0.0.0.0/0"]
  }
}


resource "aws_security_group" "inbound-ecs" {
  name        = "inbound-api-${var.environment}-collaction"
  description = "Allowed inbound traffic for ${var.environment} API containers"

  ingress {
    protocol  = "tcp"
    from_port = 5000
    to_port   = 5000

    security_groups = [
      data.aws_security_group.outbound-alb.id # Outbound ALB traffic is allowed into the container
    ]
  }
}

# Security group that allows access from the ALB is created in the commons section, with the ALB.
data "aws_security_group" "outbound-alb" {
  name = "outbound-alb"
}


resource "aws_ecs_task_definition" "api-collaction" {
  family                   = "api-${var.environment}-collaction-task"
  execution_role_arn       = aws_iam_role.ecs_task_execution_role.arn
  network_mode             = "awsvpc"
  requires_compatibilities = ["FARGATE"]
  cpu                      = var.api_cpu
  memory                   = var.api_memory
  container_definitions    = <<DEFINITION
    [
      {
        "name": "api",
        "image": "collaction/backend:${var.imageversion}",
        "networkMode": "awsvpc",
        "portMappings": [
          {
            "containerPort": 5000,
            "hostPort": 5000
          }
        ],
        "logConfiguration": {
            "logDriver": "awslogs",
            "options": {
              "awslogs-group": "/ecs/${var.environment}/api-collaction",
              "awslogs-region": "${var.region}",
              "awslogs-stream-prefix": "ecs"
            }
        },
        "environment": [
          {
            "name": "ASPNETCORE_ENVIRONMENT",
            "value": "Production"
          },
          {
            "name": "ASPNETCORE_URLS",
            "value": "http://*:5000"
          }
        ],
        "secrets": [
          %{for param in var.ssm_securestrings}
          {
            "name": "${param.description}", 
            "valueFrom": "${param.arn}"
          },
          %{endfor}
          %{for param in var.ssm_strings}
          {
            "name": "${param.description}", 
            "valueFrom": "${param.arn}"
          },
          %{endfor}
          {
            "name": "DbHost",
            "valueFrom": "${var.ssm_dbhost.arn}"
          },
          {
            "name": "Db",
            "valueFrom": "${var.ssm_db.arn}"
          },
          {
            "name": "DbUser",
            "valueFrom": "${var.ssm_dbuser.arn}"
          },
          {
            "name": "DbPassword",
            "valueFrom": "${var.ssm_dbpassword.arn}"
          }
        ]
      }
    ]
    DEFINITION
  depends_on = [
    aws_cloudwatch_log_group.api-collaction
  ]
}

# Container output is logged to CloudWatch
resource "aws_cloudwatch_log_group" "api-collaction" {
  name              = "/ecs/${var.environment}/api-collaction"
  retention_in_days = 7
}

resource "aws_cloudwatch_log_stream" "api-collaction" {
  name           = "api-${var.environment}-collaction"
  log_group_name = aws_cloudwatch_log_group.api-collaction.name
}

# Target group for the load balancer
resource "aws_alb_target_group" "api-collaction" {
  name        = "api-${var.environment}-collaction"
  port        = 5000
  protocol    = "HTTP"
  vpc_id      = var.vpc.id
  target_type = "ip"

  health_check {
    healthy_threshold   = 3
    interval            = 30
    protocol            = "HTTP"
    matcher             = 200
    timeout             = 3
    path                = "/health"
    unhealthy_threshold = 2
  }
}

# Listener rules for load balancer
resource "aws_lb_listener_rule" "api-collaction" {
  listener_arn = var.alb_listener.arn

  action {
    type             = "forward"
    target_group_arn = aws_alb_target_group.api-collaction.arn
  }

  condition {
    host_header {
      values = [
        var.hostname
      ]
    }
  }
}


# Add hostname to the DNS 
data "aws_route53_zone" "collaction" {
  name = var.route53_zone_name
}

resource "aws_route53_record" "api-collaction" {
  zone_id = data.aws_route53_zone.collaction.zone_id
  name    = var.hostname
  type    = "CNAME"
  ttl     = "300"
  records = [
    var.alb.dns_name
  ]
}

# Variables

variable "availability_zones" {
  type        = list(string)
  description = "List of availability zones to use for ELBs"
}

variable "security_groups" {
  type        = list(string)
  description = "List of additional security groups for the consul cluster"
}

variable "private_subnets" {
  type        = list(string)
  description = "Subnets ELB should deploy servers into"
}

variable "ami" {
  type        = string
  description = "AMI to use for deploying Consul. Use one based on Ubuntu Trusty."
}

variable "instance_type" {
  type        = string
  description = "AWS instance type for Consul servers."
}

variable "key_name" {
  type        = string
  description = "Name of SSH key to insert into machine to grant initial access"
}

variable "num_instances" {
  type        = number
  description = "Number of consul servers to deploy. Consul advises using odd numbers to avoid stalemate elections."
  default     = 3
}

variable "prefix" {
  type        = string
  description = "Prefix for naming instances"
  default     = "consul-"
}

variable "region" {
  type        = string
  description = "AWS region for deploying Consul nodes"
}

variable "vpc" {
  type        = string
  description = "VPC in which to deploy Consul"
}

#######################################

provider "aws" {
  region = var.region
}

resource "aws_security_group" "consul" {
  name_prefix = var.prefix
  description = "Allow consul traffic"
  vpc_id      = var.vpc
}

resource "aws_security_group_rule" "ssh" {
  type              = "ingress"
  from_port         = 22
  to_port           = 22
  protocol          = "tcp"
  security_group_id = aws_security_group.consul.id
  self              = true
}

resource "aws_security_group_rule" "consul_rpc" {
  type              = "ingress"
  from_port         = 8300
  to_port           = 8300
  protocol          = "tcp"
  security_group_id = aws_security_group.consul.id
  self              = true
}

resource "aws_security_group_rule" "consul_serf_lan" {
  type              = "ingress"
  from_port         = 8301
  to_port           = 8301
  protocol          = "all"
  security_group_id = aws_security_group.consul.id
  self              = true
}

resource "aws_security_group_rule" "consul_serf_wan" {
  type              = "ingress"
  from_port         = 8302
  to_port           = 8302
  protocol          = "all"
  security_group_id = aws_security_group.consul.id
  self              = true
}

resource "aws_security_group_rule" "consul_cli_rpc" {
  type              = "ingress"
  from_port         = 8400
  to_port           = 8400
  protocol          = "tcp"
  security_group_id = aws_security_group.consul.id
  self              = true
}

resource "aws_security_group_rule" "consul_dns_interface" {
  type              = "ingress"
  from_port         = 8600
  to_port           = 8600
  protocol          = "all"
  security_group_id = aws_security_group.consul.id
  self              = true
}

resource "aws_security_group_rule" "allow_all_outbound" {
  type              = "egress"
  from_port         = 0
  to_port           = 0
  protocol          = "-1"
  security_group_id = aws_security_group.consul.id
  cidr_blocks       = ["0.0.0.0/0"]
}

resource "aws_elb" "consul" {
  name                       = "${var.prefix}servers-elb"
  subnets                    = var.private_subnets

  listener {
    instance_port     = 8300
    instance_protocol = "tcp"
    lb_port           = 8300
    lb_protocol       = "tcp"
  }

  # Define other listeners here...

  health_check {
    healthy_threshold   = 2
    unhealthy_threshold = 2
    timeout             = 3
    target              = "TCP:8300"
    interval            = 20
  }

  cross_zone_load_balancing   = true
  idle_timeout                = 400
  connection_draining         = true
  connection_draining_timeout = 400
  security_groups             = [aws_security_group.consul.id]
}

resource "aws_iam_role" "consul" {
  name               = "${var.prefix}iam-role"
  assume_role_policy = <<EOF
{
  "Version": "2012-10-17",
  "Statement": [
    {
      "Effect": "Allow",
      "Principal": {
        "Service": "ec2.amazonaws.com"
      },
      "Action": "sts:AssumeRole"
    }
  ]
}
EOF
}



resource "aws_iam_role_policy_attachment" "ec2-read-only" {
  role       = aws_iam_role.consul.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonEC2ReadOnlyAccess"
}

resource "aws_iam_instance_profile" "consul" {
  name  = "${var.prefix}iam-instance-profile"
  roles = [aws_iam_role.consul.name]
}

data "template_file" "consul-userdata" {
  template = file("${path.module}/templates/bootstrap.sh.tmpl")

  vars = {
    prefix = var.prefix
    region = var.region
  }
}

resource "aws_launch_configuration" "consul-lc" {
  name_prefix          = var.prefix
  user_data            = data.template_file.consul-userdata.rendered
  image_id             = var.ami
  key_name             = var.key_name
  security_groups      = [aws_security_group.consul.id]
  iam_instance_profile = aws_iam_instance_profile.consul.id
  instance_type        = var.instance_type

  lifecycle {
    create_before_destroy = true
  }
}

resource "aws_autoscaling_group" "consul-servers" {
  name                      = "${var.prefix}asg"
  max_size                  = var.num_instances
  min_size                  = var.num_instances
  desired_capacity          = var.num_instances
  health_check_grace_period = 300
  health_check_type         = "EC2"
  launch_configuration      = aws_launch_configuration.consul-lc.id
  load_balancers            = [aws_elb.consul.id]
  vpc_zone_identifier       = var.private_subnets

  lifecycle {
    create_before_destroy = true
  }

  tag {
    key                 = "Name"
    value               = "consul"
    propagate_at_launch = true
  }
}

# Output

output "security_group" {
  value = aws_security_group.consul.id
}

variable "ops_manager_count" {}

variable "optional_count" {}

variable "env_name" {}

variable "ami" {}

variable "optional_ami" {}

variable "instance_type" {}

variable "subnet_id" {}

variable "vpc_id" {}

variable "iam_user_name" {}

variable "dns_suffix" {}

variable "zone_id" {}


resource "aws_key_pair" "ops_manager" {
  key_name   = "${var.env_name}-ops-manager-key"
  public_key = tls_private_key.ops_manager[*].public_key_openssh

  count      = var.ops_manager_count
}

resource "tls_private_key" "ops_manager" {
  algorithm = "RSA"
  rsa_bits  = "4096"
  count     = var.ops_manager_count
}

resource "aws_security_group" "ops_manager_security_group" {
  name        = "ops_manager_security_group"
  description = "Ops Manager Security Group"
  vpc_id      = var.vpc_id
  count       = var.ops_manager_count

  ingress {
    cidr_blocks = ["0.0.0.0/0"]
    protocol    = "tcp"
    from_port   = 22
    to_port     = 22
  }

  ingress {
    cidr_blocks = ["0.0.0.0/0"]
    protocol    = "tcp"
    from_port   = 80
    to_port     = 80
  }

  ingress {
    cidr_blocks = ["0.0.0.0/0"]
    protocol    = "tcp"
    from_port   = 443
    to_port     = 443
  }

  egress {
    cidr_blocks = ["0.0.0.0/0"]
    protocol    = "-1"
    from_port   = 0
    to_port     = 0
  }

  tags = {
    Name = "${var.env_name}-ops-manager-security-group"
  }
}

resource "aws_iam_policy" "ops_manager" {
  name   = "${var.env_name}_ops_manager"
  policy = data.template_file.ops_manager.rendered
  count  = var.ops_manager_count
}

resource "aws_iam_policy_attachment" "ops_manager_user_policy" {
  name       = "${var.env_name}_iam_user_policy"
  users      = [var.iam_user_name]
  policy_arn = aws_iam_policy.ops_manager.arn
  count      = var.ops_manager_count
}

resource "aws_iam_role" "iam_role" {
  name  = "${var.env_name}_iam_role"
  count = var.ops_manager_count

  assume_role_policy = <<EOF
{
  "Version": "2012-10-17",
  "Statement": [
    {
      "Effect": "Allow",
      "Principal": {
        "Service": [
          "ec2.amazonaws.com"
        ]
      },
      "Action": [
        "sts:AssumeRole"
      ]
    }
  ]
}
EOF
}

resource "aws_iam_instance_profile" "iam_instance_profile" {
  name  = "${var.env_name}_iam_instance_profile"
  count = var.ops_manager_count
  role  = aws_iam_role.iam_role[var.ops_manager_count].name
}

data "template_file" "ops_manager" {
  template = file("${path.module}/templates/iam_policy.json")

  vars = {
    iam_instance_profile_arn = aws_iam_instance_profile.iam_instance_profile[var.ops_manager_count].arn
    iam_role_arn             = aws_iam_role.iam_role[var.ops_manager_count].arn
    ops_manager_bucket_arn   = aws_s3_bucket.ops_manager_bucket[var.ops_manager_count].arn
  }
}

resource "aws_s3_bucket" "ops_manager_bucket" {
  bucket        = "${var.env_name}-ops-manager-bucket"
  force_destroy = true
  count         = var.ops_manager_count

  tags = {
    Name = "Ops Manager S3 Bucket"
  }
}

resource "aws_instance" "ops_manager" {
  ami                    = var.ami
  instance_type          = var.instance_type
  key_name               = aws_key_pair.ops_manager[var.ops_manager_count].key_name
  vpc_security_group_ids = [aws_security_group.ops_manager_security_group[var.ops_manager_count].id]
  source_dest_check      = false
  subnet_id              = var.subnet_id
  count                  = var.ops_manager_count

  root_block_device {
    volume_type = "gp2"
    volume_size = 150
  }

  tags = {
    Name = "${var.env_name}-ops-manager"
  }
}

resource "aws_instance" "optional_ops_manager" {
  ami                    = var.optional_ami
  instance_type          = var.instance_type
  key_name               = aws_key_pair.ops_manager[var.ops_manager_count].key_name
  vpc_security_group_ids = [aws_security_group.ops_manager_security_group[var.ops_manager_count].id]
  source_dest_check      = false
  subnet_id              = var.subnet_id
  count                  = var.optional_count

  root_block_device {
    volume_type = "gp2"
    volume_size = 150
  }

  tags = {
    Name = "${var.env_name}-optional-ops-manager"
  }
}

resource "aws_eip" "ops_manager" {
  instance = aws_instance.ops_manager[var.ops_manager_count].id
  count    = var.ops_manager_count
  vpc      = true
}

resource "aws_eip" "optional_ops_manager" {
  instance = aws_instance.optional_ops_manager[var.ops_manager_count].id
  count    = var.optional_count
  vpc      = true
}

resource "aws_route53_record" "ops_manager" {
  name    = "pcf.${var.env_name}.${var.dns_suffix}"
  zone_id = var.zone_id
  type    = "A"
  ttl     = 300
  count   = var.ops_manager_count

  records = [aws_eip.ops_manager[var.ops_manager_count].public_ip]
}

resource "aws_route53_record" "optional_ops_manager" {
  name    = "pcf-optional.${var.env_name}.${var.dns_suffix}"
  zone_id = var.zone_id
  type    = "A"
  ttl     = 300
  count   = var.optional_count

  records = [aws_eip.optional_ops_manager[var.ops_manager_count].public_ip]
}

output "bucket" {
  value = aws_s3_bucket.ops_manager_bucket[*].bucket
}

output "public_ip" {
  value = aws_eip.ops_manager[*].public_ip
}

output "dns" {
  value = aws_route53_record.ops_manager[*].name
}

output "optional_dns" {
  value = aws_route53_record.optional_ops_manager[*].name
}

output "security_group_id" {
  value = aws_security_group.ops_manager_security_group[*].id
}

output "ssh_private_key" {
  value = tls_private_key.ops_manager[*].private_key_pem
}

output "ssh_public_key_name" {
value = aws_key_pair.ops_manager[*].key_name
}

output "ops_manager_private_ip" {
value = aws_instance.ops_manager[*].private_ip
}

