resource "aws_security_group" "obelix_appengine_asg_sg" {
  vpc_id = var.vpc_id

  ingress {
    cidr_blocks = ["0.0.0.0/0"]
    from_port   = 22
    to_port     = 22
    protocol    = "tcp"
  }

  ingress {
    cidr_blocks = ["0.0.0.0/0"]
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
  }

  egress {
    cidr_blocks = ["0.0.0.0/0"]
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
  }

  tags = {
    Name = "obelix-appengine-asg-sg"
  }
}

resource "aws_lb" "obelix-appengine-alb" {
  name            = "obelix-appengine-alb"
  internal        = false
  load_balancer_type = "application"
  security_groups = [aws_security_group.obelix_appengine_alb_sg.id]
  subnets         = [aws_subnet.obelix-appengine-alb_public_a.id, aws_subnet.obelix-appengine-alb_public_b.id]

  enable_deletion_protection = false

  tags = {
    Name = "obelix-appengine-alb"
  }
}

resource "aws_lb_target_group" "obelix-appengine-target-group" {
  name                    = "obelix-appengine-target-group"
  port                    = var.protocol_port
  protocol                = var.protocol_type
  vpc_id                  = var.vpc_id
  health_check {
    interval            = var.health-check-interval-seconds
    path                = var.health-check-path
    port                = var.health-check-port
    protocol            = var.health-check-protocol
    timeout             = var.health-check-timeout-seconds
    healthy_threshold   = var.healthy-threshold-count
    unhealthy_threshold = var.unhealthy-threshold-count
    matcher             = var.matcher
  }

  deregistration_delay = var.deregistration_delay

  tags = {
    Name = "obelix-appengine-target-group"
  }
}

resource "aws_lb_listener" "obelix-appengine-alb-http-listener" {
  load_balancer_arn = aws_lb.obelix-appengine-alb.arn
  port              = var.protocol_port
  protocol          = var.protocol_type

  default_action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.obelix-appengine-target-group.arn
  }
}

resource "aws_lb_listener" "obelix-appengine-alb-https-listener" {
  load_balancer_arn = aws_lb.obelix-appengine-alb.arn
  port              = 443
  protocol          = "HTTPS"

  ssl_policy      = "ELBSecurityPolicy-2016-08"
  certificate_arn = var.certificate_arn

  default_action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.obelix-appengine-target-group.arn
  }
}

resource "aws_security_group" "obelix_appengine_alb_sg" {
  vpc_id = var.vpc_id

  ingress {
    cidr_blocks = ["0.0.0.0/0"]
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
  }

  ingress {
    cidr_blocks = ["0.0.0.0/0"]
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
  }

  egress {
    cidr_blocks = ["0.0.0.0/0"]
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
  }

  tags = {
    Name = "obelix-appengine-alb-sg"
  }
}

resource "aws_cloudwatch_metric_alarm" "obelix-appengine-alb-4xx-errors" {
  alarm_name          = "obelix-appengine-alb-4xx-errors"
  alarm_description   = "Alert when ALB has more than 4xx errors"
  comparison_operator = "GreaterThanThreshold"
  evaluation_periods  = "1"
  metric_name         = "HTTPCode_Target_4XX_Count"
  namespace           = "AWS/ApplicationELB"
  period              = "60"
  statistic           = "Sum"
  threshold           = var.alb_4xx_threshold
  alarm_actions       = [aws_sns_topic.alb_errors_sns_topic.arn]

  dimensions = {
    LoadBalancer = aws_lb.obelix-appengine-alb.id
  }
}

resource "aws_cloudwatch_metric_alarm" "obelix-appengine-alb-5xx-errors" {
  alarm_name          = "obelix-appengine-alb-5xx-errors"
  alarm_description   = "Alert when ALB has more than 5xx errors"
  comparison_operator = "GreaterThanThreshold"
  evaluation_periods  = "1"
  metric_name         = "HTTPCode_Target_5XX_Count"
  namespace           = "AWS/ApplicationELB"
  period              = "60"
  statistic           = "Sum"
  threshold           = var.alb_5xx_threshold
  alarm_actions       = [aws_sns_topic.alb_errors_sns_topic.arn]

  dimensions = {
    LoadBalancer = aws_lb.obelix-appengine-alb.id
  }
}

resource "aws_sns_topic" "alb_errors_sns_topic" {
  name = "alb_errors_sns_topic"
}

resource "aws_sns_topic_subscription" "alb_errors_sns_subscription" {
  topic_arn = aws_sns_topic.alb_errors_sns_topic.arn
  protocol  = "email"
  endpoint  = var.notification_email
}

resource "aws_iam_instance_profile" "obelix_appengine_instance_profile" {
  name = "obelix-appengine-instance-profile"
  role = aws_iam_role.obelix_appengine_instance_role.name
}

resource "aws_iam_role" "obelix_appengine_instance_role" {
  name = "obelix-appengine-instance-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "ec2.amazonaws.com"
        }
      }
    ]
  })

  inline_policy {
    name = "s3-access-policy"
    policy = jsonencode({
      Version = "2012-10-17"
      Statement = [
        {
          Action = [
            "s3:GetObject",
            "s3:ListBucket"
          ]
          Effect   = "Allow"
          Resource = [
            "arn:aws:s3:::mybucket/*"
          ]
        }
      ]
    })
  }
}

resource "aws_iam_role_policy_attachment" "obelix_appengine_ec2_basic" {
  policy_arn = "arn:aws:iam::aws:policy/AmazonEC2ReadOnlyAccess"
  role       = aws_iam_role.obelix_appengine_instance_role.name
}

resource "aws_iam_role_policy_attachment" "obelix_appengine_s3_full_access" {
  policy_arn = "arn:aws:iam::aws:policy/AmazonS3FullAccess"
  role       = aws_iam_role.obelix_appengine_instance_role.name
}

