  }
}

resource "google_compute_instance_template" "outbound_proxy" {
  name        = "squid-template"
  project     = local.project_id
  description = "Squid instance template."

  instance_description = "Squid instance"
  machine_type         = "n1-standard-1"
  can_ip_forward       = false
  metadata_startup_script = data.template_file.startup_script.rendered

  disk {
    source_image = "centos-cloud/centos-8"
    auto_delete  = true
    boot         = true
  }

  network_interface {
    subnetwork = local.subnetwork_svc
    access_config {}
  }

  service_account {
    email  = google_service_account.squid_proxy.email
    scopes = ["cloud-platform"]
  }
}

data "template_file" "squid_config" {
  template = file("templates/squid/squid.conf")
  vars = {
    squid_proxy_port    = var.squid_proxy_port
    health_service_host = local.health_service_host
  }
}

data "template_file" "squid_whitelist" {
  template = file("templates/squid/whitelist.txt")
  vars = {
    squid_whitelist = local.squid_whitelist
  }
}

data "template_file" "startup_script" {
  template = file("templates/squid/startup_script.sh.tpl")
  vars = {
    squid_conf    = data.template_file.squid_config.rendered
    whitelist_txt = data.template_file.squid_whitelist.rendered
  }
}

resource "google_compute_address" "outbound_proxy" {
  name         = "tcp-lb-ip"
  project      = local.project_id
  description  = "Internal IP address of the TCP load balancer in front of the Squid proxy"
  address_type = "INTERNAL"
  region       = google_compute_subnetwork.service.region
  subnetwork   = local.subnetwork_svc
  address      = local.proxy_address
}

resource "google_compute_forwarding_rule" "outbound_proxy" {
  name                  = "outbound-proxy-fr"
  project               = local.project_id
  region                = google_compute_subnetwork.service.region
  load_balancing_scheme = "INTERNAL"
  ip_address            = google_compute_address.outbound_proxy.address
  network               = local.network
  subnetwork            = local.subnetwork_svc
  backend_service       = google_compute_region_backend_service.outbound_proxy.self_link
  ip_protocol           = "TCP"
  ports                 = [var.squid_proxy_port]
}

resource "google_compute_region_backend_service" "outbound_proxy" {
  name             = "outbound-proxy-backend"
  project          = local.project_id
  region           = google_compute_subnetwork.service.region
  session_affinity = "CLIENT_IP"

  backend {
    group = google_compute_region_instance_group_manager.outbound_proxy.instance_group
  }

  health_checks                   = [google_compute_health_check.outbound_proxy.self_link]
  connection_draining_timeout_sec = 10
}

resource "google_compute_health_check" "outbound_proxy" {
  name                = "squid-health-check"
  project             = local.project_id
  check_interval_sec  = 10
  timeout_sec         = 5
  healthy_threshold   = 2
  unhealthy_threshold = 2

  tcp_health_check {
    request  = <<EOT
GET http://${local.health_service_host}/ HTTP/1.1
Host: ${local.health_service_host}
Cache-Control: no-cache
User-Agent: GoogleHC/1.0
Accept: */*
Proxy-Connection: Keep-Alive

EOT
    response = "HTTP/1.1 200 OK"
    port     = var.squid_proxy_port
  }
}

resource "google_dns_managed_zone" "services" {
  provider   = google-beta
  project    = local.project_id
  name       = "services"
  dns_name   = "${local.dns_services_domain}."
  visibility = "private"
  private_visibility_config {
    networks {
      network_url = local.network
    }
  }
  peering_config {
    target_network {
      network_url = local.svc_network
    }
  }
}

resource "google_logging_project_sink" "autoscaler" {
  name    = "autoscaler-sink"
  project = local.project_id

  destination = "pubsub.googleapis.com/projects/${local.svc_project_id}/topics/proxy-updates"

  filter = <<EOT
resource.type="gce_instance_group" AND 
jsonPayload.resource.name="${google_compute_region_instance_group_manager.outbound_proxy.name}" AND
jsonPayload.resource.type="instanceGroup" AND
jsonPayload.event_subtype=("compute.instanceGroups.removeInstances" OR "compute.instanceGroups.addInstances") AND
jsonPayload.event_type="GCE_OPERATION_DONE"
EOT

  unique_writer_identity = true
}

output "log_export_identity" {
  value = google_logging_project_sink.autoscaler.writer_identity
}

variable "my_region" {
  type    = string
  default = "us-east-1"
}

provider "aws" {
  region  = var.my_region
  profile = "terraform"
}

module "vpc" {
  source    = "../../modules/vpc"
  my_region = var.my_region
  my_subnets = {
    us-east-1  = "192.168.56.0/21"
    us-east-1a = "192.168.56.0/23"
    us-east-1b = "192.168.58.0/23"
    us-east-1c = "192.168.60.0/23"
    us-east-1d = "192.168.62.0/23"
  }
  prefix = "stage"
}

output "my_vpc" {
  value = module.vpc.my_vpc
}

output "my_subnets" {
  value = module.vpc.my_subnets
}

output "instance_sg" {
  value = module.vpc.instance_sg
}

