variable "env" {
  description = "Name of the product/environment"
  type        = string
}

variable "vpc_cidr" {
  description = "CIDR block for VPC"
  type        = string
}

variable "instance_type" {
  description = "Instance type for autoland EC2 instances"
  type        = string
}

variable "subnets" {
  description = "Subnets for autoland EC2 instances"
  type        = list(string)
}

variable "azs" {
  description = "Availability zones to be matched to subnets"
  type        = list(string)
}

variable "rds_subnets" {
  description = "Subnets for RDS instances"
  type        = list(string)
}

variable "rds_azs" {
  description = "Availability zones to be matched to RDS subnets"
  type        = list(string)
}

variable "rds_instance_class" {
  description = "RDS instances class type"
  type        = string
}

variable "ami_id" {
  description = "Autoland EC2 instance AMI"
  type        = string
}

variable "instance_profile" {
  description = "Autoland EC2 instance profile"
  type        = string
}

variable "allow_bastion_sg" {
  description = "Security Group to allow SSH from bastion host"
  type        = string
}

variable "peer_vpc_id" {
  description = "Bastion host VPC ID"
  type        = string
}

variable "peer_route_table_id" {
  description = "Bastion host route table"
  type        = string
}

variable "peer_cidr_block" {
  description = "Bastion host VPC CIDR block"
  type        = string
}

variable "peer_account_id" {
  description = "Bastion host account ID"
  type        = string
}

variable "user_data_bucket" {
  description = "S3 bucket containing user-data scripts"
  type        = string
}

variable "addl_user_data" {
  description = "List of user-data scripts in user-data bucket for Autoland EC2 instances"
  type        = list(string)
}

# Setup autoland VPC

resource "aws_vpc" "autoland_vpc" {
  cidr_block           = var.vpc_cidr
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "${var.env}-autoland-vpc"
  }
}

module "vpc_bastion_peer" {
  source = "../tf_vpc_peer"

  name                    = "${var.env}-bastion_peer"
  requester_vpc_id        = aws_vpc.autoland_vpc.id
  requester_route_table_id = aws_route_table.autoland_public_rt.id
  requester_cidr_block    = var.vpc_cidr
  peer_vpc_id             = var.peer_vpc_id
  peer_route_table_id     = var.peer_route_table_id
  peer_cidr_block         = var.peer_cidr_block
  peer_account_id         = var.peer_account_id
}

# Setup internet gateway for VPC
resource "aws_internet_gateway" "autoland_igw" {
  vpc_id = aws_vpc.autoland_vpc.id

  tags = {
    Name = "${var.env}-autoland-igw"
  }
}

# Setup route table for public subnets
resource "aws_route_table" "autoland_public_rt" {
  vpc_id = aws_vpc.autoland_vpc.id

  tags = {
    Name = "${var.env}-autoland-public-rt"
  }
}

# Setup route table for private subnets
resource "aws_route_table" "autoland_private_rt" {
  vpc_id = aws_vpc.autoland_vpc.id

  tags = {
    Name = "${var.env}-autoland-private-rt"
  }
}

# Add default route to internet bound route table
resource "aws_route" "autoland_public_igw_rtr" {
  route_table_id         = aws_route_table.autoland_public_rt.id
  destination_cidr_block = "0.0.0.0/0"
  gateway_id             = aws_internet_gateway.autoland_igw.id
}

# Setup public subnets for autoland
resource "aws_subnet" "autoland_subnet" {
  vpc_id            = aws_vpc.autoland_vpc.id
  cidr_block        = var.subnets[count.index]
  availability_zone = var.azs[count.index]
  count             = length(var.subnets)

  tags = {
    Name = "${var.env}-autoland-subnet-${count.index}"
  }
}

resource "aws_subnet" "autoland_rds_subnet" {
  vpc_id            = aws_vpc.autoland_vpc.id
  cidr_block        = var.rds_subnets[count.index]
  availability_zone = var.rds_azs[count.index]
  count             = length(var.rds_subnets)

  tags = {
    Name = "${var.env}-autoland-rds-subnet-${count.index}"
  }
}

resource "aws_route_table_association" "autoland_public" {
  count          = length(var.subnets)
  subnet_id      = aws_subnet.autoland_subnet[count.index].id
  route_table_id = aws_route_table.autoland_public_rt.id
}

resource "aws_route_table_association" "autoland_private" {
  count          = length(var.rds_subnets)
  subnet_id      = aws_subnet.autoland_rds_subnet[count.index].id
  route_table_id = aws_route_table.autoland_private_rt.id
}

# EC2 resources

resource "template_file" "user_data" {
  template = file("${path.module}/files/user_data.tmpl")
  vars = {
    s3_bucket      = var.user_data_bucket
    addl_user_data = var.addl_user_data
  }
  lifecycle {
    create_before_destroy = true
  }
}

resource "aws_security_group" "autoland_web_sg" {
  name        = "autoland_${var.env}_web-sg"
  description = "Web instance security group"
  vpc_id      = aws_vpc.autoland_vpc.id
  ingress {
    from_port   = 8
    to_port     = -1
    protocol    = "icmp"
    cidr_blocks = ["0.0.0.0/0"]
  }
  ingress {
    from_port       = 0
    to_port         = 0
    protocol        = "-1"
    security_groups = [var.allow_bastion_sg]
  }
  ingress {
    from_port   = 22
    to_port     = 22
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }
  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }
  ingress {
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }
  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "${var.env}-autoland-sg"
  }
}

resource "aws_eip" "autoland_web_eip" {
  vpc = true
}

# Create web head EC2 instances and evenly distribute them across the web subnets/azs
resource "aws_instance" "web_ec2_instance" {
  ami                         = var.ami_id
  count                       = length(var.subnets)
  subnet_id                   = aws_subnet.autoland_subnet[count.index % length(var.subnets)].id
  instance_type               = var.instance_type
  user_data                   = template_file.user_data.rendered
  vpc_security_group_ids      = [aws_security_group.autoland_web_sg.id]
  iam_instance_profile        = var.instance_profile
  associate_public_ip_address = true

  root_block_device {
    volume_type           = "gp2"
    volume_size           = 32
    delete_on_termination = true
  }

  ebs_block_device {
    device_name           = "/dev/sdb"
    volume_type           = "gp2"
    volume_size           = 32
    delete_on_termination = true
  }

  tags = {
    Name = "${var.env}-autoland-${count.index}"
    EIP  = aws_eip.autoland_web_eip.public_ip
  }
}

# RDS

# Setup subnet group
resource "aws_db_subnet_group" "autoland_dbsg" {
  name        = "${var.env}-db_subnet_group"
  description = "Autoland DB Subnet Group"
  subnet_ids  = aws_subnet.autoland_rds_subnet[*].id

  tags = {
    Name = "${var.env}-autoland-db-subnet-grp"
  }
}

resource "aws_security_group" "autoland_db_sg" {
  name        = "${var.env}_db-sg"
  description = "Provides RDS access to autoland instances"
  vpc_id      = aws_vpc.autoland_vpc.id
  ingress {
    from_port       = 3306
    to_port         = 3306
    protocol        = "tcp"
    security_groups = [aws_security_group.autoland_web_sg.id]
  }

  tags = {
    Name = "${var.env}-autoland-db-sg"
  }
}

resource "aws_db_instance" "autoland_rds" {
  identifier              = "${var.env}-autoland-rds"
  storage_type            = "gp2"
  allocated_storage       = 500
  engine                  = "postgres"
  engine_version          = "9.5.2"
  instance_class          = var.rds_instance_class
  username                = "autoland_admin"
  password                = "change_this_after_deployment"
