resource "aws_s3_bucket_policy" "redirect_to_apex" {
  bucket = aws_s3_bucket.redirect_to_apex.id
  policy = <<POLICY
{
  "Version": "2012-10-17",
  "Statement": [
    {
      "Principal": "*",
      "Action": [
        "s3:GetObject"
      ],
      "Resource": "${aws_s3_bucket.redirect_to_apex.arn}/*",
