## Rancher server instance profile/role ##
##########################################

# Rancher server instance profile
resource "aws_iam_instance_profile" "rancher_server_instance_profile" {
  name = "${var.server_name}-instance-profile"
  roles = [
    aws_iam_role.rancher_server_role.name
  ]

  lifecycle {
    create_before_destroy = true
  }
}

# Rancher server role
resource "aws_iam_role" "rancher_server_role" {
  name               = "${var.server_name}-role"
  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid = ""
        Effect = "Allow"
        Principal = {
          Service = "ec2.amazonaws.com"
        }
        Action = "sts:AssumeRole"
      }
    ]
  })

  lifecycle {
    create_before_destroy = true
  }
}

#####################
## Custom policies ##
#####################

# S3 credentials bucket access
resource "aws_iam_policy" "s3_server_credentials" {
  name        = "${var.server_name}-S3-credentials-access"
  path        = "/"
  description = "Allow the Rancher server to access the credentials file in the S3 bucket."
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:GetObject",
          "s3:PutObject"
        ]
        Resource = [
          "arn:aws:s3:::${aws_s3_bucket.server_credentials_bucket.id}/keys.txt"
        ]
      }
    ]
  })
}

# SQS queue create & delete messages
resource "aws_iam_policy" "sqs_queue_access" {
  name        = "${var.server_name}-SQS-queue-access"
  path        = "/"
  description = "Allow the lifecycle hook app to receive and process SQS queue messages."
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "sqs:DeleteMessage",
          "sqs:ReceiveMessage"
        ]
        Resource = [
          "${aws_sqs_queue.autoscaling_hooks_queue.arn}"
        ]
      }
    ]
  })
}

# Autoscaling lifecycle complete action
resource "aws_iam_policy" "autoscaling_complete_lifecycle_action" {
  name        = "${var.server_name}-Allow-autoscaling-complete-action"
  path        = "/"
  description = "Allow the lifecycle hook app send a complete action request that releases the instance for termination."
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "autoscaling:CompleteLifecycleAction"
        ]
        Resource = "*"
      }
    ]
  })
}

#############################
## Attach policies to role ##
#############################

# S3 bucket access
resource "aws_iam_policy_attachment" "rancher_server_s3_policy" {
  name       = "${var.server_name}_s3_policy"
  policy_arn = aws_iam_policy.s3_server_credentials.arn
  roles      = [
    aws_iam_role.rancher_server_role.name
  ]
}

# SQS access
resource "aws_iam_policy_attachment" "rancher_server_sqs_policy" {
  name       = "${var.server_name}_sqs_policy"
  policy_arn = aws_iam_policy.sqs_queue_access.arn
  roles      = [
    aws_iam_role.rancher_server_role.name
  ]
}

# Complete autoscaling hook
resource "aws_iam_policy_attachment" "complete_autoscaling_hooks" {
  name       = "${var.server_name}_complete_autoscaling_hooks"
  policy_arn = aws_iam_policy.autoscaling_complete_lifecycle_action.arn
  roles      = [
    aws_iam_role.rancher_server_role.name
  ]
}

# Rancher server security group
resource "aws_security_group" "rancher_server_sg" {
  name        = "${var.server_name}-Rancher-Server"
  description = "Rules for the Rancher server instance."
  vpc_id      = var.vpc_id

  tags = {
    Name      = var.server_name
    ManagedBy = "terraform"
  }

  lifecycle {
    create_before_destroy = true
  }
}

# Incoming HTTP from anywhere
resource "aws_security_group_rule" "http_ingress" {
  security_group_id = aws_security_group.rancher_server_sg.id
  type              = "ingress"
  from_port         = 80
  to_port           = 80
  protocol          = "tcp"
  cidr_blocks       = ["0.0.0.0/0"]

  lifecycle {
    create_before_destroy = true
  }
}

# Incoming HTTPS from anywhere
resource "aws_security_group_rule" "https_ingress" {
  security_group_id = aws_security_group.rancher_server_sg.id
  type              = "ingress"
  from_port         = 443
  to_port           = 443
  protocol          = "tcp"
  cidr_blocks       = ["0.0.0.0/0"]

  lifecycle {
    create_before_destroy = true
  }
}

# Outgoing HTTP to anywhere
resource "aws_security_group_rule" "http_egress" {
  security_group_id = aws_security_group.rancher_server_sg.id
  type              = "egress"
  from_port         = 80
  to_port           = 80
  protocol          = "tcp"
  cidr_blocks       = ["0.0.0.0/0"]

  lifecycle {
    create_before_destroy = true
  }
}

# Outgoing HTTPS to anywhere
resource "aws_security_group_rule" "https_egress" {
  security_group_id = aws_security_group.rancher_server_sg.id
  type              = "egress"
  from_port         = 443
  to_port           = 443
  protocol          = "tcp"
  cidr_blocks       = ["0.0.0.0/0"]

  lifecycle {
    create_before_destroy = true
  }
}

# Outgoing SSH to anywhere
resource "aws_security_group_rule" "ssh_egress" {
  security_group_id = aws_security_group.rancher_server_sg.id
  type              = "egress"
  from_port         = 22
  to_port           = 22
  protocol          = "tcp"
  cidr_blocks       = ["0.0.0.0/0"]

  lifecycle {
    create_before_destroy = true
  }
}

# Outgoing docker API to anywhere
resource "aws_security_group_rule" "docker_egress" {
  security_group_id = aws_security_group.rancher_server_sg.id
  type              = "egress"
  from_port         = 2376
  to_port           = 2376
  protocol          = "tcp"
  cidr_blocks       = ["0.0.0.0/0"]

  lifecycle {
    create_before_destroy = true
  }
}

# Outgoing mysql
resource "aws_security_group_rule" "mysql_egress" {
  security_group_id = aws_security_group.rancher_server_sg.id
  type              = "egress"
  from_port         = 3306
  to_port           = 3306
  protocol          = "tcp"
  cidr_blocks       = ["0.0.0.0/0"]

  lifecycle {
    create_before_destroy = true
  }
}

output "server_security_group_id" {
  value = aws_security_group.rancher_server_sg.id
}

#############################
## Rancher server instance ##
#############################

# Import the keypair
resource "aws_key_pair" "keypair" {
  key_name   = "${var.server_name}-key"
  public_key = file(var.server_key)

  lifecycle {
    create_before_destroy = true
  }
}

# User-data template
resource "template_file" "user_data" {
  template = file("${path.module}/files/userdata.template")
  vars = {
    vpc_region               = var.vpc_region
    server_version           = var.server_version
    server_credentials_bucket = aws_s3_bucket.server_credentials_bucket.id
    server_hostname          = var.server_hostname
    ssl_email                = var.ssl_email
    sqs_url                  = aws_sqs_queue.autoscaling_hooks_queue.id
    database_address         = var.database_address
    database_port            = var.database_port
    database_name            = var.database_name
    database_username        = var.database_username
    database_password        = var.database_password
  }

  lifecycle {
    create_before_destroy = true
  }
}

# Create instance
resource "aws_instance" "rancher_server" {
  ami                           = var.server_ami[var.vpc_region]
  subnet_id                     = var.server_subnet_id
  associate_public_ip_address   = true
  vpc_security_group_ids        = [aws_security_group.rancher_server_sg.id]
  key_name                      = aws_key_pair.keypair.key_name
  user_data                     = template_file.user_data.rendered
  iam_instance_profile          = aws_iam_instance_profile.rancher_server_instance_profile.id
  instance_type                 = var.server_instance_type
  root_block_device {
    volume_type           = var.server_root_volume_type
    volume_size           = var.server_root_volume_size
    delete_on_termination = var.server_root_volume_delete_on_terminate
  }

  depends_on = [
    aws_s3_bucket.server_credentials_bucket
  ]

  tags = {
    Name      = var.server_name
    ManagedBy = "terraform"
  }

  lifecycle {
    create_before_destroy = true
  }
}

output "server_public_ip" {
  value = aws_instance.rancher_server.public_ip
}

output "server_keyname" {
  value = aws_key_pair.keypair.key_name
}

# S3 bucket to hold Rancher server API credentials
resource "aws_s3_bucket" "server_credentials_bucket" {
  bucket         = "${var.server_hostname}-credentials"
  acl            = "private"
  force_destroy  = true

  tags = {
    Name      = var.server_hostname
    ManagedBy = "terraform"
  }

  lifecycle {
    create_before_destroy = true
  }
}

# Autoscaling hooks queue
resource "aws_sqs_queue" "autoscaling_hooks_queue" {
  name                       = "${var.server_name}-asg-hooks"
  visibility_timeout_seconds = 300
  message_retention_seconds  = 1800

  lifecycle {
    create_before_destroy = true
  }
}

output "lifecycle_hooks_sqs_queue_arn" {
  value = aws_sqs_queue.autoscaling_hooks_queue.arn
}

variable "region" {
  description = "The region into which to deploy the service."
  type        = string
}
variable "vpc_id" {
  description = "The ID of the VPC into which to deploy the service."
  type        = string
  default     = null
}
variable "subnet_ids" {
  description = "The IDs of the subnets in which to create ENIs when the service task network mode is "awsvpc"."
  type        = list(string)
  default     = []
  nullable    = false
}

variable "component" {
  description = "The component this service will contain."
  type        = string
}
variable "deployment_identifier" {
  description = "An identifier for this instantiation."
  type        = string
}

variable "service_task_container_definitions" {
  description = "A template for the container definitions in the task."
  type        = string
  default     = null
}

variable "service_task_network_mode" {
  description = "The network mode used for the containers in the task."
  type        = string
  default     = "bridge"
  nullable    = false
}
variable "service_task_pid_mode" {
  description = "The process namespace used for the containers in the task."
  type        = string
  default     = null
}

variable "service_name" {
  description = "The name of the service being created."
  type        = string
}
variable "service_image" {
  description = "The docker image (including version) to deploy."
  type        = string
  default     = ""
  nullable    = false
}
variable "service_command" {
  description = "The command to run to start the container."
  type        = list(string)
  default     = []
  nullable    = false
}
variable "service_port" {
  description = "The port the containers will be listening on."
  type        = string
}

variable "service_desired_count" {
  description = "The desired number of tasks in the service."
  type        = number
  default     = 3
  nullable    = false
}
variable "service_deployment_maximum_percent" {
  description = "The maximum percentage of the desired count that can be running."
  type        = number
  default     = 200
  nullable    = false
}
variable "service_deployment_minimum_healthy_percent" {
  description = "The minimum healthy percentage of the desired count to keep running."
  type        = number
  default     = 50
  nullable    = false
}
variable "service_health_check_grace_period_seconds" {
  description = "The number of seconds to wait for the service to start up before starting load balancer health checks."
  type        = number
  default     = 0
  nullable    = false
}

variable "attach_to_load_balancer" {
  description = "Whether or not this service should attach to a load balancer."
  type        = bool
  default     = true
  nullable    = false
}
variable "service_elb_name" {
  description = "The name of the ELB to configure to point at the service containers."
  type        = string
  default     = null
}
variable "target_group_arn" {
  description = "The arn of the target group to point at the service containers."
  type        = string
  default     = null
}
variable "target_container_name" {
  description = "The name of the container to which the load balancer should route traffic. Defaults to the service_name."
  type        = string
  default     = null
}
variable "target_port" {
  description = "The port to which the load balancer should route traffic. Defaults to the service_port."
  type        = string
  default     = null
}

variable "register_in_service_discovery" {
  description = "Whether or not this service should be registered in service discovery."
  type        = bool
  default     = false
  nullable    = false
}
variable "service_discovery_create_registry" {
  description = "Whether or not to create a service discovery registry for this service."
  type        = bool
  default     = true
  nullable    = false
}
variable "service_discovery_namespace_id" {
  description = "The ID of the service discovery namespace in which to create the service discovery registry. Required if service_discovery_create_registry is "yes"."
  type        = string
  default     = ""
  nullable    = false
}
variable "service_discovery_registry_arn" {
  description = "The ARN of the service discovery registry into which to register the service. Required if service_discovery_create_registry is "no"."
  type        = string
  default     = ""
  nullable    = false
}
variable "service_discovery_record_type" {
  description = "The type of record to create when registering the service in service discovery."
  type        = string
  default     = "SRV"
  nullable    = false
}
variable "service_discovery_container_name" {
  description = "The container name to use when registering the service in service discovery. Defaults to the service name."
  type        = string
  default     = null
}
variable "service_discovery_container_port" {
  description = "The container port to use when registering the service in service discovery. Defaults to the service port."
  type        = string
  default     = null
}

variable "associate_default_security_group" {
  description = "Whether or not to create and associate a default security group for the tasks created by this service. Only applicable when service_task_network_mode is "awsvpc"."
  type        = bool
  default     = true
  nullable    = false
}
variable "include_default_ingress_rule" {
  description = "Whether or not to include the default ingress rule in the default security group for the tasks created by this service. Only applicable when service_task_network_mode is "awsvpc"."
  type        = bool
  default     = true
  nullable    = false
}
variable "include_default_egress_rule" {
  description = "Whether or not to include the default egress rule in the default security group for the tasks created by this service. Only applicable when service_task_network_mode is "awsvpc"."
  type        = bool
  default     = true
  nullable    = false
}
variable "default_security_group_ingress_cidrs" {
  description = "The CIDRs allowed access to containers when using the default security group."
  type        = list(string)
  default     = ["10.0.0.0/8"]
  nullable    = false
}
variable "default_security_group_egress_cidrs" {
  description = "The CIDRs accessible from containers when using the default security group."
  type        = list(string)
  default     = ["0.0.0.0/0"]
  nullable    = false
}

variable "service_role" {
  description = "The ARN of the service task role to use."
  type        = string
  default     = null
}
variable "service_volumes" {
  description = "A list of volumes to make available to the containers in the service."
  type        = list(map(string))
  default     = []
  nullable    = false
}

variable "scheduling_strategy" {
  description = "The scheduling strategy to use for this service ("REPLICA" or "DAEMON")."
  type        = string
  default     = "REPLICA"
  nullable    = false
}

variable "placement_constraints" {
  description = "A list of placement constraints for the service."
  type        = list(map(string))
  default     = []
  nullable    = false
}

variable "ecs_cluster_id" {
  description = "The ID of the ECS cluster in which to deploy the service."
  type        = string
}
variable "ecs_cluster_service_role_arn" {
  description = "The ARN of the IAM role to provide to ECS to manage the service."
  type        = string
}

variable "include_log_group" {
  description = "Whether or not to create a log group for the service."
  type        = bool
  default     = true
  nullable    = false
}

variable "log_group_retention" {
  description = "The number of days you want to retain log events. See cloudwatch_log_group for possible values. Defaults to 0 (forever)."
  type        = number
  default     = 0
  nullable    = false
}

variable "force_new_deployment" {
  description = "Whether or not to force a new deployment of the service on apply."
  type        = bool
  default     = false
  nullable    = false
}

variable "wait_for_steady_state" {
  description = "Whether or not to wait for the service deployment to complete."
  type        = bool
  default     = false
  nullable    = false
}

variable "always_use_latest_task_definition" {
  description = "If `true`, use the latest ACTIVE revision of the task definition regardless of whether it was created by this module."
  type        = bool
  default     = false
  nullable    = false
}


terraform {
  required_version = ">= 1.1"

  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = ">= 4.59"
    }
  }
}


resource "aws_security_group" "task" {
  count = (var.associate_default_security_group && var.service_task_network_mode == "awsvpc") ? 1 : 0

  name        = "${var.component}-${var.deployment_identifier}-${var.service_name}"
  description = "Container access for component: ${var.component}, deployment: ${var.deployment_identifier}, service: ${var.service_name}"
  vpc_id      = var.vpc_id

  tags = {
    Name                 = "${var.component}-${var.deployment_identifier}-${var.service_name}"
    Component            = var.component
    DeploymentIdentifier = var.deployment_identifier
    ServiceName          = var.service_name
  }
}

resource "aws_security_group_rule" "cluster_default_ingress" {
  count = (var.associate_default_security_group && var.include_default_ingress_rule && var.service_task_network_mode == "awsvpc") ? 1 : 0

  type = "ingress"

  security_group_id = aws_security_group.task.0.id

  protocol  = "-1"
  from_port = 0
  to_port   = 0

  cidr_blocks = var.default_security_group_ingress_cidrs
}

resource "aws_security_group_rule" "cluster_default_egress" {
  count = (var.associate_default_security_group && var.include_default_egress_rule && var.service_task_network_mode == "awsvpc") ? 1 : 0

  type = "egress"

  security_group_id = aws_security_group.task.0.id

  protocol  = "-1"
  from_port = 0
  to_port   = 0

  cidr_blocks = var.default_security_group_egress_cidrs
}

resource "aws_cloudwatch_log_group" "service" {
  count = var.include_log_group ? 1 : 0

  name              = "/${var.component}/${var.deployment_identifier}/ecs-service/${var.service_name}"
  retention_in_days = var.log_group_retention

  tags = {
    DeploymentIdentifier = var.deployment_identifier
    Component            = var.component
    Service              = var.service_name
  }
}


resource "aws_service_discovery_service" "service" {
  count = (var.register_in_service_discovery && var.service_discovery_create_registry) ? 1 : 0

  name = var.service_name

  dns_config {
    namespace_id = var.service_discovery_namespace_id

    dns_records {
      ttl  = 10
      type = var.service_discovery_record_type
    }
  }
}


locals {
  service_task_container_definitions_template = coalesce(
    var.service_task_container_definitions,
    file("${path.module}/container-definitions/service.json.tpl"))
  resolved_service_task_container_definitions = replace(
    replace(
      replace(
        replace(
          replace(
            replace(
              local.service_task_container_definitions_template,
              "$${name}", var.service_name),
            "$${image}", var.service_image),
          "$${command}", jsonencode(var.service_command)),
        "$${port}", var.service_port),
      "$${region}", var.region),
    "$${log_group}", var.include_log_group ? aws_cloudwatch_log_group.service[0].name : "")
}

resource "aws_ecs_task_definition" "service" {
  family                = "${var.component}-${var.service_name}-${var.deployment_identifier}"
  container_definitions = local.resolved_service_task_container_definitions

  network_mode = var.service_task_network_mode
  pid_mode     = var.service_task_pid_mode

  task_role_arn = var.service_role

  dynamic "volume" {
    for_each = var.service_volumes
    content {
      name      = volume.value.name
      host_path = lookup(volume.value, "host_path", null)
    }
  }
}


resource "aws_ecs_service" "service" {
  name            = var.service_name
  cluster         = var.ecs_cluster_id
  task_definition = var.always_use_latest_task_definition ? aws_ecs_task_definition.service.arn_without_revision : aws_ecs_task_definition.service.arn
  desired_count   = var.service_desired_count
  iam_role        = (var.attach_to_load_balancer && var.service_task_network_mode != "awsvpc") ? var.ecs_cluster_service_role_arn : null

  deployment_maximum_percent         = var.service_deployment_maximum_percent
  deployment_minimum_healthy_percent = var.service_deployment_minimum_healthy_percent

  health_check_grace_period_seconds = var.attach_to_load_balancer ? var.service_health_check_grace_period_seconds : null

  scheduling_strategy = var.scheduling_strategy

  force_new_deployment = var.force_new_deployment

  wait_for_steady_state = var.wait_for_steady_state

  dynamic "network_configuration" {
    for_each = var.service_task_network_mode == "awsvpc" ? [var.subnet_ids] : []

    content {
      subnets         = network_configuration.value
      security_groups = compact([try(aws_security_group.task.0.id, "")])
    }
  }

  dynamic "placement_constraints" {
    for_each = var.placement_constraints

    content {
      type       = placement_constraints.value.type
      expression = placement_constraints.value.expression
    }
  }

  dynamic "service_registries" {
    for_each = var.register_in_service_discovery ? [var.service_discovery_create_registry ? aws_service_discovery_service.service[0].arn : var.service_discovery_registry_arn] : []

    content {
      registry_arn   = service_registries.value
      container_name = var.service_discovery_record_type == "SRV" ? coalesce(var.service_discovery_container_name, var.service_name) : null
      container_port = var.service_discovery_record_type == "SRV" ? coalesce(var.service_discovery_container_port, var.service_port) : null
    }
  }

  dynamic "load_balancer" {
    for_each = var.attach_to_load_balancer ? [coalesce(var.target_group_arn, var.service_elb_name)] : []

    content {
      elb_name         = var.target_group_arn == null ? var.service_elb_name : null
      target_group_arn = var.target_group_arn == null ? null : var.target_group_arn
      container_name   = coalesce(var.target_container_name, var.service_name)
      container_port   = coalesce(var.target_port, var.service_port)
    }
  }
}


output "task_definition_arn" {
  description = "The ARN of the created ECS task definition."
  value       = aws_ecs_task_definition.service.arn
}

output "log_group" {
  description = "The name of the log group capturing all task output."
  value       = var.include_log_group ? aws_cloudwatch_log_group.service[0].name : ""
}

output "security_group_id" {
  description = "The ID of the default security group associated with the network interfaces of the ECS tasks."
  value       = (var.associate_default_security_group && var.service_task_network_mode == "awsvpc") ? aws_security_group.task.0.id : ""
}

