resource "google_compute_firewall" "allow-10net" {
  name          = "allow-10net-ingress"
  network       = google_compute_network.bce.name
  project       = google_project.bce.project_id

  source_ranges = [
    "10.0.0.0/8", 
  ]

  allow {
    protocol    = "tcp"
  }

   allow {
    protocol    = "udp"
  }

  allow {
    protocol    = "icmp"
  }
}

resource "google_compute_firewall" "allow-ssh" {
  name          = "allow-ssh"
  network       = google_compute_network.bce.name
  project       = google_project.bce.project_id

  source_ranges = [
    "35.235.240.0/20", 
  ]

  allow {
    protocol    = "tcp"
    ports       = ["22"]
  }
}

# Global variables
variable "region" {
  description = "The AWS region to deploy resources"
  type        = string
}

variable "vpc_name" {
  description = "The name of the VPC"
  type        = string
}

variable "vpc_cidr_block" {
  description = "The CIDR block for the VPC"
  type        = string
}

variable "dns_domain" {
  description = "The DNS domain for the VPC"
  type        = string
}

variable "azs" {
  description = "Availability Zones"
  type        = map(list(string))
}

variable "remote_ips" {
  description = "List of approved remote IPs"
  type        = list(string)
  default     = []
}

variable "ssh_key_file_pub" {
  description = "The public SSH key file"
  type        = string
}

provider "aws" {
  region = var.region
}

resource "aws_vpc" "main" {
  cidr_block           = var.vpc_cidr_block
  enable_dns_hostnames = true
  enable_dns_support   = true
  instance_tenancy     = "default"

  tags = {
    Name = var.vpc_name
  }
}

resource "aws_vpc_dhcp_options" "default" {
  domain_name         = var.dns_domain
  domain_name_servers = ["AmazonProvidedDNS"]

  tags = {
    Name = "${var.vpc_name} DHCP Options"
  }
}

resource "aws_vpc_dhcp_options_association" "dns_resolver" {
  vpc_id           = aws_vpc.main.id
  dhcp_options_id  = aws_vpc_dhcp_options.default.id
}

resource "aws_route53_zone" "root" {
  name = var.dns_domain
}

output "dns_zone_id" {
  value = aws_route53_zone.root.zone_id
}

resource "aws_subnet" "public" {
  vpc_id                  = aws_vpc.main.id
  count                   = length(var.azs[var.region])
  cidr_block              = cidrsubnet(var.vpc_cidr_block, 8, count.index + 1)
  availability_zone       = element(var.azs[var.region], count.index)
  map_public_ip_on_launch = true

  tags = {
    Name = "${var.vpc_name} public-${element(var.azs[var.region], count.index)}"
  }
}

output "snet_public" {
  value = aws_subnet.public[*].id
}

resource "aws_subnet" "mgmt" {
  vpc_id                  = aws_vpc.main.id
  count                   = length(var.azs[var.region])
  cidr_block              = cidrsubnet(var.vpc_cidr_block, 8, count.index + 3)
  availability_zone       = element(var.azs[var.region], count.index)
  map_public_ip_on_launch = false

  tags = {
    Name = "${var.vpc_name} mgmt-${element(var.azs[var.region], count.index)}"
  }
}

output "snet_mgmt" {
  value = aws_subnet.mgmt[*].id
}

resource "aws_subnet" "webapp_1" {
  vpc_id                  = aws_vpc.main.id
  count                   = length(var.azs[var.region])
  cidr_block              = cidrsubnet(var.vpc_cidr_block, 8, count.index + 11)
  availability_zone       = element(var.azs[var.region], count.index)
  map_public_ip_on_launch = false

  tags = {
    Name = "${var.vpc_name} webapp_1-${element(var.azs[var.region], count.index)}"
  }
}

output "snet_webapp_1" {
  value = aws_subnet.webapp_1[*].id
}

resource "aws_subnet" "db_1" {
  vpc_id                  = aws_vpc.main.id
  count                   = length(var.azs[var.region])
  cidr_block              = cidrsubnet(var.vpc_cidr_block, 8, count.index + 21)
  availability_zone       = element(var.azs[var.region], count.index)
  map_public_ip_on_launch = false

  tags = {
    Name = "${var.vpc_name} db_1-${element(var.azs[var.region], count.index)}"
  }
}

output "snet_db_1" {
  value = aws_subnet.db_1[*].id
}

resource "aws_internet_gateway" "default" {
  vpc_id = aws_vpc.main.id
}

resource "aws_route_table" "public" {
  vpc_id = aws_vpc.main.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.default.id
  }

  tags = {
    Name = "public_subnet_route_table"
  }
}

resource "aws_route_table_association" "public" {
  count          = length(var.azs[var.region])
  subnet_id      = element(aws_subnet.public[*].id, count.index)
  route_table_id = aws_route_table.public.id
}

resource "aws_eip" "mgmt_nat_eip" {
  count = length(var.azs[var.region])
  vpc   = true
}

resource "aws_nat_gateway" "mgmt_nat_gw" {
  count         = length(var.azs[var.region])
  allocation_id = element(aws_eip.mgmt_nat_eip[*].id, count.index)
  subnet_id     = element(aws_subnet.public[*].id, count.index)

  depends_on = [aws_internet_gateway.default]
}

resource "aws_route_table" "mgmt_rt" {
  vpc_id = aws_vpc.main.id
  count  = length(var.azs[var.region])

  route {
    cidr_block     = "0.0.0.0/0"
    nat_gateway_id = element(aws_nat_gateway.mgmt_nat_gw[*].id, count.index)
  }

  tags = {
    Name = "mgmt_route_table_${count.index}"
  }
}

resource "aws_route_table_association" "mgmt_nat" {
  count          = length(var.azs[var.region])
  subnet_id      = element(aws_subnet.mgmt[*].id, count.index)
  route_table_id = element(aws_route_table.mgmt_rt[*].id, count.index)
}

resource "aws_security_group" "remote_ip_white_list" {
  name        = "remote_ip_white_list"
  description = "Connection from approved IPs"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = var.remote_ips
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "Remote IP White List"
  }
}

output "sg_remote_ip_white_list" {
  value = aws_security_group.remote_ip_white_list.id
}

resource "aws_security_group" "allow_mgmt_hosts" {
  name        = "allow_mgmt_hosts"
  description = "Allow all management hosts"
  vpc_id      = aws_vpc.main.id

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "Allow all mgmt hosts"
  }
}

output "sg_allow_mgmt_hosts" {
  value = aws_security_group.allow_mgmt_hosts.id
}

resource "aws_security_group" "allow_access_to_consul" {
  name        = "allow_access_to_consul"
  description = "Allow access to all Consul ports"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 8300
    to_port     = 8302
    protocol    = "tcp"
    cidr_blocks = [var.vpc_cidr_block]
  }
  ingress {
    from_port   = 8400
    to_port     = 8400
    protocol    = "tcp"
    cidr_blocks = [var.vpc_cidr_block]
  }
  ingress {
    from_port   = 8500
    to_port     = 8500
    protocol    = "tcp"
    cidr_blocks = [var.vpc_cidr_block]
  }
  ingress {
    from_port   = 8301
    to_port     = 8302
    protocol    = "udp"
    cidr_blocks = [var.vpc_cidr_block]
  }
  ingress {
    from_port   = 8600
    to_port     = 8600
    protocol    = "udp"
    cidr_blocks = [var.vpc_cidr_block]
  }

  tags = {
    Name = "Allow access to Consul ports"
  }
}

output "sg_allow_access_to_consul" {
  value = aws_security_group.allow_access_to_consul.id
}

resource "aws_key_pair" "ssh_key" {
  key_name   = "${var.vpc_name}_ssh_key"
  public_key = file(var.ssh_key_file_pub)
}

resource "null_resource" "public" {
  triggers = {
    "0" = cidrsubnet(var.vpc_cidr_block, 8, 1)
    "1" = cidrsubnet(var.vpc_cidr_block, 8, 2)
  }
}

resource "null_resource" "mgmt" {
  triggers = {
    "0" = cidrsubnet(var.vpc_cidr_block, 8, 3)
    "1" = cidrsubnet(var.vpc_cidr_block, 8, 4)
  }
}

resource "null_resource" "webapp_1" {
  triggers = {
    "0" = cidrsubnet(var.vpc_cidr_block, 8, 11)
    "1" = cidrsubnet(var.vpc_cidr_block, 8, 12)
  }
}

resource "null_resource" "db_1" {
  triggers = {
    "0" = cidrsubnet(var.vpc_cidr_block, 8, 21)
    "1" = cidrsubnet(var.vpc_cidr_block, 8, 22)
  }
}

variable "root_zone_name" {
  description = "Root zone name"
  type        = string
}

variable "mailgun_api_key" {
  description = "Mailgun API key"
  type        = string
}

variable "mailgun_prefix" {
  description = "Prefix for Mailgun"
  type        = string
  default     = "mg"
}

provider "aws" {
  region = "us-east-2"
}

provider "mailgun" {
  api_key = var.mailgun_api_key
}

resource "aws_iam_role" "ecs" {
  name               = "ecs"
  assume_role_policy = jsonencode({
    Version = "2012-10-17",
    Statement = [{
      Sid = "",
      Effect = "Allow",
      Principal = {
        Service = "ec2.amazonaws.com"
      },
      Action = "sts:AssumeRole"
    }]
  })
}

resource "aws_iam_role_policy_attachment" "ecs_AmazonEC2ContainerServiceforEC2Role" {
  role       = aws_iam_role.ecs.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AmazonEC2ContainerServiceforEC2Role"
}

resource "aws_iam_instance_profile" "ecs" {
  name  = "ecs"
  roles = [aws_iam_role.ecs.name]
}

data "aws_route53_zone" "root" {
  name = var.root_zone_name
}

resource "aws_route53_zone" "dev" {
  name = "dev.${var.root_zone_name}"
}

resource "aws_route53_record" "dev_delegation" {
  zone_id = data.aws_route53_zone.root.zone_id
  name    = "dev"
  type    = "NS"
  ttl     = 300
  records = aws_route53_zone.dev.name_servers
}

resource "random_id" "mailgun_smtp_password" {
  byte_length = 32
}

resource "mailgun_domain" "default" {
  name          = "${var.mailgun_prefix}.${var.root_zone_name}"
  smtp_password = random_id.mailgun_smtp_password.b64
}

data "aws_route53_zone" "mailgun_root" {
  name = var.root_zone_name
}

resource "aws_route53_zone" "mailgun" {
  name = "${var.mailgun_prefix}.${var.root_zone_name}"
}

resource "aws_route53_record" "mailgun_delegation" {
  zone_id = data.aws_route53_zone.mailgun_root.zone_id
  name    = var.mailgun_prefix
  type    = "NS"
  ttl     = 300
  records = aws_route53_zone.mailgun.name_servers
}

resource "aws_route53_record" "mailgun_spf" {
  zone_id = aws_route53_zone.mailgun.zone_id
  name    = ""
  type    = "TXT"
  ttl     = 300
  records = ["v=spf1 include:mailgun.org ~all"]
}

resource "aws_route53_record" "mailgun_tracking" {
