variable "env_name" {
  type = string
}

variable "verbose_name" {
  type        = string
  description = "Human-friendly name, will be used to construct resources names. E.g. Graylog"
}

variable "vpc_id" {
  type        = string
  description = "Id of the VPC to host facilities in"
}

variable "vpc_subnets" {
  type        = list(string)
  description = "List of VPC subnet ids to start servers in"
}

variable "vpc_security_groups" {
  type        = list(string)
  description = "Extra VPC security groups to be assigned"
  default     = []
}

variable "vpc_dns_zone_id" {
  type = string
}

variable "ecs_cluster_name" {
  type = string
}

variable "ecs_instance_group" {
  type    = string
  default = "flower"
}

variable "instance_ami" {
  type        = string
  description = "AMI of ECS optimized Amazon Linux in your region"
}

variable "instance_type" {
  type        = string
  description = "Size of EC2 instance to use"
}

variable "instance_key_name" {
  type        = string
  description = "SSH key name used to associate with EC2 instances"
}

variable "availability_zones" {
  type        = list(string)
  description = "List of availability zones to spread facilities between"
}

variable "enable_termination_protection" {
  type        = bool
  description = "Whether we should protect EC2 instances from accidental termination"
}

variable "trusted_networks" {
  type    = list(string)
  description = "List of network CIDRs to grant access"
  default = []
}

variable "flower_version" {
  type    = string
  default = "0.9"
}

variable "flower_username" {
  type = string
}

variable "flower_password" {
  type = string
}

variable "flower_broker_url" {
  type = string
}

variable "flower_broker_api_url" {
  type = string
}

variable "flower_port" {
  type    = number
  default = 5555
}

variable "flower_memory_limit" {
  type    = number
  default = 512
}

variable "launch_instance" {
  type    = bool
  default = true
}

variable "flower_tasks_count" {
  type    = number
  default = 1
}

resource "aws_iam_instance_profile" "flower" {
  name = "${lower(var.env_name)}-flower"
  role = aws_iam_role.flower_role.name
}

resource "aws_iam_role" "flower_role" {
  name               = "${lower(var.env_name)}-flower"
  assume_role_policy = data.aws_iam_policy_document.ec2_assume_policy.json
}

resource "aws_iam_role_policy" "docker_policy" {
  name   = "${lower(var.env_name)}-docker-policy"
  role   = aws_iam_role.flower_role.id
  policy = data.aws_iam_policy_document.docker_policy.json
}

data "aws_iam_policy_document" "ec2_assume_policy" {
  statement {
    effect = "Allow"
    actions = ["sts:AssumeRole"]
    principals {
      type        = "Service"
      identifiers = ["ec2.amazonaws.com"]
    }
  }
  statement {
    effect = "Allow"
    actions = ["sts:AssumeRole"]
    principals {
      type        = "Service"
      identifiers = ["ecs.amazonaws.com"]
    }
  }
}

data "aws_iam_policy_document" "docker_policy" {
  statement {
    effect = "Allow"
    actions = [
      "ecs:CreateCluster",
      "ecs:DeregisterContainerInstance",
      "ecs:DiscoverPollEndpoint",
      "ecs:Poll",
      "ecs:RegisterContainerInstance",
      "ecs:StartTelemetrySession",
      "ecs:Submit*",
      "ecr:GetAuthorizationToken",
      "ecr:BatchCheckLayerAvailability",
      "ecr:GetDownloadUrlForLayer",
      "ecr:BatchGetImage",
      "logs:CreateLogStream",
      "logs:PutLogEvents",
      "ec2:AuthorizeSecurityGroupIngress",
      "ec2:Describe*",
      "elasticloadbalancing:DeregisterInstancesFromLoadBalancer",
      "elasticloadbalancing:Describe*",
      "elasticloadbalancing:RegisterInstancesWithLoadBalancer"
    ]
    resources = ["*"]
  }
}

resource "aws_security_group" "flower_sg" {
  name   = "${lower(var.env_name)}-${lower(var.verbose_name)}-flower-access"
  vpc_id = var.vpc_id

  ingress {
    from_port   = var.flower_port
    to_port     = var.flower_port
    protocol    = "tcp"
    cidr_blocks = var.trusted_networks
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Env  = var.env_name
    Name = "${var.env_name}-${var.verbose_name}-Flower-Access"
  }
}

data "template_file" "flower_node_cloudconfig" {
  template = file("${path.module}/resources/userdata.tpl")
  vars = {
    cluster_role          = "flower"
    cluster_name          = var.ecs_cluster_name
    instance_group        = var.ecs_instance_group
    host_name             = "${lower(var.env_name)}-flower"
    configuration_script  = base64encode(file("${path.module}/../resources/install-unix-tools.sh"))
  }
}

resource "aws_instance" "flower_instance" {
  count                       = var.launch_instance ? 1 : 0
  ami                         = var.instance_ami
  instance_type               = var.instance_type
  subnet_id                   = element(var.vpc_subnets, 0)
  key_name                    = var.instance_key_name
  iam_instance_profile        = aws_iam_instance_profile.flower.name
  vpc_security_group_ids      = concat(var.vpc_security_groups, [aws_security_group.flower_sg.id])
  associate_public_ip_address = false
  source_dest_check           = false
  disable_api_termination     = var.enable_termination_protection
  instance_initiated_shutdown_behavior = "stop"
  user_data                   = data.template_file.flower_node_cloudconfig.rendered

  tags = {
    Env  = var.env_name
    Name = "${var.env_name}-${var.verbose_name}-Flower"
  }
}

data "aws_route53_zone" "local" {
  zone_id = var.vpc_dns_zone_id
}

resource "aws_route53_record" "flower_record" {
  count   = var.launch_instance ? 1 : 0
  zone_id = var.vpc_dns_zone_id
  name    = "flower.${data.aws_route53_zone.local.name}"
  type    = "A"
  ttl     = "60"
  records = aws_instance.flower_instance.*.private_ip
}

data "aws_ecs_cluster" "ecs_cluster" {
  cluster_name = var.ecs_cluster_name
}

resource "aws_ecs_task_definition" "flower_task" {
  family                = "${lower(var.env_name)}-flower"
  container_definitions = data.template_file.flower_task_config.rendered
}

resource "aws_ecs_service" "flower_service" {
  name            = "${lower(var.env_name)}-flower"
  desired_count   = var.flower_tasks_count
  cluster         = data.aws_ecs_cluster.ecs_cluster.id
  task_definition = aws_ecs_task_definition.flower_task.arn

  placement_constraints {
    type       = "memberOf"
    expression = "attribute:group == ${var.ecs_instance_group}"
  }

  depends_on = [
    aws_iam_role_policy.docker_policy,
    aws_ecs_task_definition.flower_task
  ]
}

data "template_file" "flower_task_config" {
  template = file("${path.module}/resources/flower.json")
  vars = {
    container_name       = "flower-monitor"
    flower_version       = var.flower_version
    flower_container_memory = var.flower_memory_limit
    flower_password      = var.flower_password
    flower_username      = var.flower_username
    flower_broker_url    = var.flower_broker_url
    flower_broker_api_url = var.flower_broker_api_url
    http_transport_port  = var.flower_port
  }
}

