variable "api_external_elb_zone_id" {
  description = "External API's ELB Zone ID"
  type        = string
}

variable "api_internal_elb_dns_name" {
  description = "Internal API's ELB DNS name"
  type        = string
}

variable "api_internal_elb_zone_id" {
  description = "Internal API's ELB Zone ID"
  type        = string
}

variable "console_elb_dns_name" {
  description = "Console's ELB DNS name"
  type        = string
}

variable "console_elb_zone_id" {
  description = "Console's ELB Zone ID"
  type        = string
}

resource "aws_route53_record" "etcd_a_nodes" {
  count   = var.self_hosted_etcd != "" ? 0 : var.etcd_count
  type    = "A"
  ttl     = 60
  zone_id = local.zone_id
  name    = "${var.cluster_name}-etcd-${count.index}"
  records = [var.etcd_ip_addresses[count.index]]
}

resource "aws_route53_record" "master_nodes" {
  count   = var.elb_alias_enabled ? 0 : var.master_count
  zone_id = data.aws_route53_zone.tectonic.zone_id
  name    = "${var.cluster_name}-master-${count.index}"
  type    = "A"
  ttl     = 60
  records = [var.master_ip_addresses[count.index]]
}

resource "aws_route53_record" "worker_nodes" {
  count   = var.elb_alias_enabled ? 0 : var.worker_count
  zone_id = data.aws_route53_zone.tectonic.zone_id
  name    = "${var.cluster_name}-worker-${count.index}"
  type    = "A"
  ttl     = 60
  records = [var.worker_ip_addresses[count.index]]
}

resource "aws_route53_record" "worker_nodes_public" {
  count   = var.worker_public_ips_enabled ? var.worker_count : 0
  zone_id = data.aws_route53_zone.tectonic.zone_id
  name    = "${var.cluster_name}-worker-${count.index}-public"
  type    = "A"
  ttl     = 60
  records = [var.worker_public_ips[count.index]]
}

data "aws_route53_zone" "tectonic" {
  name = var.base_domain
}

locals {
  private_zone_id = var.tectonic_external_private_zone == "" ? join("", aws_route53_zone.tectonic_int.*.zone_id) : var.tectonic_external_private_zone
  public_zone_id  = join("", data.aws_route53_zone.tectonic.*.zone_id)
  zone_id         = var.tectonic_private_endpoints ? local.private_zone_id : local.public_zone_id
}

resource "aws_route53_zone" "tectonic_int" {
  count         = var.tectonic_private_endpoints && var.tectonic_external_private_zone == "" ? 1 : 0
  vpc_id        = var.tectonic_external_vpc_id
  name          = var.base_domain
  force_destroy = true

  tags = merge({
    Name               = "${var.cluster_name}_tectonic_int_zone"
    KubernetesCluster  = var.cluster_name
    tectonicClusterID  = var.cluster_id
  }, var.tectonic_extra_tags)
}

resource "aws_route53_record" "tectonic_api" {
  count   = var.elb_alias_enabled ? 0 : 1
  zone_id = local.public_zone_id
  name    = "${var.cluster_name}-k8s"
  type    = "A"
  ttl     = 60
  records = var.api_ip_addresses
}

resource "aws_route53_record" "tectonic_api_external" {
  count   = var.elb_alias_enabled && var.tectonic_public_endpoints ? 1 : 0
  zone_id = local.public_zone_id
  name    = "${var.custom_dns_name == "" ? var.cluster_name : var.custom_dns_name}-api.${var.base_domain}"
  type    = "A"

  alias {
    name                   = var.api_external_elb_dns_name
    zone_id                = var.api_external_elb_zone_id
    evaluate_target_health = true
  }
}

resource "aws_route53_record" "tectonic_api_internal" {
  count   = var.elb_alias_enabled && var.tectonic_private_endpoints ? 1 : 0
  zone_id = local.private_zone_id
  name    = "${var.custom_dns_name == "" ? var.cluster_name : var.custom_dns_name}-api.${var.base_domain}"
  type    = "A"

  alias {
    name                   = var.api_internal_elb_dns_name
    zone_id                = var.api_internal_elb_zone_id
    evaluate_target_health = true
  }
}

resource "aws_route53_record" "tectonic_console" {
  count   = var.tectonic_vanilla_k8s || var.elb_alias_enabled ? 0 : 1
  zone_id = local.public_zone_id
  name    = var.cluster_name
  type    = "A"
  ttl     = 60
  records = var.worker_ip_addresses
}

resource "aws_route53_record" "tectonic_ingress_public" {
  count   = var.elb_alias_enabled && var.tectonic_public_endpoints ? 1 : 0
  zone_id = local.public_zone_id
  name    = "${var.custom_dns_name == "" ? var.cluster_name : var.custom_dns_name}.${var.base_domain}"
  type    = "A"

  alias {
    name                   = var.console_elb_dns_name
    zone_id                = var.console_elb_zone_id
    evaluate_target_health = true
  }
}

resource "aws_route53_record" "tectonic_ingress_private" {
  count   = var.elb_alias_enabled && var.tectonic_private_endpoints ? 1 : 0
  zone_id = local.private_zone_id
  name    = "${var.custom_dns_name == "" ? var.cluster_name : var.custom_dns_name}.${var.base_domain}"
  type    = "A"

  alias {
    name                   = var.console_elb_dns_name
    zone_id                = var.console_elb_zone_id
    evaluate_target_health = true
  }
}

output "etcd_a_nodes" {
  value = aws_route53_record.etcd_a_nodes.*.fqdn
}

# We have to do this join() & split() 'trick' because the ternary operator can't output lists.
output "etcd_endpoints" {
  value = split(",", length(var.external_endpoints) == 0 ? join(",", aws_route53_record.etcd_a_nodes.*.fqdn) : join(",", var.external_endpoints))
}

output "worker_nodes" {
  value = aws_route53_record.worker_nodes.*.fqdn
}

output "worker_nodes_public" {
  value = aws_route53_record.worker_nodes_public.*.fqdn
}

output "master_nodes" {
  value = aws_route53_record.master_nodes.*.fqdn
}

output "ingress_external_fqdn" {
  value = element(concat(aws_route53_record.tectonic_ingress_public.*.name, [""]), 0)
}

output "ingress_internal_fqdn" {
  value = element(concat(aws_route53_record.tectonic_ingress_private.*.name, [""]), 0)
}

output "api_external_fqdn" {
  value = element(concat(aws_route53_record.tectonic_api_external.*.name, [""]), 0)
}

output "api_internal_fqdn" {
  value = element(concat(aws_route53_record.tectonic_api_internal.*.name, [""]), 0)
}

provider "google" {
  alias = "target"
}

provider "google" {
  alias = "dns"
}

provider "google-beta" {
  alias = "target"
}


#
# General Vars
#
variable "dependencies" {
  # See: https://github.com/hashicorp/terraform/issues/21418#issuecomment-495818852
  type        = any
  default     = []
  description = "Work-around for Terraform 0.12's lack of support for 'depends_on' in custom modules."
}
variable "enable" {
  type        = bool
  description = "Enable flag for this module. If set to false, no resources will be created."
  default     = true
}
variable "google_project" {
  type        = string
  description = "The google project in which to create resources"
}
variable "cluster" {
  type        = string
  description = "Terra GKE cluster suffix, whatever is after terra-"
}
variable "cluster_short" {
  type        = string
  description = "Optional short cluster name"
  default     = ""
}
variable "owner" {
  type        = string
  description = "Environment or developer. Defaults to TF workspace name if left blank."
  default     = ""
}
locals {
  owner   = var.owner == "" ? terraform.workspace : var.owner
  service = "buffer"
}

#
# IP Vars
#
variable "global_ip" {
  type        = bool
  description = "Whether to make the IP global"
  default     = false
}

#
# DNS Vars
#
variable "dns_zone_name" {
  type        = string
  description = "DNS zone name"
  default     = "dsp-envs"
}
variable "use_subdomain" {
  type        = bool
  description = "Whether to use a subdomain between the zone and hostname"
  default     = true
}
variable "subdomain_name" {
  type        = string
  description = "Domain namespacing between zone and hostname"
  default     = ""
}
variable "hostname" {
  type        = string
  description = "Service hostname"
  default     = ""
}
locals {
  hostname       = var.hostname == "" ? local.service : var.hostname
  cluster_name   = var.cluster_short == "" ? var.cluster : var.cluster_short
  subdomain_name = var.use_subdomain ? (var.subdomain_name == "" ? ".${local.owner}.${local.cluster_name}" : var.subdomain_name) : ""
}


#
# Postgres CloudSQL DB Vars
#
variable "db_tier" {
  default     = "db-g1-small"
  description = "The default tier (DB instance size) for the CloudSQL instance"
}
variable "db_version" {
  type        = string
  default     = "POSTGRES_12"
  description = "The version for the CloudSQL instance"
}
variable "db_keepers" {
  type        = bool
  default     = true
  description = "Whether to use keepers to re-generate instance name."
}
variable "db_name" {
  type        = string
  description = "Postgres db name"
  default     = ""
}
variable "db_user" {
  type        = string
  description = "Postgres username"
  default     = ""
}
variable "stairway_db_name" {
  type        = string
  description = "Stairway db name"
  default     = ""
}
variable "stairway_db_user" {
  type        = string
  description = "Stairway db username"
  default     = ""
}
locals {
  db_name          = var.db_name == "" ? local.service : var.db_name
  db_user          = var.db_user == "" ? local.service : var.db_user
  stairway_db_name = var.stairway_db_name == "" ? "${local.service}-stairway" : var.stairway_db_name
  stairway_db_user = var.stairway_db_user == "" ? "${local.service}-stairway" : var.stairway_db_user
}

#
# List of billing accounts Resource Buffer Service has permissions on.
#
# We separate whether the roles/billing.user is set on the Resource Buffer Service SA as its own flag because the
# Broad SA that runs terraform does not want to have the broad permissions to set modify
# permissions on the service account. This was done manually instead for the Broad.
variable "billing_account_ids" {
  type        = list(string)
  description = "List of Google billing account ids to allow Resource Buffer Service to use"
  default     = []
}

# Root folder for this environment. A single folder will be created under the root folder for all
# buffer service resources, and then pool specific folders under that, i.e. structure will be
# {root_folder_id}/buffer-{env}/{pool_name} for each pool_name passed in below. The id of the
# bottom level folder must be the value of parentFolderId in the buffer service configuration.
variable "root_folder_id" {
  type        = string
  description = "Folder under which all projects will be created for this environment. If empty, no folders will be created."
  default     = ""
}

# For each pool in this list, a folder will be created and buffer service Service Account will
# be granted permission. See root_folder_id docs for folder structure. Pool name is the pool id
# from the buffer service configuration without version information.
variable "pool_names" {
  type        = list(string)
  description = "List of pools for which folders will be created and Buffer Service Account granted access to."
  default     = []
}

# This field should only be used if there is a good reason to prefer a manually managed folder for a particular pool.
variable "external_folder_ids" {
  type        = list(string)
  description = "List of already existing folders that Buffer Service Account will be granted access to."
  default     = []
}


/**
 * # Terra Resource Buffering Service module
 *
 * This module creates the service account and CloudSQL databases necessary for 
 * running the [terra-resource-buffer](http://github.com/databiosphere/terra-resource-buffer).
 * 
 * For more information, check out the [MC-Terra deployment doc](https://docs.dsp-devops.broadinstitute.org/mc-terra/mcterra-deployment)
 * and our [Terraform best practices](https://docs.dsp-devops.broadinstitute.org/best-practices-guides/terraform).
 *
 * This documentation is generated with [terraform-docs](https://github.com/segmentio/terraform-docs)
 * `terraform-docs markdown --no-sort . > README.md`
 */


locals {
  create_folders = var.enable && var.root_folder_id != ""
}

# Create a single folder under the passed in root folder. This folder will hold the pool-specific folders.
resource "google_folder" "pool_parent_folder" {
  count        = local.create_folders ? 1 : 0
  display_name = "${local.service}-${local.owner}"
  parent       = "folders/${var.root_folder_id}"
  provider     = google.target
}

# Create one folder for each pool to hold all projects created from that pool
resource "google_folder" "pool_folders" {
  for_each     = local.create_folders ? toset(var.pool_names) : []
  display_name = each.key
  // If create_folders is false, none of these will be generated. If it is true, there will be exactly one
  // pool_parent_folder.
  parent       = local.create_folders ? google_folder.pool_parent_folder[0].name : ""
  provider     = google.target
}


# The service account for the cloudsql proxy.
resource "google_service_account" "sqlproxy" {
  count = var.enable ? 1 : 0

  provider     = google.target
  project      = var.google_project
  account_id   = "${local.service}-${local.owner}-sqlproxy"
  display_name = "${local.service}-${local.owner}-sqlproxy"
}
resource "google_project_iam_member" "sqlproxy_role" {
  count = var.enable ? 1 : 0

  provider = google.target
  project  = var.google_project
  role     = "roles/cloudsql.client"
  member   = "serviceAccount:${google_service_account.sqlproxy[0].email}"
}

locals {
  app_sa_roles = [
    # Allow exporting metrics, profiling, and tracing for monitoring.
    "roles/monitoring.editor",
    "roles/cloudprofiler.agent",
    "roles/cloudtrace.agent",
    # Allow creating & publishing & subscribing pub/sub topics for multi-instance Stairway.
    "roles/pubsub.editor",
  ]

  # Roles used to manage projects for integration testing.
  app_folder_roles = [
    "roles/resourcemanager.folderAdmin",
    "roles/resourcemanager.projectCreator",
    "roles/resourcemanager.projectDeleter",
  ]
  generated_folders = local.create_folders ? [for f in google_folder.pool_folders : f.id] : []
  folder_ids_and_roles = [
    for pair in setproduct(local.app_folder_roles,
       concat(var.external_folder_ids, local.generated_folders)) : {
      folder_role = pair[0]
      folder_id = pair[1]
    }]
}

# The main service account for the Terra Resource Buffer Service service app.
resource "google_service_account" "app" {
  count = var.enable ? 1 : 0

  provider     = google.target
  project      = var.google_project
  account_id   = "${local.service}-${local.owner}"
  display_name = "${local.service}-${local.owner}"
}

# Grant Terra Resource Buffer Service App Service Account editor permission to create resources.
# TBD: This may change to organization/folder level permission depends on the Rawls integration
resource "google_project_iam_member" "app_roles" {
  count = var.enable ? length(local.app_sa_roles) : 0

  provider = google.target
  project  = var.google_project
  role     = local.app_sa_roles[count.index]
  member   = "serviceAccount:${google_service_account.app[0].email}"
}

# Grant Terra Resource Buffer Service App Service Account permission to modify resource in folder.
resource "google_folder_iam_member" "app_folder_roles" {
  // Skip if google_folder variable is not present.
  count = var.enable ? length(local.folder_ids_and_roles): 0

  provider = google.target
  folder  = local.folder_ids_and_roles[count.index].folder_id
  role     = local.folder_ids_and_roles[count.index].folder_role
  member   = "serviceAccount:${google_service_account.app[0].email}"
}

# Grant Terra Resource Buffer Service App Service Account permission use the billing accounts.
# If billing_account_ids is empty, we won't set the Resource Buffer Service SA as a billing user
resource "google_billing_account_iam_member" "app_billing_roles" {
  count              = var.enable ? length(var.billing_account_ids) : 0
  billing_account_id = var.billing_account_ids[count.index]
  role               = "roles/billing.user"
  member             = "serviceAccount:${google_service_account.app[0].email}"
}

# The service account to be able to access Buffer service.
# All services which want to access the Buffer service would need to use this service account secret.
resource "google_service_account" "client" {
  count = var.enable ? 1 : 0

  provider     = google.target
  account_id   = "${local.service}-client-${local.owner}"
  display_name = "${local.service}-client-${local.owner}"
}


resource "google_compute_address" "ingress_ip" {
  count = var.enable && !var.global_ip ? 1 : 0

  provider = google.target

  name = "terra-${var.cluster}-${local.owner}-${local.service}-ip"
}

resource "google_compute_global_address" "ingress_ip" {
  count = var.enable && var.global_ip ? 1 : 0

  provider = google.target

  name = "terra-${var.cluster}-${local.owner}-${local.service}-ip"
}

locals {
  ingress_ip = var.enable ? (var.global_ip ? [google_compute_global_address.ingress_ip[0].address] : [google_compute_address.ingress_ip[0].address]) : null
  ingress_ip_name = var.enable ? (var.global_ip ? [google_compute_global_address.ingress_ip[0].name] : [google_compute_address.ingress_ip[0].name]) : null
}


module "cloudsql" {
  source = "github.com/broadinstitute/terraform-shared.git//terraform-modules/cloudsql-postgres?ref=cloudsql-postgres-2.0.0"

  enable = var.enable

  providers = {
    google.target = google.target
  }
  project          = var.google_project

  cloudsql_name    = "${local.service}-db-${local.owner}"
  cloudsql_version = var.db_version
  cloudsql_keepers = var.db_keepers
  cloudsql_tier    = var.db_tier
  cloudsql_instance_labels = {
    "env" = local.owner
    "app" = local.service
  }

  cloudsql_database_flags = {
    "log_checkpoints" = "on",
    "log_connections" = "on",
    "log_disconnections" = "on",
    "log_lock_waits" = "on",
    "log_min_error_statement" = "error",
    "log_temp_files" = "0",
    "log_min_duration_statement" = "-1"
  }

  app_dbs = {
    "${local.service}" = {
      db       = local.db_name
      username = local.db_user
    }
    "${local.service}-stairway" = {
      db       = local.stairway_db_name
      username = local.stairway_db_user
    }
  }

  dependencies = [var.dependencies]
}


data "google_dns_managed_zone" "dns_zone" {
  count = var.enable ? 1 : 0

  provider = google.dns
  name     = var.dns_zone_name
}

locals {
  fqdn = var.enable ? "${local.hostname}${local.subdomain_name}.${data.google_dns_managed_zone.dns_zone[0].dns_name}" : null
}

resource "google_dns_record_set" "ingress" {
  count = var.enable ? 1 : 0

  provider     = google.dns
  managed_zone = data.google_dns_managed_zone.dns_zone[0].name
  name         = local.fqdn
  type         = "A"
  ttl          = "300"
  rrdatas      = local.ingress_ip
}


module "enable-services" {
  source      = "github.com/broadinstitute/terraform-shared.git//terraform-modules/api-services?ref=services-0.3.0-tf-0.12"
  enable_flag = var.enable ? "1" : "0"
  providers = {
    google.target = google.target
  }
  project = var.google_project
  services = [
    "cloudbilling.googleapis.com",
  ]
}


#
# Service Account Outputs
#
output "app_sa_id" {
  value       = var.enable ? google_service_account.app[0].account_id : null
  description = "Terra Resource Buffer Service Google service accout ID"
}
output "sqlproxy_sa_id" {
  value       = var.enable ? google_service_account.sqlproxy[0].account_id : null
  description = "Terra Resource Buffer Service Cloud SQL Proxy Google service account ID"
}
output "client_sa_id" {
  value       = var.enable ? google_service_account.client[0].account_id : null
  description = "Client Google service account ID"
}

#
# IP/DNS Outputs
#
output "ingress_ip" {
  value       = var.enable ? local.ingress_ip : null
  description = "Terra Resource Buffer Service ingress IP"
}
output "ingress_ip_name" {
  value       = var.enable ? local.ingress_ip_name : null
  description = "Terra Resource Buffer Service ingress IP name"
}
output "fqdn" {
  value       = var.enable ? local.fqdn : null
  description = "Terra Resource Buffer Service fully qualified domain name"
}

#
# CloudSQL PostgreSQL Outputs
#
output "cloudsql_public_ip" {
  value       = var.enable ? module.cloudsql.public_ip : null
  description = "Terra Resource Buffer Service CloudSQL instance IP"
}
output "cloudsql_instance_name" {
  value       = var.enable ? module.cloudsql.instance_name : null
  description = "Terra Resource Buffer Service CloudSQL instance name"
}
output "cloudsql_root_user_password" {
  value       = var.enable ? module.cloudsql.root_user_password : null
  description = "Terra Resource Buffer Service database root password"
  sensitive   = true
}
output "cloudsql_app_db_creds" {
  # Avoiding error on destroy with below condition
  value       = var.enable ? (length(module.cloudsql.app_db_creds) == 0 ? {} : module.cloudsql.app_db_creds[local.service]) : null
  description = "Terra Resource Buffer Service database user credentials"
  sensitive   = true
}
output "cloudsql_app_stairway_db_creds" {
  # Avoiding error on destroy with below condition
  value       = var.enable ? (length(module.cloudsql.app_db_creds) == 0 ? {} : module.cloudsql.app_db_creds["${local.service}-stairway"]) : null
  description = "Terra Resource Buffer Service Stairway database user credentials"
  sensitive   = true
}

#
# Pool Folder Outputs
#
output "pool_name_to_folder_id" {
  // Lookup each variable in the pool_names input list in the generated folders map. This relies on the pool_name being each.key in the
  // for_each in folder.tf
  value       = var.enable ? { for p in var.pool_names : p => google_folder.pool_folders[p].id }  : {}
  description = "Map from pool name to the folder that will contain all projects created for the pool. Only populated for pools in the pool_names input variable."
}

variable "etcd_tls_enabled" {
  description = "Indicates whether TLS is used for etcd"
  type        = string
  default     = "1"
}

variable "cluster_name" {
  description = "The name of the cluster"
  type        = string
}

variable "base_domain" {
  description = "The base domain used in records"
  type        = string
}

variable "master_count" {
  description = "The number of masters"
  type        = string
}

variable "worker_count" {
  description = "The number of workers"
  type        = string
  default     = "0"
}

variable "etcd_count" {
  description = "The number of etcd nodes"
  type        = string
}

variable "etcd_ips" {
  description = "List of string IPs for etcd nodes"
  type        = list(string)
}

variable "master_ips" {
  description = "List of string IPs for masters"
  type        = list(string)
  default     = []
}

variable "worker_ips" {
  description = "List of string IPs for workers"
  type        = list(string)
  default     = []
}

variable "cluster_id" {
  description = "Cluster ID"
  type        = string
}

variable "external_endpoints" {
  description = "List of external etcd v3 servers to connect with (hostnames/IPs only). Needs to be set if using an external etcd cluster."
  type        = list(string)
  default     = []
}

variable "worker_public_ips" {
  description = "(optional) List of string public IPs for workers"
  type        = list(string)
  default     = []
}

// hack: worker_public_ips_enabled is a workaround for https://github.com/hashicorp/terraform/issues/10857
variable "worker_public_ips_enabled" {
  description = "Worker nodes have public IPs assigned. worker_public_ips must be provided if true."
  default     = true
}

variable "api_ips" {
  description = "List of string IPs for k8s API"
  type        = list(string)
}

variable "self_hosted_etcd" {
  default     = ""
  description = "See tectonic_self_hosted_etcd in config.tf"
}

variable "tectonic_vanilla_k8s" {
  description = "If set to true, a vanilla Kubernetes cluster will be deployed, omitting any Tectonic assets."
  type        = bool
  default     = false
}

variable "tectonic_extra_tags" {
  type        = map(string)
  description = "(optional) Extra tags to be applied to created resources."
  default     = {}
}

variable "custom_dns_name" {
  type        = string
  default     = ""
  description = "DNS prefix used to construct the console and API server endpoints."
}

// AWS specific internal zone variables

variable "elb_alias_enabled" {
  description = "Whether to create an aliased record set to ELB endpoints. Refer to http://docs.aws.amazon.com/Route53/latest/DeveloperGuide/resource-record-sets-choosing-alias-non-alias.html for additional information."
  type        = bool
  default     = false
}

variable "tectonic_external_vpc_id" {
  type        = string
  description = "ID of an existing VPC to launch nodes into. If unset a new VPC is created. Example: `vpc-123456`"
  default     = ""
}

variable "tectonic_private_endpoints" {
  description = "If set to true, create private-facing ingress resources (ELB, A-records). If set to false, no private-facing ingress resources will be provisioned and all DNS records will be created in the public Route53 zone."
  type        = bool
  default     = false
}

variable "tectonic_public_endpoints" {
  description = "If set to true, create public-facing ingress resources (ELB, A-records). If set to false, no public-facing ingress resources will be created."
  type        = bool
  default     = false
}

variable "tectonic_external_private_zone" {
  description = "If set, the given Route53 zone ID will be used as the internal (private) zone. This zone will be used to create etcd DNS records as well as internal API and internal Ingress records. If set, no additional private zone will be created. Example: `"Z1ILINNUJGTAO1"`"
  type        = string
  default     = ""
}

variable "api_external_elb_dns_name" {
  description = "External API's ELB DNS name"
  type        = string
}

variable "api_external_elb_zone_id" {
  description = "External API's ELB Zone ID"
  type        = string
}

variable "api_internal_elb_dns_name" {
  description = "Internal API's ELB DNS name"
  type        = string
}

variable "api_internal_elb_zone_id" {
  description = "Internal API's ELB Zone ID"
  type        = string
}

variable "console_elb_dns_name" {
  description = "Console's ELB DNS name"
  type        = string
}

variable "console_elb_zone_id" {
  description = "Console's ELB Zone ID"
  type        = string
}


resource "aws_route53_record" "etcd_a_nodes" {
  count   = var.self_hosted_etcd != "" ? 0 : tonumber(var.etcd_count)
  type    = "A"
  ttl     = "60"
  zone_id = local.zone_id
  name    = "${var.cluster_name}-etcd-${count.index}"
  records = [var.etcd_ips[count.index]]
}


resource "aws_route53_record" "master_nodes" {
  count   = var.elb_alias_enabled ? 0 : tonumber(var.master_count)
  zone_id = data.aws_route53_zone.tectonic.zone_id
  name    = "${var.cluster_name}-master-${count.index}"
  type    = "A"
  ttl     = "60"
  records = [var.master_ips[count.index]]
}


resource "aws_route53_record" "worker_nodes" {
  count   = var.elb_alias_enabled ? 0 : tonumber(var.worker_count)
  zone_id = data.aws_route53_zone.tectonic.zone_id
  name    = "${var.cluster_name}-worker-${count.index}"
  type    = "A"
  ttl     = "60"
  records = [var.worker_ips[count.index]]
}

resource "aws_route53_record" "worker_nodes_public" {
  count   = var.worker_public_ips_enabled ? tonumber(var.worker_count) : 0
  zone_id = data.aws_route53_zone.tectonic.zone_id
  name    = "${var.cluster_name}-worker-${count.index}-public"
  type    = "A"
  ttl     = "60"
  records = [var.worker_public_ips[count.index]]
}


data "aws_route53_zone" "tectonic" {
  name = var.base_domain
}

locals {
  private_zone_id = var.tectonic_external_private_zone == "" ? join("", aws_route53_zone.tectonic_int.*.zone_id) : var.tectonic_external_private_zone
  public_zone_id  = join("", data.aws_route53_zone.tectonic.*.zone_id)
  zone_id         = var.tectonic_private_endpoints ? local.private_zone_id : local.public_zone_id
}

resource "aws_route53_zone" "tectonic_int" {
  count         = var.tectonic_private_endpoints ? (var.tectonic_external_private_zone == "" ? 1 : 0) : 0
  vpc_id        = var.tectonic_external_vpc_id
  name          = var.base_domain
  force_destroy = true

  tags = merge(
    {
      Name                = "${var.cluster_name}_tectonic_int_zone"
      KubernetesCluster   = var.cluster_name
      tectonicClusterID   = var.cluster_id
    },
    var.tectonic_extra_tags
  )
}

resource "aws_route53_record" "tectonic_api" {
  count   = var.elb_alias_enabled ? 0 : 1
  zone_id = local.public_zone_id
  name    = "${var.cluster_name}-k8s"
  type    = "A"
  ttl     = "60"
  records = var.api_ips
}

resource "aws_route53_record" "tectonic_api_external" {
  count   = var.elb_alias_enabled && var.tectonic_public_endpoints ? 1 : 0
  zone_id = local.public_zone_id
  name    = "${var.custom_dns_name == "" ? var.cluster_name : var.custom_dns_name}-api.${var.base_domain}"
  type    = "A"

  alias {
    name                   = var.api_external_elb_dns_name
    zone_id                = var.api_external_elb_zone_id
    evaluate_target_health = true
  }
}

resource "aws_route53_record" "tectonic_api_internal" {
  count   = var.elb_alias_enabled && var.tectonic_private_endpoints ? 1 : 0
  zone_id = local.private_zone_id
  name    = "${var.custom_dns_name == "" ? var.cluster_name : var.custom_dns_name}-api.${var.base_domain}"
  type    = "A"

  alias {
    name                   = var.api_internal_elb_dns_name
    zone_id                = var.api_internal_elb_zone_id
    evaluate_target_health = true
  }
}

resource "aws_route53_record" "tectonic_console" {
  count   = var.tectonic_vanilla_k8s ? 0 : var.elb_alias_enabled ? 0 : 1
  zone_id = local.public_zone_id
  name    = var.cluster_name
  type    = "A"
  ttl     = "60"
  records = var.worker_ips
}

resource "aws_route53_record" "tectonic_ingress_public" {
  count   = var.elb_alias_enabled && var.tectonic_public_endpoints ? 1 : 0
  zone_id = local.public_zone_id
  name    = "${var.custom_dns_name == "" ? var.cluster_name : var.custom_dns_name}.${var.base_domain}"
  type    = "A"

  alias {
    name                   = var.console_elb_dns_name
    zone_id                = var.console_elb_zone_id
    evaluate_target_health = true
  }
}

resource "aws_route53_record" "tectonic_ingress_private" {
  count   = var.elb_alias_enabled && var.tectonic_private_endpoints ? 1 : 0
  zone_id = local.private_zone_id
  name    = "${var.custom_dns_name == "" ? var.cluster_name : var.custom_dns_name}.${var.base_domain}"
  type    = "A"

  alias {
    name                   = var.console_elb_dns_name
    zone_id                = var.console_elb_zone_id
    evaluate_target_health = true
  }
}


output "etcd_a_nodes" {
  value = aws_route53_record.etcd_a_nodes.*.fqdn
}

# We have to do this join() & split() 'trick' because the ternary operator can't output lists.
output "etcd_endpoints" {
  value = split(",", length(var.external_endpoints) == 0 ? join(",", aws_route53_record.etcd_a_nodes.*.fqdn) : join(",", var.external_endpoints))
}

output "worker_nodes" {
  value = aws_route53_record.worker_nodes.*.fqdn
}

output "worker_nodes_public" {
  value = aws_route53_record.worker_nodes_public.*.fqdn
}

output "master_nodes" {
  value = aws_route53_record.master_nodes.*.fqdn
}

output "ingress_external_fqdn" {
  value = join(" ", aws_route53_record.tectonic_ingress_public.*.name)
}

output "ingress_internal_fqdn" {
  value = join(" ", aws_route53_record.tectonic_ingress_private.*.name)
}

output "api_external_fqdn" {
  value = join(" ", aws_route53_record.tectonic_api_external.*.name)
}

output "api_internal_fqdn" {
  value = join(" ", aws_route53_record.tectonic_api_internal.*.name)
}

