output "id" {
  description = "The memorystore instance ID."
  value       = google_memcache_instance.self.id
}

output "region" {
  description = "The region the instance lives in."
  value       = google_memcache_instance.self.region
}

output "nodes" {
  description = "Data about the memcache nodes"
  value       = google_memcache_instance.self.memcache_nodes
}

output "discovery" {
  description = "The memorystore discovery endpoint."
  value       = google_memcache_instance.self.discovery_endpoint
}

terraform {
  required_version = ">= 0.13"
  required_providers {
    aws = {
      source = "hashicorp/aws"
    }
    template = {
      source = "hashicorp/template"
    }
  }
}


variable "aws_region" {
  description = "The AWS region to create things in."
  default     = "us-west-2"
}

variable "az_count" {
  description = "Number of AZs to cover in a given AWS region"
  default     = "2"
}

variable "admin_cidr_ingress" {
  description = "CIDR to allow tcp/22 ingress to EC2 instance"
}

variable "redis_cluster_count" {
  description = "to enable/disable redis since creation is slow"
  default     = 1
}



provider "aws" {
  region = var.aws_region

  default_tags {
    tags = {
      Name       = "hello-ecs"
      Repository = "https://github.com/ericdahl/hello-ecs"
    }
  }
}

data "aws_default_tags" "default" {}

locals {
  name = data.aws_default_tags.default.tags["Name"]
}

data "aws_availability_zones" "available" {}

resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"
}

resource "aws_subnet" "public" {
  count             = var.az_count
  cidr_block        = cidrsubnet(aws_vpc.main.cidr_block, 8, count.index)
  availability_zone = data.aws_availability_zones.available.names[count.index]
  vpc_id            = aws_vpc.main.id

  map_public_ip_on_launch = true
}

resource "aws_internet_gateway" "gw" {
  vpc_id = aws_vpc.main.id
}

resource "aws_route_table" "r" {
  vpc_id = aws_vpc.main.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.gw.id
  }
}

resource "aws_route_table_association" "a" {
  count          = var.az_count
  subnet_id      = element(aws_subnet.public.*.id, count.index)
  route_table_id = aws_route_table.r.id
}

resource "aws_alb_target_group" "default" {
  name        = local.name
  port        = 8080
  protocol    = "HTTP"
  vpc_id      = aws_vpc.main.id
  target_type = "ip"

  deregistration_delay = 0
}

resource "aws_alb" "default" {
  name            = local.name
  subnets         = aws_subnet.public.*.id
  security_groups = [aws_security_group.alb.id]
}

resource "aws_alb_listener" "default" {
  load_balancer_arn = aws_alb.default.id
  port              = "80"
  protocol          = "HTTP"

  default_action {
    target_group_arn = aws_alb_target_group.default.id
    type             = "forward"
  }
}

resource "aws_security_group" "alb" {
  description = "controls access to the application ELB"

  vpc_id = aws_vpc.main.id
  name   = "${local.name}-alb"

  ingress {
    protocol    = "tcp"
    from_port   = 80
    to_port     = 80
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port = 0
    to_port   = 0
    protocol  = "-1"

    cidr_blocks = [
      "0.0.0.0/0",
    ]
  }
}



resource "aws_ecs_cluster" "default" {
  name = local.name

  setting {
    name  = "containerInsights"
    value = "enabled"
  }
}


resource "aws_iam_role" "ecs_task_execution" {
  name = "ecs-task-execution"

  assume_role_policy = <<EOF
{
  "Version": "2012-10-17",
  "Statement": [
    {
      "Effect": "Allow",
      "Principal": {
        "Service": "ecs-tasks.amazonaws.com"
      },
      "Action": "sts:AssumeRole"
    }
  ]
}
EOF
}

resource "aws_iam_policy" "ecs_task_execution" {
  policy = <<EOF
{
  "Version": "2012-10-17",
  "Statement": [
    {
      "Effect": "Allow",
      "Action": [
        "ecr:GetAuthorizationToken",
        "ecr:BatchCheckLayerAvailability",
        "ecr:GetDownloadUrlForLayer",
        "ecr:BatchGetImage",
        "logs:CreateLogStream",
        "logs:PutLogEvents"
      ],
      "Resource": "*"
    }
  ]
}
EOF
}

resource "aws_iam_role_policy_attachment" "ecs_task_execution" {
  role       = aws_iam_role.ecs_task_execution.name
  policy_arn = aws_iam_policy.ecs_task_execution.arn
}



resource "aws_ecs_task_definition" "default" {
  family                = local.name
  container_definitions = templatefile("${path.module}/templates/tasks/app.json", { redis_host = aws_elasticache_cluster.default.cache_nodes[0].address })

  requires_compatibilities = ["FARGATE"]
  network_mode             = "awsvpc"
  cpu                      = 256
  memory                   = 512
  execution_role_arn       = aws_iam_role.ecs_task_execution.arn
}

resource "aws_ecs_service" "default" {
  name            = local.name
  cluster         = aws_ecs_cluster.default.name
  task_definition = aws_ecs_task_definition.default.arn
  desired_count   = 1
  launch_type     = "FARGATE"

  network_configuration {
    subnets = aws_subnet.public.*.id

    security_groups = [
      aws_security_group.ecs_task.id
    ]
    assign_public_ip = true # not ideal, but to help avoid paying for a NAT gateway
  }

  depends_on = [aws_alb.default]

  # java app can take ~100 seconds to start up with
  # current memory settings
  # 2023-03-05 17:44:11.314  INFO 7 --- [           main] example.App                              : Started App in 88.608 seconds (JVM running for 93.593)
  health_check_grace_period_seconds = 300

  load_balancer {
    target_group_arn = aws_alb_target_group.default.arn
    container_name   = "hello-ecs"
    container_port   = 8080
  }
}

resource "aws_security_group" "ecs_task" {
  name   = "${local.name}-ecs-task"
  vpc_id = aws_vpc.main.id
}

resource "aws_security_group_rule" "ecs_task_ingress_alb" {
  security_group_id = aws_security_group.ecs_task.id

  type      = "ingress"
  from_port = 8080
  protocol  = "tcp"
  to_port   = 8080

  source_security_group_id = aws_security_group.alb.id

  description = "allows ALB to make requests to ECS Task"
}

resource "aws_security_group_rule" "ecs_task_egress_all" {
  security_group_id = aws_security_group.ecs_task.id

  type = "egress"

  from_port   = 0
  to_port     = 0
  protocol    = "-1"

  cidr_blocks = ["0.0.0.0/0"]
  description = "allows ECS task to make egress calls"
}

resource "aws_cloudwatch_log_group" "app" {
  name              = "/hello-ecs/app"
  retention_in_days = 3
}
resource "aws_appautoscaling_target" "app" {
  max_capacity       = 3
  min_capacity       = 1
  resource_id        = "service/${aws_ecs_cluster.default.name}/${aws_ecs_service.default.name}"
  scalable_dimension = "ecs:service:DesiredCount"
  service_namespace  = "ecs"
}

resource "aws_appautoscaling_policy" "app" {
  name               = "app"
  resource_id        = aws_appautoscaling_target.app.resource_id
  scalable_dimension = aws_appautoscaling_target.app.scalable_dimension
  service_namespace  = aws_appautoscaling_target.app.service_namespace

  policy_type = "TargetTrackingScaling"
  target_tracking_scaling_policy_configuration {
    target_value = 25

    predefined_metric_specification {
      predefined_metric_type = "ALBRequestCountPerTarget"
      resource_label = "${aws_alb.default.arn_suffix}/${aws_alb_target_group.default.arn_suffix}"
    }
  }
}


resource "aws_elasticache_cluster" "default" {
  cluster_id         = local.name
  engine             = "redis"
  node_type          = "cache.t4g.micro"
  port               = 6379
  num_cache_nodes    = 1
  subnet_group_name  = aws_elasticache_subnet_group.default.name
  security_group_ids = [aws_security_group.elasticache_sg.id]

  apply_immediately = true
}

resource "aws_elasticache_subnet_group" "default" {
  name       = local.name
  subnet_ids = aws_subnet.public.*.id
}

resource "aws_security_group" "elasticache_sg" {
  vpc_id = aws_vpc.main.id
  name   = "${local.name}-elasticache"
}

resource "aws_security_group_rule" "elasticache_ingresss_ecs" {
  security_group_id = aws_security_group.elasticache_sg.id

  type      = "ingress"
  protocol  = "tcp"
  from_port = 6379
  to_port   = 6379

  source_security_group_id = aws_security_group.ecs_task.id
  description              = "allows ECS Task to make connections to redis"
}

resource "aws_security_group_rule" "elasticache_ingress_admin" {
  security_group_id = aws_security_group.ecs_task.id

  from_port = 6379
  protocol  = "tcp"
  to_port   = 6379
  type      = "ingress"

  cidr_blocks = [var.admin_cidr_ingress]
  description = "allows admin to connect to redis"
}



output "alb" {
  value = "http://${aws_alb.default.dns_name}"
}

variable "allowed_user_arns" {
  type = list(string)
}

variable "allowed_user_names" {
  type = list(string)
}

variable "name" {
  type = string
}

variable "policy_arns" {
  default = []
  type    = list(string)
}

variable "policy_arn_count" {
  default = "0"
  type    = string
}

output "arn" {
  value = aws_iam_role.role.arn
}

data "aws_iam_policy_document" "role" {
  statement {
    actions = [
      "sts:AssumeRole"
    ]
    condition {
      test     = "Bool"
      values   = [
        "true"
      ]
      variable = "aws:MultiFactorAuthPresent"
    }
    principals {
      identifiers = var.allowed_user_arns
      type        = "AWS"
    }
  }
}

resource "aws_iam_role" "role" {
  assume_role_policy = data.aws_iam_policy_document.role.json
  name               = var.name
}

resource "aws_iam_role_policy_attachment" "role" {
  count      = tonumber(var.policy_arn_count)
  policy_arn = var.policy_arns[count.index]
  role       = aws_iam_role.role.name
}

module "group" {
  source            = "github.com/QuiNovas/terraform-modules//aws/assume-role-group?ref=v1.0.13"
  name              = var.name
  allowed_user_names = var.allowed_user_names
  role_arns         = [aws_iam_role.role.arn]
}

data "terraform_remote_state" "bootstrap" {
  backend = "local"

  config {
    path = "${path.cwd}/bootstrap.tfstate"
  }
}

locals {
  aws_launch_configuration_masters = data.terraform_remote_state.bootstrap.outputs.aws_launch_configuration_masters
  subnet_ids_masters               = data.terraform_remote_state.bootstrap.outputs.subnet_ids_masters
  aws_lbs_masters                  = data.terraform_remote_state.bootstrap.outputs.aws_lbs_masters
  cluster_id                       = data.terraform_remote_state.bootstrap.outputs.cluster_id
  aws_launch_configuration_workers = data.terraform_remote_state.bootstrap.outputs.aws_launch_configuration_workers
  subnet_ids_workers               = data.terraform_remote_state.bootstrap.outputs.subnet_ids_workers
  private_zone_id                  = data.terraform_remote_state.bootstrap.outputs.private_zone_id
  tnc_elb_dns_name                 = data.terraform_remote_state.bootstrap.outputs.tnc_elb_dns_name
  tnc_elb_zone_id                  = data.terraform_remote_state.bootstrap.outputs.tnc_elb_zone_id
}

provider "aws" {
  region  = var.tectonic_aws_region
  profile = var.tectonic_aws_profile

  assume_role {
    role_arn     = var.tectonic_aws_installer_role != "" ? var.tectonic_aws_installer_role : null
    session_name = "TECTONIC_INSTALLER_${var.tectonic_cluster_name}"
  }
}

resource "aws_autoscaling_group" "masters" {
  name                 = "${var.tectonic_cluster_name}-masters"
  desired_capacity     = var.tectonic_master_count
  max_size             = var.tectonic_master_count * 3
  min_size             = var.tectonic_master_count
  launch_configuration = local.aws_launch_configuration_masters
  vpc_zone_identifier  = local.subnet_ids_masters

  load_balancers = local.aws_lbs_masters

  tags = concat(
    [
      {
        key                 = "Name"
        value               = "${var.tectonic_cluster_name}-master"
        propagate_at_launch = true
      },
      {
        key                 = "kubernetes.io/cluster/${var.tectonic_cluster_name}"
        value               = "owned"
        propagate_at_launch = true
      },
      {
        key                 = "tectonicClusterID"
        value               = local.cluster_id
        propagate_at_launch = true
      }
    ],
    [for tag in var.tectonic_autoscaling_group_extra_tags : {
      key                 = tag.key
      value               = tag.value
      propagate_at_launch = tag.propagate_at_launch
    }]
  )

  lifecycle {
    create_before_destroy = true
  }
}

resource "aws_route53_record" "tnc_internal" {
  zone_id = local.private_zone_id
  name    = "${var.tectonic_cluster_name}-tnc.${var.tectonic_base_domain}"
  type    = "A"

  alias {
    name                   = local.tnc_elb_dns_name
    zone_id                = local.tnc_elb_zone_id
    evaluate_target_health = true
  }
}

variable "tectonic_aws_region" {
  description = "AWS region for the deployment"
  type        = string
}

variable "tectonic_aws_profile" {
  description = "AWS profile for the deployment"
  type        = string
}

variable "tectonic_aws_installer_role" {
  description = "AWS IAM role for the installer"
  type        = string
  default     = ""
}

variable "tectonic_cluster_name" {
  description = "Name of the Tectonic cluster"
  type        = string
}

variable "tectonic_master_count" {
  description = "Number of master nodes"
  type        = number
}

variable "tectonic_base_domain" {
  description = "Base domain for the Tectonic cluster"
  type        = string
}

variable "tectonic_autoscaling_group_extra_tags" {
  description = "Extra tags to be added to the autoscaling groups"
  type        = list(object({
    key                 = string
    value               = string
    propagate_at_launch = bool
  }))
  default = []
}

locals {
  db_subnet_group_name          = coalesce(var.db_subnet_group_name, module.db_subnet_group.this_db_subnet_group_id)
  enable_create_db_subnet_group = var.db_subnet_group_name == "" ? var.create_db_subnet_group : 0

  parameter_group_name    = coalesce(var.parameter_group_name, var.identifier)
  parameter_group_name_id = coalesce(var.parameter_group_name, module.db_parameter_group.this_db_parameter_group_id)

  option_group_name             = coalesce(var.option_group_name, module.db_option_group.this_db_option_group_id)
  enable_create_db_option_group = var.option_group_name == "" && var.engine != "postgres" ? var.create_db_option_group : 0
}

module "db_subnet_group" {
  source = "../db_subnet_group"

  create      = local.enable_create_db_subnet_group
  identifier  = var.identifier
  name_prefix = "${var.identifier}-"
  subnet_ids  = var.subnet_ids

  tags = var.tags
}

module "db_parameter_group" {
  source = "../db_parameter_group"

  create          = var.create_db_parameter_group
  identifier      = var.identifier
  name            = var.parameter_group_name
  description     = var.parameter_group_description
  name_prefix     = "${var.identifier}-"
  use_name_prefix = var.use_parameter_group_name_prefix
  family          = var.family

  parameters = var.parameters

  tags = var.tags
}

module "db_option_group" {
  source = "../db_option_group"

  create                   = local.enable_create_db_option_group
  identifier               = var.identifier
  name_prefix              = "${var.identifier}-"
  option_group_description = var.option_group_description
  engine_name              = var.engine
  major_engine_version     = var.major_engine_version

  options = var.options

  tags = var.tags
}

module "db_instance" {
  source = "../db_instance"

  create            = var.create_db_instance
  identifier        = var.identifier
  engine            = var.engine
  engine_version    = var.engine_version
  instance_class    = var.instance_class
  allocated_storage = var.allocated_storage
  storage_type      = var.storage_type
  storage_encrypted = var.storage_encrypted
  kms_key_id        = var.kms_key_id
  license_model     = var.license_model

  name                                = var.name
  username                            = var.username
  password                            = var.password
  port                                = var.port
  iam_database_authentication_enabled = var.iam_database_authentication_enabled

  replicate_source_db = var.replicate_source_db

  snapshot_identifier = var.snapshot_identifier

  vpc_security_group_ids = var.vpc_security_group_ids
  db_subnet_group_name   = local.db_subnet_group_name
  parameter_group_name   = local.parameter_group_name_id
  option_group_name      = local.option_group_name

  availability_zone   = var.availability_zone
  multi_az            = var.multi_az
  iops                = var.iops
  publicly_accessible = var.publicly_accessible

  allow_major_version_upgrade = var.allow_major_version_upgrade
  auto_minor_version_upgrade  = var.auto_minor_version_upgrade
  apply_immediately           = var.apply_immediately
  maintenance_window          = var.maintenance_window
  skip_final_snapshot         = var.skip_final_snapshot
  copy_tags_to_snapshot       = var.copy_tags_to_snapshot
  final_snapshot_identifier   = var.final_snapshot_identifier

  backup_retention_period = var.backup_retention_period
  backup_window           = var.backup_window

  monitoring_interval    = var.monitoring_interval
  monitoring_role_arn    = var.monitoring_role_arn
  monitoring_role_name   = var.monitoring_role_name
  create_monitoring_role = var.create_monitoring_role

  timezone                        = var.timezone
  character_set_name              = var.character_set_name
  enabled_cloudwatch_logs_exports = var.enabled_cloudwatch_logs_exports

  timeouts = var.timeouts

  deletion_protection = var.deletion_protection

  tags = var.tags
}

variable "identifier" {
