variable "cluster-name-base" {
  default = "kube"
}

variable "region" {
  default = "us-west1"
}

variable "zone" {
  default = "us-west1-a"
}

variable "project" {}

variable "master_machine_type" {
  default = "n1-standard-1"
}

variable "node_machine_type" {
  default = "n1-standard-1"
}

// This token is used to establish trust between nodes in the cluster. You can
// generate it with the following snippet:
//
//   python -c 'import random; print "%0x.%0x" % (random.SystemRandom().getrandbits(3*8), random.SystemRandom().getrandbits(8*8))'
//
// The token has to be in the form of '<6 chars>.<16 chars>'
variable "bootstrap_token" {
  default = ""
}

variable "cidr" {
  default = "10.20.0.0/16"
}

variable "num-nodes" {
  default = 3
}

// Create a whole new network for the Kubernetes cluster. Make the subnets be
// manually managed.
resource "google_compute_network" "network" {
  name                    = var.cluster-name-base
  auto_create_subnetworks = false
}

// Create a subnet for the cluster in the region that we are running in. Have
// it be just for the IPs that we'll assign to hosts.
resource "google_compute_subnetwork" "subnet" {
  name          = "${var.cluster-name-base}-default-${var.region}"
  ip_cidr_range = module.subnets.host_cidr
  network       = google_compute_network.network.name
}

// Allow all traffic between IPs on this network.
resource "google_compute_firewall" "firewall-internal" {
  name    = "${var.cluster-name-base}-internal"
  network = google_compute_network.network.name

  allow {
    protocol = "icmp"
  }

  allow {
    protocol = "tcp"
    ports    = ["1-65535"]
  }

  allow {
    protocol = "udp"
    ports    = ["1-65535"]
  }

  source_ranges = [var.cidr]
}

// Allow SSH (TCP port 22) traffic to reach our VMs on this network.
resource "google_compute_firewall" "firewall-ssh" {
  name    = "${var.cluster-name-base}-ssh"
  network = google_compute_network.network.name

  allow {
    protocol = "tcp"
    ports    = ["22"]
  }

  source_ranges = ["0.0.0.0/0"]
}

// Set up a script that will run per-boot on the VM to set up IP tables. This
// needs to know the overall CIDR so it can make sure that traffic not on that
// network gets NATd as it exits GCE.
data "template_file" "iptables" {
  template = file("tf-scripts/set-iptables.sh")

  vars = {
    cidr = var.cidr
  }
}

// Start up scripts

// This script will install docker, the kubelet and configure networking on the
// node.
data "template_file" "prereq-node" {
  count    = var.num-nodes
  template = file("tf-scripts/prereq.sh")

  vars = {
    bridge_cidr = element(module.subnets.node_container_cidrs, count.index)
    dns_ip      = module.subnets.dns_service_ip
  }
}

// This script will have the node join the master. It verifies itself with the
// token.
data "template_file" "node" {
  template = file("tf-scripts/node.sh")

  vars = {
    token     = var.bootstrap_token
    master_ip = google_compute_instance.master.network_interface.0.address
  }
}

// Package all of this up in to one base64 encoded string so that cloud init in
// the VM can run these scripts once booted.
data "template_cloudinit_config" "node" {
  count         = var.num-nodes
  base64_encode = true
  gzip          = true

  part {
    filename     = "scripts/per-instance/10-prereq.sh"
    content_type = "text/x-shellscript"
    content      = element(data.template_file.prereq-node.*.rendered, count.index)
  }

  part {
    filename     = "scripts/per-instance/20-node.sh"
    content_type = "text/x-shellscript"
    content      = data.template_file.node.rendered
  }

  // Note that this script is run per boot while the others are only run once
  // per instance.
  part {
    filename     = "scripts/per-boot/10-iptables.sh"
    content_type = "text/x-shellscript"
    content      = data.template_file.iptables.rendered
  }
}

// Networking

// Set up a route per node so that all traffic to the container subnet (per
// node) will be routed to that node.
resource "google_compute_route" "node" {
  count                  = var.num-nodes
  name                   = "${var.cluster-name-base}-node-${count.index}"
  dest_range             = element(module.subnets.node_container_cidrs, count.index)
  network                = google_compute_network.network.name
  next_hop_instance      = element(google_compute_instance.node.*.name, count.index)
  next_hop_instance_zone = var.zone
  priority               = 10
}

// VMs

resource "google_compute_instance" "node" {
  count          = var.num-nodes
  name           = "${var.cluster-name-base}-node-${count.index}"
  machine_type   = var.node_machine_type
  zone           = var.zone

  // This allows this VM to send traffic from containers without NAT. Without
  // this set GCE will verify that traffic from a VM only comes from an IP
  // assigned to that VM.
  can_ip_forward = true

  boot_disk {
    initialize_params {
      image = "ubuntu-os-cloud/ubuntu-1604-lts"
      type  = "pd-ssd"
      size  = "200"
    }
  }

  metadata = {
    user_data = element(data.template_cloudinit_config.node.*.rendered, count.index)
    user_data_encoding = "base64"
  }

  network_interface {
    subnetwork = google_compute_subnetwork.subnet.name
    address    = element(module.subnets.node_ips, count.index)

    access_config {
      // Ephemeral IP
    }
  }
}

// Start up scripts

// This script will install docker, the kubelet and configure networking on the
// node.
data "template_file" "prereq-master" {
  template = file("tf-scripts/prereq.sh")

  vars = {
    bridge_cidr = module.subnets.master_container_cidr
    dns_ip      = module.subnets.dns_service_ip
  }
}

// This script will install Kubernetes on the master.
data "template_file" "master" {
  template = file("tf-scripts/master.sh")

  vars = {
    token        = var.bootstrap_token
    service_cidr = module.subnets.service_cidr
  }
}

// Package all of this up in to one base64 encoded string so that cloud init in
// the VM can run these scripts once booted.
data "template_cloudinit_config" "master" {
  base64_encode = true
  gzip          = true

  part {
    filename     = "scripts/per-instance/10-prereq.sh"
    content_type = "text/x-shellscript"
    content      = data.template_file.prereq-master.rendered
  }

  part {
    filename     = "scripts/per-instance/20-master.sh"
    content_type = "text/x-shellscript"
    content      = data.template_file.master.rendered
  }

  // Note that this script is run per boot while the others are only run once
  // per instance.
  part {
    filename     = "scripts/per-boot/10-iptables.sh"
    content_type = "text/x-shellscript"
    content      = data.template_file.iptables.rendered
  }
}

// Networking

// Set up a route for the master so that all traffic to the container subnet on
// the master will be routed to the master.
resource "google_compute_route" "master" {
  name                   = "${var.cluster-name-base}-master"
  dest_range             = module.subnets.master_container_cidr
  network                = google_compute_network.network.name
  next_hop_instance      = google_compute_instance.master.name
  next_hop_instance_zone = var.zone
  priority               = 10
}

// VMs
resource "google_compute_instance" "master" {
  name           = "${var.cluster-name-base}-master"
  machine_type   = var.master_machine_type
  zone           = var.zone

  // This allows this VM to send traffic from containers without NAT. Without
  // this set GCE will verify that traffic from a VM only comes from an IP
  // assigned to that VM.
  can_ip_forward = true

  boot_disk {
    initialize_params {
      image = "ubuntu-os-cloud/ubuntu-1604-lts"
      type  = "pd-ssd"
      size  = "200"
    }
  }

  metadata = {
    user_data = data.template_cloudinit_config.master.rendered
    user_data_encoding = "base64"
  }

  network_interface {
    subnetwork = google_compute_subnetwork.subnet.name
    address    = module.subnets.master_ip

    access_config {
      // Ephemeral IP
    }
  }
}

// Subnets module
module "subnets" {
  source    = "./subnets"
  cidr      = var.cidr
  num-nodes = var.num-nodes
}

