resource "aws_internet_gateway" "chef" {
  vpc_id = aws_vpc.chef.id

  tags = {
    Name    = "Chef IGW"
    Project = "learn_chef"
  }
}

# Create a public subnet.
resource "aws_subnet" "public_subnet" {
  vpc_id                  = aws_vpc.chef.id
  cidr_block              = var.subnet_cidr
  availability_zone       = var.subnet_az
  map_public_ip_on_launch = true
  depends_on              = [aws_internet_gateway.chef]

  tags = {
    Name    = "Chef Public Subnet"
    Project = "learn_chef"
  }
}

# Create a route table allowing all addresses access to the IGW.
resource "aws_route_table" "public" {
  vpc_id = aws_vpc.chef.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.chef.id
  }

  tags = {
    Name    = "Chef Public Route Table"
    Project = "learn_chef"
  }
}

# Associate the route table with the public subnet allowing access to internet.
resource "aws_route_table_association" "public_subnet" {
  subnet_id      = aws_subnet.public_subnet.id
  route_table_id = aws_route_table.public.id
}

# Allows intra-node communication on all ports with all protocols.
resource "aws_security_group" "chef_vpc" {
  name        = "chef_vpc"
  description = "Default security group that allows all instances in the VPC to talk to each other over any port and protocol."
  vpc_id      = aws_vpc.chef.id

  ingress {
    from_port = 0
    to_port   = 0
    protocol  = "-1"
    self      = true
  }

  egress {
    from_port = 0
    to_port   = 0
    protocol  = "-1"
    self      = true
  }

  tags = {
    Name    = "Chef Internal VPC"
    Project = "learn_chef"
  }
}

# Allows public ingress to the instances for HTTP and HTTPS.
resource "aws_security_group" "chef_public_ingress" {
  name        = "chef_public_ingress"
  description = "Security group that allows public ingress to instances over HTTP and HTTPS."
  vpc_id      = aws_vpc.chef.id

  # HTTP
  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  # HTTPS
  ingress {
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name    = "Chef Public Ingress"
    Project = "learn_chef"
  }
}

# Allows public egress from the instances over HTTP and HTTPS for yum updates, git access, etc.
resource "aws_security_group" "chef_public_egress" {
  name        = "chef_public_egress"
  description = "Security group that allows egress to the internet for instances over HTTP and HTTPS."
  vpc_id      = aws_vpc.chef.id

  # HTTP
  egress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  # HTTPS
  egress {
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name    = "Chef Public Egress"
    Project = "learn_chef"
  }
}

# Security group which allows SSH access to a host.
resource "aws_security_group" "chef_ssh" {
  name        = "chef_ssh"
  description = "Security group that allows public ingress over SSH."
  vpc_id      = aws_vpc.chef.id

  # SSH
  ingress {
    from_port   = 22
    to_port     = 22
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name    = "Chef SSH Access"
    Project = "learn_chef"
  }
}

# Define RHEL 7.3 AMI.
data "aws_ami" "rhel7_3" {
  most_recent = true

  owners = ["309956199498"]

  filter {
    name   = "architecture"
    values = ["x86_64"]
  }

  filter {
    name   = "root-device-type"
    values = ["ebs"]
  }

  filter {
    name   = "virtualization-type"
    values = ["hvm"]
  }

  filter {
    name   = "name"
    values = ["RHEL-7.3*"]
  }
}

# Create SSH Key Pair.
resource "aws_key_pair" "keypair" {
  key_name   = var.key_name
  public_key = file(var.public_key_path)
}

# Create Chef Server.
resource "aws_instance" "chef_server" {
  ami           = data.aws_ami.rhel7_3.id
  instance_type = "t2.medium"
  subnet_id     = aws_subnet.public_subnet.id
  key_name      = aws_key_pair.keypair.key_name

  vpc_security_group_ids = [
    aws_security_group.chef_vpc.id,
    aws_security_group.chef_public_ingress.id,
    aws_security_group.chef_public_egress.id,
  ]

  tags = {
    Name    = "Chef Server"
    Project = "learn_chef"
  }

  connection {
    host                = self.private_ip
    user                = "ec2-user"
    private_key         = file("~/.ssh/id_rsa")
    bastion_host        = aws_instance.chef_bastion.public_dns
    bastion_user        = "ec2-user"
    bastion_private_key = file("~/.ssh/id_rsa")
  }

  provisioner "file" {
    source      = "${path.module}/files/server_install.sh"
    destination = "/tmp/server_install.sh"
  }

  provisioner "remote-exec" {
    inline = [
      "chmod +x /tmp/server_install.sh",
      "sudo /tmp/server_install.sh",
    ]
  }
}

# Load the script for the workstation install.
#   We do this because the workstation_install.sh script needs to
#   interpolate the value of the chef_server public DNS.
data "template_file" "workstation_install" {
  template = file("${path.module}/files/workstation_install.sh")

  vars = {
    chef_server = aws_instance.chef_server.public_dns
  }
}

# Create Chef Workstation
resource "aws_instance" "chef_workstation" {
  ami           = data.aws_ami.rhel7_3.id
  instance_type = var.ami_size
  subnet_id     = aws_subnet.public_subnet.id
  key_name      = aws_key_pair.keypair.key_name

  vpc_security_group_ids = [
    aws_security_group.chef_vpc.id,
    aws_security_group.chef_public_egress.id,
  ]

  tags = {
    Name    = "Chef Workstation"
    Project = "learn_chef"
  }

  connection {
    host                = self.private_ip
    user                = "ec2-user"
    private_key         = file("~/.ssh/id_rsa")
    bastion_host        = aws_instance.chef_bastion.public_dns
    bastion_user        = "ec2-user"
    bastion_private_key = file("~/.ssh/id_rsa")
  }

  provisioner "remote-exec" {
    inline = [
      data.template_file.workstation_install.rendered,
    ]
  }
}

# Create Chef Node(s).
resource "aws_instance" "chef_node" {
  ami           = data.aws_ami.rhel7_3.id
  instance_type = var.ami_size
  subnet_id     = aws_subnet.public_subnet.id
  key_name      = aws_key_pair.keypair.key_name
  count         = var.node_count

  vpc_security_group_ids = [
    aws_security_group.chef_vpc.id,
    aws_security_group.chef_public_egress.id,
  ]

  tags = {
    Name    = "Chef Node ${format(count.index + 1)}"
    Project = "learn_chef"
  }

  connection {
    host                = self.private_ip
    user                = "ec2-user"
    private_key         = file("~/.ssh/id_rsa")
    bastion_host        = aws_instance.chef_bastion.public_dns
    bastion_user        = "ec2-user"
    bastion_private_key = file("~/.ssh/id_rsa")
  }

  provisioner "file" {
    source      = "${path.module}/files/node_install.sh"
    destination = "/tmp/node_install.sh"
  }

  provisioner "remote-exec" {
    inline = [
      "chmod +x /tmp/node_install.sh",
      "sudo /tmp/node_install.sh",
    ]
  }
}

# Create Chef Bastion.
resource "aws_instance" "chef_bastion" {
  ami           = data.aws_ami.rhel7_3.id
  instance_type = "t2.micro"
  subnet_id     = aws_subnet.public_subnet.id
  key_name      = aws_key_pair.keypair.key_name

  vpc_security_group_ids = [
    aws_security_group.chef_vpc.id,
    aws_security_group.chef_ssh.id,
    aws_security_group.chef_public_egress.id,
  ]

  tags = {
    Name    = "Chef Bastion"
    Project = "learn_chef"
  }
}

# Null resource to copy keys from chef_server to chef_workstation.
#   Will not run until chef_server and chef_workstation have completed.
resource "null_resource" "copy_key" {
  depends_on = [aws_instance.chef_server, aws_instance.chef_workstation]

  connection {
    host                = aws_instance.chef_server.private_ip
    user                = "ec2-user"
    private_key         = file("~/.ssh/id_rsa")
    bastion_host        = aws_instance.chef_bastion.public_dns
    bastion_user        = "ec2-user"
    bastion_private_key = file("~/.ssh/id_rsa")
  }

  provisioner "file" {
    content     = file("~/.ssh/id_rsa")
    destination = "/tmp/id_rsa"
  }

  provisioner "remote-exec" {
    inline = [
      "chmod 400 /tmp/id_rsa",
      "scp -i /tmp/id_rsa -o StrictHostKeyChecking=no -o UserKnownHostsFile=/dev/null /drop/chefadmin.pem ${aws_instance.chef_workstation.public_dns}:/home/ec2-user/chef-repo/.chef/chefadmin.pem",
      "rm -f /tmp/id_rsa",
    ]
  }
}

# Null resource to setup SSL for chef_workstation to chef_server
resource "null_resource" "ssl_setup_and_cookbook_upload" {
  depends_on = [null_resource.copy_key]

  connection {
    host                = aws_instance.chef_workstation.private_ip
    user                = "ec2-user"
    private_key         = file("~/.ssh/id_rsa")
    bastion_host        = aws_instance.chef_bastion.public_dns
    bastion_user        = "ec2-user"
    bastion_private_key = file("~/.ssh/id_rsa")
  }

  provisioner "remote-exec" {
    inline = [
      "pushd /home/ec2-user/chef-repo && knife ssl fetch && knife ssl check && popd",
      "pushd /home/ec2-user/chef-repo/cookbooks",
      "git clone https://github.com/learn-chef/learn_chef_httpd.git",
      "knife cookbook upload learn_chef_httpd",
      "knife cookbook list",
      "popd",
    ]
  }

  provisioner "file" {
    content     = file("~/.ssh/id_rsa")
    destination = "/tmp/id_rsa"
  }

  provisioner "remote-exec" {
    inline = [
      "chmod 400 /tmp/id_rsa",
      "${data.template_file.bootstrap_nodes.rendered}",
      "rm -f /tmp/id_rsa",
    ]
  }
}

# Output some useful variables
output "chef_server_public_dns" {
