        cidr_blocks = ["0.0.0.0/0"]
    }
    ingress {
        from_port   = 22
        to_port     = 22
        protocol    = "tcp"
        cidr_blocks = ["0.0.0.0/0"]
    }
    ingress {
        from_port   = 2376
        to_port     = 2377
        protocol    = "tcp"
        cidr_blocks = ["0.0.0.0/0"]
    }
    ingress {
        from_port   = 3376
        to_port     = 3377
        protocol    = "tcp"
        cidr_blocks = ["0.0.0.0/0"]
    }
    egress {
        from_port   = 0
        to_port     = 0
        protocol    = "-1"
        cidr_blocks = ["0.0.0.0/0"]
    }
    tags = {
        Name  = "mgmt_sg"
        tool  = "terraform"
        demo  = "traefik"
        area  = "security"
    }
}

# Launch an instance to serve as a manager
resource "aws_instance" "manager" {
    ami                    = data.aws_ami.manager_ami.id
    instance_type          = var.mgr_flavor
    key_name               = var.keypair
    vpc_security_group_ids = [aws_security_group.mgmt_sg.id]
    subnet_id              = aws_subnet.traefik_pub_subnet.id
    depends_on             = [aws_internet_gateway.traefik_gw]
    tags = {
        Name  = "manager"
        tool  = "terraform"
        demo  = "traefik"
        area  = "compute"
        role  = "manager"
    }
}

# Launch one or more instances to serve as worker nodes
resource "aws_instance" "worker" {
    ami                    = data.aws_ami.worker_ami.id
    count                  = var.num_wkr_nodes
    instance_type          = var.wkr_flavor
    key_name               = var.keypair
    vpc_security_group_ids = [aws_security_group.web_sg.id]
    subnet_id              = aws_subnet.traefik_pub_subnet.id
    depends_on             = [aws_internet_gateway.traefik_gw]
    tags = {
        tool  = "terraform"
        demo  = "traefik"
        area  = "compute"
        role  = "worker"
    }
}

output "manager_pub_ip" {
    value = aws_instance.manager.public_ip
}

output "worker_pub_ips" {
    value = aws_instance.worker.*.public_ip
}

