resource "aws_instance" "database_slave" {
  ami           = data.atlas_artifact.SlaveDB.metadata_full.region-us-east-1
  instance_type = "t2.micro"
  subnet_id     = aws_subnet.private[1].id
  monitoring    = true
  key_name      = module.ssh_keys.key_name
  depends_on    = [aws_instance.database_master]

  security_groups = [
    aws_security_group.database_master_security_group.id,
    aws_security_group.consul_security_group.id,
    aws_security_group.primary.id,
  ]

  tags = {
    Name = "database_slave"
  }

