variable "vpc_id" { 
  description = "VPC ID" 
}

variable "cidrs" {
  description = "List of CIDRs, which determines the number of subnets created"
  type = list(string)
}

variable "azs" {
  description = "List of AZs"
  type = list(string)
}

resource "aws_subnet" "set" {
  count = length(var.cidrs)

  vpc_id     = var.vpc_id
  cidr_block = element(var.cidrs, count.index)
  availability_zone = element(var.azs, count.index)

  tags = {
    Env     = var.env
    Name    = "${var.name}-${count.index + 1}"
    Scope   = var.scope
    Segment = var.segment
  }
}

resource "aws_route_table" "set" {
  count  = length(var.cidrs)
  vpc_id = var.vpc_id

  tags = {
    Env     = var.env
    Name    = "${var.name}-${count.index + 1}"
    Scope   = var.scope
    Segment = var.segment
  }
}

resource "aws_route_table_association" "set" {
  count = length(var.cidrs)

  subnet_id      = element(aws_subnet.set.*.id, count.index)
  route_table_id = element(aws_route_table.set.*.id, count.index)
}

output "route_tables" {
  value = aws_route_table.set.*.id
}

output "subnets" {
  value = aws_subnet.set.*.id
}

