resource "aws_s3_bucket" "consul_backups" {
  count = var.enabled * length(var.arenas)

  #XXX
  lifecycle {
    create_before_destroy = true
  }

  bucket_prefix = "nubis-${var.project}-backup-${element(var.arenas, count.index)}-"
