  "Statement": [
    {
      "Action": "sts:AssumeRole",
      "Principal" : { "AWS" : [ ${join(",", formatlist(""%s"", concat(aws_iam_user.admin.*.arn, aws_iam_user.guest.*.arn)))} ]},
