  name = "tcp.${google_dns_managed_zone.env_dns_zone.dns_name}"
  type = "A"
  ttl  = 300

  managed_zone = google_dns_managed_zone.env_dns_zone.name

  rrdatas = [google_compute_address.cf-tcp.address]
}

// Allow ssh from public networks
resource "google_compute_firewall" "allow-ssh" {
  name    = "${var.prefix}-allow-ssh"
  network = google_compute_network.pcf-virt-net.name

  allow {
    protocol = "tcp"
    ports    = ["22"]
  }

  source_ranges = ["0.0.0.0/0"]
  target_tags   = ["allow-ssh"]
}

// Allow http from public
resource "google_compute_firewall" "pcf-allow-http" {
  name    = "${var.prefix}-allow-http"
  network = google_compute_network.pcf-virt-net.name

  allow {
    protocol = "tcp"
    ports    = ["80"]
  }

  source_ranges = ["0.0.0.0/0"]
  target_tags   = ["allow-http", "router"]
}

// Allow https from public
resource "google_compute_firewall" "pcf-allow-https" {
  name    = "${var.prefix}-allow-https"
  network = google_compute_network.pcf-virt-net.name

  allow {
    protocol = "tcp"
    ports    = ["443"]
  }

  source_ranges = ["0.0.0.0/0"]
  target_tags   = ["allow-https", "router"]
}

// GO Router Health Checks
resource "google_compute_firewall" "pcf-allow-http-8080" {
  name    = "${var.prefix}-allow-http-8080"
  network = google_compute_network.pcf-virt-net.name

  allow {
    protocol = "tcp"
    ports    = ["8080"]
  }

  source_ranges = ["0.0.0.0/0"]
  target_tags   = ["router"]
}

// Create Firewall Rule for allow-ert-all com between bosh deployed ert jobs
// This will match the default OpsMan tag configured for the deployment
resource "google_compute_firewall" "allow-ert-all" {
  name       = "${var.prefix}-allow-ert-all"
  depends_on = [google_compute_network.pcf-virt-net]
  network    = google_compute_network.pcf-virt-net.name

  allow {
    protocol = "icmp"
  }

  allow {
    protocol = "tcp"
  }

  allow {
    protocol = "udp"
  }

  target_tags = ["${var.prefix}", "${var.prefix}-opsman", "nat-traverse"]
  source_tags = ["${var.prefix}", "${var.prefix}-opsman", "nat-traverse"]
}

// Allow access to ssh-proxy [Optional]
resource "google_compute_firewall" "cf-ssh-proxy" {
  name       = "${var.prefix}-allow-ssh-proxy"
  depends_on = [google_compute_network.pcf-virt-net]
  network    = google_compute_network.pcf-virt-net.name

  allow {
    protocol = "tcp"
    ports    = ["2222"]
  }

  target_tags = ["${var.prefix}-ssh-proxy", "diego-brain"]
}

// Allow access to Optional CF TCP router
resource "google_compute_firewall" "cf-tcp" {
  name       = "${var.prefix}-allow-cf-tcp"
  depends_on = [google_compute_network.pcf-virt-net]
  network    = google_compute_network.pcf-virt-net.name

  allow {
    protocol = "tcp"
    ports    = ["1024-65535"]
  }

  target_tags = ["${var.prefix}-cf-tcp-lb"]
}

resource "google_compute_instance_group" "ert-http-lb" {
  count       = 3
  name        = "${var.prefix}-http-lb"
  description = "terraform generated pcf instance group that is multi-zone for http/https load balancing"
  zone        = element([var.gcp_zone_1, var.gcp_zone_2, var.gcp_zone_3], count.index)

  named_port {
    name = "http"
    port = 80
  }
}

resource "google_compute_backend_service" "ert_http_lb_backend_service" {
  name        = "${var.prefix}-http-lb-backend"
  port_name   = "http"
  protocol    = "HTTP"
  timeout_sec = 30
  enable_cdn  = false

  backend {
    group = google_compute_instance_group.ert-http-lb[0].self_link
  }

  backend {
    group = google_compute_instance_group.ert-http-lb[1].self_link
  }

  backend {
    group = google_compute_instance_group.ert-http-lb[2].self_link
  }

  health_checks = [google_compute_http_health_check.cf.self_link]
}

resource "google_compute_url_map" "https_lb_url_map" {
  name            = "${var.prefix}-global-pcf"
  default_service = google_compute_backend_service.ert_http_lb_backend_service.self_link
}

resource "google_compute_target_http_proxy" "http_lb_proxy" {
  name        = "${var.prefix}-http-proxy"
  description = "Load balancing front end http"
  url_map     = google_compute_url_map.https_lb_url_map.self_link
}

resource "google_compute_target_https_proxy" "https_lb_proxy" {
  name             = "${var.prefix}-https-proxy"
  description      = "Load balancing front end https"
  url_map          = google_compute_url_map.https_lb_url_map.self_link
  ssl_certificates = [google_compute_ssl_certificate.ssl-cert.self_link]
}

resource "google_compute_ssl_certificate" "ssl-cert" {
  name_prefix = "${var.prefix}-lb-cert-"
  description = "user provided ssl private key / ssl certificate pair"
  certificate = var.pcf_ert_ssl_cert
  private_key = var.pcf_ert_ssl_key

  lifecycle {
    create_before_destroy = true
  }
}

resource "google_compute_http_health_check" "cf" {
  name = "${var.prefix}-cf-public"

  port                = 8080
  request_path        = "/health"
  check_interval_sec  = 5
  timeout_sec         = 3
  healthy_threshold   = 6
  unhealthy_threshold = 3
}

resource "google_compute_global_forwarding_rule" "cf-http" {
  name       = "${var.prefix}-cf-lb-http"
  ip_address = google_compute_global_address.pcf.address
  target     = google_compute_target_http_proxy.http_lb_proxy.self_link
  port_range = "80"
}

resource "google_compute_global_forwarding_rule" "cf-https" {
  name       = "${var.prefix}-cf-lb-https"
  ip_address = google_compute_global_address.pcf.address
  target     = google_compute_target_https_proxy.https_lb_proxy.self_link
  port_range = "443"
}

// Go Router Health check
resource "google_compute_http_health_check" "cf-gorouter" {
  name                = "${var.prefix}-gorouter"
  port                = 8080
  request_path        = "/health"
  check_interval_sec  = 30
  timeout_sec         = 5
  healthy_threshold   = 10
  unhealthy_threshold = 2
}

// TCP Router Health check
resource "google_compute_http_health_check" "cf-tcp" {
  name                = "${var.prefix}-tcp-lb"
  host                = "tcp.${var.system_domain}."
  port                = 80
  request_path        = "/health"
  check_interval_sec  = 30
  timeout_sec         = 5
  healthy_threshold   = 10
  unhealthy_threshold = 2
}

// GoRouter target pool
resource "google_compute_target_pool" "cf-gorouter" {
  name = "${var.prefix}-wss-logs"

  health_checks = [
    google_compute_http_health_check.cf-gorouter.name,
  ]
}

// SSH-Proxy target pool
resource "google_compute_target_pool" "cf-ssh" {
  name = "${var.prefix}-ssh-proxy"
}

// TCP Router target pool
resource "google_compute_target_pool" "cf-tcp" {
  name = "${var.prefix}-cf-tcp-lb"

  health_checks = [
    google_compute_http_health_check.cf-tcp.name,
  ]
}

// Doppler forwarding rule
resource "google_compute_forwarding_rule" "cf-gorouter" {
  name        = "${var.prefix}-gorouter-wss"
  target      = google_compute_target_pool.cf-gorouter.self_link
  port_range  = "443"
  ip_protocol = "TCP"
  ip_address  = google_compute_address.ssh-and-doppler.address
}

// SSH Proxy forwarding rule
resource "google_compute_forwarding_rule" "cf-ssh" {
  name        = "${var.prefix}-ssh-proxy"
  target      = google_compute_target_pool.cf-ssh.self_link
  port_range  = "2222"
  ip_protocol = "TCP"
  ip_address  = google_compute_address.ssh-and-doppler.address
}

// TCP forwarding rule
resource "google_compute_forwarding_rule" "cf-tcp" {
  name        = "${var.prefix}-cf-tcp-lb"
  target      = google_compute_target_pool.cf-tcp.self_link
  port_range  = "1024-65535"
  ip_protocol = "TCP"
  ip_address  = google_compute_address.cf-tcp.address
}

// NAT Primary
resource "google_compute_instance" "nat-gateway-pri" {
  name           = "${var.prefix}-nat-gateway-pri"
  machine_type   = "n1-standard-4"
  zone           = var.gcp_zone_1
  can_ip_forward = true
  tags           = ["${var.prefix}-nat-instance", "nat-traverse"]

  boot_disk {
    initialize_params {
      image = "ubuntu-1404-trusty-v20160610"
    }
  }

  network_interface {
    subnetwork = google_compute_subnetwork.subnet-ops-manager.name

    access_config {
      // Ephemeral
    }
  }

  metadata_startup_script = <<EOF
  #!/bin/bash
  sudo sysctl -w net.ipv4.ip_forward=1
  sudo sh -c 'echo net.ipv4.ip_forward=1 | sudo tee -a /etc/sysctl.conf > /dev/null'
  sudo iptables -t nat -A POSTROUTING -o eth0 -j MASQUERADE
  EOF
}

