###############################################################################
# PowerShellUG-AdfsDemo securitygroups.tf
#
# Author: Chris Brown (chris@chrisbrown.id.au)
# Date:   08/12/2016
###############################################################################

resource "aws_security_group" "rdp" {
    name = "rdp-anywhere"
    description = "Allows ICMP, RDP, HTTP, and HTTPS from anywhere"
    vpc_id = aws_vpc.main.id

    ingress {
        from_port = 0
        to_port   = 0
        protocol  = -1
        self      = true
    }

    ingress {
        from_port = 3389
        to_port   = 3389
        protocol  = "tcp"
        cidr_blocks = ["0.0.0.0/0"]
    }

    ingress {
        from_port = 80
        to_port   = 80
        protocol  = "tcp"
        cidr_blocks = ["0.0.0.0/0"]
    }

    ingress {
        from_port = 443
        to_port   = 443
        protocol  = "tcp"
        cidr_blocks = ["0.0.0.0/0"]
    }
    ingress {
        from_port = 0
        to_port = 0
        protocol = "icmp"
        cidr_blocks = ["0.0.0.0/0"]
    }

    egress {
        from_port   = 0
        to_port     = 0
        protocol    = "-1"
        cidr_blocks = ["0.0.0.0/0"]
    }
}

