  provisioner "local-exec" {
    command =<<-EOT
      gcloud beta builds submit ${local.path} \n        --config ${local.path}/cloudbuild.yaml \n        --substitutions=_SERVICE=$SERVICE,_PROJECT=$PROJECT,_TAG=$TAG
    EOT

