}

variable "public_segment1" {
  default = "192.168.200.0/24"
}

variable "public_segment2" {
  default = "192.168.201.0/24"
}

variable "private_segment1" {
  default = "192.168.100.0/24"
}

variable "private_segment2" {
  default = "192.168.101.0/24"
}

variable "myip" {
  default = "153.156.43.75/32"
}

variable "aws_amis" {
  default = {
      "ap-northeast-1" = "ami-2b08f44a"
  }
}

variable "instance_type" {
  default = "t2.small"
}

#######################
# get current id
#######################

# get vpc id
data "aws_vpc" "selected" {
  filter {
    name   = "tag-value"
    values = ["*${var.app_name}*"]
  }
}

# get subnet id
data "aws_subnet" "public_1" {
  filter {
    name   = "tag-value"
    values = ["*${var.app_name}*public-subnet1*"]
  }
}

data "aws_subnet" "public_2" {
  filter {
    name   = "tag-value"
    values = ["*${var.app_name}*public-subnet2*"]
  }
}

data "aws_subnet" "private_1" {
  filter {
    name   = "tag-value"
    values = ["*${var.app_name}*private-subnet1*"]
  }
}

data "aws_subnet" "private_2" {
  filter {
    name   = "tag-value"
    values = ["*${var.app_name}*private-subnet2*"]
  }
}

# get security group id
data "aws_security_group" "public" {
  filter {
    name   = "tag-value"
    values = ["*${var.app_name}*public-firewall*"]
  }
}

data "aws_security_group" "private" {
  filter {
    name   = "tag-value"
    values = ["*${var.app_name}*private-firewall*"]
  }
}

#######################
# Additonal Variable
#######################

# SSH key
variable "ssh_key_name" {
  default = "hirosue"
}

resource "aws_ecs_cluster" "auth" {
  name = "${var.app_name}-auth"
}

#####################################
# OpenAM Task Setting
#####################################
data "template_file" "openam_task" {
  template = file("task/openam.json")

  vars = {
    app_name   = var.app_name
    aws_region = var.region
  }
}

resource "aws_ecs_task_definition" "openam" {
  family                = "openam"
  container_definitions = data.template_file.openam_task.rendered

  depends_on = [
    aws_cloudwatch_log_group.auth
  ]
}

#####################################
# OpenDJ Task Setting
#####################################
data "template_file" "opendj_task" {
  template = file("task/opendj.json")

  vars = {
    app_name   = var.app_name
    aws_region = var.region
  }
}

resource "aws_ecs_task_definition" "opendj" {
  family                = "opendj"
  container_definitions = data.template_file.opendj_task.rendered

  volume {
    name      = "db"
    host_path = "/ecs/db"
  }

  depends_on = [
    aws_cloudwatch_log_group.auth
  ]
}

#####################################
# OpenAM ALB Setting
#####################################
resource "aws_alb" "openam" {
  name            = "${var.app_name}-openam-alb"
  internal        = false
  security_groups = [data.aws_security_group.public.id]
  subnets         = [data.aws_subnet.public_1.id, data.aws_subnet.public_2.id]

  access_logs {
    bucket = "${var.app_name}-accesslog"
    prefix = "alb_log"
  }

  idle_timeout = 400

  tags = {
    Name  = "${var.app_name} openam-alb"
    Group = var.app_name
  }
}

resource "aws_alb_target_group" "openam" {
  name     = "${var.app_name}-openam-target-group"
  port     = 80
  protocol = "HTTP"
  vpc_id   = data.aws_vpc.selected.id

  tags = {
    Name  = "${var.app_name} openam-target-group"
    Group = var.app_name
  }
}

resource "aws_alb_listener" "openam" {
  load_balancer_arn = aws_alb.openam.id
  port              = "80"
  protocol          = "HTTP"

  default_action {
    target_group_arn = aws_alb_target_group.openam.id
    type             = "forward"
  }
}

#####################################
# OpenDJ ALB Setting
#####################################
resource "aws_alb" "opendj" {
  name            = "${var.app_name}-opendj-alb"
  internal        = true
  security_groups = [data.aws_security_group.private.id]
  subnets         = [data.aws_subnet.private_1.id, data.aws_subnet.private_2.id]

  access_logs {
    bucket = "${var.app_name}-accesslog"
    prefix = "alb_log"
  }

  idle_timeout = 400

  tags = {
    Name  = "${var.app_name} opendj-alb"
    Group = var.app_name
  }
}

resource "aws_alb_target_group" "opendj" {
  name     = "${var.app_name}-opendj-target-group"
  port     = 80
  protocol = "HTTP"
  vpc_id   = data.aws_vpc.selected.id

  tags = {
    Name  = "${var.app_name} opendj-target-group"
    Group = var.app_name
  }
}

resource "aws_alb_listener" "opendj" {
  load_balancer_arn = aws_alb.opendj.id
  port              = "80"
  protocol          = "HTTP"

  default_action {
    target_group_arn = aws_alb_target_group.opendj.id
    type             = "forward"
  }
}

data "template_file" "user_data" {
  template = file("bash/userdata.sh")

  vars = {
    cluster_name = aws_ecs_cluster.auth.name
  }
}

resource "aws_launch_configuration" "auth" {
  name                 = "${var.app_name}-launch-configuration"
  image_id             = lookup(var.aws_amis, var.region)
  key_name             = var.ssh_key_name
  instance_type        = var.instance_type
  iam_instance_profile = "ecsInstanceRole"
  security_groups      = [
    data.aws_security_group.public.id
  ]

  user_data = data.template_file.user_data.rendered
}

#####################################
# Active
#####################################
resource "aws_autoscaling_group" "active" {
  availability_zones   = [var.az1]
  name                 = "${var.app_name}-autoscaling-group-active"
  vpc_zone_identifier  = [data.aws_subnet.public_1.id]
  max_size             = 1
  min_size             = 1
  desired_capacity     = 1
  health_check_grace_period = 300
  health_check_type         = "ELB"
  force_delete              = true
  launch_configuration      = aws_launch_configuration.auth.name
}

#####################################
# Standby
#####################################
resource "aws_autoscaling_group" "standby" {
  availability_zones   = [var.az2]
  name                 = "${var.app_name}-autoscaling-group-stanby"
  vpc_zone_identifier  = [data.aws_subnet.public_2.id]
  max_size             = 0
  min_size             = 0
  desired_capacity     = 0
  health_check_grace_period = 300
  health_check_type         = "ELB"
  force_delete              = true
  launch_configuration      = aws_launch_configuration.auth.name
}

#####################################
# OpenAM Service Setting
#####################################
resource "aws_ecs_service" "openam" {
  name            = "${var.app_name}-auth-service"
  cluster         = aws_ecs_cluster.auth.id
  task_definition = aws_ecs_task_definition.openam.arn
  desired_count   = 1
  iam_role        = "ecsServiceRole"

  load_balancer {
    target_group_arn = aws_alb_target_group.openam.id
    container_name   = "OpenAM"
    container_port   = 8080
  }

  depends_on = [
    aws_alb_listener.openam
  ]
}

#####################################
# OpenDJ Service Setting
#####################################
resource "aws_ecs_service" "opendj" {
  name            = "${var.app_name}-ldap-service"
  cluster         = aws_ecs_cluster.auth.id
  task_definition = aws_ecs_task_definition.opendj.arn
  desired_count   = 1
  iam_role        = "ecsServiceRole"

  load_balancer {
    target_group_arn = aws_alb_target_group.opendj.id
    container_name   = "OpenDJ"
    container_port   = 389
  }

  depends_on = [
    aws_alb_listener.opendj
  ]
}

resource "aws_cloudwatch_log_group" "auth" {
  name = "awslogs-${var.app_name}-auth-log"
}

data "aws_route53_zone" "selected" {
  name = "btc-daifuku.tk."
}

#####################################
# OpenAM Alias Record
#####################################
resource "aws_route53_record" "openam" {
  zone_id = data.aws_route53_zone.selected.zone_id
  name    = "auth.btc-daifuku.tk"
  type    = "A"

