  },
  {
    "name": "dma_name",
    "type": "STRING"
  },
  {
    "name": "dma_id",
    "type": "INTEGER"
  },
  {
    "name": "term",
    "type": "STRING"
  },
  {
    "name": "week",
    "type": "DATE"
  },
  {
    "name": "score",
    "type": "INTEGER"
  },
  {
    "name": "rank",
    "type": "INTEGER"
  }
]
    EOF
  depends_on = [
    google_bigquery_dataset.google_trends
