variable "aws_access_key" {}
variable "aws_access_secret" {}

variable "aws_region" {
    default = "ap-northeast-1"
}

variable "aws_az_a" {
    default = "ap-northeast-1a"
}

variable "aws_az_c" {
    default = "ap-northeast-1c"
}

variable "shared_short_prefix" {
    default = "racco-test"
}

variable "instance_num" {
    default = 2
}

variable "container_count" {
    default = 4
}

variable "ami_id" {
    default = "ami-f63f6f91"
}

resource "aws_vpc" "main" {
    cidr_block           = "10.0.0.0/16"
    enable_dns_hostnames = true
    enable_dns_support   = true
    instance_tenancy     = "default"

    tags = {
        Name = var.shared_short_prefix
    }
}

##
# public subnet
resource "aws_route_table" "route-table-public" {
    vpc_id = aws_vpc.main.id

    route {
        cidr_block = "0.0.0.0/0"
        gateway_id = aws_internet_gateway.gateway-main.id
    }
    tags = {
        Name = "${var.shared_short_prefix}-public"
    }
}

resource "aws_internet_gateway" "gateway-main" {
    vpc_id = aws_vpc.main.id

    tags = {
        Name = var.shared_short_prefix
    }
}

resource "aws_eip" "nat-eip" {
    vpc = true
    depends_on = [aws_internet_gateway.gateway-main]
}

resource "aws_nat_gateway" "nat-main" {
    allocation_id = aws_eip.nat-eip.id
    subnet_id = aws_subnet.subnet-public-az-a.id
}

resource "aws_subnet" "subnet-public-az-a" {
    vpc_id                  = aws_vpc.main.id
    cidr_block              = "10.0.10.0/24"
    availability_zone       = var.aws_az_a
    map_public_ip_on_launch = false

    tags = {
        Name = "${var.shared_short_prefix}-public-az-a"
    }
}

resource "aws_route_table_association" "public-az-a-assoc" {
    route_table_id = aws_route_table.route-table-public.id
    subnet_id = aws_subnet.subnet-public-az-a.id
}

resource "aws_subnet" "subnet-public-az-c" {
    vpc_id                  = aws_vpc.main.id
    cidr_block              = "10.0.15.0/24"
    availability_zone       = var.aws_az_c
    map_public_ip_on_launch = false

    tags = {
        Name = "${var.shared_short_prefix}-public-az-c"
    }
}

resource "aws_route_table_association" "public-az-c-assoc" {
    route_table_id = aws_route_table.route-table-public.id
    subnet_id = aws_subnet.subnet-public-az-c.id
}

##
# private subnet

resource "aws_route_table" "route-table-private" {
    vpc_id = aws_vpc.main.id

    route {
        cidr_block = "0.0.0.0/0"
        nat_gateway_id = aws_nat_gateway.nat-main.id
    }
    tags = {
        Name = "${var.shared_short_prefix}-private"
    }
}

resource "aws_subnet" "subnet-private-az-a" {
    vpc_id                  = aws_vpc.main.id
    cidr_block              = "10.0.20.0/24"
    availability_zone       = var.aws_az_a
    map_public_ip_on_launch = false

    tags = {
        Name = "${var.shared_short_prefix}-private-az-a"
    }
}

resource "aws_route_table_association" "private-az-a-assoc" {
    route_table_id = aws_route_table.route-table-private.id
    subnet_id = aws_subnet.subnet-private-az-a.id
}

resource "aws_subnet" "subnet-private-az-c" {
    vpc_id                  = aws_vpc.main.id
    cidr_block              = "10.0.30.0/24"
    availability_zone       = var.aws_az_c
    map_public_ip_on_launch = false

    tags = {
        Name = "${var.shared_short_prefix}-private-az-c"
    }
}

resource "aws_route_table_association" "private-az-c-assoc" {
    route_table_id = aws_route_table.route-table-private.id
    subnet_id = aws_subnet.subnet-private-az-c.id
}

resource "aws_kms_key" "kms-key" {
    policy = data.template_file.kms-key-policy.rendered

    enable_key_rotation = false
}

data "template_file" "kms-key-policy" {
    template = file("kms-key-policy.json.tpl")

    vars = {
        aws_account_id = data.aws_caller_identity.aws-identity.account_id
    }
}

resource "aws_kms_alias" "kms-alias" {
    name          = "alias/${var.shared_short_prefix}"
    target_key_id = aws_kms_key.kms-key.key_id
}

data "aws_iam_policy_document" "kms-iam-policy-document-admin" {
    statement {
        sid = "AllowUseOfTheKey"

        actions = [
            "kms:Encrypt",
            "kms:Decrypt",
            "kms:ReEncrypt*",
            "kms:GenerateDataKey*",
            "kms:DescribeKey",
        ]

        resources = [aws_kms_key.kms-key.arn]
    }
}

resource "aws_iam_policy" "kms-iam-policy-admin" {
    name        = "${var.shared_short_prefix}-kms-admin"
    path        = "/"
    description = ""
    policy      = data.aws_iam_policy_document.kms-iam-policy-document-admin.json
}

# resource "aws_iam_policy_attachment" "kms-iam-policy-attachment-admin" {
#   name = "developers-attachment-${var.shared_prefix}-kms"
# 
#   users  = []
#   groups = []
#   roles  = []
# 
#   policy_arn = "${aws_iam_policy.kms-iam-policy-admin.arn}"
# }

data "aws_iam_policy_document" "kms-iam-policy-document-decrypt" {
    statement {
        sid = "AllowUseOfTheKey"

        actions = [
            "kms:Decrypt"
        ]

        resources = [aws_kms_key.kms-key.arn]
    }
}

resource "aws_iam_policy" "kms-iam-policy-decrypt" {
    name        = "${var.shared_short_prefix}-kms-decrypt"
    path        = "/"
    description = ""
    policy      = data.aws_iam_policy_document.kms-iam-policy-document-decrypt.json
}

output "kms_key_id" {
    value = aws_kms_key.kms-key.key_id
}

resource "aws_security_group" "cluster-instance-security-group" {
    name   = "${var.shared_short_prefix}-cluster-instance"
    vpc_id = aws_vpc.main.id

    ingress {
        from_port   = 0
        to_port     = 65535
        protocol    = "tcp"
        cidr_blocks = ["0.0.0.0/0"]
    }

    egress {
        from_port   = 0
        to_port     = 0
        protocol    = "-1"
        cidr_blocks = ["0.0.0.0/0"]
    }
}

resource "aws_instance" "cluster-instance" {
    count                       = var.instance_num
    ami                         = var.ami_id
    availability_zone           = var.aws_az_a
    ebs_optimized               = false
    instance_type               = "t2.micro"
    monitoring                  = false
    subnet_id                   = aws_subnet.subnet-private-az-a.id
    vpc_security_group_ids      = [aws_security_group.cluster-instance-security-group.id]
    associate_public_ip_address = false
    source_dest_check           = true
    iam_instance_profile        = aws_iam_instance_profile.cluster-instance-profile.name

    root_block_device {
        volume_type           = "gp2"
        volume_size           = 8
        delete_on_termination = true
    }

    tags = {
        Name = "${var.shared_short_prefix}-host"
    }

    user_data = file("user_data.sh")
}

resource "aws_alb" "lb" {
    name            = var.shared_short_prefix
    idle_timeout    = 60
    internal        = false
    security_groups = [aws_security_group.cluster-lb-security-group.id]
    subnets         = [aws_subnet.subnet-public-az-a.id, aws_subnet.subnet-public-az-c.id]

    enable_deletion_protection = false
}

resource "aws_alb_listener" "lb-listener" {
    load_balancer_arn = aws_alb.lb.arn

    port     = "80"
    protocol = "HTTP"

    default_action {
        target_group_arn = aws_alb_target_group.lb-target-group.arn
        type             = "forward"
    }
}

resource "aws_alb_target_group" "lb-target-group" {
    name     = var.shared_short_prefix
    port     = 80
    protocol = "HTTP"
    vpc_id   = aws_vpc.main.id

    health_check {
        path               = "/"
        interval           = 10
        healthy_threshold  = 2
    }
}

resource "aws_security_group" "cluster-lb-security-group" {
    name   = "${var.shared_short_prefix}-cluster-lb"
    vpc_id = aws_vpc.main.id

    ingress {
        from_port   = 80
        to_port     = 80
        protocol    = "tcp"
        cidr_blocks = ["0.0.0.0/0"]
    }

    egress {
        from_port   = 0
        to_port     = 0
        protocol    = "-1"
        cidr_blocks = ["0.0.0.0/0"]
    }
}

output "alb_target_group_arn" {
    value = aws_alb_target_group.lb-target-group.arn
}

resource "aws_ecs_cluster" "cluster" {
    name = "${var.shared_short_prefix}-cluster"
}

resource "aws_iam_instance_profile" "cluster-instance-profile" {
    name  = "${var.shared_short_prefix}-instance-profile"
    roles = [aws_iam_role.cluster-instance-role.name]
}

resource "aws_iam_role" "cluster-instance-role" {
    name               = "${var.shared_short_prefix}-instance-role"
    assume_role_policy = <<EOF
{
  "Version": "2012-10-17",
  "Statement": [
    {
      "Sid": "",
      "Effect": "Allow",
      "Principal": {
        "Service": "ec2.amazonaws.com"
      },
      "Action": "sts:AssumeRole"
    }
  ]
}
EOF
}

resource "aws_iam_policy_attachment" "cluster-instance-policy-attachment" {
    name      = "${var.shared_short_prefix}-instance-policy-attachment"
    roles     = [aws_iam_role.cluster-instance-role.name]
    policy_arn = "arn:aws:iam::aws:policy/service-role/AmazonEC2ContainerServiceforEC2Role"
}

resource "aws_iam_role" "cluster-service-role" {
    name               = "${var.shared_short_prefix}-service-role"
    assume_role_policy = <<EOF
{
  "Version": "2012-10-17",
  "Statement": [
    {
      "Sid": "",
      "Effect": "Allow",
      "Principal": {
        "Service": "ecs.amazonaws.com"
      },
      "Action": "sts:AssumeRole"
    }
  ]
}
EOF
}

resource "aws_iam_policy_attachment" "cluster-service-policy-attachment" {
    name      = "${var.shared_short_prefix}-service-policy-attachment"
    roles     = [aws_iam_role.cluster-service-role.name]
    policy_arn = "arn:aws:iam::aws:policy/service-role/AmazonEC2ContainerServiceRole"
}

resource "aws_cloudwatch_log_group" "log-group" {
    name              = var.shared_short_prefix
    retention_in_days = 14

    tags = {}
}

resource "aws_iam_role" "task-iam-role" {
    name               = "${var.shared_short_prefix}-task-role"
    assume_role_policy = <<EOF
{
  "Version": "2012-10-17",
  "Statement": [
    {
      "Sid": "",
      "Effect": "Allow",
      "Principal": {
        "Service": "ecs-tasks.amazonaws.com"
      },
      "Action": "sts:AssumeRole"
    }
  ]
}
EOF
}

output "task_role_arn" {
    value = aws_iam_role.task-iam-role.arn
}

output "cluster_service_role_arn" {
    value = aws_iam_role.cluster-service-role.arn
}

output "awslogs_group" {
    value = aws_cloudwatch_log_group.log-group.name
}

resource "aws_ecr_repository" "repo-nginx" {
    name = "${var.shared_short_prefix}/nginx"
}

resource "aws_ecr_repository" "repo-echo" {
    name = "${var.shared_short_prefix}/echo"
}

output "repository_url_nginx" {
