variable "aws_access_key" {
  description = "AWS access key"
}

variable "aws_secret_key" {
  description = "AWS secert access key"
}

variable "aws_region"     {
  description = "AWS region"
  default     = "eu-west-1"
}

variable "vpc_name" {
  default = "rancher"
}

variable "vpc_cidr" {
  description = "CIDR for VPC"
  default = {
    octet_1 = "10"
    octet_2 = "99"
    octet_3 = "0"
    octet_4 = "0"
    mask    = "16"
  }
}

variable "aws_instance_type" {
  description = "Size of aws instance for both the server and hosts"
  default = "t2.small"
}

variable "server_count" {
  description = "Number or Rancher servers to create"
  default = 0
}

variable "server_hostname" {
  description = "Rancher server name"
  default = "b4kk83"
}

variable "server_domain_name" {
  default = "corngoodness.com"
}

/*variable "stage_domain" {
  default = ".com"
}*/

variable "host_count" {
  description = "Number or Rancher hosts to create"
  default = 2
}

variable "agent_registration_url" {
  description = ""
  default = ""
}

variable "rancher_agent_image" {
  description = ""
  default = ""
}

variable "rancher_environment" {
  description = ""
  default = ""
}

variable "region_az_count" {
  default = {
    "us-east-1" = 4
    "eu-west-1" = 3
  }
}

variable "us_east_1_azs" {
  default = {
    "0" = "us-east-1a"
    "1" = "us-east-1b"
    "2" = "us-east-1d"
    "3" = "us-east-1e"
  }
}

variable "eu_west_1_azs" {
  default = {
    "0" = "eu-west-1a"
    "1" = "eu-west-1b"
    "2" = "eu-west-1c"
  }
}

variable "subnet_name" {
  default = {
    "0" = "a"
    "1" = "b"
    "2" = "d"
    "3" = "e"
  }
}

variable "public_subnet" {
  default = {
    octet_3 = "101"
    octet_4 = "0"
    mask    = "24"
  }
}

variable "private_subnet" {
  default = {
    octet_3 = "1"
    octet_4 = "0"
    mask    = "24"
  }
}

/* RanchOS amis by region */
variable "rancheros-amis" {
  description = "Base AMI to launch the instances with"
  default = {
    us-west-1 = "ami-6d2d470d"
    us-east-1 = "ami-53045239" # v0.4.2
    /*us-east-1 = "ami-11740e7b" # v0.4.1
    us-east-1 = "ami-95c09ff0" # v0.4.0*/
    eu-west-1 = "ami-7989240a"
  }
}


/* Setup aws provider */
provider "aws" {
  access_key  = var.aws_access_key
  secret_key  = var.aws_secret_key
  region      = var.aws_region
}

/* Define vpc */
resource "aws_vpc" "rancher" {
  cidr_block = "${var.vpc_cidr["octet_1"]}.${var.vpc_cidr["octet_2"]}.${var.vpc_cidr["octet_3"]}.${var.vpc_cidr["octet_4"]}/${var.vpc_cidr["mask"]}"
  enable_dns_support = true
  enable_dns_hostnames = true

  tags {
    Name = var.vpc_name
  }
}


/* Private subnets */
resource "aws_subnet" "private" {
  vpc_id = aws_vpc.rancher.id
  count  = lookup(var.region_az_count, var.aws_region)
  cidr_block = "${var.vpc_cidr["octet_1"]}.${var.vpc_cidr["octet_2"]}.${var.private_subnet["octet_3"] + count.index}.${var.private_subnet["octet_4"]}/${var.private_subnet["mask"]}"
  availability_zone = lookup(var.eu_west_1_azs, count.index)
  map_public_ip_on_launch = false
  depends_on = [aws_internet_gateway.default]

  tags { Name = "private_${lookup(var.subnet_name, count.index)}" }
}
/*
# Routing table for private subnets
resource "aws_route_table" "private" {
  vpc_id = aws_vpc.rancher.id
  route {
    cidr_block = "0.0.0.0/0"
    instance_id = aws_instance.nat.id
  }

  tags = { Name = "private" }
}

# Associate the routing table to private subnets
resource "aws_route_table_association" "private" {
  count = lookup(var.region_az_count, var.aws_region)
  subnet_id = element(aws_subnet.private.*.id, count.index)
  route_table_id = aws_route_table.private.id
}*/


/* Public subnets */
resource "aws_subnet" "public" {
  vpc_id = aws_vpc.rancher.id
  count  = lookup(var.region_az_count, var.aws_region)
  cidr_block = "${var.vpc_cidr["octet_1"]}.${var.vpc_cidr["octet_2"]}.${var.public_subnet["octet_3"] + count.index}.${var.public_subnet["octet_4"]}/${var.public_subnet["mask"]}"
  availability_zone = lookup(var.eu_west_1_azs, count.index)
  map_public_ip_on_launch = true
  depends_on = [aws_internet_gateway.default]

  tags { Name = "public_${lookup(var.subnet_name, count.index)}" }
}

/* Internet gateway for the public subnets */
resource "aws_internet_gateway" "default" {
  vpc_id = aws_vpc.rancher.id
}

/* Routing table for public subnets */
resource "aws_route_table" "public" {
  vpc_id = aws_vpc.rancher.id
  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.default.id
  }

  tags = { Name = "public" }
}

/* Associate the routing table to public subnets */
resource "aws_route_table_association" "public" {
  count = lookup(var.region_az_count, var.aws_region)
  subnet_id = element(aws_subnet.public.*.id, count.index)
  route_table_id = aws_route_table.public.id
}


/* The Cone of Silence security group */
resource "aws_security_group" "tcos" {
  name = "tcos"
  description = "Allow any inter security group traffic"
  vpc_id = aws_vpc.rancher.id

  ingress {
    from_port   = "0"
    to_port     = "0"
    protocol    = "-1"
    self        = true
  }

  egress {
    from_port   = "0"
    to_port     = "0"
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags {
    Name = "tcos"
  }
}


/* Security group for ssh */
resource "aws_security_group" "ssh" {
  name = "ssh"
  description = "Security group for instances that allow SSH traffic from internet"
  vpc_id = aws_vpc.rancher.id

  ingress {
    from_port = 22
    to_port   = 22
    protocol  = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = "0"
    to_port     = "0"
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags {
    Name = "ssh"
  }
}

/* Security group for the web */
resource "aws_security_group" "web" {
  name = "web"
  description = "Security group for web that allows web traffic from internet"
  vpc_id = aws_vpc.rancher.id

  ingress {
    from_port = 80
    to_port   = 80
    protocol  = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  ingress {
    from_port = 443
    to_port   = 443
    protocol  = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  ingress {
    from_port = 8080
    to_port   = 8080
    protocol  = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port = 0
    to_port = 0
    protocol = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags {
    Name = "web"
  }
}

/* Security group for VPN */
resource "aws_security_group" "vpn" {
  name = "vpn"
  description = "Security group for instances that allows vpn traffic from internet"
  vpc_id = aws_vpc.rancher.id

  ingress {
    from_port = 1194
    to_port   = 1194
    protocol  = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  ingress {
    from_port = 2222
    to_port   = 2222
    protocol  = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = "0"
    to_port     = "0"
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags {
    Name = "vpn"
  }
}

/* Security group for rancher */
resource "aws_security_group" "rancher" {
  name = "rancher"
  description = "Rancher only"
  vpc_id = aws_vpc.rancher.id

  ingress {
    from_port = 500
    to_port   = 500
    protocol  = "udp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  ingress {
    from_port = 4500
    to_port   = 4500
    protocol  = "udp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  ingress {
    from_port = 8080
    to_port   = 8080
    protocol  = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = "0"
    to_port     = "0"
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags {
    Name = "rancher"
  }
}

/* Everything security group */
resource "aws_security_group" "all" {
  name = "rancher-all"
  description = "Wide open for testing"
  vpc_id = aws_vpc.rancher.id

  ingress {
    from_port   = "0"
    to_port     = "0"
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = "0"
    to_port     = "0"
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags {
    Name = "all"
  }
}


resource "aws_key_pair" "insecure" {
  key_name   = "rancher(insecure)-${aws_vpc.rancher.id}"
  public_key = file("${path.module}/secrets/ssh/insecure-key.pub")
}


/* Create Rancher servers */
resource "aws_instance" "server" {
  count = var.server_count
  ami = lookup(var.rancheros-amis, var.aws_region)
  instance_type = var.aws_instance_type
  subnet_id = element(aws_subnet.public.*.id, count.index)
  vpc_security_group_ids = [
    aws_security_group.tcos.id,
    aws_security_group.web.id,
    aws_security_group.ssh.id,
    aws_security_group.rancher.id
  ]
  key_name = aws_key_pair.insecure.key_name
  source_dest_check = false
  user_data = template_file.server.rendered
  tags = {
    Name = "server-${count.index}"
  }
}

resource "aws_eip" "server" {
    instance = aws_instance.server.id
    vpc = true
}

resource "template_file" "server" {
  template = file("${path.module}/templates/server_user_data.tftmpl")

  vars {
    hostname = var.server_hostname
    domain_name = var.server_domain_name
    letsencrypt_image = "sundeer/com.corngoodness.letsencrypt:latest"
  }
}


# Create Rancher hosts
resource "aws_instance" "host" {
  /*depends_on = ["aws_instance.server"]*/
  count = var.host_count
  ami = lookup(var.rancheros-amis, var.aws_region)
  instance_type = var.aws_instance_type
  subnet_id = element(aws_subnet.public.*.id, count.index)
  vpc_security_group_ids = [
    aws_security_group.tcos.id,
    aws_security_group.web.id,
    aws_security_group.rancher.id
  ]
  key_name = aws_key_pair.insecure.key_name
  source_dest_check = false
  user_data = template_file.host.rendered
  tags = {
    Name = "host-${count.index}"
    environment = var.rancher_environment
  }
}

resource "template_file" "host" {
  template = file("${path.module}/templates/host_user_data.tftmpl")

  vars {
    rancher_agent_image = var.rancher_agent_image
    agent_registration_url = var.agent_registration_url
  }
}

output "hosts" {
  value = join(",", aws_instance.host.*.tags.Name)
}



resource "aws_route53_record" "rancher" {
  zone_id = "ZN1WXKLRSIQUR"
  name = "${var.server_hostname}.${var.server_domain_name}"
