terraform {
  required_version = ">= 0.12.0"
  backend "gcs" {
    prefix  = "spez-example-terraform-state"
  }
}

provider "google" {
  project = var.project
  region  = var.region
}

data "google_container_cluster" "primary" {
  name     = var.spez_tailer_cluster
  location = var.region
}

provider "kubernetes" {
  host  = "https://${data.google_container_cluster.primary.endpoint}"
  token = data.google_client_config.default.access_token
  cluster_ca_certificate = base64decode(data.google_container_cluster.primary.master_auth[0].cluster_ca_certificate)
}

data "google_client_config" "default" {}

resource "kubernetes_service" "spez-tailer-service" {
  metadata {
    name = "spez-tailer-service-${var.sink_table}"
  }
  spec {
    port {
      port = var.jmx_port
      name = "jmx-port"
    }
    selector = {
      app = "spez-tailer-${var.sink_table}"
    }
  }
}

resource "kubernetes_deployment" "spez-tailer-deployment" {
  depends_on = [
    google_spanner_database.event-sink-database
  ]

  metadata {
    name = "spez-tailer-deployment-${var.sink_table}"
  }
  spec {
    replicas = 1

    selector {
      match_labels = {
        app = "spez-tailer-${var.sink_table}"
      }
    }
    template {
      metadata {
        labels = {
          app = "spez-tailer-${var.sink_table}"
          version = "v1"
        }
      }
      spec {
        volume {
          name = "service-account"
          secret {
            secret_name = "service-account"
          }
        }
        container {
          name = "spez-tailer"
          image = var.tailer_image
          image_pull_policy = "Always"
          resources {
            limits = {
              memory = "16Gi"
            }
            requests = {
              memory = "8Gi"
            }
          }
          port {
            container_port = var.jmx_port
          }
          args = [
            "-ea",
            "-Djava.net.preferIPv4Stack=true",
            "-Dio.netty.allocator.type=pooled",
            "-XX:+UnlockExperimentalVMOptions",
            "-XX:+UseZGC",
            "-XX:ConcGCThreads=4",
            "-XX:+UseTransparentHugePages",
            "-XX:+UseNUMA",
            "-XX:+UseStringDeduplication",
            "-XX:+HeapDumpOnOutOfMemoryError",
            "-Dcom.sun.management.jmxremote",
            "-Dcom.sun.management.jmxremote.port=${var.jmx_port}",
            "-Dcom.sun.management.jmxremote.rmi.port=${var.jmx_port}",
            "-Dcom.sun.management.jmxremote.local.only=false",
            "-Dcom.sun.management.jmxremote.authenticate=false",
            "-Dcom.sun.management.jmxremote.ssl=false",
            "-Djava.rmi.server.hostname=127.0.0.1",
            "-Dspez.project_id=${var.project}",
            "-Dspez.auth.credentials=default",
            "-Dspez.pubsub.topic=${var.ledger_topic}",
            "-Dspez.sink.instance=${var.sink_instance}",
            "-Dspez.sink.database=${var.sink_database}",
            "-Dspez.sink.table=${var.sink_table}",
            "-Dspez.sink.uuid_column=${var.uuid_column}",
            "-Dspez.sink.timestamp_column=${var.timestamp_column}",
            "-Dspez.lpts.instance=${var.lpts_instance}",
            "-Dspez.lpts.database=${var.lpts_database}",
            "-Dspez.lpts.table=${var.lpts_table}",
            "-Dspez.loglevel.default=${var.log_level}",
            "-jar",
            "Main.jar"
          ]
        }
      }
    }
  }
}

provider "aws" {
  profile = "default"
  region  = var.region
}

# rstudio server
resource "aws_instance" "rstudio" {
  ami = lookup(var.images, var.region)

  # free tier eligible
  instance_type = var.instance_type

  # list of security groups for the instance
  security_groups = [
    aws_security_group.rstudio_security_group.name,
  ]

  availability_zone = var.zone

  key_name = var.keypair_name

  # add a public IP address
  associate_public_ip_address = true

  root_block_device {
    volume_type           = "standard"
    volume_size           = var.disk_size
    delete_on_termination = var.keep_data
  }

  tags {
    Name = "Rstudio Server"
  }

  provisioner "file" {
    connection {
      host        = aws_instance.rstudio.public_ip
      type        = "ssh"
      user        = "ubuntu"
      private_key = file(var.private_key)
    }

    source      = "provisioners/"
    destination = "/tmp"
  }

  provisioner "remote-exec" {
    connection {
      host        = aws_instance.rstudio.public_ip
      type        = "ssh"
      user        = "ubuntu"
      private_key = file(var.private_key)
    }

    inline = [
      "sudo sh /tmp/provision.sh ${var.rstudio_password}",
    ]
  }
}

resource "aws_eip" "rstudio_eip" {
  instance = aws_instance.rstudio.id
}

