    "us-west-2"      = "ami-6a52840a"
    "sa-east-1"      = "ami-55079639"
    "ap-southeast-1" = "ami-ce9c47ad"
    "ap-northeast-1" = "ami-1f79b17e"
    "ap-northeast-2" = "ami-41f4212f"
    "ap-southeast-2" = "ami-b9093fda"
