}

resource "google_compute_attached_disk" "worker_data" {
  project     = var.project_id
  zone        = var.zone
  count       = var.instance_count_worker
  disk        = element(google_compute_disk.gcp_sap_hana_data_worker.*.self_link, count.index + 1)
