    subnetwork_project = string
    network_ip         = string
    access_config = list(object({
      nat_ip       = string
      network_tier = string
    }))
    ipv6_access_config = list(object({
      network_tier = string
    }))
  }))
}

variable "hostname" {
  description = "Hostname of instances"
  type        = string
  default     = ""
}

